STASHDB_QUERY = """
query FindScenesByFullFingerprints($fingerprints: [FingerprintQueryInput!]!) {
  findScenesByFullFingerprints(fingerprints: $fingerprints) {
    id title release_date
    studio { id name }
    performers { performer { id name gender } }
    images { url width height }
  }
}
"""

TPDB_QUERY = """
query FindScenesBySceneFingerprints($fingerprints: [[FingerprintQueryInput]]!) {
  findScenesBySceneFingerprints(fingerprints: $fingerprints) {
    id title release_date
    studio { id name }
    performers { performer { id name gender } }
    images { url width height }
  }
}
"""


SEARCH_SCENES_QUERY = """
query SearchScenes($term: String!, $limit: Int) {
  searchScene(term: $term, limit: $limit) {
    id title release_date duration code
    studio { id name }
    performers { performer { id name gender } }
    images { url width height }
  }
}
"""

QUERY_SCENES_QUERY = """
query QueryScenes($input: SceneQueryInput!) {
  queryScenes(input: $input) {
    count
    scenes {
      id title release_date duration code
      studio { id name }
      performers { performer { id name gender } }
      images { url width height }
    }
  }
}
"""

SEARCH_PERFORMER_QUERY = """
query SearchPerformer($term: String!, $limit: Int) {
  searchPerformer(term: $term, limit: $limit) {
    id
    name
  }
}
"""

SEARCH_STUDIO_QUERY = """
query SearchStudio($term: String!, $limit: Int) {
  searchStudio(term: $term, limit: $limit) {
    id
    name
    images { url width height }
  }
}
"""


def _stashbox_post(endpoint: str, api_key: str, query: str, variables: dict) -> dict:
    resp = requests.post(
        endpoint,
        json={"query": query, "variables": variables},
        headers={"Content-Type": "application/json", "ApiKey": api_key},
        timeout=30,
    )
    # GraphQL servers frequently return 4xx with a JSON body that still
    # carries meaningful errors (e.g. 422 on mutations with missing
    # non-null fields). Try to parse the body before falling back to
    # raise_for_status so downstream logs can show *why* it failed.
    if resp.status_code >= 400:
        try:
            data = resp.json()
            if isinstance(data, dict) and ("errors" in data or "message" in data):
                msg = data.get("errors") or data.get("message") or data
                raise RuntimeError(f"{resp.status_code}: {msg}")
        except ValueError:
            pass
        resp.raise_for_status()
    data = resp.json()
    if "errors" in data:
        raise RuntimeError(str(data["errors"]))
    return data.get("data", {})


def _build_search_term(title: str = None, performer: str = None,
                       studio: str = None) -> str:
    """Combine structured fields into a single search term."""
    parts = []
    if title:
        parts.append(title)
    if performer:
        parts.append(performer)
    if studio:
        parts.append(studio)
    return " ".join(parts)


def search_scenes_on_db(endpoint: str, api_key: str, term: str, limit: int = 25) -> list:
    data = _stashbox_post(endpoint, api_key, SEARCH_SCENES_QUERY, {"term": term, "limit": limit})
    return data.get("searchScene") or []


def query_scenes_by_date(endpoint: str, api_key: str, term: str,
                         date_from: str = None, date_to: str = None,
                         per_page: int = 25) -> list:
    """Use queryScenes with date range filter plus free-text title match."""
    inp = {"per_page": per_page, "page": 1, "direction": "DESC", "sort": "DATE"}
    if term:
        inp["title"] = term
    if date_from or date_to:
        date_range = {}
        if date_from:
            date_range["from"] = date_from
        if date_to:
            date_range["to"] = date_to
        inp["date"] = date_range
    data = _stashbox_post(endpoint, api_key, QUERY_SCENES_QUERY, {"input": inp})
    result = data.get("queryScenes") or {}
    return result.get("scenes") or []


def search_all_databases(term: str = None, title: str = None, performer: str = None,
                         studio: str = None, date_from: str = None,
                         date_to: str = None) -> list:
    """
    Search all three databases, merge and deduplicate results.
    Strategy: build a combined search term from all text fields and use
    searchScene (full-text). If date range given, also run queryScenes
    with date filter and merge results.
    """
    keys = get_api_keys()
    sources = [
        ("StashDB",   STASHDB_ENDPOINT, keys["stashdb"]),
        ("TPDB",     TPDB_ENDPOINT,    keys["tpdb"]),
        ("FansDB",    FANSDB_ENDPOINT,  keys["fansdb"]),
    ]

    # Build a combined search term from all text inputs
    combined = _build_search_term(
        title=title or term,
        performer=performer,
        studio=studio,
    )

    all_results = []
    seen_ids = set()

    def _search_source(source_name, endpoint, api_key):
        """Search a single source, returns list of (scene, source_name) tuples."""
        results = []
        try:
            if combined:
                for s in (search_scenes_on_db(endpoint, api_key, combined) or []):
                    results.append((s, source_name))
            if date_from or date_to:
                for s in (query_scenes_by_date(endpoint, api_key, combined,
                                               date_from=date_from, date_to=date_to) or []):
                    results.append((s, source_name))
        except Exception:
            pass
        return results

    def _search_iafd():
        """IAFD runs on HTML scraping (no API key), so it sits outside the
        keyed stash-box sources. Two paths:

          * **Local first** — if the user gave us a performer name and
            that performer has already been scraped into
            ``iafd_performers`` (either by a prior bulk-scan, manual
            search or the trickle worker), score their stored
            filmography against the title query using the same bucket
            rules as the bulk matcher and return local hits with zero
            HTTP traffic. Effectively instant.
          * **Live fallback** — no performer, or performer isn't
            enriched yet: hit the comprehensive-search URL and post-
            filter by performer. Same path as before.

        The local path is the common case once the trickle has filled
        the library; the fallback covers first-time lookups and
        anonymous / performer-less searches.
        """
        if not combined:
            return []
        local_hits = _search_iafd_from_persisted(title or term, performer, limit=20)
        if local_hits is not None:
            return [(s, "IAFD") for s in local_hits]
        try:
            rows = _iafd_scene_search(combined, performer_filter=performer or "")
        except Exception as exc:
            emit(f"IAFD search failed: {exc}")
            return []
        return [(s, "IAFD") for s in rows]

    active_sources = [(n, e, k) for n, e, k in sources if k]
    #: IAFD toggle lives in settings (Databases panel). Default is on —
    #: it adds a best-effort reference row even when the stash-box DBs
    #: return nothing.
    settings = db.get_settings()
    iafd_enabled = (settings.get("iafd_search_enabled", "true").strip().lower() == "true")

    from concurrent.futures import ThreadPoolExecutor, as_completed
    worker_count = max(1, len(active_sources) + (1 if iafd_enabled else 0))
    with ThreadPoolExecutor(max_workers=worker_count) as pool:
        futures = {pool.submit(_search_source, n, e, k): n for n, e, k in active_sources}
        if iafd_enabled:
            futures[pool.submit(_search_iafd)] = "IAFD"
        for future in as_completed(futures):
            for scene, source_name in future.result():
                sid = scene.get("id")
                if sid and sid not in seen_ids:
                    seen_ids.add(sid)
                    scene["_source"] = source_name
                    all_results.append(scene)

    return all_results

# ---------------------------------------------------------------------------
# Phash
# ---------------------------------------------------------------------------

def get_video_duration(video_path: Path) -> float:
    """Return the runtime of *video_path* in seconds.

    Tries three strategies in order, because a single ffprobe query
    isn't reliable across all containers:

    1. ``packet=pts_time`` with ``-read_intervals`` — fastest for MP4/MKV.
    2. ``packet=pts_time`` over the full file — slower but same shape.
    3. ``format=duration`` — the container's stored duration.

    AVI (and some old MP4s) emit ``N/A`` for packet pts_time, which
    would otherwise raise ``ValueError: could not convert string to
    float: 'N/A'`` and bubble up into the filer as a hard error. We
    skip any ``N/A`` / empty lines and fall through until something
    parses. If every strategy fails we raise ``ValueError`` so the
    caller can decide whether that's fatal (building a sprite can't
    proceed without a duration) or just log-and-continue.
    """
    def _first_float(text: str) -> float | None:
        for line in reversed(text.strip().split("\n")):
            s = line.strip()
            if not s or s.upper() == "N/A":
                continue
            try:
                return float(s)
            except ValueError:
                continue
        return None

    base = ["ffprobe", "-hide_banner", "-loglevel", "error", "-of",
            "compact=p=0:nk=1"]
    packet_args = ["-show_entries", "packet=pts_time"]
    # Attempt 1: tail-seek for speed.
    try:
        res = subprocess.run(
            [*base, *packet_args, "-read_intervals", "9999999%+#1000",
             str(video_path)],
            check=True, capture_output=True, text=True,
        )
        v = _first_float(res.stdout)
        if v is not None:
            return v
    except subprocess.CalledProcessError:
        pass
    # Attempt 2: full scan.
    try:
        res = subprocess.run(
            [*base, *packet_args, str(video_path)],
            check=True, capture_output=True, text=True,
        )
        v = _first_float(res.stdout)
        if v is not None:
            return v
    except subprocess.CalledProcessError:
        pass
    # Attempt 3: container-reported duration (robust for AVI).
    try:
        res = subprocess.run(
            [*base, "-show_entries", "format=duration", str(video_path)],
            check=True, capture_output=True, text=True,
        )
        v = _first_float(res.stdout)
        if v is not None:
            return v
    except subprocess.CalledProcessError:
        pass
    raise ValueError(f"could not determine duration for {video_path.name}")


def probe_video_stream_meta(
    video_path: Path,
) -> tuple[str | None, int | None, int | None]:
    """First video stream: codec name, width, height (via ffprobe)."""
    cmd = [
        "ffprobe",
        "-hide_banner",
        "-loglevel",
        "error",
        "-print_format",
        "json",
        "-show_streams",
        "-select_streams",
        "v:0",
        str(video_path),
    ]
    try:
        res = subprocess.run(
            cmd,
            check=True,
            capture_output=True,
            text=True,
            timeout=120,
        )
        data = json.loads(res.stdout or "{}")
        streams = data.get("streams") or []
        if not streams:
            return None, None, None
        s0 = streams[0]
        codec = (s0.get("codec_name") or "").strip() or None
        wi = s0.get("width")
        hi = s0.get("height")
        w = int(wi) if wi is not None else None
        h = int(hi) if hi is not None else None
        return codec, w, h
    except (subprocess.CalledProcessError, json.JSONDecodeError, ValueError, subprocess.TimeoutExpired):
        return None, None, None


def _file_stat_created_iso(st: os.stat_result) -> str:
    """Best-effort file creation / birth date for library UI (YYYY-MM-DD)."""
    ts = getattr(st, "st_birthtime", None)
    if ts is None:
        ts = st.st_mtime
    try:
        return datetime.fromtimestamp(ts).strftime("%Y-%m-%d")
    except (ValueError, OSError):
        return ""


def _library_index_compute_media_probe_fields(
    row: dict, vpath: Path
) -> tuple[float, str | None, str | None, int | None, int | None] | None:
    """Stat + optional ffprobe; returns args for library_file_update_media_probe. None if stat fails."""
    try:
        st = vpath.stat()
    except OSError:
        return None
    mt = float(st.st_mtime)
    created_iso = _file_stat_created_iso(st) or None
    prev_mt = row.get("media_mtime")
    codec = row.get("media_codec")
    w = row.get("media_width")
    h = row.get("media_height")
    need_probe = True
    if prev_mt is not None:
        try:
            need_probe = abs(float(prev_mt) - mt) > 1e-6
        except (TypeError, ValueError):
            need_probe = True
    if need_probe:
        pc, pw, ph = probe_video_stream_meta(vpath)
        codec, w, h = pc, pw, ph
    else:
        if w is not None:
            try:
                w = int(w)
            except (TypeError, ValueError):
                w = None
        if h is not None:
            try:
                h = int(h)
            except (TypeError, ValueError):
                h = None
    return (mt, created_iso, codec, w, h)


def _library_index_sync_media_for_row(row: dict, vpath: Path) -> None:
    """Refresh cached size/mtime, ffprobe when the file changed on disk."""
    pr = _library_index_compute_media_probe_fields(row, vpath)
    if pr is None:
        return
    mt, created_iso, codec, w, h = pr
    db.library_file_update_media_probe(
        int(row["id"]),
        media_codec=codec,
        media_width=w,
        media_height=h,
        file_created_iso=created_iso,
        media_mtime=mt,
    )


def _library_index_row_probe_snapshot(row: dict) -> dict:
    return {
        "media_mtime": row.get("media_mtime"),
        "media_codec": row.get("media_codec"),
        "media_width": row.get("media_width"),
        "media_height": row.get("media_height"),
    }


def _library_index_probe_needed(row: dict, vpath: Path) -> bool:
    try:
        st = vpath.stat()
    except OSError:
        return False
    mt = float(st.st_mtime)
    prev = row.get("media_mtime")
    if prev is None:
        return True
    try:
        return abs(float(prev) - mt) > 1e-6
    except (TypeError, ValueError):
        return True


def _library_index_heavy_task(item: dict) -> dict:
    """Subprocess-heavy work for one video (phash and/or ffprobe). Index job runs this sequentially."""
    vpath = Path(item["path_str"])
    dest_str = item["dest_str"]
    out: dict = {
        "dest_str": dest_str,
        "phash": None,
        "phash_err": None,
        "probe": None,
    }
    if item.get("need_phash"):
        try:
            out["phash"] = compute_phash(vpath)
        except Exception as e:
            out["phash_err"] = str(e)
    if item.get("need_probe"):
        row_snap = item.get("row_for_probe")
        if row_snap is None:
            row_snap = {}
        out["probe"] = _library_index_compute_media_probe_fields(row_snap, vpath)
    return out


def _library_index_persist_heavy_task_result(item: dict, result: dict) -> None:
    """Persist phash2 and/or media probe as soon as a heavy task finishes (survives crashes)."""
    row_id = int(item["row_id"])
    name = Path(item["path_str"]).name

    if item.get("need_phash"):
        if result.get("phash_err"):
            emit(f"LIBRARY INDEX phash2 {name}: {result['phash_err']}")
        h = result.get("phash")
        if h:
            try:
                db.library_file_set_phash2(row_id, h)
            except Exception as e:
                emit(f"LIBRARY INDEX phash2 {name}: {e}")
            else:
                result["__phash_persisted"] = True

    if item.get("need_probe"):
        pr = result.get("probe")
        if pr is not None and pr:
            mt, created_iso, codec, w, h = pr
            try:
                db.library_file_update_media_probe(
                    row_id,
                    media_codec=codec,
                    media_width=w,
                    media_height=h,
                    file_created_iso=created_iso,
                    media_mtime=mt,
                )
                result["__probe_persisted"] = True
            except Exception as e:
                emit(f"LIBRARY INDEX media {name}: {e}")


def _health_video_has_sidecar_nfo(video_path: Path, library_root_str: str) -> bool:
    """Same rules as scan_library_issues: stem NFO; under Features subfolders also movie.nfo."""
    s = db.get_settings()
    fd_raw = (s.get("features_dir") or "").strip()
    try:
        par = video_path.parent
        names = [x.name for x in par.iterdir() if x.is_file()]
    except OSError:
        return False
    name_set = set(names)
    stem = video_path.stem
    if f"{stem}.nfo" in name_set:
        return True
    lower_ok = any(n.lower() == "movie.nfo" for n in names)
    if not lower_ok or not fd_raw:
        return False
    try:
        lr = Path(library_root_str).expanduser().resolve()
        feat = Path(fd_raw).expanduser().resolve()
    except OSError:
        lr = Path(library_root_str).expanduser()
        feat = Path(fd_raw).expanduser()
    try:
        if lr == feat and par != lr and par.parent.resolve() == feat:
            return True
    except OSError:
        if str(lr) == str(feat) and par != lr and str(par.parent) == str(feat):
            return True
    return False


def get_sprite_screenshot(video_path: Path, t: float) -> Image.Image:
    cmd = ["ffmpeg", "-hide_banner", "-loglevel", "error",
           "-ss", str(t), "-i", str(video_path),
           "-frames:v", "1", "-vf", f"scale={SCREENSHOT_SIZE}:{-2}",
           "-c:v", "bmp", "-f", "image2", "-"]
    res = subprocess.run(cmd, check=True, capture_output=True, timeout=60)
    return Image.open(BytesIO(res.stdout))


def build_sprite(video_path: Path) -> Image.Image:
    """
    25 ffmpeg invocations with -ss before -i (input seeking) + Pillow montage, run
    concurrently (one thread per frame grab). This is much faster on long files than a
    single decode with vf select=, which must scan/decode linearly to match timestamps.
    """
    duration = get_video_duration(video_path)
    offset = 0.05 * duration
    step = (0.9 * duration) / (COLUMNS * ROWS)
    timestamps = [offset + i * step for i in range(COLUMNS * ROWS)]

    def grab(t: float) -> Image.Image:
        return get_sprite_screenshot(video_path, t)

    with ThreadPoolExecutor(max_workers=COLUMNS * ROWS) as pool:
        images = list(pool.map(grab, timestamps))
    w, h = images[0].size
    montage = Image.new("RGB", (w * COLUMNS, h * ROWS))
    for i, img in enumerate(images):
        montage.paste(img, (w * (i % COLUMNS), h * math.floor(i / ROWS)))
    return montage


def compute_phash(video_path: Path) -> str:
    return str(imagehash.phash(build_sprite(video_path)))

# ---------------------------------------------------------------------------
# Stash-box queries
# ---------------------------------------------------------------------------

def query_stashbox(phash_hex, endpoint, api_key, query, fingerprint_var):
    if fingerprint_var == "full":
        variables = {"fingerprints": [{"hash": phash_hex, "algorithm": "PHASH"}]}
    else:
        variables = {"fingerprints": [[{"hash": phash_hex, "algorithm": "PHASH"}]]}
    resp = requests.post(endpoint,
                         json={"query": query, "variables": variables},
                         headers={"Content-Type": "application/json", "ApiKey": api_key},
                         timeout=30)
    resp.raise_for_status()
    data = resp.json()
    if "errors" in data:
        raise RuntimeError(f"Stash-box error: {data['errors']}")
    result = data.get("data", {})
    if "findScenesByFullFingerprints" in result:
        return result["findScenesByFullFingerprints"] or []
    if "findScenesBySceneFingerprints" in result:
        nested = result["findScenesBySceneFingerprints"] or []
        return [s for group in nested for s in (group or [])]
    return []


def query_with_fallback(phash_hex):
    keys = get_api_keys()
    try:
        m = query_stashbox(phash_hex, STASHDB_ENDPOINT, keys["stashdb"], STASHDB_QUERY, "full")
        if m: return m, "StashDB"
    except Exception as e:
        emit(f"  WARNING: StashDB failed ({e}), trying TPDB...")
    try:
        m = query_stashbox(phash_hex, TPDB_ENDPOINT, keys["tpdb"], TPDB_QUERY, "scene")
        if m: return m, "TPDB"
    except Exception as e:
        emit(f"  WARNING: TPDB failed ({e}), trying FansDB...")
    try:
        m = query_stashbox(phash_hex, FANSDB_ENDPOINT, keys["fansdb"], STASHDB_QUERY, "full")
        if m: return m, "FansDB"
    except Exception as e:
        raise RuntimeError(f"FansDB also failed: {e}")
    return [], "none"


# ---------------------------------------------------------------------------
# Library health: duplicate groups (recommendation, resolve, scene fetch)
# ---------------------------------------------------------------------------

_dup_resolve_lock = threading.Lock()
_dup_resolve_status: dict = {
    "running": False,
    "resolved": 0,
    "skipped": 0,
    "done": False,
    "result": None,
}


def _stashbox_normalize_match_source(ms: str) -> str:
    x = (ms or "").strip().lower()
    if x == "stashdb":
        return "StashDB"
    if x in ("tpdb", "theporndb"):
        return "TPDB"
    if x == "fansdb":
        return "FansDB"
    return (ms or "").strip() or "Manual"


def _api_source_tag(ms: str) -> str | None:
    x = (ms or "").strip().lower()
    if x == "stashdb":
        return "stashdb"
    if x in ("tpdb", "theporndb"):
        return "tpdb"
    if x == "fansdb":
        return "fansdb"
    return None


def _endpoint_query_var_for_match_source(ms: str) -> tuple[str, str, str] | None:
    keys = get_api_keys()
    x = (ms or "").strip().lower()
    if x == "stashdb":
        return STASHDB_ENDPOINT, keys["stashdb"], "full"
    if x in ("tpdb", "theporndb"):
        return TPDB_ENDPOINT, keys["tpdb"], "scene"
    if x == "fansdb":
        return FANSDB_ENDPOINT, keys["fansdb"], "full"
    return None


def _pick_scene_from_matches(
    matches: list, title: str, date: str
) -> dict | None:
    if not matches:
        return None
    t = (title or "").strip().lower()
    d = (date or "").strip()
    for s in matches:
        if not isinstance(s, dict):
            continue
        st = (s.get("title") or "").strip().lower()
        sd = (s.get("release_date") or "").strip()
        if t and d and st == t and sd == d:
            return s
    for s in matches:
        if not isinstance(s, dict):
            continue
        if (s.get("release_date") or "").strip() == d and d:
            return s
    return matches[0] if matches else None


def _fetch_scene_for_processed_row(pf: dict) -> tuple[dict | None, str]:
    """Return (stash-box scene dict, normalized source label for filing) or (None, '')."""
    ms = (pf.get("match_source") or "").strip()
    if not ms or ms.lower() == "manual":
        return None, ""
    ep = _endpoint_query_var_for_match_source(ms)
    if not ep:
        return None, ""
    endpoint, api_key, qvar = ep
    if not (api_key or "").strip():
        return None, ""
    label = _stashbox_normalize_match_source(ms)
    phash = (pf.get("phash") or "").strip()
    title = (pf.get("match_title") or "").strip()
    date = (pf.get("match_date") or "").strip()
    q = STASHDB_QUERY if qvar == "full" else TPDB_QUERY
    if phash:
        try:
            matches = query_stashbox(phash, endpoint, api_key, q, qvar)
        except Exception:
            matches = []
        scene = _pick_scene_from_matches(matches, title, date)
        if scene:
            return scene, label
    if title:
        try:
            matches = search_scenes_on_db(endpoint, api_key, title, limit=20)
        except Exception:
            matches = []
        scene = _pick_scene_from_matches(matches, title, date)
        if scene:
            return scene, label
    return None, ""


def _dup_resolution_pixels(f: dict) -> int:
    try:
        w = int(f.get("media_width")) if f.get("media_width") is not None else 0
        h = int(f.get("media_height")) if f.get("media_height") is not None else 0
    except (TypeError, ValueError):
        return 0
    return max(0, w) * max(0, h)


def _dup_int_size(f: dict) -> int:
    try:
        v = f.get("size_bytes")
        return int(v) if v is not None else 0
    except (TypeError, ValueError):
        return 0


def _duplicate_recommend(group: list[dict]) -> dict:
    """
    Pick keeper: higher resolution, larger size, longer filename, lower id.
    If top two tie on resolution and size within 1%, confidence is low.
    """
    if not group:
        return {
            "keeper": None,
            "confidence": "low",
            "recommended_destination": None,
        }
    if len(group) == 1:
        k0 = group[0]
        return {
            "keeper": k0,
            "confidence": "high",
            "recommended_destination": (k0.get("destination") or "").strip(),
        }

    def sort_key(f: dict) -> tuple:
        dst = (f.get("destination") or "").strip()
        fn = (f.get("current_filename") or "").strip()
        if not fn and dst:
            try:
                fn = Path(dst).name
            except Exception:
                fn = ""
        try:
            fid = int(f.get("id") or 0)
        except (TypeError, ValueError):
            fid = 0
        return (
            -_dup_resolution_pixels(f),
            -_dup_int_size(f),
            -len(fn),
            fid,
        )

    ranked = sorted(group, key=sort_key)
    keeper = ranked[0]
    second = ranked[1]
    confidence = "high"
    r1 = _dup_resolution_pixels(keeper)
    r2 = _dup_resolution_pixels(second)
    s1 = _dup_int_size(keeper)
    s2 = _dup_int_size(second)
    if r1 == r2 and s1 > 0 and s2 > 0:
        lo, hi = min(s1, s2), max(s1, s2)
        if hi <= lo * 1.01:
            confidence = "low"
    return {
        "keeper": keeper,
        "confidence": confidence,
        "recommended_destination": (keeper.get("destination") or "").strip(),
    }


def _health_unlink_nfo_thumb_sidecars(video_path: Path) -> None:
    """Remove same-stem NFO and poster/thumb images beside a video (not the video file)."""
    folder = video_path.parent
    stem = video_path.stem
    for name in (
        f"{stem}.nfo",
        f"{stem}-thumb.jpg",
        f"{stem}-thumb.png",
        f"{stem}.jpg",
        f"{stem}.jpeg",
        f"{stem}.png",
    ):
        p = folder / name
        if p.is_file():
            try:
                p.unlink()
            except OSError:
                pass


def _duplicate_delete_one_library_video(dest: str) -> int:
    """Delete video + sidecars, library_files row, linked processed_files row. Returns freed bytes."""
    raw = (dest or "").strip()
    if not raw:
        return 0
    p = Path(raw)
    freed = 0
    if p.is_file():
        try:
            freed = int(p.stat().st_size)
        except OSError:
            freed = 0
    row = db.library_file_get_by_destination(raw)
    if row and row.get("source_record_id") is not None:
        try:
            db.processed_file_delete_by_id(int(row["source_record_id"]))
        except Exception:
            pass
    _health_delete_video_and_sidecars(p)
    db.library_file_delete_by_destination(raw)
    return freed


def _duplicate_resolve_non_keepers(
    keep_path: str, delete_paths: list[str], *, clear_pending_keeper_id: int | None
) -> dict:
    """Shared resolve: delete non-keepers, optionally clear pending on keeper. Returns freed_bytes."""
    roots = _health_library_roots()
    kp = (keep_path or "").strip()
    if not kp:
        return {"ok": False, "error": "keep_path required", "freed_bytes": 0}
    try:
        _health_assert_path_under_roots(kp, roots)
    except ValueError as e:
        return {"ok": False, "error": str(e), "freed_bytes": 0}
    freed = 0
    seen: set[str] = set()
    for raw in delete_paths:
        d = (raw or "").strip()
        if not d or d == kp or d in seen:
            continue
        seen.add(d)
        try:
            _health_assert_path_under_roots(d, roots)
        except ValueError:
            continue
        freed += _duplicate_delete_one_library_video(d)
    if clear_pending_keeper_id is not None:
        try:
            db.library_files_clear_duplicate_pending(int(clear_pending_keeper_id))
        except Exception:
            pass
    return {"ok": True, "freed_bytes": freed}


def _duplicate_apply_metadata_sync(path_raw: str, source_record_id: int) -> dict:
    lf = db.library_file_get_by_destination((path_raw or "").strip())
    if not lf:
        return {"ok": False, "error": "Library file not found"}
    try:
        sid = int(source_record_id)
    except (TypeError, ValueError):
        return {"ok": False, "error": "Invalid source_record_id"}
    if int(lf.get("source_record_id") or 0) != sid:
        return {"ok": False, "error": "source_record_id does not match this file"}
    pf = db.processed_file_get_by_id(sid)
    if not pf:
        return {"ok": False, "error": "Could not fetch scene record"}
    scene, src_label = _fetch_scene_for_processed_row(pf)
    if not scene:
        return {"ok": False, "error": "Could not fetch scene record"}
    video = Path((path_raw or "").strip())
    if not video.is_file():
        return {"ok": False, "error": "Video not found on disk"}
    settings = db.get_settings()
    plan = _scene_filing_plan(scene, settings, src_label, video.suffix)
    st = plan.get("status")
    if st == "error":
        return {"ok": False, "error": plan.get("error", "plan error")}
    if st == "no_dir":
        return {"ok": False, "error": "Could not fetch scene record"}

    dest_season = plan["dest_season"]
    base_name = plan["base_name"]
    new_path = dest_season / f"{base_name}{video.suffix}"
    try:
        old_r = str(video.resolve())
    except OSError:
        old_r = str(video)
    try:
        new_r = str(new_path.resolve())
    except OSError:
        new_r = str(new_path)

    if old_r != new_r:
        _health_unlink_nfo_thumb_sidecars(video)
        try:
            safe_move(video, new_path)
        except Exception as e:
            return {"ok": False, "error": str(e)}
        video = new_path
    else:
        video = new_path

    wr = write_library_scene_nfo_and_thumb(video, scene, source=src_label)
    if wr.get("status") == "error":
        return {"ok": False, "error": wr.get("error", "write failed")}
    if wr.get("status") == "no_dir":
        return {"ok": False, "error": wr.get("error", "write failed")}

    row_id = int(lf["id"])
    try:
        dest_key = str(video.resolve())
    except OSError:
        dest_key = str(video)
    db.library_file_update_destination_row(
        row_id,
        destination=dest_key,
        current_filename=video.name,
        filename_stem=video.stem,
    )
    db.library_files_clear_duplicate_pending(row_id)
    db.processed_file_update_library_destination(sid, destination=dest_key, filename=video.name)
    return {"ok": True, "new_path": dest_key, "new_filename": video.name}


def _run_dup_resolve_all_job() -> None:
    global _dup_resolve_status
    resolved_n = 0
    skipped_n = 0
    freed_total = 0
    skipped_groups: list[dict] = []
    try:
        raw_groups = db.library_files_duplicate_groups()
        for g in raw_groups:
            files_raw = [dict(r) for r in g.get("files") or []]
            if any(int(r.get("duplicate_ignored") or 0) for r in files_raw):
                continue
            enriched = [_health_dup_file_payload(r) for r in files_raw]
            rec = _duplicate_recommend(enriched)
            if rec.get("confidence") == "low":
                skipped_n += 1
                ids = [int(r["id"]) for r in files_raw if r.get("id") is not None]
                db.library_files_mark_duplicate_pending(ids)
                skipped_groups.append(
                    {
                        "phash": g.get("phash"),
                        "files": enriched,
                    }
                )
                with _dup_resolve_lock:
                    _dup_resolve_status["skipped"] = skipped_n
                    _dup_resolve_status["resolved"] = resolved_n
                continue
            keeper = rec.get("keeper") or {}
            kpath = (keeper.get("destination") or "").strip()
            if not kpath:
                continue
            to_del = [
                (f.get("destination") or "").strip()
                for f in enriched
                if (f.get("destination") or "").strip() != kpath
            ]
            kid = keeper.get("id")
            r = _duplicate_resolve_non_keepers(
                kpath,
                to_del,
                clear_pending_keeper_id=int(kid) if kid is not None else None,
            )
            if r.get("ok"):
                resolved_n += 1
                freed_total += int(r.get("freed_bytes") or 0)
                with _dup_resolve_lock:
                    _dup_resolve_status["resolved"] = resolved_n
                    _dup_resolve_status["skipped"] = skipped_n
        result = {
            "resolved": resolved_n,
            "freed_bytes": freed_total,
            "skipped": skipped_n,
            "skipped_groups": skipped_groups,
        }
        with _dup_resolve_lock:
            _dup_resolve_status["resolved"] = resolved_n
            _dup_resolve_status["skipped"] = skipped_n
            _dup_resolve_status["done"] = True
            _dup_resolve_status["running"] = False
            _dup_resolve_status["result"] = result
    except Exception as e:
        with _dup_resolve_lock:
            _dup_resolve_status["running"] = False
            _dup_resolve_status["done"] = True
            _dup_resolve_status["result"] = {"error": str(e)}


# ---------------------------------------------------------------------------
# Download folder processor
# ---------------------------------------------------------------------------

JUNK_EXTENSIONS = {
    ".nfo", ".nzb", ".srr", ".sfv", ".jpg", ".jpeg", ".png", ".gif",
    ".txt", ".url", ".exe", ".bat", ".sub", ".srt", ".ass", ".ssa",
    ".idx", ".md5", ".xml", ".html", ".htm", ".lnk", ".torrent",
}


def _looks_like_gibberish(stem: str) -> bool:
    """
    True if the filename stem has no separators at all.
    Readable names use dots, spaces, dashes or underscores as word breaks.
    Pure gibberish is a run of characters with no breaks whatsoever.
    """
    return not any(c in stem for c in ".-_ ")


def _process_download_entry(entry_path: Path, dest_dir: Path) -> list[Path]:
    """
    Process a single file or folder from the download watch directory.
    - Deletes junk and sample files
    - Renames video to folder name if filename looks like gibberish
    - Moves video(s) to dest_dir
    - Deletes the source folder
    Returns paths of video files after move (for movie queue → auto-filing).
    """
    emit(f"DOWNLOAD {entry_path.name}")
    moved_videos: list[Path] = []

    if entry_path.is_file():
        # Single file dropped directly
        if entry_path.suffix.lower() not in VIDEO_EXTENSIONS:
            emit(f"  Skipped: not a video ({entry_path.suffix})")
            return moved_videos
        if "sample" in entry_path.name.lower():
            emit(f"  Skipped: sample file")
            entry_path.unlink()
            return moved_videos
        dest = dest_dir / entry_path.name
        safe_move(entry_path, dest)
        moved_videos.append(dest)
        emit(f"  Moved: {entry_path.name}")
        return moved_videos

    if not entry_path.is_dir():
        return moved_videos

    folder_name = entry_path.name

    # Gather all files recursively
    all_files = list(entry_path.rglob("*"))

    # Find non-sample videos
    videos = [
        f for f in all_files
        if f.is_file()
        and f.suffix.lower() in VIDEO_EXTENSIONS
        and "sample" not in f.name.lower()
    ]

    # Find and delete samples
    samples = [
        f for f in all_files
        if f.is_file()
        and f.suffix.lower() in VIDEO_EXTENSIONS
        and "sample" in f.name.lower()
    ]
    for s in samples:
        s.unlink()
        emit(f"  Deleted sample: {s.name}")

    if not videos:
        emit(f"  No videos found - deleting folder")
        shutil.rmtree(entry_path, ignore_errors=True)
        return moved_videos

    for video in videos:
        stem = video.stem
        ext  = video.suffix

        # Use folder name if only one video and filename looks like gibberish
        if len(videos) == 1 and _looks_like_gibberish(stem):
            new_name = f"{folder_name}{ext}"
            emit(f"  Renamed: {video.name} → {new_name}")
        else:
            new_name = video.name

        dest = dest_dir / new_name
        # Avoid collision
        if dest.exists():
            dest = dest_dir / f"{Path(new_name).stem}_1{ext}"

        safe_move(video, dest)
        moved_videos.append(dest)
        emit(f"  Moved: {new_name} → {dest_dir.name}/")

    # Delete the source folder and everything remaining
    shutil.rmtree(entry_path, ignore_errors=True)
    emit(f"  Folder deleted: {folder_name}")
    emit("---")
    return moved_videos


def _check_pending_downloads() -> None:
    """Called by scheduler every 30s - fires download processor for entries past hold time."""
    now = time.time()
    ready = []
    ready_m = []
    with _download_lock:
        for path_str, fire_at in list(_pending_downloads.items()):
            if now >= fire_at:
                ready.append(path_str)
                del _pending_downloads[path_str]
        for path_str, fire_at in list(_pending_movie_downloads.items()):
            if now >= fire_at:
                ready_m.append(path_str)
                del _pending_movie_downloads[path_str]
    if ready:
        s = db.get_settings()
        for path_str in ready:
            entry = Path(path_str)
            if not entry.exists():
                continue
            try:
                ep = entry.resolve()
                dest_dir, derr = _dl_resolve_import_dest_dir(
                    s, "", str(ep.parent), str(ep),
                )
                if derr or not dest_dir:
                    emit(f"  Download process skipped ({entry.name}): {derr}")
                    continue
                folder_name = entry.name
                _process_download_entry(entry, dest_dir)
                _remove_client_jobs_matching_watch_folder(folder_name, s)
            except Exception as e:
                emit(f"  Download process error: {e}")
    if ready_m:
        s = db.get_settings()
        mq_raw = (s.get("movies_source_dir") or "").strip()
        if not mq_raw:
            for path_str in ready_m:
                emit(
                    f"  Movie download process skipped ({Path(path_str).name}): "
                    "Movie queue directory (Settings → movies source) not configured — "
                    "imports go to the queue first, then file into Title (Year) folders."
                )
        else:
            dest_queue = Path(mq_raw).expanduser()
            if not dest_queue.is_dir():
                for path_str in ready_m:
                    emit(
                        f"  Movie download process skipped ({Path(path_str).name}): "
                        f"Movie queue directory not found: {mq_raw}"
                    )
            else:
                for path_str in ready_m:
                    entry = Path(path_str)
                    if not entry.exists():
                        continue
                    try:
                        folder_name = entry.name
                        moved = _process_download_entry(entry, dest_queue)
                        _remove_client_jobs_matching_watch_folder(folder_name, s)
                        for vpath in moved:
                            if vpath.suffix.lower() in VIDEO_EXTENSIONS:
                                process_movie_file(vpath.name)
                    except Exception as e:
                        emit(f"  Movie download process error: {e}")


class DownloadWatchHandler(FileSystemEventHandler):
    """Watches the download folder and queues new entries after a hold period."""

    def _queue(self, path_str: str) -> None:
        s = db.get_settings()
        if s.get("download_watch_enabled", "false").lower() != "true":
            return
        dl_raw = (s.get("download_watch_dir") or "").strip()
        if not dl_raw:
            return
        hold = int(s.get("download_watch_hold_secs", "300"))
        with _download_lock:
            # Only queue the top-level entry (folder or file)
            entry = Path(path_str)
            dl_dir = Path(dl_raw)
            if entry.parent == dl_dir or entry == dl_dir:
                top = path_str
            else:
                # Find the immediate child of dl_dir
                try:
                    rel = entry.relative_to(dl_dir)
                    top = str(dl_dir / rel.parts[0])
                except ValueError:
                    top = path_str
            _pending_downloads[top] = time.time() + hold

    def on_created(self, event):
        self._queue(event.src_path)

    def on_moved(self, event):
        self._queue(event.dest_path)


class MovieDownloadWatchHandler(FileSystemEventHandler):
    """Watches the movie download folder; queues top-level entries after hold (same hold as scene watch)."""

    def _queue(self, path_str: str) -> None:
        s = db.get_settings()
        if s.get("download_watch_enabled", "false").lower() != "true":
            return
        mdl_raw = (s.get("movie_download_watch_dir") or "").strip()
        if not mdl_raw:
            return
        hold = int(s.get("download_watch_hold_secs", "300"))
        with _download_lock:
            entry = Path(path_str)
            dl_dir = Path(mdl_raw)
            if entry.parent == dl_dir or entry == dl_dir:
                top = path_str
            else:
                try:
                    rel = entry.relative_to(dl_dir)
                    top = str(dl_dir / rel.parts[0])
                except ValueError:
                    top = path_str
            _pending_movie_downloads[top] = time.time() + hold

    def on_created(self, event):
        self._queue(event.src_path)

    def on_moved(self, event):
        self._queue(event.dest_path)


def _start_download_watcher() -> None:
    global download_observer
    s = db.get_settings()
    if s.get("download_watch_enabled", "false").lower() != "true":
        if download_observer:
            download_observer.stop()
            download_observer = None
        return
    if download_observer:
        download_observer.stop()
        download_observer = None
    dl_raw = (s.get("download_watch_dir") or "").strip()
    mdl_raw = (s.get("movie_download_watch_dir") or "").strip()
    obs = Observer()
    scheduled = False
    if dl_raw:
        dl_dir = Path(dl_raw)
        if dl_dir.exists():
            obs.schedule(DownloadWatchHandler(), str(dl_dir), recursive=True)
            scheduled = True
    if mdl_raw:
        mdl_dir = Path(mdl_raw)
        if mdl_dir.exists():
            obs.schedule(MovieDownloadWatchHandler(), str(mdl_dir), recursive=True)
            scheduled = True
    if not scheduled:
        return
    download_observer = obs
    download_observer.start()


def _restart_download_watcher() -> None:
    global download_observer
    if download_observer:
        download_observer.stop()
        download_observer = None
    _start_download_watcher()


