def fansdb_submit_scene(title: str, date: str, studio_id: str,
                         performer_ids: list, phash: str,
                         details: str, image_url: str, api_key: str,
                         duration: int = 0) -> dict:
    """Submit a new scene to FansDB. FansDB uses the same stash-box
    schema as StashDB so we can reuse SCENE_CREATE verbatim."""
    fingerprints = []
    if phash:
        fingerprints.append({"algorithm": "PHASH", "hash": phash, "duration": duration})
    image_ids = []
    if image_url:
        img_id = fansdb_upload_image(image_url, api_key)
        if img_id:
            image_ids = [img_id]
    inp = {
        "title":        title,
        "date":         date,
        "details":      details or "",
        "fingerprints": fingerprints,
    }
    if studio_id:
        inp["studio_id"] = studio_id
    if performer_ids:
        inp["performers"] = [{"performer_id": pid} for pid in performer_ids]
    if image_ids:
        inp["image_ids"] = image_ids
    try:
        data = _stashbox_post(FANSDB_ENDPOINT, api_key, STASHDB_SCENE_CREATE, {"input": inp})
        errors = data.get("errors") or []
        if errors:
            msgs = [e.get("message", str(e)) for e in errors]
            if any("not authorized" in m.lower() for m in msgs):
                return {"success": False, "error": "Not authorised — your FansDB account needs EDIT permissions to submit scenes"}
            return {"success": False, "error": "; ".join(msgs)}
        scene = data.get("sceneCreate") or {}
        return {"success": True, "id": scene.get("id"), "title": scene.get("title")}
    except Exception as e:
        return {"success": False, "error": str(e)}


def stashdb_submit_scene(title: str, date: str, studio_id: str,
                          performer_ids: list, phash: str,
                          details: str, image_url: str, api_key: str,
                          duration: int = 0) -> dict:
    """Submit a new scene to StashDB."""
    fingerprints = []
    if phash:
        fingerprints.append({"algorithm": "PHASH", "hash": phash, "duration": duration})

    # Upload image first to get image_id if URL provided
    image_ids = []
    if image_url:
        img_id = stashdb_upload_image(image_url, api_key)
        if img_id:
            image_ids = [img_id]

    inp = {
        "title":        title,
        "date":         date,
        "details":      details or "",
        "fingerprints": fingerprints,  # NON_NULL - always required
    }
    if studio_id:
        inp["studio_id"] = studio_id
    if performer_ids:
        # StashDB expects [{performer_id, as}] not a flat list of IDs
        inp["performers"] = [{"performer_id": pid} for pid in performer_ids]
    if image_ids:
        inp["image_ids"] = image_ids

    try:
        data = _stashbox_post(STASHDB_ENDPOINT, api_key, STASHDB_SCENE_CREATE, {"input": inp})
        errors = data.get("errors") or []
        if errors:
            msgs = [e.get("message", str(e)) for e in errors]
            if any("not authorized" in m.lower() for m in msgs):
                return {"success": False, "error": "Not authorised — your StashDB account needs EDIT permissions to submit scenes"}
            return {"success": False, "error": "; ".join(msgs)}
        scene = data.get("sceneCreate") or {}
        return {"success": True, "id": scene.get("id"), "title": scene.get("title")}
    except Exception as e:
        return {"success": False, "error": str(e)}


def capture_frame_as_base64(video_path: Path, percent: float) -> str | None:
    """Capture a single frame from a video at percent (0-100) of duration."""
    try:
        duration = get_video_duration(video_path)
        if not duration:
            return None
        t = duration * (percent / 100.0)
        cmd = [
            "ffmpeg", "-ss", str(t), "-i", str(video_path),
            "-frames:v", "1", "-f", "image2", "-vcodec", "mjpeg", "pipe:1",
            "-loglevel", "error"
        ]
        result = subprocess.run(cmd, capture_output=True, timeout=30)
        if result.returncode != 0 or not result.stdout:
            return None
        import base64
        return "data:image/jpeg;base64," + base64.b64encode(result.stdout).decode()
    except Exception:
        return None


# ── Queue thumbnail filmstrip cache ──────────────────────────────────
#: Five JPEGs per file, taken at 10/30/50/70/90% so we skip the
#: typical intro/outro frames. Cached on disk under
#: ``metadata/queue_thumbs/<sha1(filename)>/{0..4}.jpg`` so the user
#: pays the FFmpeg cost once per source file. Generated lazily on
#: first request; pre-warmed by the unmatched-file branch of
#: ``process_single`` so files the user is likely to investigate
#: already have thumbs ready.
QUEUE_THUMB_PERCENTS = (10.0, 30.0, 50.0, 70.0, 90.0)
QUEUE_THUMB_COUNT = len(QUEUE_THUMB_PERCENTS)


def _queue_thumbs_dir(filename: str) -> Path:
    """Per-source-file cache dir keyed by sha1(filename) — collisions
    are unlikely and the filename itself can contain path-hostile
    characters that we'd otherwise have to sanitise."""
    import hashlib as _hashlib
    h = _hashlib.sha1((filename or "").encode("utf-8")).hexdigest()
    d = _metadata_base_dir() / "queue_thumbs" / h
    d.mkdir(parents=True, exist_ok=True)
    return d


def _queue_thumb_path(filename: str, i: int) -> Path:
    return _queue_thumbs_dir(filename) / f"{int(i)}.jpg"


def _generate_queue_thumb(video_path: Path, dest: Path, t: float) -> bool:
    """Write a single JPEG frame to *dest* at timestamp *t* seconds.
    Returns True on success. Failures (timeout, missing codec) are
    swallowed so the caller can fall through to the next frame."""
    try:
        cmd = [
            "ffmpeg", "-y", "-ss", str(max(0.0, t)),
            "-i", str(video_path),
            "-frames:v", "1", "-q:v", "4",
            "-vf", "scale='min(640,iw)':-2",
            str(dest),
            "-loglevel", "error",
        ]
        res = subprocess.run(cmd, capture_output=True, timeout=30)
        return res.returncode == 0 and dest.is_file() and dest.stat().st_size > 0
    except Exception:
        return False


def _ensure_queue_thumbs(filename: str) -> list[Path]:
    """Generate (or reuse) the 5-frame filmstrip for *filename*. Returns
    the list of JPEG paths in percentile order — empty when the source
    file is missing or FFmpeg can't decode it. Idempotent: only seeks
    frames that aren't already on disk, so a partial cache is healed
    instead of rebuilt."""
    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    video = db.resolve_source_video_path(source_dir, filename)
    if video is None or not video.is_file():
        return []
    dest_dir = _queue_thumbs_dir(filename)
    paths: list[Path] = [dest_dir / f"{i}.jpg" for i in range(QUEUE_THUMB_COUNT)]
    if all(p.is_file() and p.stat().st_size > 0 for p in paths):
        return paths
    try:
        duration = get_video_duration(video)
    except Exception:
        return []
    if not duration or duration <= 0:
        return []
    out: list[Path] = []
    for i, pct in enumerate(QUEUE_THUMB_PERCENTS):
        p = paths[i]
        if p.is_file() and p.stat().st_size > 0:
            out.append(p)
            continue
        t = duration * (pct / 100.0)
        if _generate_queue_thumb(video, p, t):
            out.append(p)
    return out


def _prewarm_queue_thumbs_async(filename: str) -> None:
    """Fire-and-forget thumb generation. Used from the unmatched-file
    branch — by the time the user opens the queue, frames the matcher
    couldn't ID already have visual previews ready. Best-effort: any
    exception is swallowed because this is opportunistic warming."""
    def _job() -> None:
        try:
            _ensure_queue_thumbs(filename)
        except Exception as exc:
            try:
                emit(f"queue thumbs prewarm failed for {filename!r}: {exc}")
            except Exception:
                pass
    threading.Thread(target=_job, daemon=True).start()


# ---------------------------------------------------------------------------
# StashDB phash submission
# ---------------------------------------------------------------------------

SUBMIT_FINGERPRINT_MUTATION = """
mutation SubmitFingerprint($input: FingerprintSubmission!) {
  submitFingerprint(input: $input)
}
"""

def submit_phash_to_stashdb(scene_id: str, phash: str, duration: float = None) -> bool:
    """Submit a phash fingerprint to StashDB for a given scene ID."""
    s = db.get_settings()
    if s.get("submit_phash_enabled", "true").lower() != "true":
        return False
    api_key = s.get("api_key_stashdb", "")
    if not api_key or not scene_id or not phash:
        return False
    try:
        fingerprint = {
            "hash":      phash,
            "algorithm": "PHASH",
        }
        # Duration is required by StashDB - get it from the filed file if possible
        if duration and duration > 0:
            fingerprint["duration"] = int(duration)
        else:
            # Try to get duration from DB path if available
            fingerprint["duration"] = 0
        payload = {
            "query": SUBMIT_FINGERPRINT_MUTATION,
            "variables": {
                "input": {
                    "scene_id":    scene_id,
                    "fingerprint": fingerprint,
                }
            }
        }
        resp = requests.post(
            STASHDB_ENDPOINT,
            json=payload,
            headers={"Content-Type": "application/json", "ApiKey": api_key},
            timeout=15,
        )
        resp.raise_for_status()
        data = resp.json()
        if "errors" in data:
            msgs = [e.get("message", str(e)) for e in data["errors"]]
            if any("not authorized" in m.lower() for m in msgs):
                emit("  Phash submit: not authorised (READ-only StashDB account)")
            else:
                emit(f"  Phash submit: failed ({'; '.join(msgs)})")
            return False
        emit("  Phash submit: sent to StashDB")
        return True
    except Exception as e:
        emit(f"  Phash submit: error ({e})")
        return False


def _submit_phash_to_stashbox(endpoint: str, api_key: str, label: str,
                               scene_id: str, phash: str, duration: float = 0) -> bool:
    """Submit a phash fingerprint to any stash-box instance (FansDB or
    StashDB). Returns True on success, False otherwise. Logs via emit."""
    if not api_key or not scene_id or not phash:
        return False
    try:
        fingerprint = {
            "hash":      phash,
            "algorithm": "PHASH",
            "duration":  int(duration) if duration and duration > 0 else 0,
        }
        payload = {
            "query": SUBMIT_FINGERPRINT_MUTATION,
            "variables": {"input": {"scene_id": scene_id, "fingerprint": fingerprint}},
        }
        resp = requests.post(
            endpoint,
            json=payload,
            headers={"Content-Type": "application/json", "ApiKey": api_key},
            timeout=15,
        )
        resp.raise_for_status()
        data = resp.json()
        if "errors" in data:
            msgs = [e.get("message", str(e)) for e in data["errors"]]
            if any("not authorized" in m.lower() for m in msgs):
                emit(f"  Phash submit ({label}): not authorised (READ-only account)")
            else:
                emit(f"  Phash submit ({label}): failed ({'; '.join(msgs)})")
            return False
        emit(f"  Phash submit: sent to {label}")
        return True
    except Exception as e:
        emit(f"  Phash submit ({label}): error ({e})")
        return False


def submit_phash_to_fansdb(scene_id: str, phash: str, duration: float = 0) -> bool:
    """Submit a phash fingerprint to FansDB for a given scene ID."""
    s = db.get_settings()
    api_key = s.get("api_key_fansdb", "")
    return _submit_phash_to_stashbox(FANSDB_ENDPOINT, api_key, "FansDB", scene_id, phash, duration)


def _extract_scene_fields_for_submit(scene: dict) -> dict:
    """Pull the subset of fields needed to submit a scene to a stash-box
    instance via SCENE_CREATE. Sources typically share the same schema
    so we can just dig the same fields out regardless of origin."""
    if not isinstance(scene, dict):
        return {}
    images = scene.get("images") or []
    image_url = ""
    if images:
        best = max(images, key=lambda im: (im.get("width") or 0) * (im.get("height") or 0))
        image_url = best.get("url") or ""
    perfs = []
    for p in (scene.get("performers") or []):
        perf = (p or {}).get("performer") or {}
        nm = (perf.get("name") or "").strip()
        if nm:
            perfs.append(nm)
    studio_name = ((scene.get("studio") or {}).get("name") or "").strip()
    return {
        "title":          (scene.get("title") or "").strip(),
        "date":           (scene.get("release_date") or "").strip(),
        "studio_name":    studio_name,
        "performer_names": perfs,
        "image_url":      image_url,
        "details":        (scene.get("details") or "").strip(),
    }


def _auto_backfill_external_dbs(scene: dict, filed_source: str,
                                phash: str, duration: float = 0) -> None:
    """
    After a scene is filed, try to propagate the phash (and optionally
    the full scene) to the other supported stash-box databases.

    Flow, per DB (StashDB, FansDB — TPDB has no public submission API):
      1. If this DB is where we filed from: submit phash to the known
         scene_id (if phash toggle is on).
      2. Otherwise, look up the phash on the DB:
           - match found → submit phash to that DB's scene_id.
           - no match   → if scene-creation toggle is on and we have
                          enough fields, create the scene there.

    All failures are logged but swallowed — a propagation failure must
    never break the primary filing result.
    """
    if not phash:
        return
    # Manual filing owns its own cross-DB submission path via the
    # `/api/{stashdb,fansdb}/submit-manual` endpoints driven by the
    # modal's per-target toggles + resolved IDs. If we also ran the
    # automated backfill we'd fire duplicate mutations (using blindly
    # name-resolved IDs that often don't match what the user chose)
    # and the user sees noisy 422s for submissions that *already*
    # succeeded via the modal's picks. Bail early in that case.
    if (filed_source or "").strip().lower() == "manual":
        return
    s = db.get_settings()
    targets = [
        # (label, tag, endpoint, api_key, phash_toggle, scene_toggle, submit_scene_fn)
        ("StashDB", "StashDB", STASHDB_ENDPOINT, s.get("api_key_stashdb", "") or "",
         (s.get("submit_phash_stashdb", "true") or "true").lower() == "true",
         (s.get("submit_scene_stashdb", "false") or "false").lower() == "true",
         stashdb_submit_scene),
        ("FansDB",  "FansDB",  FANSDB_ENDPOINT,  s.get("api_key_fansdb", "") or "",
         (s.get("submit_phash_fansdb", "true") or "true").lower() == "true",
         (s.get("submit_scene_fansdb", "false") or "false").lower() == "true",
         fansdb_submit_scene),
    ]
    scene_fields = _extract_scene_fields_for_submit(scene or {})
    filed = (filed_source or "").strip()
    for label, tag, endpoint, api_key, phash_on, scene_on, submit_fn in targets:
        if not api_key:
            continue
        try:
            if filed == tag:
                # Scene was matched and filed from this DB — just bolt the
                # phash onto the known scene_id.
                if not phash_on:
                    continue
                scene_id = (scene or {}).get("id") if isinstance(scene, dict) else None
                if scene_id:
                    _submit_phash_to_stashbox(endpoint, api_key, label, str(scene_id), phash, duration)
                continue
            # Other DB — probe by phash first.
            try:
                hits = query_stashbox(phash, endpoint, api_key, STASHDB_QUERY, "full")
            except Exception as e:
                emit(f"  Cross-DB ({label}): lookup failed ({e})")
                continue
            if hits:
                hit_id = (hits[0] or {}).get("id")
                if hit_id and phash_on:
                    _submit_phash_to_stashbox(endpoint, api_key, label, str(hit_id), phash, duration)
                continue
            # No existing record — optionally create.
            if not scene_on:
                continue
            if not scene_fields.get("title") or not scene_fields.get("date"):
                emit(f"  Cross-DB ({label}): skip create (missing title or date)")
                continue
            # Resolve studio + performer IDs on the target. We submit
            # with the fields we can resolve; unresolvable names are
            # dropped silently because the stash-box create mutation
            # would reject unknown string names anyway.
            studio_id = None
            if scene_fields.get("studio_name"):
                try:
                    matches = _stashbox_post(endpoint, api_key, STASHDB_STUDIO_SEARCH,
                                             {"term": scene_fields["studio_name"]})
                    studios = (matches.get("data") or {}).get("searchStudio") or matches.get("searchStudio") or []
                    if isinstance(studios, list):
                        exact = next((m for m in studios
                                      if (m.get("name") or "").lower() == scene_fields["studio_name"].lower()), None)
                        if exact:
                            studio_id = exact.get("id")
                except Exception:
                    pass
            performer_ids: list[str] = []
            for pname in scene_fields.get("performer_names", []):
                try:
                    matches = _stashbox_post(endpoint, api_key, STASHDB_PERFORMER_SEARCH,
                                             {"term": pname})
                    perfs = (matches.get("data") or {}).get("searchPerformer") or matches.get("searchPerformer") or []
                    if isinstance(perfs, list):
                        exact = next((m for m in perfs
                                      if (m.get("name") or "").lower() == pname.lower()), None)
                        if exact and exact.get("id"):
                            performer_ids.append(exact["id"])
                except Exception:
                    pass
            # stash-box `sceneCreate` rejects the mutation (422) when
            # `studio_id` is null, and also when no performers resolve
            # — the server treats a scene with no studio as
            # unprocessable. Bail early with a clear reason so the user
            # knows the record on the target DB couldn't be vetted,
            # rather than firing a mutation that will always fail.
            if not studio_id:
                emit(f"  Cross-DB ({label}): skip create (studio '{scene_fields.get('studio_name') or ''}' not found on {label})")
                continue
            if not performer_ids:
                emit(f"  Cross-DB ({label}): skip create (no performers matched on {label})")
                continue
            result = submit_fn(
                title         = scene_fields["title"],
                date          = scene_fields["date"],
                studio_id     = studio_id,
                performer_ids = performer_ids,
                phash         = phash,
                details       = scene_fields.get("details", ""),
                image_url     = scene_fields.get("image_url", ""),
                api_key       = api_key,
                duration      = int(duration) if duration else 0,
            )
            if result.get("success"):
                emit(f"  Cross-DB ({label}): new scene created (id {result.get('id')})")
            else:
                emit(f"  Cross-DB ({label}): create failed ({result.get('error')})")
        except Exception as e:
            emit(f"  Cross-DB ({label}): unexpected error ({e})")


# ---------------------------------------------------------------------------
# Filename parser
# ---------------------------------------------------------------------------

#: Noise tokens that commonly appear in filenames alongside the real
#: title but tank DB search relevance when included verbatim:
#:   "Chick Flick 6 Scene 2"      → "Chick Flick 6"
#:   "Bondage Anthology Part 4"   → "Bondage Anthology"
#:   "Dark Desires Episode 7"     → "Dark Desires"
#:   "Film Name CD1" / "…Disc 2"  → "Film Name"
#: We strip these *after* the pattern matches its title group so the
#: pattern's parsing logic is unaffected, and we strip both the
#: leading separator ("- Scene 2") and any dangling separator left
#: behind ("Title - " → "Title"). The regex is anchored to the end so
#: we don't accidentally chop "Scene" out of titles like
#: "Behind The Scene". Returns the cleaned title.
_TITLE_NOISE_RE = re.compile(
    r"""
    (?:^|[\s._\-–—]+)          # separator before the token
    (?:
        scene \s* [#]? \s* \d+           # Scene 2, Scene #2
      | part  \s*       \d+              # Part 3
      | pt    \.? \s*   \d+              # Pt 3, Pt. 3
      | episode \s*     \d+              # Episode 4
      | ep    \s*       \d+              # Ep 4
      | cd              \s* \d+          # CD1, CD 1
      | disc  \s*       \d+              # Disc 1
    )
    \s* $                                # anchored to end
    """,
    re.IGNORECASE | re.VERBOSE,
)


def _strip_title_noise(title: str) -> str:
    if not title:
        return title
    out = title
    #: Loop because multiple noise tokens can stack ("Title Scene 2 Part 1").
    for _ in range(3):
        new = _TITLE_NOISE_RE.sub("", out).strip()
        new = re.sub(r"[\s._\-–—]+$", "", new).strip()
        if new == out:
            break
        out = new
    return out


def parse_filename(filename: str, settings: dict) -> dict:
    """
    Attempt to extract site, date, performers, and title from a filename.
    Returns a dict with keys: site, date, performers, title (all may be empty).
    Tries patterns in order based on settings["filename_patterns"].
    """
    import json as _json

    stem = Path(filename).stem

    # Strip gubbins words from stem first
    strip_words = [w.strip().lower() for w in settings.get("filename_strip_words", "").split(",") if w.strip()]
    for word in strip_words:
        stem = re.sub(re.escape(word), "", stem, flags=re.IGNORECASE).strip(".-_ ")

    # Load site abbreviations and expand them
    try:
        abbrevs = _json.loads(settings.get("site_abbreviations", "{}"))
    except Exception:
        abbrevs = {}

    try:
        rename_map = _json.loads(settings.get("site_rename_map", "{}"))
    except Exception:
        rename_map = {}

    def expand_abbrev(text: str) -> str:
        # First try rename map (exact match)
        for old_name, new_name in rename_map.items():
            if text.strip().lower() == old_name.strip().lower():
                return new_name
        # Then try abbreviations
        low = text.lower()
        for abbr, full in abbrevs.items():
            if low == abbr.lower():
                return full
        return text

    def clean(text: str) -> str:
        return re.sub(r"\s+", " ", text.replace(".", " ").replace("_", " ")).strip()

    result = {"site": "", "date": "", "performers": "", "title": ""}

    patterns = settings.get("filename_patterns", "pipe|dot_date").split("|")

    for pattern in patterns:
        pattern = pattern.strip()

        # Pipe-separated namer format: site|date|performers|title|network|parent
        if pattern == "pipe":
            parts = stem.split("|")
            if len(parts) >= 4:
                result["site"]       = expand_abbrev(parts[0].strip())
                result["date"]       = parts[1].strip()
                result["performers"] = parts[2].strip()
                result["title"]      = _strip_title_noise(parts[3].strip())
                return result

        # site.YYYY.MM.DD.title (dot separated, full year)
        elif pattern == "dot_date":
            m = re.match(r'^(.+?)\.(20\d{2}|19\d{2})\.(\d{2})\.(\d{2})\.(.+)$', stem)
            if m:
                result["site"]  = expand_abbrev(clean(m.group(1)))
                result["date"]  = f"{m.group(2)}-{m.group(3)}-{m.group(4)}"
                result["title"] = _strip_title_noise(clean(m.group(5)))
                return result

        # site.YY.MM.DD.title (dot separated, short year)
        elif pattern == "dot_date_short":
            m = re.match(r'^(.+?)\.(\d{2})\.(\d{2})\.(\d{2})\.(.+)$', stem)
            if m:
                result["site"]  = expand_abbrev(clean(m.group(1)))
                result["date"]  = f"20{m.group(2)}-{m.group(3)}-{m.group(4)}"
                result["title"] = _strip_title_noise(clean(m.group(5)))
                return result

        # [Site] Title - Performer (YYYY)
        elif pattern == "bracket_site":
            m = re.match(r'^\[(.+?)\]\s*(.+?)(?:\s*-\s*(.+?))?\s*(?:\((\d{4})\))?$', stem)
            if m:
                result["site"]       = expand_abbrev(m.group(1).strip())
                result["title"]      = _strip_title_noise((m.group(2) or "").strip())
                result["performers"] = (m.group(3) or "").strip()
                result["date"]       = m.group(4) or ""
                return result

        # site - YYYY-MM-DD - title
        elif pattern == "dash_date":
            m = re.match(r'^(.+?)\s*[-–]\s*(20\d{2}|19\d{2}-\d{2}-\d{2})\s*[-–]\s*(.+)$', stem)
            if m:
                result["site"]  = expand_abbrev(m.group(1).strip())
                result["date"]  = m.group(2).strip()
                result["title"] = _strip_title_noise(m.group(3).strip())
                return result

    # Fallback: return cleaned stem as title
    result["title"] = _strip_title_noise(clean(stem))
    return result


def apply_rename_map(name: str, settings: dict) -> str:
    """Apply site rename corrections to a studio name."""
    import json as _json
    try:
        rename_map = _json.loads(settings.get("site_rename_map", "{}"))
    except Exception:
        rename_map = {}
    for old_name, new_name in rename_map.items():
        if name.strip().lower() == old_name.strip().lower():
            return new_name
    return name


# ══════════════════════════════════════════════════════════════════════
# Phase 3 — Filing-time favourites name index
# ══════════════════════════════════════════════════════════════════════
# Builds an in-memory lookup of every known name for every performer /
# studio in the favourites library. Keys include:
#
#     • folder_name                      — the on-disk directory name
#     • match_tpdb_name                  — canonical TPDB name (populated by Fill Gaps)
#     • match_stashdb_name               — canonical StashDB name
#     • match_fansdb_name                — canonical FansDB name
#     • aliases_json entries (performer) — scraped alias list
#
# The filing pipeline (`find_studio_dir` / `find_performer_dir`) checks
# this index as a fallback when the scene's studio / performer name
# doesn't textually match a local folder. That fixes the "ManyVids: 2
# Drops" → "2 Drops" case: the DB already knows TPDB calls that studio
# "ManyVids: 2 Drops" because Fill Gaps wrote it to `match_tpdb_name`.
#
# The index is cached per-kind for a short TTL (_NAME_INDEX_TTL_S) so
# a new link made through the /library UI becomes resolvable within
# ~30s. The filing pipeline runs on batches slower than that, so the
# worst case is a one-batch delay before new cross-walk names take
# effect. Hot callers can force-expire via `_favourites_name_index_bump()`.
_NAME_INDEX_CACHE: dict[str, tuple[float, dict[str, dict]]] = {}
_NAME_INDEX_TTL_S = 30.0
_NAME_INDEX_LOCK = threading.Lock()

# Common network / separator prefixes we strip before retrying the
# lookup — these are the most frequent "DB has extra prefix" patterns
# seen across TPDB / StashDB / FansDB. Kept intentionally short; if a
# real match isn't in the list, the word-subset pass below catches it.
_NETWORK_PREFIX_RES = [
    re.compile(r"^(?:[a-z0-9]+(?:[ .-][a-z0-9]+){0,3})\s*[:\u2014\u2013\-]\s+"),  # "ManyVids: ", "BangBros - "
    re.compile(r"^(?:the\s+)?[a-z0-9]+(?:[ .-][a-z0-9]+){0,2}\s*network\s*[:\u2014\u2013\-]*\s*"),
]


def _favourites_name_index_bump() -> None:
    """Force the cached name index to rebuild on next access. Call after
    any write you want to see reflected immediately (eg. manual link
    from the /library UI). Cheap — clears both kind caches."""
    with _NAME_INDEX_LOCK:
        _NAME_INDEX_CACHE.clear()


def _favourites_name_index(kind: str) -> dict[str, dict]:
    """Return a map of normalised-name-slug → row dict for every
    performer or studio row in the favourites library. Cached in
    memory for `_NAME_INDEX_TTL_S` seconds.

    For each row we inject every known name (folder_name + the three
    canonical DB names + any performer aliases) into the map, with a
    '_hit_via' tag recording which field produced the match — useful
    for emit() logging so you can see how the filing pipeline found
    the folder."""
    if kind not in ("performer", "studio"):
        return {}
    now = time.time()
    with _NAME_INDEX_LOCK:
        cached = _NAME_INDEX_CACHE.get(kind)
        if cached and (now - cached[0]) < _NAME_INDEX_TTL_S:
            return cached[1]
    idx: dict[str, dict] = {}

    def _add(slug: str, row: dict, via: str) -> None:
        if not slug or slug in idx:
            return
        tagged = dict(row)
        tagged["_hit_via"] = via
        idx[slug] = tagged

    try:
        for r in db.favourite_list():
            if (r.get("kind") or "").strip().lower() != kind:
                continue
            # 1. Folder name (always highest priority — already handled
            # by the direct-match path in find_*_dir, but included here
            # so exact-slug hits on folder_name still work when the
            # filing caller reaches the name-index path directly).
            _add(normalise(r.get("folder_name") or ""), r, "folder_name")
            # 2. Canonical DB names
            _add(normalise(r.get("match_tpdb_name") or ""),    r, "tpdb_name")
            _add(normalise(r.get("match_stashdb_name") or ""), r, "stashdb_name")
            _add(normalise(r.get("match_fansdb_name") or ""),  r, "fansdb_name")
            # 3. Performer aliases (from aliases_json)
            if kind == "performer":
                aj = (r.get("aliases_json") or "").strip()
                if aj:
                    try:
                        aliases = json.loads(aj) or []
                    except Exception:
                        aliases = []
                    if isinstance(aliases, list):
                        for a in aliases:
                            if isinstance(a, str):
                                _add(normalise(a), r, "alias")
                            elif isinstance(a, dict):
                                _add(normalise(a.get("name") or ""), r, "alias")
    except Exception as exc:
        _log.debug("favourites name index build failed: %s", exc)

    with _NAME_INDEX_LOCK:
        _NAME_INDEX_CACHE[kind] = (time.time(), idx)
    return idx


def _strip_network_prefix(name: str) -> str | None:
    """Return `name` with one of the known network prefixes stripped,
    or None if none match. `"ManyVids: 2 Drops"` → `"2 drops"`."""
    lower = (name or "").lower()
    for patt in _NETWORK_PREFIX_RES:
        m = patt.match(lower)
        if m and m.end() < len(lower):
            return lower[m.end():]
    return None


def _resolve_favourite_by_any_name(name: str, kind: str) -> dict | None:
    """Look up a performer or studio by any name we know for it.

    Tries the cached name index in this order:
      1. exact slug lookup
      2. strip a network prefix (`"ManyVids: 2 Drops"` → `"2 drops"`)
         and retry the exact slug lookup
      3. longest word-subset match — every token in the query slug
         must appear in a key, and we pick the key with the shortest
         length (most specific). Requires the query to have at least
         2 tokens OR a single token of ≥5 characters to avoid generic
         one-word false positives.

    Returns the matching favourite row dict with a `_hit_via` tag
    indicating which field produced the hit, or None if nothing
    matched."""
    q = (name or "").strip()
    if not q:
        return None
    idx = _favourites_name_index(kind)
    if not idx:
        return None
    # 1. Exact slug
    slug = normalise(q)
    if slug and slug in idx:
        return idx[slug]
    # 2. Strip network prefix and retry
    stripped = _strip_network_prefix(q)
    if stripped:
        s2 = normalise(stripped)
        if s2 and s2 in idx:
            hit = dict(idx[s2])
            hit["_hit_via"] = (hit.get("_hit_via") or "?") + "+prefix-strip"
            return hit
    # 3. Word-subset: tokenise the query, require all tokens present in
    # a candidate key's tokens. Only runs for MULTI-token queries —
    # single-token names like "Baily" are too easily swallowed by a
    # longer distinct performer's alias ("Bailey Blaze" with "baily"
    # somewhere in its aliases_json). For single-token names the only
    # safe match paths are the exact-slug (step 1) and network-prefix-
    # strip (step 2) above — if neither fires we return None and let
    # the caller decide (usually means the scene is from a performer
    # we don't have in the library).
    q_tokens = [t for t in slug.split() if t]
    if len(q_tokens) >= 2:
        q_set = set(q_tokens)
        best_key: str | None = None
        best_len = 0
        for k in idx.keys():
            k_tokens = k.split()
            if len(k_tokens) < len(q_tokens):
                continue
            if q_set.issubset(k_tokens):
                if best_key is None or len(k) < best_len:
                    best_key = k
                    best_len = len(k)
        if best_key:
            hit = dict(idx[best_key])
            hit["_hit_via"] = (hit.get("_hit_via") or "?") + "+word-subset"
            return hit
    return None


def find_studio_dir(studio_name: str, settings: dict) -> Path | None:
    studio_name = apply_rename_map(studio_name, settings)
    series_dir = Path(settings.get("series_dir", ""))
    if not series_dir.exists():
        return None
    norm = normalise(studio_name)
    for folder in (d.name for d in series_dir.iterdir() if d.is_dir()):
        if normalise(folder) == norm:
            return series_dir / folder
    # ── Phase 3 fallback: check the favourites name index ──
    # A scene's studio might come back from TPDB as "ManyVids: 2 Drops"
    # when the local folder is just "2 Drops". The folder has TPDB/Stash/
    # Fans links stored in favourite_entities via Fill Gaps, so the
    # canonical name from each source is known. Look `studio_name` up
    # in the combined name index — if it resolves to a favourites row
    # whose folder lives under series_dir, return that folder.
    resolved = _resolve_favourite_by_any_name(studio_name, "studio")
    if resolved:
        fp = (resolved.get("path") or "").strip()
        if fp:
            fp_path = Path(fp)
            try:
                fp_path.resolve().relative_to(series_dir.resolve())
            except (ValueError, OSError):
                return None
            if fp_path.is_dir():
                emit(f"  STUDIO name-index match: '{studio_name}' → '{fp_path.name}' (via {resolved.get('_hit_via', '?')})")
                return fp_path
    return None


def _gender_priority_names(performers: list) -> list[str]:
    """Scene performer names filtered by gender priority (female/trans-female
    first, else unknown-gender, else all). Shared by the exact-name and
    alias matchers."""
    female_names = [
        p["performer"]["name"] for p in performers
        if (p["performer"].get("gender") or "").upper() in ("FEMALE", "TRANSGENDER_FEMALE")
    ]
    unknown_names = [
        p["performer"]["name"] for p in performers
        if not (p["performer"].get("gender") or "").strip()
    ]
    return female_names or unknown_names or [p["performer"]["name"] for p in performers]


def find_performer_dir(performers: list, performer_dirs: list) -> list[tuple[Path, str, dict | None]]:
    """Resolve scene performers to existing library folders.

    Returns the full list of candidates — `(folder_path, display_name,
    favourite_row | None)` tuples — so the caller (`_scene_filing_plan`)
    can score them via `_performer_weight` and pick the winner. Legacy
    behaviour of stopping at the first match is preserved implicitly
    when the list has exactly one entry.

    Matching is **exact** normalised folder-name equality only. The old
    fuzzy word-subset pass was dropped because aliases (e.g. "Baily"
    tokenising into "Bailey Blaze") produced false positives. Crosswalk-
    ID matching in `_find_performer_dir_via_library_index` handles the
    precise path; this function is a safety net for folders whose
    library row hasn't been linked to TPDB/StashDB/FansDB ids yet.
    """
    candidates = _gender_priority_names(performers)
    out: list[tuple[Path, str, dict | None]] = []
    seen_paths: set[str] = set()
    for entry in sorted(performer_dirs, key=lambda x: x["rank"]):
        base = Path(entry["path"])
        if not base.exists():
            continue
        norm_folders = {normalise(d.name): d.name for d in base.iterdir() if d.is_dir()}
        for name in candidates:
            folder_name = norm_folders.get(normalise(name))
            if not folder_name:
                continue
            folder_path = base / folder_name
            key = str(folder_path)
            if key in seen_paths:
                continue
            seen_paths.add(key)
            fav_row = db.favourite_get_by_path(key)
            out.append((folder_path, name, fav_row))
    return out


def _find_performer_dir_with_aliases(performers: list, performer_dirs: list) -> list[tuple[Path, str, dict | None]]:
    """Alias-backed fallback to `find_performer_dir`.

    Returns the same `(path, display_name, favourite_row | None)` shape
    so the weighted picker can score these candidates alongside any
    exact-name matches.
    """
    all_folders: dict[str, tuple[Path, str]] = {}
    for entry in sorted(performer_dirs, key=lambda x: x["rank"]):
        base = Path(entry["path"])
        if not base.exists():
            continue
        for d in base.iterdir():
            if d.is_dir():
                key = normalise(d.name)
                if key not in all_folders:
                    all_folders[key] = (base / d.name, d.name)

    out: list[tuple[Path, str, dict | None]] = []
    if not all_folders:
        return out

    seen_paths: set[str] = set()
    for name in _gender_priority_names(performers):
        aliases = _fetch_performer_aliases(name)
        emit(f"  ALIAS lookup '{name}' → found {len(aliases)} aliases: {aliases[:5]}")
        for alias in aliases:
            hit = all_folders.get(normalise(alias))
            if not hit:
                continue
            folder_path, folder_name = hit
            key = str(folder_path)
            if key in seen_paths:
                continue
            seen_paths.add(key)
            emit(f"  ALIAS match: '{name}' → alias '{alias}' → folder '{folder_name}'")
            fav_row = db.favourite_get_by_path(key)
            out.append((folder_path, folder_name, fav_row))
    if not out:
        emit(f"  ALIAS no match found (checked {len(all_folders)} folders)")
    return out


def _performer_objects_in_match_order(performers: list) -> list:
    """Same gender priority as find_performer_dir; returns performer dicts from scene."""
    female = []
    for p in performers:
        pf = p.get("performer") or {}
        if (pf.get("gender") or "").upper() in ("FEMALE", "TRANSGENDER_FEMALE"):
            female.append(pf)
    if female:
        return female
    unk = []
    for p in performers:
        pf = p.get("performer") or {}
        if not (pf.get("gender") or "").strip():
            unk.append(pf)
    if unk:
        return unk
    return [p.get("performer") or {} for p in performers]


def _performer_weight(fav_row: dict | None) -> int:
    """Scoring weight for the scene-filing router's performer pick.

    Resolution order:
      1. Manual override `weight` on the favourite row (1..10) if set,
      2. 2 when is_favourite is truthy (starred in /library),
      3. 1 otherwise (or when no DB row exists — e.g. folder-name-only match).

    Keeps the router deterministic with a sensible default so existing
    installs behave the same until the user dials a weight in.
    """
    if not fav_row:
        return 1
    raw = fav_row.get("weight")
    try:
        if raw is not None and raw != "":
            w = int(raw)
            if 1 <= w <= 10:
                return w
    except (TypeError, ValueError):
        pass
    return 2 if int(fav_row.get("is_favourite") or 0) else 1


def _performer_crosswalk_ids(pf: dict, source: str) -> tuple[str, str, str]:
    """Map scene performer id to favourite_entities columns for the active match source."""
    pid = str((pf or {}).get("id") or "").strip()
    if not pid:
        return "", "", ""
    s = (source or "").upper()
    if "MANUAL" in s:
        return pid, pid, pid
    if "STASH" in s:
        return "", pid, ""
    if "FANS" in s:
        return "", "", pid
    return pid, "", ""


def _library_index_queue_matching_enabled(settings: dict) -> bool:
    """Prefer saved folder links from the library entity index when filing the queue."""
    v = settings.get("library_index_queue_matching_enabled")
    if v is None:
        v = settings.get("favourites_crosswalk_queue_enabled", "true")
    return str(v).lower() == "true"


def _find_performer_dir_via_library_index(
    performers: list,
    source: str,
) -> list[tuple[Path, str, dict | None]]:
    """Crosswalk-id matching against the library index.

    Returns every candidate `(path, display_name, favourite_row)` the
    scene's performers resolve to so the weighted picker can pick the
    top-scored folder. The favourite row already comes back with
    `is_favourite` + `weight` from `favourite_find_performer_folder_by_crosswalk`.
    """
    out: list[tuple[Path, str, dict | None]] = []
    seen_paths: set[str] = set()
    for pf in _performer_objects_in_match_order(performers):
        tid, sid, fid = _performer_crosswalk_ids(pf, source)
        row = db.favourite_find_performer_folder_by_crosswalk(tid, sid, fid)
        if not row:
            continue
        path = Path(row["path"])
        if not path.is_dir():
            continue
        key = str(path)
        if key in seen_paths:
            continue
        seen_paths.add(key)
        name = (pf.get("name") or row.get("folder_name") or "").strip() or row.get("folder_name") or "Unknown"
        emit(f"  Library index: performer id → folder '{row['folder_name']}'")
        out.append((path, name, row))
    return out


def _studio_crosswalk_ids(studio_obj: dict, source: str) -> tuple[str, str, str]:
    sid = str((studio_obj or {}).get("id") or "").strip()
    if not sid:
        return "", "", ""
    s = (source or "").upper()
    if "MANUAL" in s:
        return sid, sid, sid
    if "STASH" in s:
        return "", sid, ""
    if "FANS" in s:
        return "", "", sid
    return sid, "", ""


def _fetch_performer_aliases(name: str, quiet: bool = False) -> list[str]:
    """Search all configured sources for a performer and return their aliases (parallel)."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    def _ae(msg: str) -> None:
        if not quiet:
            emit(msg)

    settings = db.get_settings()
    tasks = []

    def _tpdb_aliases():
        aliases = []
        try:
            resp = requests.get(TPDB_PERFORMER_SEARCH, params={"q": name},
                                headers=_tpdb_headers(), timeout=10)
            if resp.status_code == 200:
                perf_data = resp.json().get("data") or []
                # Include primary names of ALL search results (not just first)
                for p in perf_data[:5]:
                    pname = p.get("name", "")
                    if pname and pname not in aliases:
                        aliases.append(pname)
                # Fetch detailed aliases from the top result
                if perf_data:
                    pid = perf_data[0].get("id") or perf_data[0].get("_id")
                    if pid:
                        detail = fetch_performer_detail("TPDB", str(pid))
                        if detail:
                            for a in (detail.get("aliases") or []):
                                aname = a if isinstance(a, str) else a.get("name", "")
                                if aname and aname not in aliases:
                                    aliases.append(aname)
                            _ae(f"    TPDB aliases for '{name}': {aliases}")
                        else:
                            _ae(f"    TPDB no detail for pid={pid}")
                else:
                    _ae(f"    TPDB no results for '{name}'")
        except Exception as e:
            _ae(f"    TPDB alias error: {e}")
        return aliases

    def _stashdb_aliases():
        aliases = []
        try:
            gql = """
            query ($name: String!) {
              searchPerformer(term: $name, limit: 5) {
                id name aliases
              }
            }
            """
            resp = requests.post(
                "https://stashdb.org/graphql",
                json={"query": gql, "variables": {"name": name}},
                headers={"ApiKey": settings['api_key_stashdb'],
                          "Content-Type": "application/json"},
                timeout=10,
            )
            if resp.status_code == 200:
                data = resp.json().get("data", {})
                for p in (data.get("searchPerformer") or []):
                    pname = p.get("name", "")
                    if pname and pname not in aliases:
                        aliases.append(pname)
                    for a in (p.get("aliases") or []):
                        if a and a not in aliases:
                            aliases.append(a)
        except Exception:
            pass
        return aliases

    def _fansdb_aliases():
        aliases = []
        try:
            gql = """
            query ($term: String!) {
              searchPerformer(term: $term, limit: 5) {
                id name aliases
              }
            }
            """
            data = _fansdb_gql(gql, {"term": name})
            for p in (data.get("searchPerformer") or []):
                pname = p.get("name", "")
                if pname and pname not in aliases:
                    aliases.append(pname)
                for a in (p.get("aliases") or []):
                    if a and a not in aliases:
                        aliases.append(a)
        except Exception:
            pass
        return aliases

    if settings.get("api_key_tpdb"):
        tasks.append(_tpdb_aliases)
    if settings.get("api_key_stashdb"):
        tasks.append(_stashdb_aliases)
    if settings.get("api_key_fansdb"):
        tasks.append(_fansdb_aliases)

    if not tasks:
        return []

    all_aliases = []
    seen = set()
    with ThreadPoolExecutor(max_workers=len(tasks)) as pool:
        futures = [pool.submit(fn) for fn in tasks]
        for future in as_completed(futures):
            for a in future.result():
                if a and a not in seen:
                    seen.add(a)
                    all_aliases.append(a)

    return all_aliases

# ---------------------------------------------------------------------------
# Filename pattern rendering
# ---------------------------------------------------------------------------

def apply_caps(text: str) -> str:
    return " ".join(w.upper() if w.lower() in UPPERCASE_KEYWORDS else w for w in text.split())


def render_pattern(pattern: str, fields: dict) -> str:
    """Substitute {field} tokens in a pattern string."""
    result = pattern
    for key, value in fields.items():
        result = result.replace("{" + key + "}", str(value))
    return result

# ---------------------------------------------------------------------------
# File operations
# ---------------------------------------------------------------------------

def emit(msg: str) -> None:
    processing_state["log"].append(msg)
    try:
        db.activity_log_append(msg)
    except Exception:
        pass
    if log_queue:
        try:
            log_queue.put_nowait(msg)
        except Exception:
            pass


# Filed videos: clients often finish as 0700; shutil.move keeps that mode. Sidecars (.nfo, thumbs) are
# new files and follow process umask (often group-writable). Align video with matching .nfo when present.
LIBRARY_FILED_MODE_DEFAULT = 0o664


def _ensure_library_filed_permissions(path: Path) -> None:
    """Make filed outputs readable by group (and other) for downstream tools (e.g. FileFlows/ffmpeg)."""
    try:
        if not path.is_file():
            return
        mode = LIBRARY_FILED_MODE_DEFAULT
        nfo_same_stem = path.with_name(path.stem + ".nfo")
        if nfo_same_stem.is_file():
            try:
                mode = stat.S_IMODE(nfo_same_stem.stat().st_mode)
            except OSError:
                pass
        if mode == 0:
            mode = LIBRARY_FILED_MODE_DEFAULT
        os.chmod(path, mode)
    except OSError:
            pass


def safe_move(src: Path, dst: Path) -> None:
    try:
        shutil.move(str(src), str(dst))
    except (OSError, PermissionError) as e:
        if "cross-device" in str(e).lower() or getattr(e, "errno", None) in (18, 1):
            shutil.copyfile(str(src), str(dst))
            os.remove(str(src))
        else:
            raise
    _ensure_library_filed_permissions(dst)


def _video_quality_score(path: Path) -> tuple[int, int, int]:
    """Return (pixels, file_size_bytes, height) for quality ranking.

    Higher tuple = better quality.  pixels = width * height gives the
    most reliable resolution comparison; file_size breaks ties (higher
    bitrate at same resolution); height is a tiebreaker for edge cases.
    Returns (0, size, 0) if ffprobe fails so we still compare by size.
    """
    try:
        size = path.stat().st_size
    except OSError:
        size = 0
    _, w, h = probe_video_stream_meta(path)
    if w and h:
        return (w * h, size, h)
    return (0, size, 0)


def _quality_gate_move(src: Path, dst: Path, label: str = "Video") -> bool:
    """Move *src* to *dst*, but only if *src* is better quality than any
    existing file at *dst*.  If the incumbent is equal or better, *src*
    is deleted instead.

    Returns True if the file was moved, False if the incoming file was
    discarded in favour of the incumbent.
    """
    if not dst.exists():
        safe_move(src, dst)
        return True

    inc_score = _video_quality_score(dst)
    new_score = _video_quality_score(src)

    inc_px, inc_sz, inc_h = inc_score
    new_px, new_sz, new_h = new_score

    def _fmt(px, sz, h):
        res = f"{h}p" if h else "?"
        mb = f"{sz / 1048576:.0f} MB" if sz else "?"
        return f"{res} / {mb}"

    if new_score > inc_score:
        emit(f"  {label}: incoming is better quality ({_fmt(new_px, new_sz, new_h)} > {_fmt(inc_px, inc_sz, inc_h)}) — replacing incumbent")
        try:
            db.notification_add("pipeline", f"Upgraded {dst.name}: {_fmt(new_px, new_sz, new_h)} replaces {_fmt(inc_px, inc_sz, inc_h)}", ttl_seconds=120)
        except Exception:
            pass
        try:
            dst.unlink()
        except OSError:
            pass
        safe_move(src, dst)
        return True
    else:
        emit(f"  {label}: incumbent is equal or better quality ({_fmt(inc_px, inc_sz, inc_h)} >= {_fmt(new_px, new_sz, new_h)}) — discarding incoming file")
        try:
            db.notification_add("pipeline", f"Kept incumbent {dst.name} ({_fmt(inc_px, inc_sz, inc_h)}), discarded lower quality incoming ({_fmt(new_px, new_sz, new_h)})", ttl_seconds=120)
        except Exception:
            pass
        try:
            src.unlink()
        except OSError as e:
            emit(f"  {label}: failed to delete incoming file: {e}")
        return False


def _pil_resize_max_edge(im: Image.Image, max_edge: int) -> Image.Image:
    if max_edge <= 0:
        return im
    w, h = im.size
    if w <= 0 or h <= 0:
        return im
    m = max(w, h)
    if m <= max_edge:
        return im
    scale = max_edge / float(m)
    nw = max(1, int(round(w * scale)))
    nh = max(1, int(round(h * scale)))
    return im.resize((nw, nh), Image.Resampling.LANCZOS)


def _pil_normalize_for_output(im: Image.Image) -> Image.Image:
    if im.mode == "CMYK":
        return im.convert("RGB")
    if im.mode == "LA":
        return im.convert("RGBA")
    if im.mode in ("L", "I", "F"):
        return im.convert("RGB")
    if im.mode == "P":
        # Palette PNG-8 / GIF: tRNS + transparency index need RGBA merge — not only im.info["transparency"].
        return im.convert("RGBA")
    return im


_PNG_FILE_MAGIC = b"\x89PNG\r\n\x1a\n"


def save_image_bytes_optimized(
    data: bytes,
    dest: Path,
    *,
    max_edge: int,
    jpeg_quality: int = IMAGE_CACHE_JPEG_QUALITY,
) -> bool:
    """Decode image bytes, downscale if needed, write JPEG or PNG from dest suffix.

    PNG outputs: if input is already PNG, copy bytes unchanged (no re-encode / resize) so
    transparency stays bit-exact. Other formats decoded to PNG use Pillow without PNG
    ``optimize=`` packing. JPEG path unchanged (resize + quality encode).
    """
    try:
        dest.parent.mkdir(parents=True, exist_ok=True)
        suffix = dest.suffix.lower()
        if suffix == ".png" and len(data) >= 8 and data.startswith(_PNG_FILE_MAGIC):
            dest.write_bytes(data)
            return True
        im = Image.open(BytesIO(data))
        im.load()
        im = _pil_normalize_for_output(im)
        im = _pil_resize_max_edge(im, max_edge)
        if suffix == ".png":
            if im.mode == "LA":
                im = im.convert("RGBA")
            elif im.mode not in ("RGB", "RGBA"):
                im = im.convert("RGBA")
            im.save(dest, format="PNG", optimize=False)
        else:
            base = Image.new("RGB", im.size, (255, 255, 255))
            if im.mode == "RGBA":
                base.paste(im, mask=im.split()[3])
            elif im.mode == "RGB":
                base = im
            else:
                base.paste(im.convert("RGB"))
            base.save(
                dest,
                format="JPEG",
                quality=jpeg_quality,
                optimize=True,
                subsampling=2,
            )
            return True
    except Exception:
        return False


def download_image(
    url: str,
    dest: Path,
    *,
    max_edge: int = IMAGE_CACHE_POSTER_MAX,
    jpeg_quality: int = IMAGE_CACHE_JPEG_QUALITY,
) -> bool:
    try:
        resp = requests.get(url, timeout=30)
        if resp.status_code != 200:
            return False
        return save_image_bytes_optimized(
            resp.content, dest, max_edge=max_edge, jpeg_quality=jpeg_quality
        )
    except Exception:
        return False


def best_image_url(images: list) -> str | None:
    valid = [i for i in (images or []) if i.get("url")]
    if not valid:
        return None
    return max(valid, key=lambda i: (i.get("width") or 0) * (i.get("height") or 0))["url"]


def best_studio_image_url(images: list) -> str | None:
    """Prefer landscape/wide images (typical logos/banners) over tall posters when dimensions exist."""
    valid = [
        i
        for i in (images or [])
        if isinstance(i, dict) and (str(i.get("url") or "").strip())
    ]
    if not valid:
        return None
    dimmed = [
        i
        for i in valid
        if (i.get("width") or 0) > 0 and (i.get("height") or 0) > 0
    ]
    if not dimmed:
        return str(valid[0]["url"]).strip()

    def sort_key(i: dict):
        w, h = i.get("width") or 0, i.get("height") or 0
        r = w / h if h else 0.0
        area = w * h
        wide = 1 if r >= 1.05 else 0
        return (wide, w if wide else 0, area)

    return str(max(dimmed, key=sort_key)["url"]).strip()


def build_nfo(title, show_title, studio, performers, date) -> str:
    try:
        dt = datetime.strptime(date, "%Y-%m-%d")
        year, mmdd = str(dt.year), dt.strftime("%m%d")
    except Exception:
        year, mmdd = "0000", "0000"
    root = ET.Element("episodedetails")
    for tag, val in [("title", title), ("showtitle", show_title), ("season", year),
                     ("episode", mmdd), ("aired", date), ("premiered", date),
                     ("year", year), ("studio", studio),
                     ("dateadded", f"{date} 00:00:00"), ("mpaa", "Adult")]:
        ET.SubElement(root, tag).text = val
    ET.SubElement(root, "tag").text = "Porn"
    ET.SubElement(root, "tag").text = "XXX"
    for name in performers:
        actor = ET.SubElement(root, "actor")
        ET.SubElement(actor, "name").text = name.strip()
    tree = ET.ElementTree(root)
    ET.indent(tree, space="  ")
    buf = io.BytesIO()
    tree.write(buf, encoding="utf-8", xml_declaration=True)
    return buf.getvalue().decode("utf-8")

# ---------------------------------------------------------------------------
# Filing logic (shared between pipeline and manual filing)
# ---------------------------------------------------------------------------

def _scene_filing_plan(scene: dict, settings: dict, source: str, video_suffix: str) -> dict:
    """
    Resolve studio/performer route and naming for a stash-box-shaped scene.
    Returns status ok | error | no_dir (no database side effects).
    """
    performer_dirs = db.get_directories("performer")

    title      = apply_caps(scene.get("title") or "Untitled")
    date       = scene.get("release_date") or ""
    studio_obj = scene.get("studio") or {}
    studio     = studio_obj.get("name") or ""
    performers = scene.get("performers") or []
    images     = scene.get("images") or []
    perf_names = [p["performer"]["name"] for p in performers]

    emit(f"  Match: [{source}] {studio} - {date} - {title}")
    emit(f"  Performers: {', '.join(perf_names) or 'Unknown'}")

    if not date:
        emit("  ERROR: no release date in match")
        return {"status": "error", "error": "no release date"}

    try:
        dt = datetime.strptime(date, "%Y-%m-%d")
        year, month, day = str(dt.year), dt.strftime("%m"), dt.strftime("%d")
    except Exception:
        emit(f"  ERROR: unparseable date '{date}'")
        return {"status": "error", "error": f"bad date: {date}", "bare": True}

    season_token = f"Season {year}"

    # Filename components must be sanitised — scene titles frequently contain
    # forward slashes (e.g. "Pokemon B/G/G/G") which the OS would otherwise
    # interpret as directory separators during the move / NFO write.
    base_fields = {
        "title":      _sanitize_fs_component(title),
        "studio":     _sanitize_fs_component(apply_caps(studio)) if studio else "Unknown",
        "date":       date,
        "year":       year,
        "month":      month,
        "day":        day,
        "source":     _sanitize_fs_component(source),
        "performers": _sanitize_fs_component(", ".join(perf_names)) if perf_names else "",
    }

    # Manual-vice filing from the queue short-circuits routing — whatever
    # vice the user picked wins over any studio/performer folder match.
    # When this hint is present we MUST route via the vice; falling through
    # to studio matching would silently file the scene under a same-named
    # studio folder (or park it as no_dir), which is never what the user
    # asked for.
    forced_vice = (scene.get("_force_vice") or "").strip() if isinstance(scene, dict) else ""
    if forced_vice:
        vice_hit = _match_vice_by_scene_tags(scene, settings)
        if not vice_hit:
            emit(f"  ERROR: could not resolve vice folder for '{forced_vice}'")
            return {
                "status": "error",
                "error": f"could not resolve vice folder for '{forced_vice}' (check Vices directory setting)",
            }
        vice_name, vice_path = vice_hit
        emit(f"  Manual vice → {vice_name}")
        fields      = {**base_fields, "performer": _sanitize_fs_component(perf_names[0] if perf_names else "Unknown")}
        pattern     = settings.get("pattern_series", db.DEFAULTS["pattern_series"])
        base_name   = render_pattern(pattern, fields)
        show_title  = apply_caps(vice_name)
        nfo_title   = f"{', '.join(perf_names)} - {title}" if perf_names else title
        dest_season = vice_path / season_token
        route       = f"Vices/{vice_name}"
        studio      = studio or vice_name
        emit(f"  Route: {route}")
        emit(f"  Dest:  {base_name}{video_suffix}")
        return {
            "status": "ok",
            "dest_season": dest_season,
            "base_name": base_name,
            "nfo_title": nfo_title,
            "show_title": show_title,
            "studio": studio,
            "perf_names": perf_names,
            "date": date,
            "images": images,
            "thumb_data_url": scene.get("_thumb_data_url", "") or "",
            "route": route,
            "title": title,
        }

    cross_on = _library_index_queue_matching_enabled(settings)

    studio_dir = None
    if cross_on:
        st_tp, st_st, st_fn = _studio_crosswalk_ids(studio_obj, source)
        row_st = db.favourite_find_studio_folder_by_crosswalk(st_tp, st_st, st_fn)
        if row_st:
            cand = Path(row_st["path"])
            if cand.is_dir():
                studio_dir = cand
                emit(f"  Series: library index → {row_st['folder_name']}")
    if studio_dir is None:
        studio_dir = find_studio_dir(studio, settings) if studio else None

    if studio_dir:
        fields     = {**base_fields, "performer": _sanitize_fs_component(perf_names[0] if perf_names else "Unknown")}
        pattern    = settings.get("pattern_series", db.DEFAULTS["pattern_series"])
        base_name  = render_pattern(pattern, fields)
        show_title = apply_caps(studio)
        nfo_title  = f"{', '.join(perf_names)} - {title}" if perf_names else title
        dest_season = studio_dir / season_token
        route      = f"Series/{studio_dir.name}"
    else:
        # Collect every performer-folder candidate the scene resolves to
        # and pick the highest-weighted. Crosswalk-id matches come first,
        # then exact-name, then aliases (opt-in). Dedup by folder path so
        # the same folder surfaced by two layers is only scored once.
        candidates: list[tuple[Path, str, dict | None]] = []
        seen_paths: set[str] = set()
        def _extend(layer_hits: list[tuple[Path, str, dict | None]]) -> None:
            for path, nm, fav in layer_hits or []:
                key = str(path)
                if key in seen_paths:
                    continue
                seen_paths.add(key)
                candidates.append((path, nm, fav))
        if cross_on:
            _extend(_find_performer_dir_via_library_index(performers, source))
        _extend(find_performer_dir(performers, performer_dirs))
        if not candidates and settings.get("alias_lookup_enabled", "false") == "true":
            emit("  No direct performer match — checking aliases...")
            _extend(_find_performer_dir_with_aliases(performers, performer_dirs))
        result = None
        if candidates:
            # Highest weight wins; ties resolved by the original order
            # (which already reflects the crosswalk > exact > alias
            # precedence + scene performer ordering inside each layer).
            best = max(range(len(candidates)), key=lambda i: _performer_weight(candidates[i][2]))
            best_path, best_name, best_fav = candidates[best]
            if len(candidates) > 1:
                score_summary = ", ".join(
                    f"{nm}={_performer_weight(fav)}" for _, nm, fav in candidates
                )
                emit(f"  Performer scoring ({len(candidates)} candidates): {score_summary}")
                emit(f"  Picked: {best_name} (weight {_performer_weight(best_fav)})")
            result = (best_path, best_name)
        if not result:
            # Fallback: if the scene's tags match any Vice's assigned tags,
            # file under that vice's folder. Keeps matched-but-orphan scenes
            # inside the library instead of parking them as no_dir.
            vice_hit = _match_vice_by_scene_tags(scene, settings)
            if vice_hit:
                vice_name, vice_path = vice_hit
                emit(f"  Vice match → {vice_name}")
                fields      = {**base_fields, "performer": _sanitize_fs_component(perf_names[0] if perf_names else "Unknown")}
                pattern     = settings.get("pattern_series", db.DEFAULTS["pattern_series"])
                base_name   = render_pattern(pattern, fields)
                show_title  = apply_caps(vice_name)
                nfo_title   = f"{', '.join(perf_names)} - {title}" if perf_names else title
                dest_season = vice_path / season_token
                route       = f"Vices/{vice_name}"
                studio      = studio or vice_name
            else:
                emit(f"  WARNING: no Series dir for '{studio}' and no performer/vice dir match")
                return {
                    "status": "no_dir",
                    "title": title,
                    "studio": studio,
                    "date": date,
                    "perf_names": perf_names,
                    "source": source,
                }
        else:
            performer_path, performer_name = result
            fields     = {**base_fields, "performer": _sanitize_fs_component(performer_name)}
            pattern    = settings.get("pattern_performer", db.DEFAULTS["pattern_performer"])
            base_name  = render_pattern(pattern, fields)
            show_title = performer_name
            nfo_title  = f"{performer_name} - {title}"
            dest_season = performer_path / season_token
            route      = f"{performer_path.parent.name}/{performer_path.name}"

    emit(f"  Route: {route}")
    emit(f"  Dest:  {base_name}{video_suffix}")

    return {
        "status": "ok",
        "dest_season": dest_season,
        "base_name": base_name,
        "nfo_title": nfo_title,
        "show_title": show_title,
        "studio": studio,
        "perf_names": perf_names,
        "date": date,
        "images": images,
        "thumb_data_url": scene.get("_thumb_data_url", "") or "",
        "route": route,
        "title": title,
    }


def write_library_scene_nfo_and_thumb(video: Path, scene: dict, source: str) -> dict:
    """
    Write Kodi-style episode NFO and -thumb.jpg beside an existing library video (no move/copy).
    """
    settings = db.get_settings()
    plan = _scene_filing_plan(scene, settings, source, video.suffix)
    if plan.get("status") == "error":
        return {"status": "error", "error": plan.get("error", "error")}
    if plan.get("status") == "no_dir":
        return {
            "status": "no_dir",
            "error": "No matching studio or performer folder for this metadata (check favourites / paths).",
        }

    parent = video.parent
    stem = video.stem
    nfo_title = plan["nfo_title"]
    show_title = plan["show_title"]
    studio = plan["studio"]
    perf_names = plan["perf_names"]
    date = plan["date"]
    images = plan["images"]
    thumb_data_url = plan.get("thumb_data_url") or ""

    nfo = build_nfo(nfo_title, show_title, studio or "Unknown", perf_names, date)
    nfo_path = parent / f"{stem}.nfo"
    nfo_path.write_text(nfo, encoding="utf-8")
    _ensure_library_filed_permissions(nfo_path)

    thumb_path = parent / f"{stem}-thumb.jpg"
    if thumb_data_url and thumb_data_url.startswith("data:image"):
        try:
            _hdr, b64data = thumb_data_url.split(",", 1)
            raw = base64.b64decode(b64data)
            ok = save_image_bytes_optimized(
                raw, thumb_path, max_edge=IMAGE_CACHE_SCENE_THUMB_MAX
            )
            emit("  Thumb: saved (generated frame)" if ok else "  Thumb: save failed (encode)")
        except Exception as e:
            emit(f"  Thumb: save failed ({e})")
    else:
        image_url = best_image_url(images)
        if image_url:
            ok = download_image(
                image_url, thumb_path, max_edge=IMAGE_CACHE_SCENE_THUMB_MAX
            )
            emit("  Thumb: downloaded" if ok else "  Thumb: download failed")
        else:
            emit("  Thumb: no image available")
    if thumb_path.is_file():
        _ensure_library_filed_permissions(thumb_path)

    try:
        dest_key = str(video.resolve())
    except OSError:
        dest_key = str(video)
    row = db.library_file_get_by_destination(dest_key)
    phash = None
    if row:
        phash = (
            (row.get("phash_3") or "").strip()
            or (row.get("phash_2") or "").strip()
            or (row.get("phash_1") or "").strip()
            or None
        )
    if not phash:
        try:
            phash = compute_phash(video)
        except Exception:
            phash = None
    if phash:
        try:
            duration_for_submit = 0
            try:
                dur = get_video_duration(video)
                if dur:
                    duration_for_submit = int(dur)
            except Exception:
                pass
            _auto_backfill_external_dbs(scene, source, phash, duration_for_submit)
        except Exception as exc:
            emit(f"  Cross-DB submission: skipped ({exc})")

    trigger_media_scans(str(video))
    return {"status": "ok", "nfo": str(nfo_path), "thumb": str(thumb_path)}


def file_scene_from_match(video: Path, scene: dict, source: str = "") -> dict:
    """
    File a video using a scene dict (stash-box shape).
    Returns a result dict with status and optional destination.
    """
    filename = video.name
    settings = db.get_settings()
    plan = _scene_filing_plan(scene, settings, source, video.suffix)

    if plan.get("status") == "error":
        err = plan.get("error", "error")
        db.update_file(filename, status="error", error=err)
        if plan.get("bare"):
            return {"status": "error"}
        return {"status": "error", "error": err}

    if plan.get("status") == "no_dir":
        db.update_file(
            filename,
            status="no_dir",
            match_source=plan["source"],
            match_title=plan["title"],
            match_studio=plan["studio"],
            match_date=plan["date"],
            performers=", ".join(plan["perf_names"]),
            match_external_id=(scene.get("id") or "") if isinstance(scene, dict) else "",
        )
        return {"status": "no_dir"}

    dest_season = plan["dest_season"]
    base_name = plan["base_name"]
    nfo_title = plan["nfo_title"]
    show_title = plan["show_title"]
    studio = plan["studio"]
    perf_names = plan["perf_names"]
    date = plan["date"]
    images = plan["images"]
    thumb_data_url = plan.get("thumb_data_url") or ""
    title = plan["title"]
    ext = video.suffix

    dest_season.mkdir(parents=True, exist_ok=True)

    nfo = build_nfo(nfo_title, show_title, studio or "Unknown", perf_names, date)
    (dest_season / f"{base_name}.nfo").write_text(nfo, encoding="utf-8")
    emit("  NFO: saved")

    if thumb_data_url and thumb_data_url.startswith("data:image"):
        try:
            _hdr, b64data = thumb_data_url.split(",", 1)
            raw = base64.b64decode(b64data)
            ok = save_image_bytes_optimized(
                raw,
                dest_season / f"{base_name}-thumb.jpg",
                max_edge=IMAGE_CACHE_SCENE_THUMB_MAX,
            )
            if ok:
                emit("  Thumb: saved (generated frame)")
            else:
                emit("  Thumb: save failed (could not encode image)")
        except Exception as e:
            emit(f"  Thumb: save failed ({e})")
    else:
        image_url = best_image_url(images)
        if image_url:
            ok = download_image(
                image_url,
                dest_season / f"{base_name}-thumb.jpg",
                max_edge=IMAGE_CACHE_SCENE_THUMB_MAX,
            )
            emit("  Thumb: downloaded" if ok else "  Thumb: download failed")
        else:
            emit("  Thumb: no image available")

    scene_ext_id = (scene.get("id") or "") if isinstance(scene, dict) else ""
    scene_dest = dest_season / f"{base_name}{ext}"
    if not _quality_gate_move(video, scene_dest, label="Video"):
        db.update_file(
            filename,
            status="filed",
            match_source=source,
            match_title=title,
            match_studio=studio,
            match_date=date,
            performers=", ".join(perf_names),
            destination=str(scene_dest),
            match_external_id=scene_ext_id,
        )
        return
    emit("  Video: moved")

    destination = str(scene_dest)
    db.update_file(
        filename,
        status="filed",
        match_source=source,
        match_title=title,
        match_studio=studio,
        match_date=date,
        performers=", ".join(perf_names),
        destination=destination,
        match_external_id=scene_ext_id,
    )

    _health_register_filed_scene(filename, destination)

    # Auto-clear matching wanted-list entry — check every source the
    # phash can be queried against so a scene added from /scenes (TPDB)
    # still clears when the phash only matches on StashDB or FansDB.
    try:
        ph_hex = db.get_phash(filename)
        scene_id_for_wanted = scene.get("id") if isinstance(scene, dict) else None
        if scene_id_for_wanted:
            # Direct mark via the match that actually filed the scene.
            db.wanted_mark_acquired("scene", (source or "").lower(), str(scene_id_for_wanted))
            # Also stash the phash on any active wanted row for this id
            # so a future scan on a different filename still auto-clears.
            if ph_hex:
                db.wanted_set_phash("scene", (source or "").lower(), str(scene_id_for_wanted), ph_hex)
        # Cross-source: if the phash matches on a different DB than we
        # filed through, cross-reference each DB's scene id and clear.
        if ph_hex:
            db.wanted_mark_acquired_by_phash(ph_hex)
            _wanted_cross_reference_by_phash(ph_hex)
    except Exception:
        pass

    # Phash back-propagation to every supported stash-box database.
    # Covers "filed from StashDB, also tell FansDB", and the inverse.
    # Per-DB toggles in settings gate whether we touch each one.
    try:
        phash_for_submit = db.get_phash(filename)
        duration_for_submit = 0
        try:
            dur = get_video_duration(Path(destination))
            if dur:
                duration_for_submit = int(dur)
        except Exception:
            pass
        if phash_for_submit:
            _auto_backfill_external_dbs(scene, source, phash_for_submit, duration_for_submit)
    except Exception as exc:
        emit(f"  Cross-DB submission: skipped ({exc})")

    trigger_media_scans(destination)
    # Mirror Radarr's DownloadCompletedEvent → DownloadEventHub flow:
    # once a scene file has been successfully filed, remove the matching
    # job from the source download client (gated on the same
    # `download_import_remove_client` setting as the watch-folder path).
    # The helper itself short-circuits when the toggle is off, so the
    # call is a no-op in the default config.
    try:
        _remove_client_jobs_after_import(filename, settings)
    except Exception as exc:
        emit(f"  Client remove (scene import): {exc}")

    emit("  DONE")
    return {"status": "filed", "destination": destination}


# ---------------------------------------------------------------------------
# Core pipeline
# ---------------------------------------------------------------------------

def _scene_dict_from_grab_row(grab: dict) -> dict:
    """Build a stash-box-shape scene dict from a `scene_grab_log` row.
    The row was populated at grab time from the source DB's payload
    on /scenes, so we already have the canonical title / studio /
    performers / poster — no second API call needed."""
    try:
        performers = json.loads(grab.get("source_performers") or "[]")
        if not isinstance(performers, list):
            performers = []
    except Exception:
        performers = []
    poster = (grab.get("source_poster_url") or "").strip()
    return {
        "id":           grab.get("source_id") or "",
        "title":        grab.get("source_title") or "",
        "release_date": grab.get("source_date") or "",
        "studio":       {"name": grab.get("source_studio") or ""},
        "performers":   [{"performer": {"name": n, "gender": ""}} for n in performers if n],
        "images":       [{"url": poster, "width": 0, "height": 0}] if poster else [],
    }


def process_single(video: Path) -> dict:
    filename = video.name
    db.upsert_file(filename)
    emit(f"FILE {filename}")

    settings = db.get_settings()
    performer_dirs = db.get_directories("performer")

    # Phash - check database first, compute and store if missing
    cached = db.get_phash(filename)
    if cached:
        phash = cached
        emit(f"  Phash: cached ({phash})")
    else:
        try:
            emit("  Phash: computing...")
            phash = compute_phash(video)
            emit(f"  Phash: done ({phash})")
        except Exception as e:
            emit(f"  Phash: FAILED - {e}")
            db.update_file(filename, status="error", error=str(e))
            return {"status": "error", "error": str(e)}

    db.update_file(filename, status="processing", phash=phash)

    early = _queue_resolve_phash_vs_indexed_library(video, filename, phash)
    if early is not None:
        return early

    # Auto-file short-circuit: if this file carries the Top-Shelf
    # `[ts-XXXXXXXX]` tag we injected at grab time, look up the
    # `scene_grab_log` row by that uid (bulletproof — survives any
    # client rename). The tag may live on:
    #   • the filename itself
    #   • a parent directory (NZBGet/SAB typically create a job-named
    #     folder and put the unpacked .mkv inside; only the folder
    #     carries the tag)
    #   • a grandparent (qBittorrent + category sub-dirs, etc.)
    # so we walk up to 3 levels looking for the tag before falling
    # back to filename-based lookup. Only honoured for `kind = scene`
    # so a multi-file Movie release doesn't get every file written
    # under the parent movie's metadata. On full miss (or
    # movie-kind), fall through to the standard phash-based query
    # below.
    try:
        ts_uid = ""
        for candidate in (
            video.name,
            video.parent.name if video.parent else "",
            video.parent.parent.name if video.parent and video.parent.parent else "",
            video.parent.parent.parent.name if video.parent and video.parent.parent and video.parent.parent.parent else "",
        ):
            if not candidate:
                continue
            _, found = _strip_ts_uid(candidate)
            if found:
                ts_uid = found
                break
        grab = db.lookup_scene_grab_by_ts_uid(ts_uid) if ts_uid else None
        if not grab:
            grab = db.lookup_scene_grab_for_filename(filename)
    except Exception as exc:
        emit(f"  Grab tag: lookup error ({exc})")
        grab = None
    if grab and (grab.get("kind") or "scene").lower() == "scene":
        if grab.get("source_id") and grab.get("source_title"):
            label = _stashbox_normalize_match_source(grab.get("source_db") or "")
            emit(f"  Grab tag: matched {label}/{grab.get('source_id')} — auto-filing without phash lookup")
            try:
                scene = _scene_dict_from_grab_row(grab)
                result = file_scene_from_match(video, scene, source=label)
                if result.get("status") == "filed":
                    db.mark_scene_grab_consumed(grab.get("id"))
                    return result
                emit(f"  Grab tag: file_scene_from_match returned {result.get('status')!r}, falling back to phash")
            except Exception as exc:
                emit(f"  Grab tag: filing failed ({exc}), falling back to phash")

    # Lookup
    try:
        emit("  Lookup: querying databases...")
        matches, source = query_with_fallback(phash)
    except Exception as e:
        emit(f"  Lookup: FAILED - {e}")
        db.update_file(filename, status="error", error=str(e))
        return {"status": "error", "error": str(e)}

    if not matches:
        emit("  Lookup: no match found")
        db.update_file(filename, status="unmatched")
        #: Pre-warm the queue thumbnail filmstrip so when the user
        #: opens this row to investigate, the frames are already on
        #: disk. FFmpeg is still warm on this file from the phash
        #: pass, so the marginal cost is small.
        _prewarm_queue_thumbs_async(filename)
        return {"status": "unmatched"}

    return file_scene_from_match(video, matches[0], source=source)


def run_pipeline(filenames: list = None) -> None:
    processing_state["running"] = True
    processing_state["log"] = []
    try:
        settings = db.get_settings()
        source_dir = Path(settings.get("source_dir", ""))
        if filenames:
            video_files = [
                p for f in filenames
                if (p := db.resolve_source_video_path(source_dir, f)) is not None
            ]
        else:
            video_files = sorted([
                f for f in source_dir.iterdir()
                if f.is_file() and f.suffix.lower() in VIDEO_EXTENSIONS
            ])
        n = len(video_files)
        processing_state["pipeline_total"] = n
        processing_state["pipeline_done"] = 0
        emit(f"PIPELINE START - {n} file(s)")
        emit("---")
        _pipeline_outcomes = {"filed": 0, "unmatched": 0, "no_dir": 0, "error": 0}
        for i, video in enumerate(video_files):
            processing_state["current_file"] = video.name
            result = process_single(video)
            st = (result or {}).get("status", "error") if isinstance(result, dict) else "error"
            if st in _pipeline_outcomes:
                _pipeline_outcomes[st] += 1
            processing_state["pipeline_done"] = i + 1
            emit("---")
        emit("PIPELINE COMPLETE")
        try:
            n_files = len(video_files)
            if n_files == 1:
                sole = video_files[0].name
                if _pipeline_outcomes["filed"]:
                    msg = f"Sorted: {sole}"
                elif _pipeline_outcomes["no_dir"]:
                    msg = f"No directory for {sole}"
                elif _pipeline_outcomes["unmatched"]:
                    msg = f"Unmatched: {sole}"
                else:
                    msg = f"Failed: {sole}"
                db.notification_add("pipeline", msg, ttl_seconds=240)
            elif n_files > 1:
                parts = []
                if _pipeline_outcomes["filed"]:
                    parts.append(f"{_pipeline_outcomes['filed']} sorted")
                if _pipeline_outcomes["unmatched"]:
                    parts.append(f"{_pipeline_outcomes['unmatched']} unmatched")
                if _pipeline_outcomes["no_dir"]:
                    parts.append(f"{_pipeline_outcomes['no_dir']} no-dir")
                if _pipeline_outcomes["error"]:
                    parts.append(f"{_pipeline_outcomes['error']} errors")
                summary = " · ".join(parts) if parts else "no changes"
                db.notification_add(
                    "pipeline",
                    f"{n_files} files processed · {summary}",
                    ttl_seconds=240,
                )
        except Exception:
            pass
    except Exception as e:
        emit(f"PIPELINE ERROR: {e}")
        try:
            db.notification_add("error", f"Sorting error: {e}", ttl_seconds=400)
        except Exception:
            pass
    finally:
        processing_state["running"] = False
        processing_state["current_file"] = None
        processing_state["pipeline_total"] = 0
        processing_state["pipeline_done"] = 0

# ---------------------------------------------------------------------------
# TMDB movie search and filing
# ---------------------------------------------------------------------------

TMDB_BASE = "https://api.themoviedb.org/3"
TMDB_IMG_BASE = "https://image.tmdb.org/t/p/w500"


def get_tmdb_headers() -> dict:
    s = db.get_settings()
    return {
        "Authorization": f"Bearer {s.get('api_key_tmdb', '')}",
        "Accept": "application/json",
    }


def search_tmdb(query: str, year: str = None) -> list[dict]:
    params = {"query": query, "include_adult": "true", "language": "en-US", "page": 1}
    if year:
        params["year"] = year
    resp = requests.get(f"{TMDB_BASE}/search/movie", params=params,
                        headers=get_tmdb_headers(), timeout=15)
    resp.raise_for_status()
    results = resp.json().get("results", [])
    return [{
        "id":          str(r["id"]),
        "title":       r.get("title") or r.get("original_title") or "Unknown",
        "year":        (r.get("release_date") or "")[:4],
        "overview":    r.get("overview") or "",
        "poster_url":  f"{TMDB_IMG_BASE}{r['poster_path']}" if r.get("poster_path") else None,
        "rating":      r.get("vote_average"),
    } for r in results]


def get_tmdb_movie(tmdb_id: str) -> dict:
    resp = requests.get(f"{TMDB_BASE}/movie/{tmdb_id}",
                        params={"append_to_response": "credits"},
                        headers=get_tmdb_headers(), timeout=15)
    resp.raise_for_status()
    data = resp.json()
    cast = [m["name"] for m in data.get("credits", {}).get("cast", [])[:10]]
    crew = data.get("credits", {}).get("crew", [])
    directors = [m["name"] for m in crew if m.get("job") == "Director"]
    return {
        "id":           str(data["id"]),
        "title":        data.get("title") or data.get("original_title") or "Unknown",
        "year":         (data.get("release_date") or "")[:4],
        "overview":     data.get("overview") or "",
        "poster_url":   f"{TMDB_IMG_BASE}{data['poster_path']}" if data.get("poster_path") else None,
        "backdrop_url": f"https://image.tmdb.org/t/p/original{data['backdrop_path']}" if data.get("backdrop_path") else None,
        "rating":       data.get("vote_average"),
        "cast":         cast,
        "directors":    directors,
        "genres":       [g["name"] for g in data.get("genres", [])],
        "runtime":      data.get("runtime"),
        "tagline":      data.get("tagline") or "",
    }


def build_movie_nfo(movie: dict, filename: str) -> str:
    root = ET.Element("movie")
    ET.SubElement(root, "title").text        = movie["title"]
    ET.SubElement(root, "originaltitle").text = movie["title"]
    ET.SubElement(root, "year").text         = movie.get("year") or ""
    ET.SubElement(root, "plot").text         = movie.get("overview") or ""
    ET.SubElement(root, "outline").text      = movie.get("tagline") or ""
    ET.SubElement(root, "rating").text       = str(movie.get("rating") or "")
    ET.SubElement(root, "runtime").text      = str(movie.get("runtime") or "")
    ET.SubElement(root, "id").text           = movie.get("id") or ""
    ET.SubElement(root, "tmdbid").text       = movie.get("id") or ""
    ET.SubElement(root, "mpaa").text         = "Adult"
    ET.SubElement(root, "tag").text          = "Porn"
    ET.SubElement(root, "tag").text          = "XXX"
    for genre in movie.get("genres") or []:
        ET.SubElement(root, "genre").text = genre
    for director in movie.get("directors") or []:
        ET.SubElement(root, "director").text = director
    for name in movie.get("cast") or []:
        actor = ET.SubElement(root, "actor")
        ET.SubElement(actor, "name").text = name
    tree = ET.ElementTree(root)
    ET.indent(tree, space="  ")
    buf = io.BytesIO()
    tree.write(buf, encoding="utf-8", xml_declaration=True)
    return buf.getvalue().decode("utf-8")


def _sanitize_fs_component(name: str) -> str:
    """Strip characters invalid or unreliable in file/folder names (cross-platform).

    Used for any value that becomes a filesystem segment: movie titles, scene
    titles, performer names, studio names. Replaces path separators so scene
    titles like 'Pokemon B/G/G/G' don't get interpreted as nested directories.
    """
    if not name or not str(name).strip():
        return "Unknown"
    t = str(name).strip()
    for ch in '<>:"/\\|?*':
        t = t.replace(ch, " ")
    t = re.sub(r"[\x00-\x1f]", "", t)
    t = re.sub(r"\s+", " ", t).strip()
    t = t.rstrip(". ")
    return t or "Unknown"


def _movie_filing_stem(movie: dict) -> str:
    """Folder and file basename (no extension): ``Title (Year)`` safe for the filesystem."""
    safe_title = _sanitize_fs_component(movie.get("title") or "Unknown")
    yraw = str(movie.get("year") or "").strip()
    ydigits = re.sub(r"\D", "", yraw)
    if len(ydigits) >= 4:
        year_str = ydigits[:4]
    elif len(yraw) == 4 and yraw.isdigit():
        year_str = yraw
    else:
        year_str = "0000"
    return f"{safe_title} ({year_str})"


def file_movie(
    video: Path,
    movie: dict,
    *,
    tpdb_id: str | None = None,
    match_source: str = "tmdb",
) -> dict:
    """File a movie using TMDB metadata (or TPDB-shaped dict from _tpdb_detail_as_movie_filing_dict)."""
    filename = video.name
    db.upsert_movie(filename)
    settings = db.get_settings()
    features_dir = Path(settings.get("features_dir", ""))
    if not (settings.get("features_dir") or "").strip() or not features_dir.exists():
        db.update_movie(
            filename,
            status="no_dir",
            error="Features directory not configured or does not exist",
        )
        emit("  ERROR: features_dir missing")
        return {"status": "no_dir"}

    title = movie["title"]
    year = movie.get("year") or "0000"
    base_name = _movie_filing_stem(movie)
    folder_name = base_name
    dest_dir = features_dir / folder_name
    ext = video.suffix

    emit(f"  Movie: {title} ({year})")
    emit(f"  Dest:  {folder_name}/{base_name}{ext}")

    dest_dir.mkdir(parents=True, exist_ok=True)

    # NFO
    nfo = build_movie_nfo(movie, filename)
    (dest_dir / f"{base_name}.nfo").write_text(nfo, encoding="utf-8")
    emit("  NFO: saved")

    # Poster
    if movie.get("poster_url"):
        if download_image(
            movie["poster_url"],
            dest_dir / f"{base_name}-poster.jpg",
            max_edge=IMAGE_CACHE_POSTER_MAX,
        ):
            emit("  Poster: downloaded")
        else:
            emit("  Poster: download failed")

    # Backdrop / fanart
    if movie.get("backdrop_url"):
        if download_image(
            movie["backdrop_url"],
            dest_dir / f"{base_name}-fanart.jpg",
            max_edge=IMAGE_CACHE_FANART_MAX,
        ):
            emit("  Fanart: downloaded")
        else:
            emit("  Fanart: download failed")

    # Move video (quality gate: only replace if incoming is better)
    movie_dest = dest_dir / f"{base_name}{ext}"
    if not _quality_gate_move(video, movie_dest, label="Movie"):
        tid = str(movie.get("id") or "").strip() or None
        db.update_movie(
            filename,
            status="filed",
            tmdb_id=tid,
            tpdb_id=(str(tpdb_id).strip() or None) if tpdb_id else None,
            match_source=match_source,
            title=title,
            year=year,
            overview=movie.get("overview"),
            poster_url=movie.get("poster_url"),
            destination=str(movie_dest),
        )
        return
    emit("  Movie: moved")

    destination = str(movie_dest)
    tid = str(movie.get("id") or "").strip() or None
    db.update_movie(
        filename,
        status="filed",
        tmdb_id=tid,
        tpdb_id=(str(tpdb_id).strip() or None) if tpdb_id else None,
        match_source=match_source,
        title=title,
        year=year,
        overview=movie.get("overview"),
        poster_url=movie.get("poster_url"),
        destination=destination,
    )

    try:
        ph_mv = compute_phash(Path(destination))
    except Exception:
        ph_mv = None
    _health_register_filed_movie(destination, ph_mv)

    # Auto-clear matching wanted-list entry for this movie so the item
    # disappears from /downloads → Wanted once it lands in the library.
    try:
        if tpdb_id:
            db.wanted_mark_acquired("movie", "tpdb", str(tpdb_id).strip())
        if tid:
            db.wanted_mark_acquired("movie", "tmdb", str(tid).strip())
        if ph_mv:
            db.wanted_mark_acquired_by_phash(ph_mv)
    except Exception:
        pass

    # Trigger media server scans
    trigger_media_scans(destination)
    # Same Radarr-style post-import client cleanup as the scene
    # pipeline above. The toggle gate inside the helper means this is
    # a no-op unless `download_import_remove_client` is enabled.
    try:
        _remove_client_jobs_after_import(filename, db.get_settings())
    except Exception as exc:
        emit(f"  Client remove (movie import): {exc}")

    emit("  DONE")
    return {"status": "filed", "destination": destination}


def guess_movie_query_from_filename(filename: str) -> tuple[str, str | None]:
    """Best-effort title + optional release year from a video filename."""
    stem = Path(filename).stem
    s = re.sub(r"\[[^\]]*\]", " ", stem, flags=re.I)
    s = s.replace("_", " ").replace(".", " ")
    year_m = re.search(r"\b(19\d{2}|20\d{2})\b", s)
    year = year_m.group(1) if year_m else None
    title = re.sub(r"\s*\(?\s*(19\d{2}|20\d{2})\s*\)?\s*$", "", s).strip()
    title = re.sub(r"\s+", " ", title)
    return (title or stem, year)


def _favourite_row_sort_birth_date_movie(row: dict) -> str | None:
    mdb = (row.get("match_tmdb_id") or "").strip()
    if mdb:
        try:
            mm = get_tmdb_movie(mdb)
            yy = (mm.get("year") or "")[:4]
            if yy.isdigit() and len(yy) == 4:
                return f"{yy}-01-01"
        except Exception:
            pass
    _, yg = guess_movie_query_from_filename((row.get("folder_name") or "") + ".mkv")
    if yg and len(yg) == 4 and yg.isdigit():
        return f"{yg}-01-01"
    return None


def search_tpdb_movie_first_hit(query: str, year: str | None) -> dict | None:
    """First TPDB /movies hit for parse= query (no feed content filter — for filing)."""
    s = db.get_settings()
    if not (s.get("api_key_tpdb") or "").strip():
        return None
    params: dict = {"parse": query.strip(), "limit": 10}
    if year:
        params["year"] = year
    try:
        resp = requests.get(
            "https://api.theporndb.net/movies",
            params=params,
            headers={
                "Accept": "application/json",
                "Authorization": f"Bearer {s.get('api_key_tpdb', '')}",
            },
            timeout=15,
        )
        if resp.status_code != 200:
            return None
        data = (resp.json() or {}).get("data") or []
        return data[0] if data else None
    except Exception:
        return None


def _tpdb_detail_as_movie_filing_dict(m: dict) -> dict:
    """Normalize TPDB movie payload for file_movie / build_movie_nfo."""
    poster = m.get("image") or m.get("poster") or m.get("poster_image")
    if not poster:
        posters_obj = m.get("posters") or {}
        if isinstance(posters_obj, dict):
            poster = posters_obj.get("full") or posters_obj.get("large")
    bg = m.get("back_image") or m.get("backdrop_url")
    performers: list[str] = []
    for p in m.get("performers") or []:
        if isinstance(p, dict):
            perf = p.get("performer") or p
            n = perf.get("name") or perf.get("full_name")
            if n:
                performers.append(str(n))
        elif isinstance(p, str):
            performers.append(p)
    dirs: list[str] = []
    for d in m.get("directors") or []:
        if isinstance(d, dict) and d.get("name"):
            dirs.append(str(d["name"]))
        elif isinstance(d, str):
            dirs.append(d)
    genres: list[str] = []
    for g in m.get("tags") or []:
        if isinstance(g, dict):
            n = g.get("name") or (g.get("tag") or {}).get("name")
            if n:
                genres.append(str(n))
    y = (m.get("date") or "")[:4] or "0000"
    mid = str(m.get("_id") or m.get("id") or "")
    return {
        "id": "",
        "title": m.get("title") or m.get("name") or "Unknown",
        "year": y,
        "overview": m.get("description") or m.get("synopsis") or "",
        "poster_url": poster,
        "backdrop_url": bg if isinstance(bg, str) and bg.startswith("http") else None,
        "rating": m.get("rating"),
        "cast": performers,
        "directors": dirs,
        "genres": genres,
        "runtime": m.get("duration"),
        "tagline": "",
        "_tpdb_id": mid,
    }


def process_movie_file(filename: str, src: Path | None = None) -> None:
    settings = db.get_settings()
    if src is None:
        src = Path((settings.get("movies_source_dir") or "").strip())
    video = src / filename
    if not video.exists():
        return
    existing = db.get_movie_by_filename(filename)
    if existing and existing.get("status") == "filed":
        emit("  Already filed — skipped")
        return
    db.upsert_movie(filename)
    title_guess, year_guess = guess_movie_query_from_filename(filename)
    movie_dict: dict | None = None
    tpdb_id_used: str | None = None
    match_src = "tmdb"

    tmdb_results = None
    try:
        if (settings.get("api_key_tmdb") or "").strip():
            tmdb_results = search_tmdb(title_guess, year_guess)
    except Exception:
        tmdb_results = None
    if tmdb_results:
        try:
            movie_dict = get_tmdb_movie(tmdb_results[0]["id"])
            match_src = "tmdb"
        except Exception:
            movie_dict = None
    if not movie_dict:
        hit = search_tpdb_movie_first_hit(title_guess, year_guess)
        if hit:
            mid = str(hit.get("_id") or hit.get("id") or "")
            detail = _fetch_tpdb_movie_detail(mid) if mid else {}
            merged = {**hit, **detail} if detail else hit
            movie_dict = _tpdb_detail_as_movie_filing_dict(merged)
            tpdb_id_used = movie_dict.pop("_tpdb_id", None) or mid
            match_src = "tpdb"
    if not movie_dict:
        db.update_movie(
            filename,
            status="unmatched",
            error="No TMDB or TPDB match for parsed title",
        )
        emit("  No TMDB/TPDB match")
        return
    result = file_movie(
        video,
        movie_dict,
        tpdb_id=tpdb_id_used if match_src == "tpdb" else None,
        match_source=match_src,
    )
    if isinstance(result, dict) and result.get("status") == "no_dir":
        return


def run_movie_pipeline(filenames: list[str] | None = None) -> None:
    if processing_state["running"]:
        return
    settings = db.get_settings()
    src = Path((settings.get("movies_source_dir") or "").strip())
    if not src.exists():
        emit("MOVIE PIPELINE: movies_source_dir not configured or missing")
        return
    if filenames is None:
        terminal = db.get_movie_terminal_filenames()
        filenames = []
        for f in sorted(src.iterdir()):
            if f.is_file() and f.suffix.lower() in VIDEO_EXTENSIONS:
                if f.name not in terminal:
                    filenames.append(f.name)
    if not filenames:
        emit("MOVIE PIPELINE: nothing to process")
        return
    processing_state["running"] = True
    processing_state["pipeline_total"] = len(filenames)
    processing_state["pipeline_done"] = 0
    try:
        emit("PIPELINE MOVIES START")
        for idx, fn in enumerate(filenames):
            processing_state["current_file"] = fn
            emit(f"FILE {fn}")
            try:
                process_movie_file(fn, src)
            except Exception as e:
                db.update_movie(fn, status="error", error=str(e))
                emit(f"  ERROR: {e}")
            emit("---")
            processing_state["pipeline_done"] = idx + 1
        emit("PIPELINE MOVIES COMPLETE")
    finally:
        processing_state["running"] = False
        processing_state["current_file"] = None
        processing_state["pipeline_total"] = 0
        processing_state["pipeline_done"] = 0


# ---------------------------------------------------------------------------
# Performer / Studio metadata scraper
# ---------------------------------------------------------------------------

TPDB_PERFORMER_SEARCH = "https://api.theporndb.net/performers"
TPDB_PERFORMER_DETAIL = "https://api.theporndb.net/performers/{id}"
TPDB_STUDIO_SEARCH    = "https://api.theporndb.net/sites"
TPDB_STUDIO_DETAIL    = "https://api.theporndb.net/sites/{id}"

FANSDB_PERFORMER_SEARCH_GQL = """
query($term: String!) {
  searchPerformer(term: $term, limit: 10) {
    id name images { url }
  }
}
"""

FANSDB_PERFORMER_DETAIL_GQL = """
query($id: ID!) {
  findPerformer(id: $id) {
    name disambiguation aliases birth_date ethnicity country gender
    images { url }
    urls { url type }
  }
}
"""


def _tpdb_headers() -> dict:
    s = db.get_settings()
    return {"Accept": "application/json",
            "Authorization": f"Bearer {s.get('api_key_tpdb', '')}"}


def _extract_movie_genders(movie_data: dict) -> list[str]:
    """Extract performer genders from a TPDB movie/detail payload."""
    genders = []
    for p in (movie_data.get("performers") or []):
        if not isinstance(p, dict):
            continue
        perf = p.get("performer") or {}
        candidates = [
            ((p.get("parent") or {}).get("extras", {}) or {}).get("gender"),
            ((p.get("extra") or {}).get("gender")),
            (p.get("gender")),
            ((perf or {}).get("gender")),
            ((perf or {}).get("sex")),
        ]
        for g in candidates:
            if not g:
                continue
            g = str(g).strip().upper()
            if g and g != "UNKNOWN":
                genders.append(g)
                break
    return genders


def _classify_content(genders: list[str]) -> str:
    """Classify content from performer genders (first match wins).

    1. Any trans / non-binary / intersex-style label -> 'trans'
    2. Else: only females, exactly one -> 'solo_female'
    3. Else: more than one female, no males -> 'lesbian'
    4. Else: only male(s) -> 'gay'
    5. Else: at least one male and at least one female -> 'straight'
    6. Else -> 'unknown'
    """
    if not genders:
        return "unknown"

    females = 0
    males = 0
    trans = 0
    for g in genders:
        g = str(g).upper()
        if g in ("FEMALE", "F", "WOMAN", "CIS_FEMALE"):
            females += 1
        elif g in ("MALE", "M", "MAN", "CIS_MALE", "BOY", "GUY", "MALE_PERFORMER"):
            males += 1
        elif "TRANS" in g or g in ("NON_BINARY", "NONBINARY", "NON-BINARY", "INTERSEX", "OTHER"):
            trans += 1

    # 1. Trans / non-binary / intersex-style
    if trans > 0:
        return "trans"
    # 2. Single female, no males
    if females == 1 and males == 0:
        return "solo_female"
    # 3. Multiple females, no males
    if females > 1 and males == 0:
        return "lesbian"
    # 4. One or more males, no females
    if males > 0 and females == 0:
        return "gay"
    # 5. Mixed male and female
    if males > 0 and females > 0:
        return "straight"
    # 6. Unclassifiable (e.g. unrecognized gender strings only)
    return "unknown"


def _get_content_filter_config() -> tuple[dict[str, bool], bool, set[str]]:
    """Return content-filter settings as (cats, filter_active, allowed)."""
    s = db.get_settings()
    cats = {
        "straight":    s.get("cat_straight", "true") == "true",
        "lesbian":     s.get("cat_lesbian", "true") == "true",
        "gay":         s.get("cat_gay", "true") == "true",
        "solo_female": s.get("cat_solo_female", "true") == "true",
        "trans":       s.get("cat_trans", "true") == "true",
    }
    allowed = {k for k, v in cats.items() if v}
    filter_active = len(allowed) != 5
    return cats, filter_active, allowed


def _title_category_hint(title: str, studio: str = "") -> str:
    text = f" {(title or '').lower()} {(studio or '').lower()} "

    gay_terms = [
        " dick ", " dicks ", " bro ", " bros ", " men ", " boys ", " male ",
        " gay ", " twink ", " twinks ", " bareback ", " jock ", " dudes ",
        " me cum ", " loads ", " daddy ", " cocks ", " blowjob boys ",
        " corbin fisher ", " hot twinks ",
    ]
    lesbian_terms = [
        " lesbian ", " lesbians ", " girlsway ", " girlfriends films ",
        " girl girl ", " all girls ", " all-girl ", " stepmommy ",
    ]
    # Avoid bare "solo" — male solo titles often include it and were mislabeled as solo_female.
    solo_female_terms = [" masturbation ", " self play ", " solo girl ", " solochick "]
    female_context = (
        " her ", " she ", " milf ", " wife ", " girls ", " girl ", " babe ", " woman ",
        " women ", " mom ", " mommy ", " daughter ", " stepsis ", " step sis ",
    )
    trans_terms = [
        " trans ", " shemale ", " tgirl ", " tgirl ", " ts ",
    ]

    if any(term in text for term in trans_terms):
        return "trans"
    if any(term in text for term in gay_terms):
        return "gay"
    if any(term in text for term in lesbian_terms):
        return "lesbian"
    if any(term in text for term in solo_female_terms):
        if any(h in text for h in female_context):
            return "solo_female"
    if " solo " in text and any(h in text for h in female_context):
        return "solo_female"
    return "unknown"


def _fetch_tpdb_movie_detail(movie_id: str) -> dict:
    try:
        resp = requests.get(f"https://api.theporndb.net/movies/{movie_id}", headers=_tpdb_headers(), timeout=15)
        if resp.status_code != 200:
            return {}
        return resp.json().get("data") or {}
    except Exception:
        return {}


def _extract_movie_genders_with_fallback(movie_data: dict) -> tuple[list[str], str, str]:
    """Return (genders, source, category) for MOVIES.
    Prefer movie detail (accurate genders). If detail omits genders, try the list
    payload (often has partial gender). Then title/studio heuristic, then fail closed.
    source is one of detail/payload/title_heuristic/unknown."""
    movie_id = str(movie_data.get("_id") or movie_data.get("id") or "")
    if movie_id:
        detail = _fetch_tpdb_movie_detail(movie_id)
        genders = _extract_movie_genders(detail)
        category = _classify_content(genders)
        if genders and category != "unknown":
            return genders, "detail", category

    genders = _extract_movie_genders(movie_data)
    category = _classify_content(genders)
    if genders and category != "unknown":
        return genders, "payload", category

    # Only use title/studio guessing when API gender data is unusable.
    category = _title_category_hint(
        movie_data.get("title") or "",
        ((movie_data.get("site") or {}).get("name") or movie_data.get("studio") or ""),
    )
    if category != "unknown":
        return [], "title_heuristic", category

    return [], "unknown", "unknown"


def _passes_content_filter(genders, allowed: set = None, category: str | None = None) -> bool:
    """Check if content passes the category-based content filter.
    If no usable category data and filtering is active, exclude the content."""
    if isinstance(genders, set):
        genders = list(genders)
    if allowed is None:
        _, _, allowed = _get_content_filter_config()
        if len(allowed) == 5:
            return True

    if category is None:
        category = _classify_content(genders or [])

    if not category or category == "unknown":
        return False
    return category in allowed


def _tag_blacklist_normalized() -> frozenset[str]:
    """Lowercase tag names from settings ``tag_blacklist``.

    Accepts two storage formats for backward compatibility:
    - JSON array ``[{"id","slug","name"},...]`` (the new picker format —
      names are extracted for scene-tag comparison)
    - Legacy comma-separated string ``"Watersports, Fisting"``
    """
    raw = (db.get_settings().get("tag_blacklist") or "").strip()
    if not raw:
        return frozenset()
    if raw.startswith("["):
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, list):
                return frozenset(
                    str(t.get("name") or "").strip().lower()
                    for t in parsed
                    if isinstance(t, dict) and t.get("name")
                )
        except Exception:
            pass
    return frozenset(x.strip().lower() for x in raw.split(",") if x.strip())


def _tag_names_from_tpdb_entity(entity: dict) -> set[str]:
    """Lowercase tag names from a TPDB REST scene/movie payload."""
    names: set[str] = set()
    if not isinstance(entity, dict):
        return names
    raw = entity.get("tags")
    if not isinstance(raw, list):
        return names
    for t in raw:
        if isinstance(t, str) and t.strip():
            names.add(t.strip().lower())
        elif isinstance(t, dict):
            n = t.get("name") or t.get("label")
            if not n and isinstance(t.get("tag"), dict):
                n = t["tag"].get("name")
            if n and str(n).strip():
                names.add(str(n).strip().lower())
    return names


def _passes_tag_filter(entity: dict) -> bool:
    """Exclude if any item tag exactly matches a blacklisted tag (case-insensitive).

    If the blacklist is empty, always pass. If the API payload has no tags, pass
    (gender/category filters still apply)."""
    bl = _tag_blacklist_normalized()
    if not bl:
        return True
    item_tags = _tag_names_from_tpdb_entity(entity)
    if not item_tags:
        return True
    return not (item_tags & bl)


def _content_filters_fingerprint() -> tuple:
    """Invalidate feed/movie caches when category toggles or tag blacklist change."""
    s = db.get_settings()
    cats = tuple(
        s.get(k, "true") == "true"
        for k in ("cat_straight", "cat_lesbian", "cat_gay", "cat_solo_female", "cat_trans")
    )
    tag_bl = (s.get("tag_blacklist") or "").strip()
    return (cats, tag_bl)


def _movie_card_from_tpdb(m: dict) -> dict:
    poster = m.get("image") or m.get("poster") or m.get("poster_image")
    if not poster:
        posters_obj = m.get("posters") or {}
        if isinstance(posters_obj, dict):
            poster = posters_obj.get("full") or posters_obj.get("large")
    slug = m.get("slug") or str(m.get("_id", ""))
    # Pull performer names from the list payload so the feed card can show
    # hover headshots via /api/performers/headshots-by-name without needing
    # a follow-up detail fetch per card. Dedupe on a case-insensitive key
    # so TPDB records with the same performer listed twice (occasionally
    # happens on older entries) don't surface a duplicate headshot tile.
    perf_names: list[str] = []
    seen_perfs: set[str] = set()
    def _add_perf(n: str) -> None:
        s = (n or "").strip()
        if not s:
            return
        key = s.lower()
        if key in seen_perfs:
            return
        seen_perfs.add(key)
        perf_names.append(s)
    for p in (m.get("performers") or []):
        if isinstance(p, dict):
            perf = p.get("performer") or p
            _add_perf(perf.get("name") or perf.get("full_name") or "")
        elif isinstance(p, str):
            _add_perf(p)
    return {
        "id": str(m.get("_id") or m.get("id") or ""),
        "slug": slug,
        "title": m.get("title") or "",
        "date": m.get("date") or "",
        "studio": (m.get("site") or {}).get("name") or "",
        "poster": poster,
        "performer": ", ".join(perf_names),
        "link": f"https://theporndb.net/movies/{slug}",
    }


def _collect_filtered_tpdb_movies(base_params: dict, page: int, page_size: int = 20) -> dict:
    """Collect filtered TPDB movies, applying filter before local paging."""
    cats, filter_active, allowed = _get_content_filter_config()
    start = max(0, (int(page) - 1) * page_size)
    end = start + page_size
    upstream_page = 1
    accepted = []
    total_before_filter = 0
    excluded_unknown = 0
    excluded_by_category = 0
    excluded_by_tags = 0
    classification_sources = {"payload": 0, "detail": 0, "title_heuristic": 0, "unknown": 0}
    total_pages_hint = 1

    while True:
        params = dict(base_params)
        params["page"] = upstream_page
        params["limit"] = 50
        resp = requests.get("https://api.theporndb.net/movies", params=params, headers=_tpdb_headers(), timeout=15)
        if resp.status_code != 200:
            raise RuntimeError(f"TPDB returned {resp.status_code}")

        payload = resp.json() or {}
        raw_movies = payload.get("data") or []
        meta = payload.get("meta") or {}
        total_pages_hint = meta.get("last_page", total_pages_hint)
        total_before_filter += len(raw_movies)
        if not raw_movies:
            break

        for m in raw_movies:
            if filter_active:
                genders, source, category = _extract_movie_genders_with_fallback(m)
                classification_sources[source] = classification_sources.get(source, 0) + 1
                if category == "unknown":
                    excluded_unknown += 1
                    continue
                if not _passes_content_filter(genders, allowed, category):
                    excluded_by_category += 1
                    continue
            if not _passes_tag_filter(m):
                excluded_by_tags += 1
                continue
            accepted.append(_movie_card_from_tpdb(m))
            if len(accepted) >= end:
                break

        if len(accepted) >= end:
            break
        if upstream_page >= int(meta.get("last_page") or upstream_page):
            break
        upstream_page += 1

    page_results = accepted[start:end]
    total_after_filter = len(accepted)
    computed_total_pages = max(1, ((total_after_filter - 1) // page_size) + 1) if total_after_filter else 1
    return {
        "results": page_results,
        "page": int(page),
        "total_pages": computed_total_pages,
        "total": total_after_filter,
        "_debug": {
            "filter_active": filter_active,
            "cats": cats,
            "total_before_filter": total_before_filter,
            "total_after_filter": total_after_filter,
            "excluded_unknown": excluded_unknown,
            "excluded_by_category": excluded_by_category,
            "excluded_by_tags": excluded_by_tags,
            "classification_sources": classification_sources,
            "upstream_pages_scanned": upstream_page,
            "upstream_total_pages_hint": total_pages_hint,
        },
    }


ALLOWED_GENDER_BUCKETS = frozenset({"female", "male", "trans", "other"})


def normalize_performer_gender_to_bucket(g: str | None) -> str | None:
    """Map API gender strings to female | male | trans | other."""
    if not g or not str(g).strip():
        return None
    s = str(g).strip().upper().replace("-", "_").replace(" ", "_")
    if s in ("FEMALE", "F", "WOMAN", "CIS_FEMALE", "FEMALE_PERFORMER"):
        return "female"
    if s in ("MALE", "M", "MAN", "CIS_MALE", "MALE_PERFORMER", "BOY"):
        return "male"
    if "TRANS" in s or s in ("TRANSGENDER_FEMALE", "TRANSGENDER_MALE", "TRANSGENDER"):
        return "trans"
    if s in ("NON_BINARY", "NONBINARY", "INTERSEX", "OTHER", "NON_BINARY_GENDER"):
        return "other"
    return None


def gender_allowlist_from_json(s: str | None) -> frozenset[str] | None:
    """Empty list / missing = no filter. Non-empty JSON list → allow only those buckets."""
    if not s or not str(s).strip():
        return None
    try:
        arr = json.loads(s)
    except json.JSONDecodeError:
        return None
    if not isinstance(arr, list) or len(arr) == 0:
        return None
    out = {x for x in arr if x in ALLOWED_GENDER_BUCKETS}
    return frozenset(out) if out else None


def gender_allowlist_from_list(lst: list | None) -> frozenset[str] | None:
    if not lst or not isinstance(lst, list) or len(lst) == 0:
        return None
    out = {x for x in lst if x in ALLOWED_GENDER_BUCKETS}
    return frozenset(out) if out else None


def _tpdb_raw_gender_from_search_hit(p: dict) -> str | None:
    v = p.get("gender")
    if v:
        return str(v)
    ex = p.get("extra")
    if isinstance(ex, dict) and ex.get("gender"):
        return str(ex["gender"])
    extras = p.get("extras") or {}
    if isinstance(extras, dict) and extras.get("gender"):
        return str(extras["gender"])
    return None


def _tpdb_detail_gender_bucket(tpdb_id: str) -> str | None:
    """Authoritative gender from TPDB performer detail (search may omit extras)."""
    if not tpdb_id or not str(tpdb_id).strip():
        return None
    try:
        resp = requests.get(
            TPDB_PERFORMER_DETAIL.format(id=str(tpdb_id).strip()),
            headers=_tpdb_headers(),
            timeout=12,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data")
        if not data or not isinstance(data, dict):
            return None
        raw = _tpdb_raw_gender_from_search_hit(data)
        return normalize_performer_gender_to_bucket(raw)
    except Exception:
        return None


def _stashdb_find_performer_gender_bucket(sid: str) -> str | None:
    """Authoritative gender from StashDB findPerformer (search may omit or differ)."""
    settings = db.get_settings()
    key = (settings.get("api_key_stashdb") or "").strip()
    if not key or not sid or not str(sid).strip():
        return None
    try:
        gql = """
        query($id: ID!) {
          findPerformer(id: $id) {
            gender
          }
        }
        """
        resp = requests.post(
            "https://stashdb.org/graphql",
            json={"query": gql, "variables": {"id": str(sid).strip()}},
            headers={"ApiKey": key, "Content-Type": "application/json"},
            timeout=10,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data") or {}
        p = data.get("findPerformer") or {}
        raw_g = p.get("gender")
        raw_g = str(raw_g) if raw_g is not None else None
        return normalize_performer_gender_to_bucket(raw_g)
    except Exception:
        return None


def _fansdb_find_performer_gender_bucket(fid: str) -> str | None:
    if not fid or not str(fid).strip():
        return None
    try:
        data = _fansdb_gql(
            "query($id: ID!) { findPerformer(id: $id) { gender } }",
            {"id": str(fid).strip()},
        )
        p = data.get("findPerformer") or {}
        raw_g = p.get("gender")
        raw_g = str(raw_g) if raw_g is not None else None
        return normalize_performer_gender_to_bucket(raw_g)
    except Exception:
        return None


def _enforce_favourite_performer_slots_by_detail_gender(
    g_allow: frozenset[str],
    mt_id,
    mt_n,
    ms_id,
    ms_n,
    mf_id,
    mf_n,
):
    """Drop any link whose findPerformer / TPDB detail gender is not in the allowlist.
    Skips Stash/Fans verification when no API key (cannot call findPerformer)."""
    settings = db.get_settings()
    if mt_id:
        b = _tpdb_detail_gender_bucket(str(mt_id).strip())
        if b is None or b not in g_allow:
            mt_id = None
            mt_n = ""
    if ms_id and (settings.get("api_key_stashdb") or "").strip():
        b = _stashdb_find_performer_gender_bucket(str(ms_id).strip())
        if b is None or b not in g_allow:
            ms_id = None
            ms_n = ""
    if mf_id and (settings.get("api_key_fansdb") or "").strip():
        b = _fansdb_find_performer_gender_bucket(str(mf_id).strip())
        if b is None or b not in g_allow:
            mf_id = None
            mf_n = ""
    return mt_id, mt_n, ms_id, ms_n, mf_id, mf_n


def _apply_gender_allowlist(results: list[dict], allow: frozenset[str] | None) -> list[dict]:
    """When allowlist is set, keep only rows whose gender_bucket is in the set (unknown excluded)."""
    if not allow or len(allow) == 0:
        return results
    out: list[dict] = []
    for r in results:
        bucket = r.get("gender_bucket")
        if bucket is not None and bucket in allow:
            out.append(r)
    return out


def _fansdb_gql(query: str, variables: dict) -> dict:
    """FansDB is stash-box; use ApiKey like StashDB (Bearer alone is rejected)."""
    key = (db.get_settings().get("api_key_fansdb") or "").strip()
    if not key:
        return {}
    resp = requests.post(
        FANSDB_ENDPOINT,
        json={"query": query, "variables": variables},
        headers={"ApiKey": key, "Content-Type": "application/json"},
        timeout=15,
    )
    resp.raise_for_status()
    body = resp.json()
    if body.get("errors") and not body.get("data"):
        raise RuntimeError(str(body["errors"]))
    return body.get("data") or {}


def search_performers(
    name: str,
    *,
    gender_allowlist: frozenset[str] | None = None,
    strict_name_match: bool = False,
) -> list[dict]:
    """Search TPDB + StashDB + FansDB. If strict_name_match, fetch a wider result set then keep
    only rows whose normalised name equals the query (no fuzzy/single-hit guessing)."""
    results = []
    settings = db.get_settings()
    tpdb_take = 40 if strict_name_match else 5
    stash_limit = 40 if strict_name_match else 5
    fans_limit = 40 if strict_name_match else 10

    def _append_tpdb(p: dict) -> None:
        posters = p.get("posters") or []
        img = posters[0] if posters and isinstance(posters[0], str) else (posters[0].get("url") if posters else None)
        raw_g = _tpdb_raw_gender_from_search_hit(p)
        results.append({
            "source": "TPDB",
            "id":     str(p.get("id") or p.get("_id") or ""),
            "slug":   p.get("slug") or p.get("_id") or str(p.get("id") or p.get("_id") or ""),
            "name":   p["name"],
            "image":  img,
            "gender": raw_g,
            "gender_bucket": normalize_performer_gender_to_bucket(raw_g),
        })

    # TPDB
    try:
        resp = requests.get(TPDB_PERFORMER_SEARCH, params={"q": name},
                            headers=_tpdb_headers(), timeout=15)
        if resp.status_code == 200:
            for p in (resp.json().get("data") or [])[:tpdb_take]:
                _append_tpdb(p)
    except Exception:
        pass
    # StashDB
    if settings.get("api_key_stashdb"):
        try:
            gql = f"""
            query($t: String!) {{
              searchPerformer(term: $t, limit: {stash_limit}) {{
                id name gender images {{ url }}
              }}
            }}
            """
            resp = requests.post(
                "https://stashdb.org/graphql",
                json={"query": gql, "variables": {"t": name}},
                headers={"ApiKey": settings["api_key_stashdb"],
                          "Content-Type": "application/json"},
                timeout=10,
            )
            if resp.status_code == 200:
                body = resp.json()
                data = body.get("data") or {}
                # Do not skip Stash hits when TPDB already returned the same display name —
                # favourites needs one row per source so TPDB / Stash / Fans filters work.
                for p in (data.get("searchPerformer") or []):
                    imgs = p.get("images") or []
                    img = imgs[0].get("url") if imgs and isinstance(imgs[0], dict) else (imgs[0] if imgs else None)
                    raw_g = p.get("gender")
                    raw_g = str(raw_g) if raw_g is not None else None
                    results.append({
                        "source": "StashDB",
                        "id":     str(p["id"]),
                        "slug":   str(p["id"]),
                        "name":   p["name"],
                        "image":  img,
                        "gender": raw_g,
                        "gender_bucket": normalize_performer_gender_to_bucket(raw_g),
                    })
        except Exception:
            pass
    # FansDB (stash-box: same ApiKey auth as scene search; variable name `term` matches API)
    if settings.get("api_key_fansdb"):

        def _fansdb_append_from_data(data: dict) -> None:
            for p in (data.get("searchPerformer") or []):
                imgs = p.get("images") or []
                img = imgs[0].get("url") if imgs and isinstance(imgs[0], dict) else (imgs[0] if imgs else None)
                raw_g = p.get("gender")
                raw_g = str(raw_g) if raw_g is not None else None
                results.append({
                    "source": "FansDB",
                    "id":     str(p["id"]),
                    "slug":   str(p["id"]),
                    "name":   p["name"],
                    "image":  img,
                    "gender": raw_g,
                    "gender_bucket": normalize_performer_gender_to_bucket(raw_g),
                })

        try:
            gql_img = f"""
            query($term: String!) {{
              searchPerformer(term: $term, limit: {fans_limit}) {{
                id name gender images {{ url }}
              }}
            }}
            """
            data = _fansdb_gql(gql_img, {"term": name})
            _fansdb_append_from_data(data)
        except Exception:
            try:
                gql_min = f"""
                query($term: String!) {{
                  searchPerformer(term: $term, limit: {fans_limit}) {{
                    id name gender
                  }}
                }}
                """
                data = _fansdb_gql(gql_min, {"term": name})
                _fansdb_append_from_data(data)
            except Exception:
                pass
    if strict_name_match:
        want = normalise(name)
        results = [r for r in results if normalise(r.get("name") or "") == want]
    return _apply_gender_allowlist(results, gender_allowlist)


def _tpdb_site_image_url(site: dict) -> str | None:
    """Resolve a usable image URL from a TPDB /sites item (logo/poster may be str or nested)."""
    for key in ("logo", "poster", "image"):
        v = site.get(key)
        if isinstance(v, str) and v.strip():
            return v.strip()
        if isinstance(v, dict):
            u = v.get("url") or v.get("full") or v.get("large")
            if isinstance(u, str) and u.strip():
                return u.strip()
    for key in ("logos", "posters", "images"):
        arr = site.get(key)
        if isinstance(arr, list) and arr and isinstance(arr[0], dict):
            got = (
                best_image_url(arr)
                if key == "logos"
                else best_studio_image_url(arr)
            )
            if got:
                return got
    return None


def _tpdb_scalar_media_url(val) -> str | None:
    """TPDB field that is either a URL string or {url, full, large}."""
    if isinstance(val, str) and val.strip():
        return val.strip()
    if isinstance(val, dict):
        u = val.get("url") or val.get("full") or val.get("large")
        if isinstance(u, str) and u.strip():
            return u.strip()
    return None


def search_studios(name: str) -> list[dict]:
    results = []
    settings = db.get_settings()
    try:
        resp = requests.get(TPDB_STUDIO_SEARCH, params={"q": name},
                            headers=_tpdb_headers(), timeout=15)
        if resp.status_code == 200:
            for s in (resp.json().get("data") or [])[:10]:
                sid = s.get("id") or s.get("_id")
                if sid is None:
                    continue
                sid_s = str(sid)
                results.append({
                    "source": "TPDB",
                    "id":     sid_s,
                    "slug":   str(s.get("slug") or s.get("_id") or sid_s),
                    "name":   s.get("name") or s.get("title", ""),
                    "image":  _tpdb_site_image_url(s),
                })
    except Exception:
        pass
    if settings.get("api_key_stashdb"):
        try:
            for s in stashdb_search_studio(name, settings["api_key_stashdb"])[:10]:
                results.append({
                    "source": "StashDB",
                    "id":     str(s["id"]),
                    "slug":   str(s["id"]),
                    "name":   s.get("name") or "",
                    "image":  best_studio_image_url(s.get("images") or []),
                })
        except Exception:
            pass
    if settings.get("api_key_fansdb"):
        try:
            gql = """
            query($term: String!) {
              searchStudio(term: $term, limit: 10) {
                id name images { url width height }
              }
            }
            """
            data = _fansdb_gql(gql, {"term": name})
            for s in (data.get("searchStudio") or []):
                imgs = s.get("images") or []
                img = best_studio_image_url(imgs) if imgs else None
                if not img and imgs and isinstance(imgs[0], dict):
                    img = (imgs[0].get("url") or "").strip() or None
                results.append({
                    "source": "FansDB",
                    "id":     str(s["id"]),
                    "slug":   str(s["id"]),
                    "name":   s.get("name") or "",
                    "image":  img,
                })
        except Exception:
            pass
    return results


def _pick_best_name_match(results: list[dict], folder_name: str) -> dict | None:
    """Normalised name equality only (no fuzzy or single-result fallback)."""
    if not results:
        return None
    want = normalise(folder_name)
    for r in results:
        if normalise(r.get("name") or "") == want:
            return r
    return None


def _favourites_collect_folder_rows() -> list[dict]:
    """Subfolders under performer directory roots and under series_dir (studios)."""
    rows: list[dict] = []
    s = db.get_settings()
    for entry in db.get_directories("performer"):
        base = Path(entry["path"])
        label = entry.get("label") or base.name
        if not base.is_dir():
            emit(f"FAVOURITES collect: performer root not found: {base}")
            continue
        subdirs = sorted([d for d in base.iterdir() if d.is_dir() and not d.name.startswith(".")], key=lambda p: p.name.lower())
        emit(f"FAVOURITES collect: {len(subdirs)} folders in {label} ({base})")
        for d in subdirs:
                gf = entry.get("gender_filters")
                if not isinstance(gf, list):
                    gf = []
                rows.append({
                    "kind": "performer",
                    "folder_name": d.name,
                    "path": str(d.resolve()),
                    "root_label": label,
                    "gender_filters": gf,
                })
    series_dir = (s.get("series_dir") or "").strip()
    if series_dir and Path(series_dir).is_dir():
        base = Path(series_dir)
        for d in sorted(base.iterdir(), key=lambda p: p.name.lower()):
            if d.is_dir() and not d.name.startswith("."):
                rows.append({
                    "kind": "studio",
                    "folder_name": d.name,
                    "path": str(d.resolve()),
                    "root_label": "Series",
                })
    features_dir = (s.get("features_dir") or "").strip()
    if features_dir and Path(features_dir).is_dir():
        base = Path(features_dir)
        label = base.name or "Features"
        for d in sorted(base.iterdir(), key=lambda p: p.name.lower()):
            if d.is_dir() and not d.name.startswith("."):
                rows.append({
                    "kind": "movie",
                    "folder_name": d.name,
                    "path": str(d.resolve()),
                    "root_label": label,
                })
    return rows


def _normalize_sort_birth_date(raw: str | None) -> str | None:
    if not raw or not str(raw).strip():
        return None
    s = str(raw).strip()
    m = re.match(r"^(\d{4})(?:-(\d{2})(?:-(\d{2}))?)?", s)
    if not m:
        return None
    y, mo, d = m.group(1), m.group(2) or "01", m.group(3) or "01"
    try:
        mo_i = max(1, min(12, int(mo)))
        d_i = max(1, min(31, int(d)))
        return f"{y}-{mo_i:02d}-{d_i:02d}"
    except ValueError:
        return f"{y}-{mo}-{d}"


def _tpdb_performer_sort_birth_date(tpdb_id: str) -> str | None:
    try:
        resp = requests.get(
            TPDB_PERFORMER_DETAIL.format(id=tpdb_id),
            headers=_tpdb_headers(),
            timeout=12,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data") or {}
        extras = data.get("extras") or {}
        b = extras.get("birthday") or data.get("birth_date")
        return _normalize_sort_birth_date(b)
    except Exception:
        return None


def _fansdb_performer_sort_birth_date(fans_id: str) -> str | None:
    try:
        data = _fansdb_gql(
            "query($id: ID!) { findPerformer(id: $id) { birth_date } }",
            {"id": fans_id},
        )
        p = data.get("findPerformer") or {}
        return _normalize_sort_birth_date(p.get("birth_date"))
    except Exception:
        return None


def _stashdb_performer_sort_birth_date(sid: str) -> str | None:
    settings = db.get_settings()
    if not settings.get("api_key_stashdb"):
        return None
    try:
        gql = """
        query($id: ID!) {
          findPerformer(id: $id) {
            birth_date
          }
        }
        """
        resp = requests.post(
            "https://stashdb.org/graphql",
            json={"query": gql, "variables": {"id": sid}},
            headers={"ApiKey": settings["api_key_stashdb"],
                     "Content-Type": "application/json"},
            timeout=10,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data") or {}
        p = data.get("findPerformer") or {}
        return _normalize_sort_birth_date(p.get("birth_date"))
    except Exception:
        return None


def _favourite_performer_sort_birth_date(
    mt_id: str | None, ms_id: str | None, mf_id: str | None
) -> str | None:
    if mt_id:
        d = _tpdb_performer_sort_birth_date(mt_id)
        if d:
            return d
    if mf_id:
        d = _fansdb_performer_sort_birth_date(mf_id)
        if d:
            return d
    if ms_id:
        d = _stashdb_performer_sort_birth_date(ms_id)
        if d:
            return d
    return None


def _tpdb_studio_sort_birth_date(site_id: str) -> str | None:
    try:
        resp = requests.get(
            TPDB_STUDIO_DETAIL.format(id=site_id),
            headers=_tpdb_headers(),
            timeout=12,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data") or {}
        extras = data.get("extras") or {}
        y = extras.get("career_start_year") or extras.get("founded")
        if y is None or y == "":
            return None
        if isinstance(y, (int, float)):
            return f"{int(y)}-01-01"
        s = str(y).strip()
        m = re.match(r"^(\d{4})", s)
        if m:
            return f"{m.group(1)}-01-01"
        return _normalize_sort_birth_date(s)
    except Exception:
        return None


def _favourite_studio_sort_birth_date(mt_id: str | None) -> str | None:
    if mt_id:
        return _tpdb_studio_sort_birth_date(mt_id)
    return None


_FAVOURITE_LOCAL_POSTER_NAMES = ("poster.jpg", "folder.jpg")


def _favourite_find_local_poster_file(folder_path: str) -> Path | None:
    """Root-of-folder poster.jpg or folder.jpg (case-insensitive)."""
    raw = (folder_path or "").strip()
    if not raw:
        return None
    try:
        root = Path(raw).expanduser().resolve()
    except (OSError, RuntimeError):
        return None
    if not root.is_dir():
        return None
    for name in _FAVOURITE_LOCAL_POSTER_NAMES:
        p = root / name
        if p.is_file():
            return p.resolve()
    found: dict[str, Path] = {}
    try:
        for child in root.iterdir():
            if not child.is_file():
                continue
            key = child.name.lower()
            if key in ("poster.jpg", "folder.jpg"):
                found[key] = child
    except OSError:
        return None
    for name in _FAVOURITE_LOCAL_POSTER_NAMES:
        p = found.get(name.lower())
        if p:
            try:
                return p.resolve()
            except OSError:
                continue
    return None


# Studio folder art: logos / landscape / banner before poster.jpg. Logo-only exact pass, then
# case-insensitive map, so Logo.png wins over poster.jpg on Linux before poster is considered.
_FAVOURITE_STUDIO_LOCAL_LOGO_NAMES = (
    "logo.png",
    "clearlogo.png",
    "logo.jpg",
    "clearlogo.jpg",
    "logo.jpeg",
    "clearlogo.jpeg",
    "logo.webp",
    "clearlogo.webp",
    "landscape.png",
    "landscape.jpg",
    "landscape.webp",
    "banner.png",
    "banner.jpg",
    "banner.webp",
    "clearart.png",
    "clearart.jpg",
    "clearart.webp",
)
_FAVOURITE_STUDIO_LOCAL_POSTER_NAMES = ("poster.jpg", "folder.jpg")
_STUDIO_ART_IMAGE_EXT = frozenset({".png", ".webp", ".jpg", ".jpeg"})
_STUDIO_LOGO_STEMS_EXACT = frozenset(
    {
        "logo",
        "clearlogo",
        "clear_logo",
        "studialogo",
        "landscape",
        "banner",
        "clearart",
    }
)
_STUDIO_LOGO_STEM_SEGMENTS = frozenset({"logo", "clearlogo", "clearart", "studialogo"})


def _favourite_studio_root_logo_candidates(root: Path) -> list[Path]:
    """Root files that look like logo art (not poster.jpg / folder.jpg)."""
    poster_lower = {n.lower() for n in _FAVOURITE_STUDIO_LOCAL_POSTER_NAMES}
    candidates: list[tuple[int, int, str, Path]] = []
    try:
        for child in root.iterdir():
            if not child.is_file():
                continue
            if child.suffix.lower() not in _STUDIO_ART_IMAGE_EXT:
                continue
            nl = child.name.lower()
            if nl in poster_lower:
                continue
            stem_l = child.stem.lower()
            tier: int | None = None
            if stem_l in _STUDIO_LOGO_STEMS_EXACT:
                tier = 0
            elif nl.startswith("clearlogo"):
                tier = 0
            elif stem_l.endswith("-logo") or stem_l.endswith("_logo"):
                tier = 1
            else:
                parts = [p for p in re.split(r"[-_.\s]+", stem_l) if p]
                if _STUDIO_LOGO_STEM_SEGMENTS.intersection(parts):
                    tier = 2
            if tier is None:
                continue
            candidates.append((tier, len(nl), nl, child))
    except OSError:
        return []
    candidates.sort(key=lambda t: (t[0], t[1], t[2]))
    out: list[Path] = []
    for _a, _b, _c, child in candidates:
        try:
            out.append(child.resolve())
        except OSError:
            continue
    return out


def _favourite_find_local_studio_art(folder_path: str) -> Path | None:
    """Show root: logo / landscape / banner art first, then poster.jpg / folder.jpg."""
    raw = (folder_path or "").strip()
    if not raw:
        return None
    try:
        root = Path(raw).expanduser().resolve()
    except (OSError, RuntimeError):
        return None
    if not root.is_dir():
        return None
    all_names = _FAVOURITE_STUDIO_LOCAL_LOGO_NAMES + _FAVOURITE_STUDIO_LOCAL_POSTER_NAMES
    allowed_lower = {n.lower() for n in all_names}

    for name in _FAVOURITE_STUDIO_LOCAL_LOGO_NAMES:
        p = root / name
        if p.is_file():
            try:
                return p.resolve()
            except OSError:
                continue

    found: dict[str, Path] = {}
    try:
        for child in root.iterdir():
            if not child.is_file():
                continue
            key = child.name.lower()
            if key in allowed_lower:
                found[key] = child
    except OSError:
        return None

    for name in _FAVOURITE_STUDIO_LOCAL_LOGO_NAMES:
        p = found.get(name.lower())
        if p:
            try:
                return p.resolve()
            except OSError:
                continue

    for p in _favourite_studio_root_logo_candidates(root):
        if p.is_file():
            return p

    for name in _FAVOURITE_STUDIO_LOCAL_POSTER_NAMES:
        p = root / name
        if p.is_file():
            try:
                return p.resolve()
            except OSError:
                continue
    for name in _FAVOURITE_STUDIO_LOCAL_POSTER_NAMES:
        p = found.get(name.lower())
        if p:
            try:
                return p.resolve()
            except OSError:
                continue
    return None


def _maybe_kick_performer_image_enrichment(row: dict) -> None:
    """Fire the enrichment thread if a performer row is missing any image
    data we can backfill (headshot, poster_secondary). Works for BOTH locked
    and unlocked rows — the lock is meant to freeze match IDs, not block
    image downloads. Callers pass the current row dict; this helper reads
    it directly and never mutates the database.
    """
    if (row or {}).get("kind") != "performer":
        return
    try:
        row_id = int(row["id"])
    except (KeyError, TypeError, ValueError):
        return
    try:
        _iafd_dir = _performers_iafd_dir(row_id)
        _meta = _performers_iafd_read_meta(row_id)
        _has_img = bool(_performers_iafd_image_api_url(row_id, 0, _meta))
        _fresh = not (_iafd_dir / f"{row_id}.json").exists()
        _missing_ext = not all([
            (row.get("match_iafd_url") or "").strip(),
            (row.get("match_freeones_url") or "").strip(),
            (row.get("match_babepedia_url") or "").strip(),
        ])
        _has_db_id = any([
            (row.get("match_tpdb_id") or "").strip(),
            (row.get("match_stashdb_id") or "").strip(),
            (row.get("match_fansdb_id") or "").strip(),
        ])
        _missing_poster_secondary = True
        _md = _metadata_dir_for("performer", row_id)
        _ps = _md / f"{row_id}_poster_secondary.jpg"
        if _ps.is_file() and _ps.stat().st_size > 500:
            _missing_poster_secondary = False
    except Exception:
        return
    if (
        _fresh
        or (not _has_img)
        or (_missing_ext and _has_db_id)
        or (_missing_poster_secondary and _has_db_id)
    ):
        threading.Thread(
            target=_enrich_performer_ext_links_bg, args=(row_id,), daemon=True
        ).start()


def favourites_refresh_entity_row(
    row_id: int,
    *,
    scrape_aliases: bool = True,
    only_missing: bool = False,
) -> dict:
    """Resolve library folder → external IDs for cross-reference across databases.

    Each configured source (TPDB, StashDB, FansDB) is queried independently; when a
    performer/studio name matches (or a single unambiguous search hit), that source’s
    ID and display name are stored so the same folder links all three where possible.

    If only_missing is True, existing non-empty match_* ids are kept; only empty slots
    are filled. Image and aliases are not overwritten when already present unless a new
    match supplies them for an empty slot.

    When matches_locked is set, this function is skipped entirely (returns skipped: True).
    Manual link updates from the overlay search modal use api_favourites_match instead and
    are not blocked by the lock.
    """
    row = db.favourite_get(row_id)
    if not row:
        return {"error": "Not found"}
    if int(row.get("matches_locked") or 0):
        # Lock protects match IDs, but image enrichment (headshot + posters)
        # is safe to run — it only writes to metadata/performers/{id}/ and
        # never touches DB match_* columns. Fire the enrichment thread for
        # locked rows too so they can still catch up on missing images.
        _maybe_kick_performer_image_enrichment(row)
        return {"ok": True, "id": row_id, "skipped": True}
    name = row["folder_name"]
    kind = row["kind"]
    if kind not in ("performer", "studio", "movie"):
        return {"error": "unsupported kind"}
    if only_missing:
        scrape_aliases = False

    img: str | None = row.get("image_url")
    had_img = bool(str(img or "").strip())
    aliases: list[str] = []

    mt_id = mt_n = ms_id = ms_n = mf_id = mf_n = None
    mdb_id: str | None = None
    mdb_n: str | None = None
    movie_sort_bd: str | None = None

    if kind == "performer":
        g_allow = gender_allowlist_from_json(row.get("gender_filters_json"))
        res_tp = search_performers(
            name, gender_allowlist=g_allow, strict_name_match=True
        )
        res_st = [r for r in res_tp if r.get("source") == "StashDB"]
        res_tpdb = [r for r in res_tp if r.get("source") == "TPDB"]
        res_fan = [r for r in res_tp if r.get("source") == "FansDB"]
        p_tp = _pick_best_name_match(res_tpdb, name)
        p_st = _pick_best_name_match(res_st, name)
        p_fn = _pick_best_name_match(res_fan, name)
        if only_missing:
            mt_id = (row.get("match_tpdb_id") or "").strip() or None
            mt_n = (row.get("match_tpdb_name") or "") or ""
            ms_id = (row.get("match_stashdb_id") or "").strip() or None
            ms_n = (row.get("match_stashdb_name") or "") or ""
            mf_id = (row.get("match_fansdb_id") or "").strip() or None
            mf_n = (row.get("match_fansdb_name") or "") or ""
            # Drop stored links that violate the directory gender allowlist (search_performers
            # already filters; a stale match from before filters or wrong gender must be cleared).
            if g_allow is not None:

                def _id_in_results(res_list: list[dict], sid: str | None) -> bool:
                    if not sid or not str(sid).strip():
                        return False
                    s = str(sid).strip()
                    return any(str(r.get("id") or "") == s for r in res_list)

                if mt_id and not _id_in_results(res_tpdb, mt_id):
                    mt_id = None
                    mt_n = ""
                if ms_id and not _id_in_results(res_st, ms_id):
                    ms_id = None
                    ms_n = ""
                if mf_id and not _id_in_results(res_fan, mf_id):
                    mf_id = None
                    mf_n = ""
            if not mt_id and p_tp:
                mt_id = str(p_tp.get("id") or "")
                mt_n = p_tp.get("name") or ""
                if not had_img and p_tp.get("image"):
                    img = p_tp.get("image")
                    had_img = True
            if not ms_id and p_st:
                ms_id = str(p_st.get("id") or "")
                ms_n = p_st.get("name") or ""
                if not had_img and p_st.get("image"):
                    img = p_st.get("image")
                    had_img = True
            if not mf_id and p_fn:
                mf_id = str(p_fn.get("id") or "")
                mf_n = p_fn.get("name") or ""
                if not had_img and p_fn.get("image"):
                    img = p_fn.get("image")
                    had_img = True
        else:
            if p_tp:
                mt_id, mt_n = str(p_tp.get("id") or ""), p_tp.get("name") or ""
            if p_st:
                ms_id, ms_n = str(p_st.get("id") or ""), p_st.get("name") or ""
            if p_fn:
                mf_id, mf_n = str(p_fn.get("id") or ""), p_fn.get("name") or ""
            img = (
                (p_tp.get("image") if p_tp else None)
                or (p_st.get("image") if p_st else None)
                or (p_fn.get("image") if p_fn else None)
                or img
            )
            if scrape_aliases:
                aliases = _fetch_performer_aliases(name, quiet=True)
        if g_allow is not None:
            mt_id, mt_n, ms_id, ms_n, mf_id, mf_n = _enforce_favourite_performer_slots_by_detail_gender(
                g_allow, mt_id, mt_n, ms_id, ms_n, mf_id, mf_n
            )
    elif kind == "studio":
        res_s = search_studios(name)
        res_tpdb = [r for r in res_s if r.get("source") == "TPDB"]
        res_st = [r for r in res_s if r.get("source") == "StashDB"]
        res_fan = [r for r in res_s if r.get("source") == "FansDB"]
        p_tp = _pick_best_name_match(res_tpdb, name)
        p_st = _pick_best_name_match(res_st, name)
        p_fn = _pick_best_name_match(res_fan, name)
        if only_missing:
            mt_id = (row.get("match_tpdb_id") or "").strip() or None
            mt_n = (row.get("match_tpdb_name") or "") or ""
            ms_id = (row.get("match_stashdb_id") or "").strip() or None
            ms_n = (row.get("match_stashdb_name") or "") or ""
            mf_id = (row.get("match_fansdb_id") or "").strip() or None
            mf_n = (row.get("match_fansdb_name") or "") or ""
            if not mt_id and p_tp:
                mt_id = str(p_tp.get("id") or "")
                mt_n = p_tp.get("name") or ""
                if not had_img and p_tp.get("image"):
                    img = p_tp.get("image")
                    had_img = True
            if not ms_id and p_st:
                ms_id = str(p_st.get("id") or "")
                ms_n = p_st.get("name") or ""
                if not had_img and p_st.get("image"):
                    img = p_st.get("image")
                    had_img = True
            if not mf_id and p_fn:
                mf_id = str(p_fn.get("id") or "")
                mf_n = p_fn.get("name") or ""
                if not had_img and p_fn.get("image"):
                    img = p_fn.get("image")
                    had_img = True
        else:
            if p_tp:
                mt_id, mt_n = str(p_tp.get("id") or ""), p_tp.get("name") or ""
            if p_st:
                ms_id, ms_n = str(p_st.get("id") or ""), p_st.get("name") or ""
            if p_fn:
                mf_id, mf_n = str(p_fn.get("id") or ""), p_fn.get("name") or ""
            img = (
                (p_tp.get("image") if p_tp else None)
                or (p_st.get("image") if p_st else None)
                or (p_fn.get("image") if p_fn else None)
                or img
            )

    elif kind == "movie":
        title_guess, year_guess = guess_movie_query_from_filename(f"{name}.mkv")
        settings_mv = db.get_settings()
        tmdb_key_mv = (settings_mv.get("api_key_tmdb") or "").strip()
        tpdb_key_mv = (settings_mv.get("api_key_tpdb") or "").strip()
        ms_id = ms_n = mf_id = mf_n = None
        if only_missing:
            mdb_id = (row.get("match_tmdb_id") or "").strip() or None
            mdb_n = (row.get("match_tmdb_name") or "") or ""
            mt_id = (row.get("match_tpdb_id") or "").strip() or None
            mt_n = (row.get("match_tpdb_name") or "") or ""
            if not mdb_id and tmdb_key_mv:
                try:
                    t_res = search_tmdb(title_guess, year_guess) or []
                except Exception:
                    t_res = []
                if t_res:
                    try:
                        m_full = get_tmdb_movie(t_res[0]["id"])
                        mdb_id = str(m_full.get("id") or "").strip() or None
                        mdb_n = m_full.get("title") or ""
                        if not had_img and m_full.get("poster_url"):
                            img = m_full.get("poster_url")
                            had_img = True
                    except Exception:
                        pass
            if not mt_id and tpdb_key_mv:
                hit_mv = search_tpdb_movie_first_hit(title_guess, year_guess)
                if hit_mv:
                    mt_id = str(hit_mv.get("_id") or hit_mv.get("id") or "").strip() or None
                    mt_n = hit_mv.get("title") or ""
                    if not had_img:
                        pic_mv = _movie_card_from_tpdb(hit_mv).get("poster")
                        if pic_mv:
                            img = pic_mv
                            had_img = True
        else:
            mdb_id = mdb_n = mt_id = mt_n = None
            if tmdb_key_mv:
                try:
                    t_res = search_tmdb(title_guess, year_guess) or []
                except Exception:
                    t_res = []
                if t_res:
                    try:
                        m_full = get_tmdb_movie(t_res[0]["id"])
                        mdb_id = str(m_full.get("id") or "").strip() or None
                        mdb_n = m_full.get("title") or ""
                        img = m_full.get("poster_url") or img
                    except Exception:
                        pass
            if not mt_id and tpdb_key_mv:
                hit_mv = search_tpdb_movie_first_hit(title_guess, year_guess)
                if hit_mv:
                    mt_id = str(hit_mv.get("_id") or hit_mv.get("id") or "").strip() or None
                    mt_n = hit_mv.get("title") or ""
                    if not img:
                        pic_mv = _movie_card_from_tpdb(hit_mv).get("poster")
                        if pic_mv:
                            img = pic_mv
        y_key = year_guess if year_guess and len(year_guess) == 4 and year_guess.isdigit() else None
        if not y_key and mdb_id:
            try:
                mm = get_tmdb_movie(mdb_id)
                yy = (mm.get("year") or "")[:4]
                if yy.isdigit() and len(yy) == 4:
                    y_key = yy
            except Exception:
                pass
        movie_sort_bd = f"{y_key}-01-01" if y_key else None

    now = datetime.now(timezone.utc).isoformat()
    if kind == "performer" and scrape_aliases:
        aliases_json = json.dumps(aliases)
    elif kind == "performer":
        aliases_json = row.get("aliases_json")
    else:
        aliases_json = None

    if kind == "performer":
        sort_bd = _favourite_performer_sort_birth_date(mt_id, ms_id, mf_id)
    elif kind == "studio":
        sort_bd = _favourite_studio_sort_birth_date(mt_id)
    elif kind == "movie":
        sort_bd = movie_sort_bd
    else:
        sort_bd = None

    if kind == "performer" and _favourite_find_local_poster_file(row.get("path") or ""):
        img = f"/api/favourites/folder-poster?row_id={row_id}"
    elif kind == "movie" and _favourite_find_local_poster_file(row.get("path") or ""):
        img = f"/api/favourites/folder-poster?row_id={row_id}"
    elif kind == "studio" and _favourite_find_local_studio_art(row.get("path") or ""):
        img = f"/api/favourites/folder-logo?row_id={row_id}"

    db.favourite_overwrite_matches(
        row_id,
        image_url=img,
        aliases_json=aliases_json,
        match_tmdb_id=mdb_id,
        match_tmdb_name=mdb_n,
        match_tpdb_id=mt_id,
        match_tpdb_name=mt_n,
        match_stashdb_id=ms_id,
        match_stashdb_name=ms_n,
        match_fansdb_id=mf_id,
        match_fansdb_name=mf_n,
        sort_birth_date=sort_bd,
    )
    with db.get_conn() as c:
        c.execute(
            "UPDATE favourite_entities SET scanned_at = ? WHERE id = ?",
            (now, row_id),
        )
        c.commit()
    # Kick off enrichment for performers: ext links from DB cross-refs,
    # headshot, and posters. Same helper the locked-skip branch uses so the
    # trigger conditions stay in one place.
    if kind == "performer":
        _maybe_kick_performer_image_enrichment(db.favourite_get(row_id) or row)
    return {"ok": True, "id": row_id}


def favourites_scan_index(
    *,
    prune_missing: bool = False,
    folders: list[dict] | None = None,
    progress_init: bool = True,
    only_missing: bool = True,
) -> dict:
    """Scan configured library folders into favourite_entities; optionally drop removed folders.

    only_missing: when True (default), refresh each row without overwriting existing DB matches.
    """
    if folders is None:
        folders = _favourites_collect_folder_rows()
    valid_paths = {f["path"] for f in folders}
    seen = 0
    done = 0
    if progress_init:
        _favourites_progress_start("scan", len(folders))
    try:
        for f in folders:
            nm = f.get("folder_name") or ""
            _favourites_progress_update(nm, done)
            gf_json = None
            if f.get("kind") == "performer":
                lst = f.get("gender_filters")
                if isinstance(lst, list):
                    gf_json = json.dumps(lst)
            rid = db.favourite_upsert_folder(
                f["kind"],
                f["folder_name"],
                f["path"],
                f["root_label"],
                gender_filters_json=gf_json,
            )
            seen += 1
            if rid:
                favourites_refresh_entity_row(
                    rid,
                    scrape_aliases=not only_missing,
                    only_missing=only_missing,
                )
            done += 1
            _favourites_progress_update(nm, done)
        removed = 0
        if prune_missing:
            _favourites_progress_update("prune", done)
            removed = db.favourite_delete_missing_paths(valid_paths)
        _favourites_progress_update("paths", done)
        db.favourite_refresh_all_path_existence()
        emit(f"FAVOURITES index: {seen} folders scanned, {removed} stale rows removed")
        # Phase 3: NFO walk to discover any new studio names. Run in a daemon
        # thread so the scan response returns immediately — first run can be
        # slow on large libraries, subsequent runs are mtime-incremental.
        # Phase 4: kick the StashDB fetcher right after so newly-discovered
        # studios get their logos without waiting for the next scheduled tick.
        threading.Thread(
            target=lambda: (_studio_logos_discover_run(), _studio_logo_fetcher_job()),
            daemon=True,
            name="studio-logo-discover-fetch",
        ).start()
        return {"scanned": seen, "removed_stale": removed}
    finally:
        _favourites_progress_finish()


def run_favourites_scheduled_scan() -> None:
    s = db.get_settings()
    if s.get("favourites_scan_enabled", "false").lower() != "true":
        return
    try:
        favourites_scan_index(prune_missing=False, only_missing=True)
    except Exception as e:
        emit(f"FAVOURITES scheduled scan error: {e}")
    threading.Thread(target=_background_iafd_enrich_all, daemon=True).start()


def fetch_performer_detail(source: str, pid: str) -> dict | None:
    if source == "TPDB":
        try:
            resp = requests.get(TPDB_PERFORMER_DETAIL.format(id=pid),
                                headers=_tpdb_headers(), timeout=15)
            if resp.status_code == 200:
                data = resp.json().get("data")
                return data
        except Exception:
            pass
    elif source == "StashDB":
        key = (db.get_settings().get("api_key_stashdb") or "").strip()
        if not key:
            emit(f"fetch_performer_detail: no StashDB API key")
            return None
        try:
            # Stash-box's Performer type has cup_size/band_size/waist_size/
            # hip_size as top-level fields (not nested under measurements)
            # and has no `bio` field — we use disambiguation as the display
            # caption. Requesting either causes the server to reject the
            # query with HTTP 422.
            gql = """
            query($id: ID!) {
              findPerformer(id: $id) {
                id
                name
                disambiguation
                aliases
                birth_date
                ethnicity
                country
                gender
                hair_color
                height
                tattoos { location description }
                piercings { location description }
                breast_type
                cup_size
                band_size
                waist_size
                hip_size
                eye_color
                career_start_year
                career_end_year
                urls { url type }
                images { url }
              }
            }
            """
            resp = requests.post(
                "https://stashdb.org/graphql",
                json={"query": gql, "variables": {"id": str(pid).strip()}},
                headers={"ApiKey": key, "Content-Type": "application/json"},
                timeout=15,
            )
            if resp.status_code != 200:
                body_snip = (resp.text or "")[:240].replace("\n", " ")
                emit(f"fetch_performer_detail: StashDB HTTP {resp.status_code} for {pid}: {body_snip}")
                return None
            body = resp.json()
            if body.get("errors"):
                emit(f"fetch_performer_detail: StashDB GQL errors for {pid}: {body['errors']}")
                return None
            data = (body.get("data") or {}).get("findPerformer") or {}
            if not data:
                emit(f"fetch_performer_detail: StashDB returned empty for {pid}")
                return None

            def _stash_body_mod_line(mods) -> str | None:
                if not mods:
                    return None
                parts: list[str] = []
                for m in mods:
                    if not isinstance(m, dict):
                        continue
                    loc = (m.get("location") or "").strip()
                    desc = (m.get("description") or "").strip()
                    if loc and desc:
                        parts.append(f"{loc} ({desc})")
                    elif loc:
                        parts.append(loc)
                return "; ".join(parts) if parts else None

            meas_bits: list[str] = []
            for lbl, key in (
                ("Cup", "cup_size"),
                ("Band", "band_size"),
                ("Waist", "waist_size"),
                ("Hip", "hip_size"),
            ):
                v = data.get(key)
                if v is None or v == "":
                    continue
                meas_bits.append(f"{lbl} {v}")
            measure_line = ", ".join(meas_bits) if meas_bits else None

            extras = {
                "birthday": data.get("birth_date") or data.get("birthdate"),
                "ethnicity": data.get("ethnicity"),
                "nationality": data.get("country"),
                "gender": data.get("gender"),
                "hair_colour": data.get("hair_color"),
                "height": data.get("height"),
                "measurements": measure_line,
                "tattoos": _stash_body_mod_line(data.get("tattoos")),
                "piercings": _stash_body_mod_line(data.get("piercings")),
                "breast_type": data.get("breast_type"),
                "eye_color": data.get("eye_color"),
                "career_start_year": data.get("career_start_year"),
                "career_end_year": data.get("career_end_year"),
            }
            return {
                "stash_id": str(data.get("id") or "").strip() or None,
                "name": data.get("name"),
                "bio": data.get("disambiguation") or "",
                "aliases": data.get("aliases") or [],
                "posters": data.get("images") or [],
                "extras": {k: v for k, v in extras.items() if v is not None and str(v).strip()},
                "urls": data.get("urls") or [],
            }
        except Exception as exc:
            emit(f"fetch_performer_detail: StashDB exception for {pid}: {exc}")
    elif source == "FansDB":
        try:
            data = _fansdb_gql(FANSDB_PERFORMER_DETAIL_GQL, {"id": pid})
            p = data.get("findPerformer")
            if p:
                ex = {
                    "birthday":    p.get("birth_date"),
                    "ethnicity":   p.get("ethnicity"),
                    "nationality": p.get("country"),
                }
                g = p.get("gender")
                if g is not None and str(g).strip():
                    ex["gender"] = g
                return {
                    "fansdb_id": str(pid).strip(),
                    "name":    p.get("name"),
                    "bio":     p.get("disambiguation") or "",
                    "aliases": p.get("aliases", []),
                    "posters": p.get("images", []),
                    "extras":  {k: v for k, v in ex.items() if v is not None and str(v).strip()},
                    "urls":    p.get("urls") or [],
                }
        except Exception:
            pass
    return None


def fetch_studio_detail(source: str, sid: str) -> dict | None:
    if source == "TPDB":
        try:
            resp = requests.get(TPDB_STUDIO_DETAIL.format(id=sid),
                                headers=_tpdb_headers(), timeout=15)
            if resp.status_code == 200:
                return resp.json().get("data")
        except Exception:
            pass
    elif source == "StashDB":
        key = (db.get_settings().get("api_key_stashdb") or "").strip()
        if not key:
            return None
        try:
            gql = """
            query($id: ID!) {
              findStudio(id: $id) {
                id
                name
                details
                images { url }
              }
            }
            """
            resp = requests.post(
                "https://stashdb.org/graphql",
                json={"query": gql, "variables": {"id": str(sid).strip()}},
                headers={"ApiKey": key, "Content-Type": "application/json"},
                timeout=15,
            )
            if resp.status_code != 200:
                return None
            s = (resp.json().get("data") or {}).get("findStudio") or {}
            if not s:
                return None
            return {
                "id": s.get("id"),
                "name": s.get("name"),
                "title": s.get("name"),
                "description": s.get("details") or "",
                "images": s.get("images") or [],
            }
        except Exception:
            pass
    return None


def _favourites_index_created_folder(kind: str, folder: Path, dest_root: Path) -> bool:
    """Upsert one new folder into favourites index and refresh its links/image."""
    try:
        folder_resolved = folder.resolve()
        root_resolved = dest_root.resolve()
    except (OSError, RuntimeError):
        return False
    root_label = root_resolved.name or ("Series" if kind == "studio" else "Performer")
    gf: list[str] = []
    if kind == "performer":
        for entry in db.get_directories("performer"):
            ep = (entry.get("path") or "").strip()
            if not ep:
                continue
            try:
                if Path(ep).expanduser().resolve() == root_resolved:
                    root_label = entry.get("label") or root_label
                    val = entry.get("gender_filters")
                    if isinstance(val, list):
                        gf = val
                    break
            except (OSError, RuntimeError):
                continue
    else:
        s = db.get_settings()
        sd = (s.get("series_dir") or "").strip()
        if sd:
            try:
                if Path(sd).expanduser().resolve() == root_resolved:
                    root_label = "Series"
            except (OSError, RuntimeError):
                pass
    gf_json = json.dumps(gf) if kind == "performer" else None
    rid = db.favourite_upsert_folder(
        kind,
        folder_resolved.name,
        str(folder_resolved),
        root_label,
        gender_filters_json=gf_json,
    )
    if not rid:
        return False
    favourites_refresh_entity_row(rid, scrape_aliases=False, only_missing=True)
    return True


def _favourite_urls_from_poster_like_list(posters) -> list[str]:
    """Extract http(s) URLs from TPDB-style poster list (str or {url})."""
    out: list[str] = []
    for p in posters or []:
        if isinstance(p, str) and p.strip():
            out.append(p.strip())
        elif isinstance(p, dict):
            u = (p.get("url") or "").strip()
            if u:
                out.append(u)
    return out


def _tpdb_site_all_media_urls(site: dict | None) -> list[str]:
    """Every image URL on a TPDB site/studio detail payload (logos, posters, etc.)."""
    if not site:
        return []
    urls: list[str] = []
    seen: set[str] = set()

    def add(u: str | None) -> None:
        if not u or not str(u).strip():
            return
        s = str(u).strip()
        if s not in seen:
            seen.add(s)
            urls.append(s)

    for key in ("logo", "poster", "image"):
        v = site.get(key)
        if isinstance(v, str):
            add(v)
        elif isinstance(v, dict):
            add(v.get("url") or v.get("full") or v.get("large"))
    for key in ("logos", "posters", "images"):
        arr = site.get(key)
        if not isinstance(arr, list):
            continue
        for item in arr:
            if isinstance(item, str):
                add(item)
            elif isinstance(item, dict):
                add(item.get("url") or item.get("full") or item.get("large"))
    return urls


def _stashdb_performer_all_image_urls(ms_id: str) -> list[str]:
    if not ms_id or not str(ms_id).strip():
        return []
    key = (db.get_settings().get("api_key_stashdb") or "").strip()
    if not key:
        return []
    try:
        gql = """
        query($id: ID!) {
          findPerformer(id: $id) {
            images { url width height }
          }
        }
        """
        resp = requests.post(
            "https://stashdb.org/graphql",
            json={"query": gql, "variables": {"id": str(ms_id).strip()}},
            headers={"ApiKey": key, "Content-Type": "application/json"},
            timeout=10,
        )
        if resp.status_code != 200:
            return []
        data = resp.json().get("data") or {}
        p = data.get("findPerformer") or {}
        out: list[str] = []
        for i in p.get("images") or []:
            if isinstance(i, dict) and (i.get("url") or "").strip():
                out.append(str(i["url"]).strip())
        return out
    except Exception:
        return []


