def _favourites_matched_link_image_items(row: dict) -> list[dict]:
    """Picker rows: every distinct image URL from linked TPDB / StashDB / FansDB profiles.

    For group folders (``is_group=1``) we also walk the additional crosswalk
    IDs in ``group_ids_json`` so the image picker surfaces every linked
    performer's posters/headshots, not just the row's primary match.
    """
    kind = row.get("kind")
    items: list[dict] = []
    seen_urls: set[str] = set()

    def push(source: str, ext_id: str, name: str, url: str) -> None:
        u = (url or "").strip()
        if not u:
            return
        if u in seen_urls:
            return
        seen_urls.add(u)
        items.append({
            "source": source,
            "id": ext_id,
            "name": name,
            "image": u,
        })

    group_ids = {"tpdb": [], "stashdb": [], "fansdb": []}
    if row.get("is_group"):
        try:
            raw = json.loads(row.get("group_ids_json") or "{}") or {}
        except Exception:
            raw = {}
        if isinstance(raw, dict):
            for k in ("tpdb", "stashdb", "fansdb"):
                vals = raw.get(k) or []
                if isinstance(vals, list):
                    group_ids[k] = [str(x).strip() for x in vals if str(x).strip()]

    def _dedup_ids(primary: str, extras: list[str]) -> list[str]:
        seen: set[str] = set()
        out: list[str] = []
        if primary:
            seen.add(primary)
            out.append(primary)
        for x in extras:
            if x and x not in seen:
                seen.add(x)
                out.append(x)
        return out

    if kind == "performer":
        mt = (row.get("match_tpdb_id") or "").strip()
        mtn = (row.get("match_tpdb_name") or "").strip()
        for tid in _dedup_ids(mt, group_ids["tpdb"]):
            d = fetch_performer_detail("TPDB", tid)
            nm = (mtn if tid == mt else "") or (d.get("name") if d else "") or ""
            for u in _favourite_urls_from_poster_like_list((d or {}).get("posters")):
                push("TPDB", tid, nm, u)
        ms = (row.get("match_stashdb_id") or "").strip()
        msn = (row.get("match_stashdb_name") or "").strip()
        for sid in _dedup_ids(ms, group_ids["stashdb"]):
            for u in _stashdb_performer_all_image_urls(sid):
                push("StashDB", sid, msn if sid == ms else "", u)
        mf = (row.get("match_fansdb_id") or "").strip()
        mfn = (row.get("match_fansdb_name") or "").strip()
        for fid in _dedup_ids(mf, group_ids["fansdb"]):
            d = fetch_performer_detail("FansDB", fid)
            nm = (mfn if fid == mf else "") or (d.get("name") if d else "") or ""
            for u in _favourite_urls_from_poster_like_list((d or {}).get("posters")):
                push("FansDB", fid, nm, u)
    elif kind == "studio":
        mt = (row.get("match_tpdb_id") or "").strip()
        mtn = (row.get("match_tpdb_name") or "").strip()
        for tid in _dedup_ids(mt, group_ids["tpdb"]):
            d = fetch_studio_detail("TPDB", tid)
            nm = (mtn if tid == mt else "") or (d.get("name") or d.get("title") if d else None) or ""
            for u in _tpdb_site_all_media_urls(d):
                push("TPDB", tid, nm, u)
        ms = (row.get("match_stashdb_id") or "").strip()
        msn = (row.get("match_stashdb_name") or "").strip()
        for sid in _dedup_ids(ms, group_ids["stashdb"]):
            for u in _stashdb_studio_all_image_urls(sid):
                push("StashDB", sid, msn if sid == ms else "", u)
        mf = (row.get("match_fansdb_id") or "").strip()
        mfn = (row.get("match_fansdb_name") or "").strip()
        for fid in _dedup_ids(mf, group_ids["fansdb"]):
            for u in _fansdb_studio_all_image_urls(fid):
                push("FansDB", fid, mfn if fid == mf else "", u)
    return items


def _favourite_tpdb_performer_image(mt_id: str | None) -> str | None:
    if not mt_id or not str(mt_id).strip():
        return None
    d = fetch_performer_detail("TPDB", str(mt_id).strip())
    if not d:
        return None
    posters = d.get("posters") or []
    if not posters:
        return None
    p0 = posters[0]
