def favourites_refresh_entity_images(row_id: int) -> dict:
    """Set image_url from local art first, then TPDB → StashDB → FansDB for stored match IDs only."""
    row = db.favourite_get(row_id)
    if not row:
        return {"error": "Not found"}
    if int(row.get("matches_locked") or 0):
        return {"ok": True, "id": row_id, "skipped": True}
    kind = row["kind"]
    path = row.get("path") or ""
    mt = (row.get("match_tpdb_id") or "").strip() or None
    ms = (row.get("match_stashdb_id") or "").strip() or None
    mf = (row.get("match_fansdb_id") or "").strip() or None
    prev = row.get("image_url")
    if kind == "performer":
        if _favourite_find_local_poster_file(path):
            img: str | None = f"/api/favourites/folder-poster?row_id={row_id}"
        else:
            img = (
                _favourite_tpdb_performer_image(mt)
                or _favourite_stashdb_performer_image(ms)
                or _favourite_fansdb_performer_image(mf)
                or prev
            )
    elif kind == "movie":
        if _favourite_find_local_poster_file(path):
            img = f"/api/favourites/folder-poster?row_id={row_id}"
        else:
            img = None
            mdb = (row.get("match_tmdb_id") or "").strip()
            if mdb:
                try:
                    img = get_tmdb_movie(mdb).get("poster_url")
                except Exception:
                    pass
            if not img and mt:
                try:
                    det = _fetch_tpdb_movie_detail(mt)
                    img = _tpdb_detail_as_movie_filing_dict(det or {}).get("poster_url")
                except Exception:
                    pass
            img = img or prev
    elif kind == "studio":
        if _favourite_find_local_studio_art(path):
            img = f"/api/favourites/folder-logo?row_id={row_id}"
        else:
            img = (
                _favourite_tpdb_studio_image(mt)
                or _favourite_stashdb_studio_image(ms)
                or _favourite_fansdb_studio_image(mf)
                or prev
            )
    else:
        return {"error": "unsupported kind"}
    db.favourite_update_matches(row_id, image_url=img)
    return {"ok": True, "id": row_id}


def _performer_aliases_as_strings(raw) -> list[str]:
    out: list[str] = []
    for a in raw or []:
        if isinstance(a, str):
            s = a.strip()
            if s:
                out.append(s)
        elif isinstance(a, dict):
            n = (a.get("name") or a.get("alias") or "").strip()
            if n:
                out.append(n)
    return out


def _performer_flatten_extras_for_tvshow_nfo(data: dict) -> dict[str, str]:
    """Merge TPDB-style `extras` / `extra` / top-level hints into string values for NFO plot."""
    merged: dict[str, object] = {}
    ex = data.get("extras")
    if isinstance(ex, dict):
        for k, v in ex.items():
            if v is None:
                continue
            s = str(v).strip()
            if s:
                merged[str(k)] = v
    one = data.get("extra")
    if isinstance(one, dict):
        for k, v in one.items():
            if v is None or str(k) in merged:
                continue
            s = str(v).strip()
            if s:
                merged[str(k)] = v
    if "birthday" not in merged and data.get("birth_date"):
        merged["birthday"] = data["birth_date"]
    if "gender" not in merged:
        raw_g = _tpdb_raw_gender_from_search_hit(data)
        if raw_g:
            merged["gender"] = str(raw_g).strip()
    return {k: str(v).strip() for k, v in merged.items() if str(v).strip()}


def _performer_cast_role_from_extras(extras_flat: dict[str, str]) -> str:
    g = (extras_flat.get("gender") or "").strip().upper()
    if g in (
        "MALE", "M", "MAN", "CIS_MALE", "BOY", "GUY", "MALE_PERFORMER",
        "TRANSGENDER_MALE",
    ):
        return "Himself"
    if g in (
        "FEMALE", "F", "WOMAN", "CIS_FEMALE",
        "TRANSGENDER_FEMALE",
    ):
        return "Herself"
    return "Performer"


def _performer_external_urls_for_plot(data: dict) -> list[str]:
    lines: list[str] = []
    seen: set[str] = set()
    for link_item in (data.get("urls") or data.get("links") or []):
        if isinstance(link_item, str):
            u = link_item.strip()
            if u and u not in seen:
                seen.add(u)
                lines.append(u)
        elif isinstance(link_item, dict):
            url = (link_item.get("url") or link_item.get("link") or "").strip()
            if not url or url in seen:
                continue
            seen.add(url)
            label = (link_item.get("type") or link_item.get("label") or "").strip()
            lines.append(f"{label}: {url}" if label else url)
    return lines


def _parse_performer_ext_links(data_or_urls) -> dict:
    """Extract TMDB/IAFD/Freeones/Babepedia profile URLs from a TPDB/StashDB/FansDB data dict or URL list.

    Accepts:
      - A data dict (TPDB response) — checks ``urls``, ``links``, ``extras.links``
      - A list of URL strings or ``{url, type}`` dicts (StashDB/FansDB format)

    Returns a dict with keys from {"tmdb", "iafd", "freeones", "babepedia"} for each URL found.
    For "tmdb" the value is the numeric person ID string.
    """
    if isinstance(data_or_urls, dict):
        extras = data_or_urls.get("extras") or {}
        urls_data: list = (
            data_or_urls.get("urls")
            or data_or_urls.get("links")
            or extras.get("links")
            or extras.get("urls")
            or []
        )
    else:
        urls_data = list(data_or_urls or [])

    out: dict[str, str] = {}
    for item in urls_data:
        if isinstance(item, str):
            u = item.strip()
        elif isinstance(item, dict):
            u = (item.get("url") or item.get("link") or "").strip()
        else:
            continue
        if not u:
            continue
        ul = u.lower()
        if "themoviedb.org/person/" in ul and "tmdb" not in out:
            m = re.search(r'/person/(\d+)', u)
            if m:
                out["tmdb"] = m.group(1)
        elif "iafd.com" in ul and "iafd" not in out:
            out["iafd"] = u
        elif "freeones.com" in ul and "freeones" not in out:
            out["freeones"] = u
        elif "babepedia.com" in ul and "babepedia" not in out:
            out["babepedia"] = u
        elif "coomer.st" in ul and "coomer" not in out:
            out["coomer"] = u
        elif "onlyfans.com/" in ul and "coomer" not in out:
            m = re.search(r'onlyfans\.com/([^/?#]+)', u)
            if m:
                out["coomer"] = f"https://coomer.st/onlyfans/user/{m.group(1)}"
        elif "fansly.com/" in ul and "coomer" not in out:
            m = re.search(r'fansly\.com/([^/?#]+)', u)
            if m:
                out["coomer"] = f"https://coomer.st/fansly/user/{m.group(1)}"
    return out


def build_performer_tvshow_nfo(data: dict) -> str:
    perf_name = (data.get("name") or "Unknown").strip() or "Unknown"
    extras_flat = _performer_flatten_extras_for_tvshow_nfo(data)
    plot_parts: list[str] = []

    bio = (data.get("bio") or data.get("description") or "").strip()
    if bio:
        plot_parts.append(bio)

    aliases = _performer_aliases_as_strings(data.get("aliases"))
    if aliases:
        plot_parts.append("AKA: " + ", ".join(aliases))

    info_lines = []
    for key, label in [
        ("gender", "Gender"),
        ("birthday", "Birthday"),
        ("birthplace", "Birthplace"),
        ("career_start_year", "Active since"),
        ("career_end_year", "Active until"),
        ("ethnicity", "Ethnicity"),
        ("nationality", "Country"),
        ("hair_colour", "Hair"),
        ("hair_color", "Hair"),
        ("height", "Height"),
        ("weight", "Weight"),
        ("measurements", "Measurements"),
        ("breast_type", "Breast type"),
        ("cup_size", "Cup"),
        ("eye_color", "Eyes"),
        ("fake_tits", "Enhanced"),
        ("tattoos", "Tattoos"),
        ("piercings", "Piercings"),
    ]:
        raw_v = extras_flat.get(key)
        if not raw_v:
            continue
        if raw_v.lower() in ("true", "false"):
            val = "Yes" if raw_v.lower() == "true" else "No"
        else:
            val = raw_v
        line = f"{label}: {val}"
        if line not in info_lines:
            info_lines.append(line)
    if info_lines:
        plot_parts.append("\n".join(info_lines))

    url_lines = _performer_external_urls_for_plot(data)
    if url_lines:
        plot_parts.append("Links:\n" + "\n".join(url_lines))

    plot_text = "\n\n".join(plot_parts) if plot_parts else ""

    root = ET.Element("tvshow")
    ET.SubElement(root, "title").text = perf_name
    ET.SubElement(root, "plot").text = plot_text
    ET.SubElement(root, "mpaa").text = "Adult"
    ET.SubElement(root, "genre").text = "Adult"
    ET.SubElement(root, "tag").text = "Porn"

    uid_specs: list[tuple[str, str]] = []
    tid = str(data.get("_id") or data.get("id") or "").strip()
    if tid:
        uid_specs.append(("theporndb", tid))
    sid = str(data.get("stash_id") or "").strip()
    if sid:
        uid_specs.append(("stashdb", sid))
    fid = str(data.get("fansdb_id") or "").strip()
    if fid:
        uid_specs.append(("fansdb", fid))
    for i, (typ, val) in enumerate(uid_specs):
        uid_el = ET.SubElement(root, "uniqueid")
        uid_el.set("type", typ)
        uid_el.set("default", "true" if i == 0 else "false")
        uid_el.text = val

    posters = data.get("posters") or []
    poster_url = None
    if posters:
        poster_url = posters[0].get("url") if isinstance(posters[0], dict) else posters[0]
    if isinstance(poster_url, str):
        poster_url = poster_url.strip() or None

    role = _performer_cast_role_from_extras(extras_flat)
    actor = ET.SubElement(root, "actor")
    ET.SubElement(actor, "name").text = perf_name
    role_el = ET.SubElement(actor, "role")
    role_el.text = role
    ET.SubElement(actor, "order").text = "0"
    if poster_url:
        ET.SubElement(actor, "thumb").text = poster_url

    year = (extras_flat.get("career_start_year") or
            (extras_flat.get("birthday") or "")[:4] or "2000")
    ET.SubElement(root, "premiered").text = f"{year}-01-01"
    ET.SubElement(root, "year").text = str(year)

    tree = ET.ElementTree(root)
    ET.indent(tree, space="  ")
    buf = io.BytesIO()
    tree.write(buf, encoding="utf-8", xml_declaration=True)
    return buf.getvalue().decode("utf-8")


def build_studio_tvshow_nfo(data: dict) -> str:
    root = ET.Element("tvshow")
    ET.SubElement(root, "title").text  = data.get("name") or data.get("title", "Unknown")
    ET.SubElement(root, "plot").text   = data.get("description") or data.get("bio") or ""
    ET.SubElement(root, "mpaa").text   = "Adult"
    ET.SubElement(root, "genre").text  = "Adult"
    ET.SubElement(root, "tag").text    = "Porn"
    ET.SubElement(root, "studio").text = data.get("name") or data.get("title", "")

    year = (data.get("year") or
            (data.get("founded") or "")[:4] or "2000")
    ET.SubElement(root, "premiered").text = f"{year}-01-01"
    ET.SubElement(root, "year").text      = str(year)

    tree = ET.ElementTree(root)
    ET.indent(tree, space="  ")
    buf = io.BytesIO()
    tree.write(buf, encoding="utf-8", xml_declaration=True)
    return buf.getvalue().decode("utf-8")


def create_tvshow_folder(
    name: str,
    dest_dir: Path,
    nfo_content: str,
    poster_url: str | None = None,
    *,
    logo_url: str | None = None,
) -> Path:
    folder = dest_dir / name
    folder.mkdir(parents=True, exist_ok=True)
    nfo_path = folder / "tvshow.nfo"
    nfo_path.write_text(nfo_content, encoding="utf-8")
    if logo_url:
        download_image(
            logo_url, folder / "logo.png", max_edge=IMAGE_CACHE_LOGO_MAX
        )
    if poster_url:
        download_image(
            poster_url, folder / "poster.jpg", max_edge=IMAGE_CACHE_POSTER_MAX
        )
    return folder


# ---------------------------------------------------------------------------
# Prowlarr integration
# ---------------------------------------------------------------------------

def _prowlarr_headers() -> dict:
    s = db.get_settings()
    return {"X-Api-Key": s.get("prowlarr_api_key", ""), "Content-Type": "application/json"}


def _prowlarr_url() -> str:
    s = db.get_settings()
    return s.get("prowlarr_url", "").rstrip("/")


def _fetch_and_cache_indexers() -> list[dict]:
    """Fetch indexers from Prowlarr API and cache in DB."""
    base = _prowlarr_url()
    if not base:
        return []
    try:
        resp = requests.get(f"{base}/api/v1/indexer",
                            headers=_prowlarr_headers(), timeout=10)
        resp.raise_for_status()
        indexers = [{"id": i["id"], "name": i["name"],
                     "protocol": i.get("protocol", "torrent")}
                    for i in resp.json()]
        db.cache_indexers(indexers)
        return indexers
    except Exception:
        return []


def _get_indexers() -> list[dict]:
    """Get indexers from cache, fetching from Prowlarr if empty."""
    cached = db.get_cached_indexers()
    if cached:
        return cached
    return _fetch_and_cache_indexers()


def _parse_newznab_xml(xml_text: str, indexer_name: str, protocol: str) -> list[dict]:
    """Parse Newznab RSS XML into result dicts."""
    import xml.etree.ElementTree as ET
    out = []
    try:
        root = ET.fromstring(xml_text)
        ns = {"newznab": "http://www.newznab.com/DTD/2010/feeds/attributes/",
              "torznab":  "http://torznab.com/schemas/2015/feed"}
        for item in root.findall(".//item"):
            title     = (item.findtext("title") or "").strip()
            guid      = item.findtext("guid") or ""
            size      = 0
            link      = item.findtext("link") or ""
            seeders   = None
            pub_date  = item.findtext("pubDate") or ""

            enc = item.find("enclosure")
            if enc is not None:
                size = int(enc.get("length") or 0)
                if not link:
                    link = enc.get("url") or ""

            # Get indexer ID from prowlarrindexer element
            indexer_elem = item.find("prowlarrindexer")
            parsed_indexer_id = None
            if indexer_elem is not None:
                try:
                    parsed_indexer_id = int(indexer_elem.get("id", 0))
                except Exception:
                    pass

            magnet_url = ""
            for attr in item.findall("newznab:attr", ns) + item.findall("torznab:attr", ns):
                name = attr.get("name", "")
                val  = attr.get("value", "")
                if name == "size" and not size:
                    size = int(val or 0)
                elif name == "seeders":
                    try: seeders = int(val)
                    except: pass
                elif name == "magneturl" and val:
                    magnet_url = val

            if not title:
                continue

            # Calculate age in hours from pubDate
            age_hours = None
            published_ts = None
            if pub_date:
                try:
                    from email.utils import parsedate_to_datetime
                    dt = parsedate_to_datetime(pub_date)
                    age_hours = (datetime.now(dt.tzinfo) - dt).total_seconds() / 3600
                    published_ts = dt.timestamp()
                except Exception:
                    pass
            if published_ts is None and age_hours is not None:
                published_ts = time.time() - age_hours * 3600

            # Prefer explicit magneturl attr, fall back to link if it's a magnet
            if not magnet_url and link.startswith("magnet:"):
                magnet_url = link

            out.append({
                "guid":         guid,
                "title":        title,
                "indexer":      indexer_name,
                "size_mb":      round(size / 1024 / 1024, 0),
                "seeders":      seeders,
                "age":          age_hours,
                "download_url": link if not link.startswith("magnet:") else "",
                "magnet":       magnet_url,
                "protocol":     protocol,
                "type":         "torrent" if protocol == "torrent" else "nzb",
                "indexer_id":   parsed_indexer_id,
                "published_ts": published_ts or 0.0,
            })
    except Exception:
        pass
    return out


def _local_xml_tag(tag: str) -> str:
    if not tag:
        return ""
    return tag.split("}")[-1]


def _xml_text(el: ET.Element | None, child_local: str) -> str:
    if el is None:
        return ""
    for c in el:
        if _local_xml_tag(c.tag) == child_local:
            t = (c.text or "").strip()
            if t:
                return t
    return ""


def _xml_find_first_text(el: ET.Element, *local_names: str) -> str:
    for name in local_names:
        t = _xml_text(el, name)
        if t:
            return t
    return ""


def _pubdate_str_to_ts(pub: str) -> float | None:
    pub = (pub or "").strip()
    if not pub:
        return None
    try:
        from email.utils import parsedate_to_datetime

        dt = parsedate_to_datetime(pub)
        return dt.timestamp()
    except Exception:
        pass
    try:
        iso = pub
        if iso.endswith("Z"):
            iso = iso[:-1] + "+00:00"
        dt = datetime.fromisoformat(iso)
        if dt.tzinfo is None:
            return dt.replace(tzinfo=timezone.utc).timestamp()
        return dt.timestamp()
    except Exception:
        return None


def _atom_link_href(entry: ET.Element) -> str:
    first_any = ""
    for link in entry:
        if _local_xml_tag(link.tag) != "link":
            continue
        href = link.get("href") or ""
        if not href:
            continue
        if not first_any:
            first_any = href
        rel = (link.get("rel") or "alternate").lower()
        if rel in ("alternate", "enclosure") or "enclosure" in rel:
            return href
    return first_any


def _infer_release_urls(
    link: str, enc_url: str, enc_type: str
) -> tuple[str, str, str]:
    """Return (type, download_url, magnet) with type ``torrent`` or ``nzb``."""
    link = link or ""
    enc_url = enc_url or ""
    enc_type_l = (enc_type or "").lower()
    if link.startswith("magnet:"):
        return "torrent", "", link
    if enc_url.startswith("magnet:"):
        return "torrent", "", enc_url
    for u in (enc_url, link):
        ul = u.lower()
        if ul.endswith(".nzb") or "nzb" in enc_type_l:
            return "nzb", u, ""
    for u in (enc_url, link):
        ul = u.lower()
        if (
            ul.endswith(".torrent")
            or "bittorrent" in enc_type_l
            or "torrent" in enc_type_l
        ):
            return "torrent", u, ""
    u = enc_url or link
    if u.startswith("http"):
        return "torrent", u, ""
    return "torrent", "", ""


def _parse_generic_rss_channel(parent: ET.Element, source_label: str) -> list[dict]:
    """RSS 2.0 ``item`` elements (and similar) not handled by Newznab parser."""
    out: list[dict] = []
    for item in parent.findall(".//{*}item"):
        title = _xml_find_first_text(item, "title")
        if not title:
            continue
        link = _xml_find_first_text(item, "link")
        guid = _xml_find_first_text(item, "guid")
        pub_raw = _xml_find_first_text(item, "pubDate", "date")
        published_ts = _pubdate_str_to_ts(pub_raw) or 0.0

        enc_el = None
        for c in item:
            if _local_xml_tag(c.tag) == "enclosure":
                enc_el = c
                break
        enc_url = (enc_el.get("url") or "") if enc_el is not None else ""
        enc_type = (enc_el.get("type") or "") if enc_el is not None else ""

        desc = _xml_find_first_text(item, "description", "content", "encoded")
        magnet = ""
        if desc:
            m = re.search(r"magnet:\?[^\s<>&\"']+", desc)
            if m:
                magnet = m.group(0)

        typ, dl_url, mag = _infer_release_urls(link, enc_url, enc_type)
        if magnet:
            typ, dl_url, mag = "torrent", "", magnet
        if not dl_url and not mag and link.startswith("http"):
            typ, dl_url, mag = _infer_release_urls(link, "", "")

        if not dl_url and not mag:
            continue

        size = 0
        if enc_el is not None:
            try:
                size = int(enc_el.get("length") or 0)
            except Exception:
                pass

        age_hours = None
        if published_ts:
            age_hours = (time.time() - published_ts) / 3600

        out.append(
            {
                "guid": guid or link or title,
                "title": title,
                "indexer": source_label,
                "size_mb": round(size / 1024 / 1024, 0) if size else 0,
                "seeders": None,
                "age": age_hours,
                "download_url": dl_url if typ == "nzb" else (dl_url if not mag else ""),
                "magnet": mag if typ == "torrent" else "",
                "protocol": "torrent" if typ == "torrent" else "nzb",
                "type": typ,
                "indexer_id": None,
                "published_ts": published_ts,
            }
        )
    return out


def _parse_atom_feed(root: ET.Element, source_label: str) -> list[dict]:
    out: list[dict] = []
    for entry in root.findall("{*}entry"):
        title = _xml_find_first_text(entry, "title")
        if not title:
            continue
        link_href = _atom_link_href(entry)
        pub_raw = _xml_find_first_text(entry, "published", "updated")
        published_ts = _pubdate_str_to_ts(pub_raw) or 0.0

        enc_url = ""
        enc_type = ""
        for child in entry:
            if _local_xml_tag(child.tag) != "link":
                continue
            rel = (child.get("rel") or "").lower()
            if rel == "enclosure":
                enc_url = child.get("href") or ""
                enc_type = child.get("type") or ""
                break
        if not enc_url:
            enc_url = link_href

        summary = _xml_find_first_text(entry, "summary", "content")
        magnet = ""
        if summary:
            m = re.search(r"magnet:\?[^\s<>&\"']+", summary)
            if m:
                magnet = m.group(0)

        if link_href.startswith("magnet:"):
            typ, dl_url, mag = "torrent", "", link_href
        elif magnet:
            typ, dl_url, mag = "torrent", "", magnet
        else:
            typ, dl_url, mag = _infer_release_urls(link_href, enc_url, enc_type)

        if not dl_url and not mag:
            continue

        age_hours = None
        if published_ts:
            age_hours = (time.time() - published_ts) / 3600

        out.append(
            {
                "guid": _xml_find_first_text(entry, "id") or link_href or title,
                "title": title,
                "indexer": source_label,
                "size_mb": 0,
                "seeders": None,
                "age": age_hours,
                "download_url": dl_url if typ == "nzb" else (dl_url if not mag else ""),
                "magnet": mag if typ == "torrent" else "",
                "protocol": "torrent" if typ == "torrent" else "nzb",
                "type": typ,
                "indexer_id": None,
                "published_ts": published_ts,
            }
        )
    return out


def _parse_any_feed_xml(xml_text: str, source_label: str) -> list[dict]:
    """Torznab/Newznab first, then RSS 2.0 or Atom.

    Detect NZB vs torrent from enclosure MIME type before parsing so items
    are tagged correctly. Newznab feeds (e.g. NZBGeek, NinjaCentral) use
    type="application/x-nzb" on the enclosure element.
    """
    # Sniff the enclosure type from the raw XML to choose the right protocol
    _proto = "torrent"
    try:
        _root_sniff = ET.fromstring(xml_text)
        for _enc in _root_sniff.iter():
            if _local_xml_tag(_enc.tag).lower() == "enclosure":
                _et = (_enc.get("type") or "").lower()
                if "nzb" in _et or _et == "application/x-nzb":
                    _proto = "usenet"
                    break
                if _enc.get("url", "").lower().endswith(".nzb"):
                    _proto = "usenet"
                    break
    except Exception:
        pass

    nz = _parse_newznab_xml(xml_text, source_label, _proto)
    if not nz:
        nz = _parse_newznab_xml(xml_text, source_label, "torrent" if _proto == "usenet" else "usenet")
    if nz:
        return nz
    try:
        root = ET.fromstring(xml_text)
    except Exception:
        return []
    tag = _local_xml_tag(root.tag).lower()
    if tag == "feed":
        return _parse_atom_feed(root, source_label)
    if tag == "rss":
        channel = root.find("{*}channel")
        parent = channel if channel is not None else root
        return _parse_generic_rss_channel(parent, source_label)
    return _parse_generic_rss_channel(root, source_label)


def _fetch_one_rss_feed(url: str) -> list[dict]:
    url = (url or "").strip()
    if not url:
        return []
    label = urlparse(url).netloc or url
    try:
        r = requests.get(
            url,
            timeout=25,
            headers={"User-Agent": "Top-Shelf/1.0 (+https://github.com)"},
        )
        if r.status_code != 200:
            return []
        items = _parse_any_feed_xml(r.text, label)
        for it in items:
            it["source_feed"] = label
        return items
    except Exception:
        return []


def _rss_library_match_names() -> frozenset[str]:
    """Normalised name surfaces for every favourite performer + studio.

    Includes ``folder_name`` and the canonical primary-name fields
    (``match_tpdb_name`` / ``match_stashdb_name`` / ``match_fansdb_name``).
    ``aliases_json`` is intentionally excluded — those entries are
    scraped off each DB's alias section and routinely include
    first-name-only stage names / shared nicknames that fire for every
    performer carrying them. Only names the external DBs return as a
    performer's *primary* name are trusted.

    Names under 3 chars are dropped (noise). Empty set = no library
    yet; callers skip the filter entirely in that case.
    """
    out: set[str] = set()

    def _add(name: str) -> None:
        if not name:
            return
        n = normalise(name)
        if len(n) < 3:
            return
        out.add(n)

    try:
        for row in db.favourite_list():
            k = (row.get("kind") or "").strip().lower()
            if k not in ("performer", "studio"):
                continue
            _add(row.get("folder_name") or "")
            for canon_field in ("match_tpdb_name", "match_stashdb_name", "match_fansdb_name"):
                _add(row.get(canon_field) or "")
    except Exception:
        pass
    return frozenset(out)


def _rss_title_matches_library(title: str, library_names: frozenset[str]) -> bool:
    if not library_names:
        return True
    nt = normalise(title or "")
    if not nt:
        return False
    nt_nospace = nt.replace(" ", "")
    for name in library_names:
        if name in nt:
            return True
        # Also match CamelCase / run-together titles e.g. ExploitedCollegeGirls vs "exploited college girls"
        if name.replace(" ", "") in nt_nospace:
            return True
    return False


# ---------------------------------------------------------------------------
# RSS feed cache (populated by hourly background job)
# ---------------------------------------------------------------------------
_rss_cache: dict = {"items": [], "errors": [], "fetched_at": 0.0}
_rss_cache_lock = threading.Lock()

def _clean_rss_title(raw: str) -> str:
    """Strip release-group noise from a title for display and grouping.

    Order matters: dots→spaces first, then token removal.
    """
    t = raw or ""
    # Dots that are word separators (not decimal points)
    t = re.sub(r"\.(?=[^\d])|(?<=[^\d])\.", " ", t)
    # Bracketed/parenthesised dates and tags  e.g. [24.07.2025] (26.03.20)
    t = re.sub(r"[\[\(]\d{2}[.\-]\d{2}[.\-]\d{2,4}[\]\)]", " ", t)
    # Bare dates e.g. 25.07.24 26.04.05 at word boundary
    t = re.sub(r"\b\d{2}[.\-]\d{2}[.\-]\d{2,4}\b", " ", t)
    # Resolution tokens
    t = re.sub(r"\b\d{3,4}[piP]\b", " ", t)
    # Codec / container / release-group tokens. Keep this in sync with the
    # JS regex in static/downloads.html cleanRssTitle().
    t = re.sub(
        r"\b(x264|x265|h264|h265|hevc|avc|av1|xvid|divx|ipt.?team|ktr|p0rnfuscated|pornfuscated|lulustream|fuckingsession"
        r"|mp4|mkv|avi|wmv|mov"
        r"|web|webrip|web-?dl|bluray|blu-?ray|bdrip|dvdrip|hdtv|hdrip"
        r"|p2p|wrb|nbq|ntr|cpg|rarbg|yify|fgt|ntb|playxd|eztv"
        r"|prt|hq|nogroup|fetish|xleech|gapfill)\b",
        " ", t, flags=re.IGNORECASE,
    )
    # Standalone XXX (case-insensitive, not part of a longer word like "XXXL")
    t = re.sub(r"(?<![A-Za-z])XXX(?![A-Za-z])", " ", t)
    # Trailing/leading punctuation cruft e.g. "-No Tapping" after studio prefix
    t = re.sub(r"\s[-–]+\s", " ", t)
    # Strip trailing/leading punctuation left by token removal
    # Remove isolated dots left by date stripping (e.g. "BangBros18.")
    t = re.sub(r"(?<=\w)\.(?=\s|$)", " ", t)
    t = re.sub(r"^[\s\-\[\]\(\).]+|[\s\-\[\]\(\).]+$", "", t)
    # Collapse whitespace
    return re.sub(r"\s{2,}", " ", t).strip()


def _rss_group_items(items: list[dict]) -> list[dict]:
    """Group RSS items by scene -- same performers + similar title = one entry.

    Each group has a ``releases`` list of the individual items (sorted by
    size descending) and the largest release's fields promoted to top level.
    """
    import difflib

    def _scene_key(it: dict) -> str:
        """Stable key: sorted performer names + cleaned normalised title."""
        matched = it.get("matched_rows") or []
        perf_names = sorted(
            {r["folder_name"].lower() for r in matched if r.get("kind") == "performer"}
        )
        title_clean = normalise(_clean_rss_title(it.get("title") or ""))
        return "||".join(perf_names) + "||" + title_clean[:60]

    # First pass: exact-key grouping
    groups: dict[str, list[dict]] = {}
    for it in items:
        k = _scene_key(it)
        groups.setdefault(k, []).append(it)

    # Second pass: merge groups whose titles are very similar (>= 0.82 ratio)
    keys = list(groups.keys())
    merged: list[set] = []
    used = set()
    for i, k in enumerate(keys):
        if k in used:
            continue
        grp = {k}
        for j in range(i + 1, len(keys)):
            k2 = keys[j]
            if k2 in used:
                continue
            # Only merge if performer sets are identical
            perf1 = k.split("||")[:-1]
            perf2 = k2.split("||")[:-1]
            if perf1 != perf2:
                continue
            t1 = k.split("||")[-1]
            t2 = k2.split("||")[-1]
            if difflib.SequenceMatcher(None, t1, t2).ratio() >= 0.82:
                grp.add(k2)
                used.add(k2)
        merged.append(grp)
        used.add(k)

    result: list[dict] = []
    for grp_keys in merged:
        releases = []
        for k in grp_keys:
            releases.extend(groups[k])
        # Sort releases by size descending
        releases.sort(key=lambda x: x.get("size_mb") or 0, reverse=True)
        # Promote largest release fields, attach full releases list
        primary = dict(releases[0])
        primary["releases"] = releases
        primary["clean_title"] = _clean_rss_title(primary.get("title") or "")
        result.append(primary)

    # Sort groups by publication time of newest release
    result.sort(key=lambda x: max(r.get("published_ts") or 0 for r in x["releases"]), reverse=True)
    return result


def _refresh_rss_cache() -> None:
    """Fetch all RSS feeds, group results, and store in cache. Called by scheduler."""
    try:
        items, errors = download_rss_feeds_merged()
        grouped = _rss_group_items(items)
        with _rss_cache_lock:
            _rss_cache["items"] = grouped
            _rss_cache["errors"] = errors
            _rss_cache["fetched_at"] = time.time()
    except Exception as e:
        logger.warning(f"RSS cache refresh failed: {e}")


def download_rss_feeds_merged() -> tuple[list[dict], list[str]]:
    """Fetch all configured RSS feeds, merge and sort by ``published_ts`` (newest first).

    Items are kept only when the release title contains a normalised performer or
    studio folder name from the library (favourites index). If no such names exist
    yet, nothing is filtered.
    """
    s = db.get_settings()
    raw = s.get("download_rss_feeds") or "[]"
    try:
        urls = json.loads(raw)
    except Exception:
        urls = []
    if not isinstance(urls, list):
        urls = []
    urls = [u.strip() for u in urls if isinstance(u, str) and u.strip()]
    errors: list[str] = []
    if not urls:
        return [], errors

    lib_names = _rss_library_match_names()

    all_items: list[dict] = []
    with ThreadPoolExecutor(max_workers=min(len(urls), 6)) as pool:
        futs = {pool.submit(_fetch_one_rss_feed, u): u for u in urls}
        for fut, u in futs.items():
            try:
                all_items.extend(fut.result())
            except Exception as e:
                errors.append(f"{u}: {e}")

    # Two indexes keyed by library row:
    #   - studio_rows  → lenient substring / spaceless match (studios are
    #     often glued camelCase in release titles, so we can't require
    #     token-level precision there)
    #   - perf_surfaces → token-subsequence match with tier + overlap
    #     tracking, so two rows with identical alias tokens (e.g. a
    #     "Livi Blossom" folder AND a "Lily Blossom" folder with
    #     "Livi Blossom" as a scraped alias) can't both surface for
    #     the same release — the folder-tier match wins the token
    #     range and the alias-tier match on a different row is blocked
    #     by overlap. Same algorithm `_library_guess_from_release_name`
    #     uses for /downloads filing, kept in sync by design.
    studio_rows: list[dict] = []
    perf_surfaces: list[tuple[tuple[str, ...], int, int, int, str, int]] = []
    # Each perf_surfaces entry: (tokens, token_count_neg, tier, total_chars_neg, folder_name, row_id)
    # sorted ascending so longest names try first, and within same
    # length, folder beats canonical. Aliases from aliases_json are
    # deliberately NOT indexed — too noisy for title matching; only
    # each DB's primary name (match_*_name) feeds the matcher.
    perf_fav_by_id: dict[int, int] = {}
    try:
        for row in db.favourite_list():
            k = (row.get("kind") or "").strip().lower()
            if k not in ("performer", "studio"):
                continue
            rid = row.get("id")
            fn = (row.get("folder_name") or "").strip()
            is_fav = 1 if row.get("is_favourite") else 0
            if k == "studio":
                n = normalise(fn)
                if len(n) >= 3:
                    studio_rows.append({
                        "id": rid, "kind": k, "folder_name": fn,
                        "_norm": n, "is_favourite": is_fav,
                    })
                continue
            # Performer — collect token surfaces at each tier.
            perf_fav_by_id[rid] = is_fav
            seen_token_tuples: set[tuple[str, ...]] = set()

            def _push(name_str: str, *, tier: int) -> None:
                s = (name_str or "").strip()
                if not s:
                    return
                tokens = tuple(db._tokenize_for_match(s))
                if not tokens:
                    return
                total_chars = sum(len(t) for t in tokens)
                if total_chars < 5:
                    return
                if tokens in seen_token_tuples:
                    return
                seen_token_tuples.add(tokens)
                perf_surfaces.append((
                    tokens, -len(tokens), tier, -total_chars, fn, rid,
                ))

            # Folder name (tier 0) + each DB's primary name (tier 1).
            # Aliases intentionally skipped — see docstring above.
            _push(fn, tier=0)
            for canon_field in ("match_tpdb_name", "match_stashdb_name", "match_fansdb_name"):
                _push((row.get(canon_field) or "").strip(), tier=1)
    except Exception:
        pass
    # Sort: longest-token-count first, then tier asc (folder wins),
    # then longest-char-count first.
    perf_surfaces.sort(key=lambda x: (x[1], x[2], x[3]))

    if lib_names:
        filtered: list[dict] = []
        for it in all_items:
            title_raw = it.get("title") or ""
            nt = normalise(title_raw)
            nt_nospace = nt.replace(" ", "")
            title_tokens = db._tokenize_for_match(title_raw)

            matches: list[dict] = []
            seen_ids: set = set()

            # Studios — lenient substring + spaceless fallback, unchanged.
            for r in studio_rows:
                n = r["_norm"]
                if n in nt or n.replace(" ", "") in nt_nospace:
                    if r["id"] not in seen_ids:
                        seen_ids.add(r["id"])
                        matches.append(r)

            # Performers — token-subsequence with overlap + row dedup.
            if title_tokens and perf_surfaces:
                used_ranges: list[tuple[int, int]] = []
                matched_perf_rids: set = set()

                def _overlaps(a: int, b: int) -> bool:
                    return any(not (b < s or a > e) for s, e in used_ranges)

                for ptokens, _nlen, _tier, _nchars, folder_name, rid in perf_surfaces:
                    if rid in matched_perf_rids:
                        continue
                    n = len(ptokens)
                    if n == 0 or n > len(title_tokens):
                        continue
                    for i in range(len(title_tokens) - n + 1):
                        if title_tokens[i:i + n] == list(ptokens):
                            if not _overlaps(i, i + n - 1):
                                used_ranges.append((i, i + n - 1))
                                matched_perf_rids.add(rid)
                                if rid not in seen_ids:
                                    seen_ids.add(rid)
                                    matches.append({
                                        "id": rid,
                                        "kind": "performer",
                                        "folder_name": folder_name,
                                        "is_favourite": perf_fav_by_id.get(rid, 0),
                                    })
                            break

            if matches:
                it["matched_rows"] = [
                    {"id": r["id"], "kind": r["kind"], "folder_name": r["folder_name"],
                     "is_favourite": r.get("is_favourite", 0)}
                    for r in matches
                ]
                filtered.append(it)
        all_items = filtered
    else:
        for it in all_items:
            it["matched_rows"] = []

    # RSS keyword blacklist — case-insensitive substring filter
    raw_blacklist = s.get("rss_keyword_blacklist") or ""
    blacklist_terms = [t.strip().lower() for t in raw_blacklist.split(",") if t.strip()]
    if blacklist_terms:
        def _not_blacklisted(item: dict) -> bool:
            tl = (item.get("title") or "").lower()
            return not any(term in tl for term in blacklist_terms)
        all_items = [it for it in all_items if _not_blacklisted(it)]

    all_items.sort(
        key=lambda x: (
            float(x.get("published_ts") or 0),
            x.get("title") or "",
        ),
        reverse=True,
    )
    return all_items, errors


def _search_indexer(base: str, api_key: str, indexer: dict, query: str) -> list[dict]:
    """Search a single indexer via Prowlarr's Newznab proxy."""
    iid      = indexer["id"]
    name     = indexer["name"]
    protocol = indexer.get("protocol", "torrent")
    try:
        resp = requests.get(
            f"{base}/{iid}/api",
            params={"t": "search", "q": query, "apikey": api_key,
                    "cat": "6000,6010,6020,6030,6040,6050,6060,6070,6080,6090"},
            timeout=20,
        )
        if resp.status_code == 200:
            return _parse_newznab_xml(resp.text, name, protocol)
        elif resp.status_code in (400, 404, 500):
            # Indexer may be broken - clear cache so it gets re-fetched next time
            db.clear_indexer_cache()
    except Exception:
        pass
    return []


def prowlarr_search(query: str) -> list[dict]:
    """Search all Prowlarr indexers via their Newznab proxy endpoints (parallel)."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    base    = _prowlarr_url()
    api_key = db.get_settings().get("prowlarr_api_key", "")
    if not base or not api_key:
        return []

    indexers = _get_indexers()
    if not indexers:
        return []

    all_results = []
    with ThreadPoolExecutor(max_workers=min(len(indexers), 8)) as pool:
        futures = {pool.submit(_search_indexer, base, api_key, idx, query): idx for idx in indexers}
        for future in as_completed(futures):
            try:
                all_results.extend(future.result())
            except Exception:
                pass

    nzbs     = sorted([r for r in all_results if r["type"] == "nzb"],
                      key=lambda x: x.get("age") or 0)
    torrents = sorted([r for r in all_results if r["type"] == "torrent"],
                      key=lambda x: x.get("seeders") or 0, reverse=True)
    return nzbs[:25] + torrents[:25]


def prowlarr_grab(guid: str, indexer_id: int, is_torrent: bool) -> dict:
    """Send a result to the configured download client via Prowlarr."""
    s    = db.get_settings()
    base = _prowlarr_url()
    if not base:
        return {"error": "Prowlarr URL not configured"}
    client_name = s.get("prowlarr_torrent_client" if is_torrent else "prowlarr_nzb_client", "")
    try:
        # Resolve download client ID from name if configured
        download_client_id = None
        if client_name:
            try:
                cr = requests.get(f"{base}/api/v1/downloadclient",
                                   headers=_prowlarr_headers(), timeout=10)
                cr.raise_for_status()
                for c in cr.json():
                    if c.get("name") == client_name:
                        download_client_id = c["id"]
                        break
            except Exception:
                pass

        # Prowlarr grab endpoint
        payload = {"guid": guid, "indexerId": indexer_id}
        if download_client_id:
            payload["downloadClientId"] = download_client_id

        resp = requests.post(
            f"{base}/api/v1/search",
            json=payload,
            headers=_prowlarr_headers(),
            timeout=15,
        )
        if resp.status_code in (200, 201, 202, 204):
            return {"ok": True}
        # Return Prowlarr's error message for debugging
        try:
            err_detail = resp.json()
        except Exception:
            err_detail = resp.text[:200]
        return {"error": f"Prowlarr returned {resp.status_code}: {err_detail}"}
    except Exception as e:
        return {"error": str(e)}


def prowlarr_get_clients() -> list[dict]:
    """Get configured download clients from Prowlarr."""
    base = _prowlarr_url()
    if not base:
        return []
    try:
        resp = requests.get(f"{base}/api/v1/downloadclient",
                            headers=_prowlarr_headers(), timeout=10)
        resp.raise_for_status()
        return [{"id": c["id"], "name": c["name"],
                 "type": "torrent" if "torrent" in c.get("implementation", "").lower() else "nzb"}
                for c in resp.json()]
    except Exception:
        return []


# ---------------------------------------------------------------------------
# Download clients — combined queue/history for UI (matches Settings clients)
# ---------------------------------------------------------------------------


def _dl_resolve_nzb_settings(s: dict) -> dict | None:
    nzb_client = s.get("dl_nzb_client", "").lower().strip()
    nzb_host = s.get("dl_nzb_host", "").strip()
    nzb_port = s.get("dl_nzb_port", "").strip()
    nzb_user = s.get("dl_nzb_user", "").strip()
    nzb_pass = s.get("dl_nzb_pass", "")
    nzb_apikey = s.get("dl_nzb_api_key", "").strip()
    if not nzb_client and s.get("nzbget_url", "").strip():
        nzb_client = "nzbget"
        legacy_url = s.get("nzbget_url", "").strip().rstrip("/")
        m = re.match(r"https?://([^:/]+)(?::(\d+))?", legacy_url)
        if m:
            nzb_host = m.group(1)
            nzb_port = m.group(2) or "6789"
        nzb_user = s.get("nzbget_user", "").strip()
        nzb_pass = s.get("nzbget_pass", "")
    if not nzb_client or not nzb_host:
        return None
    if nzb_client not in ("nzbget", "sabnzbd"):
        return None
    return {
        "client": nzb_client,
        "host": nzb_host,
        "port": nzb_port,
        "user": nzb_user,
        "pass": nzb_pass,
        "apikey": nzb_apikey,
    }


def _dl_resolve_torrent_settings(s: dict) -> dict | None:
    torrent_client = s.get("dl_torrent_client", "").lower().strip()
    torrent_host = s.get("dl_torrent_host", "").strip()
    if not torrent_client or not torrent_host:
        return None
    if torrent_client not in ("qbittorrent", "transmission", "deluge"):
        return None
    return {
        "client": torrent_client,
        "host": torrent_host,
        "port": s.get("dl_torrent_port", "").strip(),
        "user": s.get("dl_torrent_user", "").strip(),
        "pass": s.get("dl_torrent_pass", ""),
    }


def _dl_parse_category_param(category: str | None, s: dict) -> str | None:
    """None = all categories (* or empty query). Otherwise exact match on client category/label.

    When the request omits ``category``, use Prowlarr scene tag, then movie tag, so we only
    list jobs that match Settings (not every torrent/NZB in the client).
    """
    if category is not None:
        t = category.strip()
        if t in ("*", ""):
            return None
        return t
    scene = (s.get("prowlarr_category") or "").strip()
    if scene:
        return scene
    movie = (s.get("prowlarr_category_movies") or "").strip()
    if movie:
        return movie
    return None


def _dl_cat_match(item_cat: str | None, filt: str | None, s: dict | None = None) -> bool:
    """Match client category to filter. When filter is the scene Prowlarr category, also allow movie category."""
    if filt is None:
        return True
    ic = (item_cat or "").strip().lower()
    f = filt.strip().lower()
    if ic == f:
        return True
    if s:
        movie_cat = (s.get("prowlarr_category_movies") or "").strip().lower()
        scene_cat = (s.get("prowlarr_category") or "").strip().lower()
        if movie_cat and f == scene_cat and ic == movie_cat:
            return True
    return False


def _dl_resolve_import_dest_dir(
    s: dict,
    category: str | None,
    save_path: str,
    content_path: str,
) -> tuple[Path | None, str | None]:
    """
    Where to move videos after download-folder-style processing: scene queue (source_dir)
    or movie queue (movies_source_dir). Uses movie Prowlarr category and/or paths under
    movies_source_dir — same signals as the Downloads list filter.
    """
    movie_cat = (s.get("prowlarr_category_movies") or "").strip().lower()
    cat = (category or "").strip().lower()
    is_movie = bool(movie_cat and cat == movie_cat)
    if not is_movie:
        is_movie = _dl_path_under_movies_source(save_path, content_path, s)

    if is_movie:
        md = (s.get("movies_source_dir") or "").strip()
        if not md:
            return None, (
                "This job is treated as a movie (category or path under your Movies download folder), "
                "but Movies input folder is not set in Settings (Movies page)."
            )
        p = Path(md).expanduser()
        if not p.is_dir():
            return None, f"Movies input folder not found: {md}"
        return p, None

    sd = (s.get("source_dir") or "").strip()
    if not sd:
        return None, (
            "Scenes input folder is missing — set Input folder (files to process) "
            "(queue folder) under Scene Source Directory in Settings"
        )
    p = Path(sd).expanduser()
    if not p.is_dir():
        return None, f"Scenes input folder not found: {sd}"
    return p, None


def _dl_path_under_movies_source(save_path: str, content_path: str, s: dict) -> bool:
    """True if save/content path lies under the movie download watch dir or movies_source_dir."""
    roots: list[str] = []
    for key in ("movie_download_watch_dir", "movies_source_dir"):
        v = (s.get(key) or "").strip()
        if v:
            roots.append(v)
    if not roots:
        return False
    root_paths: list[Path] = []
    for r in roots:
        try:
            root_paths.append(Path(r).expanduser().resolve())
        except Exception:
            continue
    if not root_paths:
        return False
    for p in (save_path, content_path):
        if not (p or "").strip():
            continue
        try:
            pp = Path(p).expanduser().resolve()
            if any(pp == rp or rp in pp.parents for rp in root_paths):
                return True
        except Exception:
            continue
    return False


def _dl_torrent_matches_filter(
    cat: str | None,
    filt: str | None,
    save_path: str,
    content_path: str,
    s: dict,
) -> bool:
    """Category filter plus movie-category pairing; include torrents under movies_source_dir when filter is scene default."""
    if filt is None:
        return True
    if _dl_cat_match(cat, filt, s):
        return True
    scene_cat = (s.get("prowlarr_category") or "").strip().lower()
    if scene_cat and filt.strip().lower() == scene_cat:
        return _dl_path_under_movies_source(save_path, content_path, s)
    return False


def _qbittorrent_torrents_for_filter(sess, qb_base: str, filt: str | None, s: dict) -> list:
    """Fetch torrent list; when filter is scene default, also fetch movie Prowlarr category."""
    if filt is None:
        r = sess.get(f"{qb_base}/api/v2/torrents/info", timeout=25)
        r.raise_for_status()
        return r.json() if isinstance(r.json(), list) else []

    scene_cat = (s.get("prowlarr_category") or "").strip()
    movie_cat = (s.get("prowlarr_category_movies") or "").strip()
    fl = filt.strip().lower()
    if (
        movie_cat
        and scene_cat
        and fl == scene_cat.lower()
        and movie_cat.strip().lower() != fl
    ):
        r1 = sess.get(
            f"{qb_base}/api/v2/torrents/info",
            params={"category": filt},
            timeout=25,
        )
        r1.raise_for_status()
        merged = list(r1.json() if isinstance(r1.json(), list) else [])
        by_hash = {(t.get("hash") or "").lower(): t for t in merged if t.get("hash")}
        r2 = sess.get(
            f"{qb_base}/api/v2/torrents/info",
            params={"category": movie_cat},
            timeout=25,
        )
        r2.raise_for_status()
        for t in r2.json() if isinstance(r2.json(), list) else []:
            h = (t.get("hash") or "").lower()
            if h and h not in by_hash:
                by_hash[h] = t
        return list(by_hash.values())

    r = sess.get(
        f"{qb_base}/api/v2/torrents/info",
        params={"category": filt},
        timeout=25,
    )
    r.raise_for_status()
    return r.json() if isinstance(r.json(), list) else []


def _nzbget_i64(lo, hi) -> int:
    return int(hi or 0) * (2**32) + int(lo or 0)


def _nzbget_rpc(host: str, port: str, method: str, params: list,
                user: str, password: str):
    p = port or "6789"
    url = f"http://{host}:{p}/jsonrpc"
    auth = (user, password) if user else None
    r = requests.post(
        url, json={"method": method, "params": params, "id": 1},
        auth=auth, timeout=25,
    )
    r.raise_for_status()
    data = r.json()
    if data.get("error"):
        raise RuntimeError(str(data["error"]))
    return data.get("result")


def _dl_collect_nzbget(ncfg: dict, filt: str | None, items: list, errors: list, s: dict) -> None:
    host, port = ncfg["host"], ncfg["port"]
    user, pw = ncfg["user"], ncfg["pass"]
    try:
        groups = _nzbget_rpc(host, port, "listgroups", [], user, pw)
        if not isinstance(groups, list):
            groups = []
        for g in groups:
            cat = str(g.get("Category") or "")
            if not _dl_cat_match(cat, filt, s):
                continue
            size = _nzbget_i64(g.get("FileSizeLo"), g.get("FileSizeHi"))
            rem = _nzbget_i64(g.get("RemainingSizeLo"), g.get("RemainingSizeHi"))
            if size <= 0 and g.get("FileSizeMB"):
                try:
                    size = int(float(g["FileSizeMB"])) * 1024 * 1024
                except (TypeError, ValueError):
                    size = 0
            prog = round(100.0 * (size - rem) / size, 1) if size > 0 else 0.0
            tid = g.get("NZBID")
            items.append({
                "id": f"nzbget-{tid}",
                "source": "nzb",
                "client": "nzbget",
                "name": g.get("NZBName") or g.get("Name") or "?",
                "category": cat,
                "progress_pct": prog,
                "size_mb": round(size / (1024 * 1024), 1) if size else None,
                "status": str(g.get("Status") or "QUEUED"),
                "queue": "active",
                # NZBGet groups carry the original NZB fetch URL — used
                # by the scene-grab join to link this job back to the
                # /scenes search result it was grabbed from.
                "source_url": str(g.get("URL") or "").strip(),
            })
    except Exception as e:
        errors.append(f"NZBGet queue: {e}")

    try:
        hist = None
        for params in ([False, 0, 200], [False], []):
            try:
                hist = _nzbget_rpc(host, port, "history", list(params), user, pw)
                break
            except Exception:
                continue
        if hist is None:
            raise RuntimeError("history RPC not supported or failed")
        if not isinstance(hist, list):
            hist = []
        for h in hist[:200]:
            cat = str(h.get("Category") or "")
            if not _dl_cat_match(cat, filt, s):
                continue
            size = _nzbget_i64(h.get("FileSizeLo"), h.get("FileSizeHi"))
            if size <= 0 and h.get("FileSizeMB"):
                try:
                    size = int(float(h["FileSizeMB"])) * 1024 * 1024
                except (TypeError, ValueError):
                    size = 0
            st = h.get("Status") or h.get("HistoryStatus") or "?"
            if isinstance(st, int):
                st = {1: "SUCCESS", 2: "FAILURE", 3: "DELETED"}.get(st, str(st))
            hid = h.get("NZBID") or h.get("Id") or len(items)
            st_u = str(st).upper()
            # NZBGet uses SUCCESS/UNPACK, SUCCESS/PAR, etc. — not the bare word "SUCCESS"
            ok = st_u.startswith("SUCCESS") or st_u in ("1", "COMPLETED")
            items.append({
                "id": f"nzbget-h-{hid}",
                "source": "nzb",
                "client": "nzbget",
                "name": h.get("Name") or h.get("NZBName") or "?",
                "category": cat,
                "progress_pct": 100.0 if ok else 0.0,
                "size_mb": round(size / (1024 * 1024), 1) if size else None,
                "status": str(st),
                "queue": "history",
                "source_url": str(h.get("URL") or "").strip(),
            })
    except Exception as e:
        errors.append(f"NZBGet history: {e}")


def _dl_collect_sabnzbd(ncfg: dict, filt: str | None, items: list, errors: list, s: dict) -> None:
    host = ncfg["host"]
    port = ncfg["port"] or "8080"
    key = ncfg["apikey"]
    if not key:
        errors.append("SABnzbd: API key not configured")
        return
    base = f"http://{host}:{port}/sabnzbd/api"

    def _get(mode: str) -> dict:
        r = requests.get(
            base,
            params={"mode": mode, "apikey": key, "output": "json", "limit": 200},
            timeout=25,
        )
        r.raise_for_status()
        return r.json()

    try:
        data = _get("queue")
        q = data.get("queue") or {}
        slots = q.get("slots") or []
        for slot in slots:
            if not isinstance(slot, dict):
                continue
            cat = str(slot.get("cat") or "")
            if not _dl_cat_match(cat, filt, s):
                continue
            try:
                pct = float(str(slot.get("percentage") or "0").replace("%", ""))
            except ValueError:
                pct = 0.0
            try:
                mb = float(slot.get("mb") or 0)
            except (TypeError, ValueError):
                mb = 0
            nzo_id = str(slot.get("nzo_id") or slot.get("index") or len(items))
            items.append({
                "id": f"sab-q-{nzo_id}",
                "source": "nzb",
                "client": "sabnzbd",
                "name": slot.get("filename") or slot.get("nzb_name") or "?",
                "category": cat,
                "progress_pct": round(pct, 1),
                "size_mb": round(mb, 1) if mb else None,
                "status": str(slot.get("status") or "Downloading"),
                "queue": "active",
                # SAB exposes the original NZB URL (when the job was
                # added by URL rather than file upload) on the queue
                # slot. Empty for file-uploaded jobs — the title-match
                # fallback covers that case.
                "source_url": str(slot.get("url") or "").strip(),
            })
    except Exception as e:
        errors.append(f"SABnzbd queue: {e}")

    try:
        data = _get("history")
        hsec = data.get("history") or {}
        slots = hsec.get("slots") or []
        for slot in slots:
            if not isinstance(slot, dict):
                continue
            cat = str(slot.get("category") or slot.get("cat") or "")
            if not _dl_cat_match(cat, filt, s):
                continue
            try:
                sz_b = int(slot.get("bytes") or slot.get("size") or 0)
            except (TypeError, ValueError):
                sz_b = 0
            status = str(slot.get("status") or "")
            hid = str(slot.get("nzo_id") or slot.get("nzb_id") or slot.get("nz_id") or len(items))
            items.append({
                "id": f"sab-h-{hid}",
                "source": "nzb",
                "client": "sabnzbd",
                "name": slot.get("name") or slot.get("nzb_name") or "?",
                "category": cat,
                "progress_pct": 100.0 if status.lower() in ("completed", "complete") else 0.0,
                "size_mb": round(sz_b / (1024 * 1024), 1) if sz_b else None,
                "status": status or "?",
                "queue": "history",
                "source_url": str(slot.get("url") or "").strip(),
            })
    except Exception as e:
        errors.append(f"SABnzbd history: {e}")


def _qbittorrent_session(tcfg: dict) -> tuple[requests.Session, str]:
    port = tcfg["port"] or "8080"
    qb_base = f"http://{tcfg['host']}:{port}"
    sess = requests.Session()
    sess.headers.update({"Referer": f"{qb_base}/", "Origin": qb_base})
    login_r = sess.post(
        f"{qb_base}/api/v2/auth/login",
        data={"username": tcfg["user"], "password": tcfg["pass"]},
        timeout=12,
    )
    if login_r.status_code == 403:
        raise RuntimeError("qBittorrent 403 — check Web UI / IP ban")
    if (login_r.text or "").strip() == "Fails.":
        raise RuntimeError("qBittorrent login failed")
    return sess, qb_base


def _dl_collect_qbittorrent(tcfg: dict, filt: str | None, items: list, errors: list, s: dict) -> None:
    try:
        sess, qb_base = _qbittorrent_session(tcfg)
        torrents = _qbittorrent_torrents_for_filter(sess, qb_base, filt, s)
        if not isinstance(torrents, list):
            return
        for t in torrents:
            cat = str(t.get("category") or "")
            sp = (t.get("save_path") or "").strip()
            cp = (t.get("content_path") or "").strip()
            if not _dl_torrent_matches_filter(cat, filt, sp, cp, s):
                continue
            prog = round(float(t.get("progress") or 0) * 100.0, 1)
            sz = int(t.get("size") or 0)
            st = str(t.get("state") or "")
            qh = (t.get("hash") or "").strip().lower()
            if not qh:
                continue
            # qBittorrent surfaces magnet_uri for torrents added via
            # magnet, and stores the source URL in `comment` when added
            # via .torrent file. Either is a stable match against the
            # download_url we sent at grab time.
            items.append({
                "id": f"qbit-{qh}",
                "source": "torrent",
                "client": "qbittorrent",
                "name": t.get("name") or "?",
                "category": cat,
                "progress_pct": prog,
                "size_mb": round(sz / (1024 * 1024), 1) if sz else None,
                "status": st,
                "queue": "active",
                "source_url": (t.get("magnet_uri") or t.get("comment") or "").strip(),
            })
    except Exception as e:
        errors.append(f"qBittorrent: {e}")


def _transmission_rpc_session(tcfg: dict) -> tuple[requests.Session, str]:
    tsess = requests.Session()
    if tcfg["user"]:
        tsess.auth = (tcfg["user"], tcfg["pass"])
    port = tcfg["port"] or "9091"
    base = f"http://{tcfg['host']}:{port}/transmission/rpc"
    try:
        sr = tsess.get(base, timeout=12)
    except Exception:
        sr = type("R", (), {"status_code": 0, "headers": {}})()
    tsess.headers["X-Transmission-Session-Id"] = sr.headers.get("X-Transmission-Session-Id", "") if sr.status_code == 409 else ""
    return tsess, base


def _dl_collect_transmission(tcfg: dict, filt: str | None, items: list, errors: list, s: dict) -> None:
    status_names = {
        0: "stopped", 1: "check-wait", 2: "checking", 3: "download-wait",
        4: "downloading", 5: "seed-wait", 6: "seeding",
    }
    try:
        tsess, base = _transmission_rpc_session(tcfg)
        body = {
            "method": "torrent-get",
            "arguments": {
                "fields": [
                    "id", "name", "status", "percentDone", "totalSize",
                    "rateDownload", "eta", "errorString", "labels", "downloadDir",
                    # magnetLink is the source URI for any torrent
                    # added via magnet; matches against the
                    # download_url we stored at grab time.
                    "magnetLink",
                ],
            },
        }
        r = tsess.post(base, json=body, timeout=25)
        r.raise_for_status()
        resp = r.json()
        if resp.get("result") != "success":
            raise RuntimeError(resp.get("result", resp))
        torrents = resp.get("arguments", {}).get("torrents") or []
        for t in torrents:
            labels = t.get("labels") or []
            cat = labels[0] if isinstance(labels, list) and labels else ""
            dd = (t.get("downloadDir") or "").strip()
            if not _dl_torrent_matches_filter(cat, filt, dd, "", s):
                continue
            pct = round(float(t.get("percentDone") or 0) * 100.0, 1)
            sz = int(t.get("totalSize") or 0)
            st_i = t.get("status")
            st = status_names.get(st_i, str(st_i))
            err = (t.get("errorString") or "").strip()
            if err:
                st = f"{st}: {err[:80]}"
            items.append({
                "id": f"tr-{t.get('id')}",
                "source": "torrent",
                "client": "transmission",
                "name": t.get("name") or "?",
                "category": cat,
                "progress_pct": pct,
                "size_mb": round(sz / (1024 * 1024), 1) if sz else None,
                "status": st,
                "queue": "active",
                "source_url": (t.get("magnetLink") or "").strip(),
            })
    except Exception as e:
        errors.append(f"Transmission: {e}")


def _dl_collect_deluge(tcfg: dict, filt: str | None, items: list, errors: list, s: dict) -> None:
    port = tcfg["port"] or "8112"
    base = f"http://{tcfg['host']}:{port}"
    try:
        ds = requests.Session()
        lr = ds.post(
            f"{base}/json",
            json={"method": "auth.login", "params": [tcfg["pass"]], "id": 1},
            timeout=12,
        )
        lr.raise_for_status()
        if not lr.json().get("result"):
            raise RuntimeError("Deluge login failed")
        r2 = ds.post(
            f"{base}/json",
            json={
                "method": "core.get_torrents_status",
                "params": [
                    {},
                    [
                        "name", "state", "progress", "total_wanted",
                        "download_payload_rate", "save_path",
                        # `magnet` carries the magnet URI used to add
                        # the torrent; matches the download_url we
                        # stored at grab time. Empty for .torrent-file
                        # adds (title fallback handles those).
                        "magnet",
                    ],
                ],
                "id": 2,
            },
            timeout=25,
        )
        r2.raise_for_status()
        res = r2.json().get("result") or {}
        if not isinstance(res, dict):
            return
        for tid, t in res.items():
            if not isinstance(t, dict):
                continue
            cat = ""
            sp = str(t.get("save_path") or "").strip()
            if not _dl_torrent_matches_filter(cat, filt, sp, "", s):
                continue
            name = t.get("name") or "?"
            prog = float(t.get("progress") or 0)
            if 0 <= prog <= 1.0:
                prog = prog * 100.0
            tw = float(t.get("total_wanted") or 0)
            st = str(t.get("state") or "")
            items.append({
                "id": f"dl-{tid}",
                "source": "torrent",
                "client": "deluge",
                "name": name,
                "category": cat,
                "progress_pct": round(prog, 1),
                "size_mb": round(tw / (1024 * 1024), 1) if tw else None,
                "status": st,
                "queue": "active",
                "source_url": str(t.get("magnet") or "").strip(),
            })
    except Exception as e:
        errors.append(f"Deluge: {e}")


def _dl_item_import_ready(it: dict) -> bool:
    """True if the row is complete enough to run the same processing as download-folder watch."""
    q = it.get("queue")
    st = str(it.get("status") or "").upper()
    try:
        pct = float(it.get("progress_pct") if it.get("progress_pct") is not None else 0.0)
    except (TypeError, ValueError):
        pct = 0.0
    if q == "active":
        return pct >= 99.5
    if q == "history":
        if pct >= 99.0:
            return True
        # NZBGet: SUCCESS/UNPACK, SUCCESS/PAR, … — not always reflected in progress_pct
        if st.startswith("SUCCESS") or st in ("1", "COMPLETED", "COMPLETE") or st.startswith("COMPLETE"):
            return True
        return False
    return False


def _qbittorrent_content_path(sess, qb_base: str, hash_hex: str) -> Path | None:
    r = sess.get(
        f"{qb_base}/api/v2/torrents/info",
        params={"hashes": hash_hex},
        timeout=25,
    )
    if r.status_code != 200:
        return None
    arr = r.json()
    if not isinstance(arr, list) or not arr:
        return None
    t = arr[0]
    cp = (t.get("content_path") or "").strip()
    if cp:
        return Path(cp)
    save_path = (t.get("save_path") or "").strip()
    name = (t.get("name") or "").strip()
    if save_path and name:
        return Path(save_path) / name
    if save_path:
        return Path(save_path)
    return None


def _resolve_local_download_path(raw_path: Path, s: dict) -> Path | None:
    """
    Map paths reported by download clients (NAS/container) to paths visible on this host.

    1) Try the path as-is (before URL-decoding) to handle literal %XX characters in folder names.
    2) URL-decode, normalise, and check existence.
    3) If the path is under download_watch_dir, movie_download_watch_dir, source_dir,
       movies_source_dir, or features_dir, resolve via that directory prefix (same paths as in
       Settings — no remapping needed when mounts match).
    """
    # Try the raw path before any URL-decoding (e.g. folder literally named with %2C)
    try:
        if raw_path.exists():
            return raw_path.resolve()
    except OSError:
        pass
    qs = _normalize_import_path_str(str(raw_path))
    if not qs:
        return None
    try:
        p = Path(qs).expanduser()
    except Exception:
        p = Path(qs)
    try:
        pnorm = Path(os.path.normpath(str(p)))
        for cand in (pnorm, p):
            try:
                if cand.exists():
                    return cand.resolve()
            except OSError:
                continue
            # If only the final segment differs (e.g. apostrophe removed by indexer/client),
            # resolve via parent folder fuzzy match before broader fallbacks.
            try:
                par = cand.parent
                if par.is_dir():
                    alt = _find_matching_child_dir(par, cand.name)
                    if alt is not None:
                        return alt.resolve()
            except OSError:
                pass
    except OSError:
        pass

    def _try_anchor_prefix(anchor_str: str) -> Path | None:
        """
        If ``p`` is under ``anchor`` on disk, return the path via Settings' anchor.

        Uses ``os.path.realpath`` so NAS symlink layouts match (e.g. ``/share/Download/…`` in
        Top-Shelf vs ``/volume4/Downloads/…`` from NZBGet).
        """
        a = (anchor_str or "").strip()
        if not a:
            return None
        try:
            anchor = Path(a).expanduser()
            if not anchor.is_dir():
                return None
            ar = os.path.realpath(str(anchor))
            pr = os.path.realpath(str(p))
            if pr != ar and not pr.startswith(ar + os.sep):
                return None
            rel = os.path.relpath(pr, ar)
            if rel == ".." or rel.startswith(".."):
                return None
            candidate = anchor / rel
            if candidate.exists():
                return candidate.resolve()
        except (ValueError, OSError):
            return None
        return None

    for key in ("download_watch_dir", "movie_download_watch_dir", "source_dir", "movies_source_dir", "features_dir"):
        got = _try_anchor_prefix(s.get(key) or "")
        if got:
            return got

    try:
        lab = p.name
        if lab:
            par = p.parent
            if par.is_dir():
                alt = _find_matching_child_dir(par, lab)
                if alt is not None:
                    return alt
    except OSError:
        pass
    return None


def _fold_release_dir_name(s: str) -> str:
    """
    Loose name compare for release folders: casefold, strip apostrophe-like chars (NZB/usenet
    titles often drop `'` vs filesystem), collapse whitespace.
    """
    if not s:
        return ""
    try:
        x = unicodedata.normalize("NFC", s).casefold()
    except Exception:
        x = s.casefold()
    for ch in (
        "'", "\u2019", "\u2018", "\u02bc", "\u00b4", "`", "\u0060", "\u02b9",
    ):
        x = x.replace(ch, "")
    x = re.sub(r"\s+", " ", x).strip()
    return x


def _download_client_dir_name_matches(on_disk: str, from_client: str) -> bool:
    """True if directory names match, including +/URL vs spaces and case/NFC."""
    if not from_client:
        return False
    variants: list[str] = []
    for raw in (from_client.strip(),):
        if not raw:
            continue
        variants.append(raw)
        v2 = _normalize_import_path_str(raw)
        if v2 and v2 not in variants:
            variants.append(v2)
    try:
        dn = unicodedata.normalize("NFC", on_disk).casefold()
    except Exception:
        dn = on_disk.casefold()
    try:
        fdisk = _fold_release_dir_name(on_disk)
        for a in variants:
            if fdisk and fdisk == _fold_release_dir_name(a):
                return True
    except Exception:
        pass
    for a in variants:
        try:
            if unicodedata.normalize("NFC", a).casefold() == dn:
                return True
        except Exception:
            if a.casefold() == dn:
                return True
    return False


def _find_matching_child_dir(parent: Path, label: str) -> Path | None:
    """
    Return ``parent/label`` if it exists; otherwise find a directory under ``parent`` whose name
    matches ``label`` ignoring case or Unicode NFC. Handles NAS/client vs filesystem naming drift.
    """
    if not label:
        return None
    nlab = _normalize_import_path_str(label)
    if nlab and nlab != label.strip():
        hit = _find_matching_child_dir(parent, nlab)
        if hit is not None:
            return hit
    try:
        if not parent.is_dir():
            return None
        direct = parent / label
        if direct.exists():
            return direct.resolve()
    except OSError:
        return None
    try:
        want = unicodedata.normalize("NFC", label).casefold()
    except Exception:
        want = label.casefold()
    try:
        want_fold = _fold_release_dir_name(label)
    except Exception:
        want_fold = ""
    try:
        for ch in parent.iterdir():
            if not ch.is_dir():
                continue
            try:
                cn = unicodedata.normalize("NFC", ch.name).casefold()
            except Exception:
                cn = ch.name.casefold()
            if cn == want:
                return ch.resolve()
            if want_fold and _fold_release_dir_name(ch.name) == want_fold:
                return ch.resolve()
    except OSError:
        pass
    alt2 = _find_overlap_child_dir(parent, label)
    if alt2 is not None:
        return alt2
    return None


def _find_overlap_child_dir(parent: Path, label: str) -> Path | None:
    """
    When the client path's last segment differs slightly from the folder on disk (truncation or
    extra ``.x264``-style suffix), pick the only subdirectory whose name shares a long prefix with
    ``label`` and similar length.
    """
    if not label or len(label) < 16:
        return None
    try:
        if not parent.is_dir():
            return None
        lf = unicodedata.normalize("NFC", label).casefold()
    except Exception:
        lf = label.casefold()
    stem = min(40, len(lf))
    if stem < 16:
        return None
    head = lf[:stem]
    hits: list[Path] = []
    try:
        for ch in parent.iterdir():
            if not ch.is_dir():
                continue
            try:
                cn = unicodedata.normalize("NFC", ch.name).casefold()
            except Exception:
                cn = ch.name.casefold()
            if cn == lf:
                continue
            if len(cn) < 8:
                continue
            if len(cn) >= stem:
                if cn[:stem] != head[:stem]:
                    continue
            else:
                if not head.startswith(cn):
                    continue
            if abs(len(cn) - len(lf)) > 28:
                continue
            hits.append(ch)
    except OSError:
        return None
    if len(hits) == 1:
        return hits[0].resolve()
    return None


def _download_client_dest_candidates(dest_raw: str, job_name: str) -> list[str]:
    """
    Download clients often report only the category folder (…/Features) or the full job path.
    Prefer ``base/job`` when the last component of ``base`` is not already the job folder name.
    Used for NZBGet and SABnzbd.
    """
    d = _normalize_import_path_str((dest_raw or "").strip())
    if not d:
        return []
    j = (job_name or "").replace(".nzb", "").strip()
    jn = _normalize_import_path_str(j) if j else ""
    if not jn:
        return [d]
    try:
        if Path(d).name.casefold() == unicodedata.normalize("NFC", jn).casefold():
            return [d]
    except Exception:
        if Path(d).name == jn:
            return [d]
    combined = os.path.normpath(d.rstrip("/") + "/" + jn)
    out = [combined, d] if combined != d else [d]
    # Also yield the dest without URL-decoding so literal %XX folder names are tried
    raw_s = os.path.normpath((dest_raw or "").strip().replace("\\", "/"))
    if raw_s and raw_s not in out:
        out.append(raw_s)
    return out


def _normalize_import_path_str(p: str) -> str:
    """Normalize client-reported paths for comparison (URL decoding, Windows backslashes, etc.)."""
    x = (p or "").strip().replace("\\", "/")
    if not x:
        return ""
    # NZBGet/SABnzbd (and similar) often echo paths with '+' where the filesystem has spaces.
    # unquote alone leaves '+' intact; unquote_plus matches application/x-www-form-urlencoded rules.
    x = unquote_plus(x)
    return os.path.normpath(x)


def _relative_path_under_client_root(client_abs: str, root: str) -> Path | None:
    """
    Path of ``client_abs`` relative to ``root`` when the client path is under that directory.
    Uses string prefix logic (not pathlib.relative_to) so odd filenames (e.g. brackets) and
    non-existent paths behave consistently.
    """
    ca = _normalize_import_path_str(client_abs)
    r = _normalize_import_path_str(root)
    if not r or not ca:
        return None
    if ca == r:
        return Path(".")
    sep = "/"
    prefix = r if r.endswith(sep) else r + sep
    if not ca.startswith(prefix):
        return None
    rel = ca[len(prefix) :].strip("/")
    return Path(rel) if rel else Path(".")


def _dest_dir_for_local_download_path(local: Path, s: dict) -> Path | None:
    """
    Scene queue (source_dir), movie queue (movies_source_dir), or movie library (features_dir)
    from where the file actually lives on this host (watch folders vs movies input).
    """
    watch = (s.get("download_watch_dir") or "").strip()
    mdw = (s.get("movie_download_watch_dir") or "").strip()
    ms = (s.get("movies_source_dir") or "").strip()
    sd = (s.get("source_dir") or "").strip()
    feat = (s.get("features_dir") or "").strip()
    try:
        lr = local.resolve()
    except OSError:
        return None
    try:
        if watch and sd:
            wr = Path(watch).expanduser().resolve()
            if lr == wr or wr in lr.parents:
                return Path(sd).expanduser()
        if mdw and feat:
            mwr = Path(mdw).expanduser().resolve()
            if lr == mwr or mwr in lr.parents:
                return Path(feat).expanduser()
        if ms:
            mr = Path(ms).expanduser().resolve()
            if lr == mr or mr in lr.parents:
                return Path(ms).expanduser()
    except OSError:
        return None
    return None


def _candidate_client_path_roots(save_path: str, content_path: str, reported: str) -> list[str]:
    """Possible torrent roots on the client (save_path, content parent, etc.) in try order."""
    seen: set[str] = set()
    out: list[str] = []
    for raw in (save_path, content_path):
        x = _normalize_import_path_str(raw)
        if x and x not in seen:
            seen.add(x)
            out.append(x)
    cp = _normalize_import_path_str(content_path)
    if cp:
        try:
            if Path(cp).suffix.lower() in VIDEO_EXTENSIONS:
                parent = _normalize_import_path_str(str(Path(cp).parent))
                if parent and parent not in seen:
                    seen.add(parent)
                    out.append(parent)
        except OSError:
            pass
    rp = _normalize_import_path_str(reported)
    if rp:
        parent = _normalize_import_path_str(str(Path(rp).parent))
        if parent and parent not in seen:
            seen.add(parent)
            out.append(parent)
    return out


def _resolve_local_download_path_via_save_mirror(
    reported: Path,
    save_path: str,
    content_path: str,
    s: dict,
    dest_dir: Path,
) -> Path | None:
    """
    When the client reports paths that only exist on another machine (e.g. /share/... on the
    torrent host) but the same files exist here under scene/movie watch directories or Movies input
    folder, map by path relative to each plausible client root onto local anchors.

    Tries multiple roots (save_path, content_path, parent of file video, etc.), then a
    basename-only match in each anchor directory.

    ``dest_dir`` is unused for picking anchors; callers should set import destination via
    ``_dest_dir_for_local_download_path`` when mirror succeeds.
    """
    _ = dest_dir  # kept for call-site compatibility
    rep_s = _normalize_import_path_str(str(reported))
    if not rep_s:
        return None
    watch = (s.get("download_watch_dir") or "").strip()
    mwatch = (s.get("movie_download_watch_dir") or "").strip()
    ms = (s.get("movies_source_dir") or "").strip()
    try:
        bn_early = Path(rep_s).name
    except OSError:
        bn_early = ""
    if bn_early:
        for anchor_str in (watch, mwatch, ms):
            if not anchor_str:
                continue
            anchor = Path(anchor_str).expanduser()
            if not anchor.is_dir():
                continue
            direct = anchor / bn_early
            try:
                if direct.exists():
                    return direct.resolve()
            except OSError:
                continue
    roots = _candidate_client_path_roots(save_path, content_path, rep_s)
    # Drop roots that equal the full reported path — they yield rel "." and would map to the
    # anchor dir instead of the job subfolder (NZB/SAB storage paths).
    roots = [r for r in roots if _normalize_import_path_str(r) != rep_s]
    if not roots:
        try:
            roots = [_normalize_import_path_str(str(Path(rep_s).parent))]
        except OSError:
            return None
    for sp in roots:
        rel = _relative_path_under_client_root(rep_s, sp)
        if rel is None:
            try:
                pp = _normalize_import_path_str(str(Path(rep_s).parent))
                if pp == sp:
                    rel = Path(Path(rep_s).name)
            except OSError:
                continue
        if rel is None:
            continue
        for anchor_str in (watch, mwatch, ms):
            if not anchor_str:
                continue
            anchor = Path(anchor_str).expanduser()
            if not anchor.is_dir():
                continue
            candidate = anchor / rel
            try:
                if candidate.exists():
                    return candidate.resolve()
            except OSError:
                continue
    return None


def _path_parts_no_root(norm: str) -> list[str]:
    """Path segments without leading drive/root (for building relative tails)."""
    try:
        p = Path(_normalize_import_path_str(norm))
        parts = list(p.parts)
    except Exception:
        return []
    out: list[str] = []
    for x in parts:
        if not x or x == "/" or x == "\\":
            continue
        if len(x) == 2 and x[1] == ":":
            continue
        out.append(x)
    return out


def _relative_tail_candidates_from_client_path(norm: str) -> list[str]:
    """
    All meaningful relative paths from the client-reported absolute path.

    Includes every suffix (…/Top-Shelf/Warez/…/Folder) and, when present, the path from
    ``Top-Shelf`` onward so we match Docker roots like ``/downloads`` → ``Top-Shelf/Warez/…``
    without a spurious ``Download/`` segment from the NAS path.
    """
    parts = _path_parts_no_root(norm)
    if not parts:
        return []
    tails: list[str] = []
    for i in range(len(parts)):
        tails.append("/".join(parts[i:]))
    low = [p.lower() for p in parts]
    for marker in ("top-shelf", "warez", "features", "series"):
        try:
            idx = low.index(marker)
        except ValueError:
            continue
        tails.append("/".join(parts[idx:]))
        if marker in ("top-shelf", "warez"):
            break
    seen: set[str] = set()
    out: list[str] = []
    for t in tails:
        t = (t or "").strip().strip("/")
        if t and t not in seen:
            seen.add(t)
            out.append(t)
    return out


def _bfs_find_dir_named(root: Path, dirname: str, max_depth: int = 14) -> Path | None:
    """Breadth-first search for a directory whose name equals ``dirname`` (exact)."""
    if not dirname:
        return None
    from collections import deque

    q: deque[tuple[Path, int]] = deque([(root, 0)])
    while q:
        cur, d = q.popleft()
        if d > max_depth:
            continue
        try:
            for ch in cur.iterdir():
                if not ch.is_dir():
                    continue
                if ch.name == dirname or _download_client_dir_name_matches(ch.name, dirname):
                    return ch.resolve()
                if d < max_depth:
                    q.append((ch, d + 1))
        except OSError:
            continue
    return None


def _find_local_download_under_watch_dirs(
    s: dict,
    *,
    job_name: str = "",
    client_reported_path: str = "",
) -> Path | None:
    """
    Locate the completed download under configured local dirs only (ignore client host prefix).

    Uses scene/movie watch dirs plus scene/movie *input* dirs as search roots. Tries relative
    tails from the client path (including from ``Top-Shelf`` onward), job/NZB name, basename,
    and a bounded directory-name search (handles ``..`` in folder names that break glob).
    """
    root_keys = (
        "download_watch_dir",
        "movie_download_watch_dir",
        "movies_source_dir",
        "features_dir",
        "source_dir",
    )
    roots: list[Path] = []
    seen_r: set[str] = set()
    for key in root_keys:
        raw = (s.get(key) or "").strip()
        if not raw:
            continue
        try:
            p = Path(raw).expanduser()
            if not p.is_dir():
                continue
            rp = str(p.resolve())
            if rp in seen_r:
                continue
            seen_r.add(rp)
            roots.append(p)
        except OSError:
            continue
    if not roots:
        return None

    rel_tails: list[str] = []
    cp = (client_reported_path or "").strip()
    if cp:
        try:
            norm = _normalize_import_path_str(cp)
            rel_tails.extend(_relative_tail_candidates_from_client_path(norm))
            rel_tails.append(Path(norm).name)
        except Exception:
            pass

    jn = (job_name or "").strip()
    name_candidates: list[str] = []
    if jn:
        name_candidates.append(jn.replace(".nzb", "").strip())
        name_candidates.append(jn)

    seen: set[str] = set()
    path_candidates: list[str] = []

    def _add_candidate(label: str) -> None:
        for t in (label or "",):
            t = (t or "").strip().strip("/")
            if not t:
                continue
            for v in (t, _normalize_import_path_str(t)):
                v = (v or "").strip().strip("/")
                if not v or v in seen:
                    continue
                seen.add(v)
                path_candidates.append(v)

    for t in rel_tails + name_candidates:
        _add_candidate(t)
    # If watch dir is …/Top-Shelf, also try path below it (drop leading Top-Shelf/)
    for t in list(path_candidates):
        if "/" in t and t.lower().startswith("top-shelf/"):
            sub = t.split("/", 1)[1].strip()
            _add_candidate(sub)
    # Movie watch is often …/Warez/Features — avoid doubling Warez/Features/ when joining root.
    for t in list(path_candidates):
        low = t.lower()
        if low.startswith("warez/features/") and "/" in t:
            sub = t.split("/", 2)[2].strip()
            _add_candidate(sub)

    for root in roots:
        for c in path_candidates:
            if "/" in c or "\\" in c:
                try:
                    c_rel = c.replace("\\", "/").lstrip("/")
                    hit = root / c_rel
                    if hit.exists():
                        return hit.resolve()
                    parent_rel, _, base = c_rel.rpartition("/")
                    if parent_rel and base:
                        par = root / parent_rel
                        if par.is_dir():
                            alt = _find_matching_child_dir(par, base)
                            if alt is not None:
                                return alt
                            alt2 = _find_overlap_child_dir(par, base)
                            if alt2 is not None:
                                return alt2
                except OSError:
                    continue
            else:
                try:
                    hit = root / c
                    if hit.exists():
                        return hit.resolve()
                    alt = _find_matching_child_dir(root, c)
                    if alt is not None:
                        return alt
                except OSError:
                    continue

        for c in path_candidates:
            if "/" in c or "\\" in c:
                continue
            if ".." in c or "*" in c or "[" in c or "?" in c:
                found = _bfs_find_dir_named(root, c)
                if found:
                    return found
                continue
            for depth in range(0, 9):
                pat = ("/".join(["*"] * depth) + "/" + c) if depth else c
                try:
                    for hit in root.glob(pat):
                        if hit.exists():
                            return hit.resolve()
                except OSError:
                    continue
            found = _bfs_find_dir_named(root, c)
            if found:
                return found
    return None


def _download_path_not_found_client_report(raw: str) -> dict:
    """JSON error for NZB/SAB when no local path matched client-reported storage/dest."""
    r = (raw or "").strip()
    n = _normalize_import_path_str(r)
    suffix = f" — also tried: {n!r}" if n and n != r else ""
    return {"error": f"Path not found: {r}{suffix}"}


def _download_path_missing_message(s: dict, reported_path: str) -> str:
    """User-facing hint when a client-reported path is not visible to this process."""
    bits = []
    for key, label in (
        ("download_watch_dir", "Scene watch directory"),
        ("movie_download_watch_dir", "Movie watch directory"),
        ("source_dir", "Scene source folder"),
        ("movies_source_dir", "Movies input folder"),
        ("features_dir", "Movies Library Directory"),
    ):
        raw = (s.get(key) or "").strip()
        if not raw:
            continue
        try:
            ap = Path(raw).expanduser()
            ok = ap.is_dir()
            bits.append(f"{label} {raw!r} → {'ok' if ok else 'not found on this host'}")
        except OSError:
            bits.append(f"{label} {raw!r} → not accessible")
    cfg = (" (" + "; ".join(bits) + ")") if bits else ""
    return (
        f"Download path not found on this host: {reported_path}{cfg}. "
        "If the file exists under your scene or movie watch directory (or Movies input folder) with the same path "
        "relative to the torrent save path, import should still work; otherwise align bind mounts so that path "
        "is visible here, or set those directories to the roots that match the client’s folder layout."
    )


def _download_remove_by_id(dl_id: str) -> dict:
    """Remove job from download client without importing (torrents: delete data)."""
    s = db.get_settings()
    if dl_id.startswith("qbit-"):
        h = dl_id[5:].strip().lower()
        tcfg = _dl_resolve_torrent_settings(s)
        if not tcfg or tcfg.get("client") != "qbittorrent":
            return {"error": "qBittorrent not configured"}
        sess, qb_base = _qbittorrent_session(tcfg)
        gr = sess.post(
            f"{qb_base}/api/v2/torrents/delete",
            data={"hashes": h, "deleteFiles": "true"},
            timeout=20,
        )
        if gr.status_code == 200:
            return {"ok": True}
        return {"error": f"qBittorrent HTTP {gr.status_code}"}

    if dl_id.startswith("tr-"):
        try:
            tid = int(dl_id[3:])
        except ValueError:
            return {"error": "Invalid id"}
        tcfg = _dl_resolve_torrent_settings(s)
        if not tcfg or tcfg.get("client") != "transmission":
            return {"error": "Transmission not configured"}
        tsess, base = _transmission_rpc_session(tcfg)
        r = tsess.post(
            base,
            json={
                "method": "torrent-remove",
                "arguments": {"ids": [tid], "delete-local-data": True},
                "tag": 1,
            },
            timeout=20,
        )
        if r.status_code == 200 and r.json().get("result") == "success":
            return {"ok": True}
        return {"error": r.text[:200]}

    if dl_id.startswith("dl-"):
        tid_hex = dl_id[3:].strip()
        tcfg = _dl_resolve_torrent_settings(s)
        if not tcfg or tcfg.get("client") != "deluge":
            return {"error": "Deluge not configured"}
        port = tcfg["port"] or "8112"
        base = f"http://{tcfg['host']}:{port}"
        ds = requests.Session()
        ds.post(
            f"{base}/json",
            json={"method": "auth.login", "params": [tcfg["pass"]], "id": 1},
            timeout=12,
        )
        r = ds.post(
            f"{base}/json",
            json={"method": "core.remove_torrent", "params": [tid_hex, True], "id": 2},
            timeout=20,
        )
        if r.status_code == 200:
            return {"ok": True}
        return {"error": r.text[:200]}

    if dl_id.startswith("sab-q-") or dl_id.startswith("sab-h-"):
        nzo_id = dl_id.split("-", 2)[2]
        ncfg = _dl_resolve_nzb_settings(s)
        if not ncfg or ncfg.get("client") != "sabnzbd":
            return {"error": "SABnzbd not configured"}
        host = ncfg["host"]
        port = ncfg["port"] or "8080"
        key = ncfg["apikey"]
        mode = "queue" if dl_id.startswith("sab-q-") else "history"
        params = {
            "mode": mode,
            "name": "delete",
            "value": nzo_id,
            "del_files": "1",
            "apikey": key,
            "output": "json",
        }
        if mode == "history":
            # archive=0 tells SAB to actually delete the history entry rather than
            # move it into the archive (which would leave it visible in the list).
            params["archive"] = "0"
        try:
            r = requests.get(f"http://{host}:{port}/sabnzbd/api", params=params, timeout=20)
        except Exception as e:
            return {"error": f"SABnzbd request failed: {e}"}
        if r.status_code != 200:
            return {"error": f"SABnzbd HTTP {r.status_code}: {r.text[:200]}"}
        try:
            body = r.json()
        except Exception:
            body = None
        if isinstance(body, dict):
            if body.get("status") is False:
                return {"error": f"SABnzbd refused: {body.get('error') or body}"}
            # Either {"status": true} (queue) or {"status": true, "nzo_ids": [...]} (history)
            return {"ok": True}
        # Non-JSON 200 — SAB has historically returned plain "ok" for some endpoints
        return {"ok": True}

    if dl_id.startswith("nzbget-") and not dl_id.startswith("nzbget-h-"):
        try:
            tid = int(dl_id[7:])
        except ValueError:
            return {"error": "Invalid id"}
        ncfg = _dl_resolve_nzb_settings(s)
        if not ncfg or ncfg.get("client") != "nzbget":
            return {"error": "NZBGet not configured"}
        host, port = ncfg["host"], ncfg["port"]
        user, pw = ncfg["user"], ncfg["pass"]
        try:
            _nzbget_rpc(host, port, "editqueue", ["GroupDelete", 0, "", [tid]], user, pw)
            return {"ok": True}
        except Exception as e:
            # If the delete failed, verify whether the job still exists in the queue.
            # If it's already gone (moved to history or cleaned up), treat as success.
            try:
                groups = _nzbget_rpc(host, port, "listgroups", [], user, pw)
                if isinstance(groups, list) and any(int(g.get("NZBID", -1)) == tid for g in groups):
                    return {"error": str(e)}
            except Exception:
                pass
            return {"ok": True}

    if dl_id.startswith("nzbget-h-"):
        try:
            hid = int(dl_id[9:])
        except ValueError:
            return {"error": "Invalid id"}
        ncfg = _dl_resolve_nzb_settings(s)
        if not ncfg or ncfg.get("client") != "nzbget":
            return {"error": "NZBGet not configured"}
        host, port = ncfg["host"], ncfg["port"]
        user, pw = ncfg["user"], ncfg["pass"]
        # NZBGet has no `historydelete` RPC — the only way to remove a history
        # entry is `editqueue` with Command=HistoryFinalDelete (permanent) or
        # HistoryDelete (soft). Both use the standard 4-arg signature:
        #   editqueue(Command, Offset, EditText, IDs)
        # The IDs list goes in slot 4 — not slot 2. The previous version had
        # the id in slot 2 with an empty IDs list, so NZBGet was acting on
        # nothing and returning success without touching the entry.
        last_err: Exception | None = None
        for cmd in ("HistoryFinalDelete", "HistoryDelete"):
            try:
                _nzbget_rpc(host, port, "editqueue", [cmd, 0, "", [hid]], user, pw)
                return {"ok": True}
            except Exception as e:
                last_err = e
                continue
        # If both failed, verify whether the entry still exists.
        # If it's already gone, treat as success.
        try:
            hist = _nzbget_rpc(host, port, "history", [False, 0, 500], user, pw)
            if isinstance(hist, list) and not any(
                int(x.get("NZBID", x.get("Id", -1))) == hid for x in hist
            ):
                return {"ok": True}
        except Exception:
            pass
        return {"error": str(last_err) if last_err else "NZBGet history delete failed"}

    return {"error": "Unsupported download id"}


def _watch_import_name_matches_client_job(client_job_name: str, watch_folder_name: str) -> bool:
    """True when NZB/torrent display name matches the folder the download watcher just processed."""
    if not client_job_name or not watch_folder_name:
        return False
    j = client_job_name.strip()
    if j.lower().endswith(".nzb"):
        j = j[:-4].strip()
    w = watch_folder_name.strip()
    jn = _normalize_import_path_str(j)
    wn = _normalize_import_path_str(w)
    if _fold_release_dir_name(wn) == _fold_release_dir_name(jn):
        return True
    try:
        if len(normalise(j)) > 12 and normalise(j) == normalise(w):
            return True
    except Exception:
        pass
    # Third fallback: alnum-only compare. Some sources (esp. sanitised folder
    # names) strip all dots/hyphens/spaces, so "Foo.Bar.1080p-GRP" in the
    # client and "FooBar1080pGRP" on disk should still match.
    try:
        ja = re.sub(r"[^a-z0-9]", "", j.lower())
        wa = re.sub(r"[^a-z0-9]", "", w.lower())
        if len(ja) > 12 and ja == wa:
            return True
    except Exception:
        pass
    return False


def _remove_client_jobs_matching_watch_folder(folder_name: str, s: dict) -> None:
    """
    After the download-folder watcher imports a completed release, remove the matching job from
    NZB/torrent clients when download_import_remove_client is enabled in Settings.
    """
    if s.get("download_import_remove_client", "false").lower() != "true":
        emit("  Client remove: disabled in Settings (Downloads → remove matching job from client)")
        return
    if not (folder_name or "").strip():
        return
    try:
        data = download_clients_combined_status(None)
    except Exception as e:
        emit(f"  Client remove (watch): could not list downloads: {e}")
        return
    items = data.get("items") or []
    emit(f"  Client remove: scanning {len(items)} client item(s) for folder '{folder_name}'")
    skipped_ineligible = 0
    skipped_nomatch = 0
    skipped_done = 0
    removed = 0
    failed = 0
    for it in items:
        dl_id = it.get("id")
        if not dl_id:
            continue
        if not _dl_item_import_ready(it):
            skipped_ineligible += 1
            continue
        nm = (it.get("name") or "").strip()
        if not _watch_import_name_matches_client_job(nm, folder_name):
            skipped_nomatch += 1
            continue
        if db.was_download_import_done(dl_id):
            skipped_done += 1
            continue
        res = _download_remove_by_id(dl_id)
        if res.get("ok"):
            db.mark_download_import_done(dl_id)
            emit(f"  Removed from download client (watch import): {dl_id} [{nm}]")
            removed += 1
        else:
            emit(f"  Client remove (watch) failed {dl_id}: {res.get('error', '')}")
            failed += 1
    if removed == 0 and failed == 0:
        emit(
            f"  Client remove: no match (ineligible={skipped_ineligible}, "
            f"name-mismatch={skipped_nomatch}, already-done={skipped_done})"
        )


def _remove_client_jobs_after_import(filename: str, s: dict) -> None:
    """Mirror of the watch-folder client cleanup but driven by the main
    pipeline's per-file successful-import sites (scenes from source_dir,
    movies from movies_source_dir).

    Matches a filename — typically `Some.Release.Title.1080p.mkv` —
    against any active job on the configured download clients by
    feeding it through `_watch_import_name_matches_client_job()`. That
    helper already strips file extensions, normalises separators, and
    fuzzy-matches on the title body, so it works for both folder-style
    drops AND single-file releases the watcher path doesn't see.

    Mirrors Radarr's DownloadEventHub.Handle(DownloadCompletedEvent)
    pattern with the same idempotency + eligibility gates:
      • Toggle: download_import_remove_client (default false)
      • Eligibility: _dl_item_import_ready() — the equivalent of
        Radarr's CanBeRemoved + Status != Downloading checks
      • Idempotency: db.was_download_import_done / mark_download_import_done
        prevent double-removal across the watch-folder and main-pipeline
        call sites firing for the same release
      • Per-client API: dispatched through _download_remove_by_id which
        routes to qBittorrent / Transmission / Deluge / SAB queue+history
        / NZBGet queue+history with the matching delete-files behaviour
        Radarr's per-client RemoveItem implementations use
    """
    if s.get("download_import_remove_client", "false").lower() != "true":
        return
    name = (filename or "").strip()
    if not name:
        return
    try:
        data = download_clients_combined_status(None)
    except Exception as e:
        emit(f"  Client remove (import): could not list downloads: {e}")
        return
    # Strip the extension so a release "Foo.Release.Title.mkv" matches
    # client jobs named "Foo.Release.Title" / "Foo Release Title".
    stem = Path(name).stem or name
    for it in data.get("items") or []:
        dl_id = it.get("id")
        if not dl_id:
            continue
        if not _dl_item_import_ready(it):
            continue
        nm = (it.get("name") or "").strip()
        # Try filename, then bare stem — matches both folder-named jobs
        # and single-file release names.
        if not (
            _watch_import_name_matches_client_job(nm, name)
            or _watch_import_name_matches_client_job(nm, stem)
        ):
            continue
        if db.was_download_import_done(dl_id):
            continue
        res = _download_remove_by_id(dl_id)
        if res.get("ok"):
            db.mark_download_import_done(dl_id)
            emit(f"  Removed from download client (import): {dl_id}")
        else:
            emit(f"  Client remove (import) failed {dl_id}: {res.get('error', '')}")


def download_clients_combined_status(category: str | None) -> dict:
    """NZB + torrent rows from whichever clients are selected in Settings."""
    s = db.get_settings()
    filt = _dl_parse_category_param(category, s)
    items: list = []
    errors: list = []
    notes: list = []

    ncfg = _dl_resolve_nzb_settings(s)
    if ncfg:
        if ncfg["client"] == "nzbget":
            _dl_collect_nzbget(ncfg, filt, items, errors, s)
        else:
            _dl_collect_sabnzbd(ncfg, filt, items, errors, s)

    tcfg = _dl_resolve_torrent_settings(s)
    if tcfg:
        tc = tcfg["client"]
        if tc == "qbittorrent":
            _dl_collect_qbittorrent(tcfg, filt, items, errors, s)
        elif tc == "transmission":
            if filt is not None:
                notes.append(
                    "Transmission: filter uses labels plus download dir vs Movies source folder when set."
                )
            _dl_collect_transmission(tcfg, filt, items, errors, s)
        elif tc == "deluge":
            if filt is not None:
                notes.append(
                    "Deluge: filter uses save path vs Movies source folder when category is unset."
                )
            _dl_collect_deluge(tcfg, filt, items, errors, s)

    items.sort(key=lambda x: (x.get("queue") != "active", (x.get("name") or "").lower()))

    # Extract the Top-Shelf `[ts-XXXXXXXX]` tag from each item. We
    # leave the original `name` intact (so downstream filing-status
    # joins keep matching the tagged name written to processed_files)
    # but expose:
    #   • `it["ts_uid"]` — for the source-scene matcher to use as the
    #     strongest available key.
    #   • `it["display_name"]` — the cleaned release title the
    #     frontend renders on the tile.
    for it in items:
        cleaned, uid = _strip_ts_uid(it.get("name") or "")
        if uid:
            it["ts_uid"] = uid
        it["display_name"] = cleaned or (it.get("name") or "")

    db.enrich_download_items_with_filing(items)
    db.enrich_download_items_with_source_scene(items)

    return {
        "category_filter": filt,
        "default_category": (s.get("prowlarr_category") or "Top-Shelf").strip(),
        "movie_category": (s.get("prowlarr_category_movies") or "").strip(),
        "movies_source_dir": (s.get("movies_source_dir") or "").strip(),
        "items": items,
        "errors": errors,
        "notes": notes,
        "configured": {
            "nzb": (ncfg or {}).get("client"),
            "torrent": (tcfg or {}).get("client"),
        },
    }


def _tpdb_scene_thumb(scene: dict) -> str | None:
    p0 = (scene.get("posters") or [None])[0]
    if not p0:
        return None
    if isinstance(p0, str):
        return p0
    if isinstance(p0, dict):
        return p0.get("url")
    return None


def _tpdb_scenes_list_from_response(body: dict) -> list:
    """TPDB sometimes returns data as a bare list; sometimes nested under data.scenes etc."""
    data = body.get("data")
    if isinstance(data, list):
        return data
    if isinstance(data, dict):
        for key in ("scenes", "content", "items", "results", "records", "rows"):
            inner = data.get(key)
            if isinstance(inner, list):
                return inner
    return []


def _tpdb_scene_row_from_api_item(s: dict) -> dict | None:
    """Normalise one scene object from /performers/…/scenes or /sites/…/scenes."""
    if not isinstance(s, dict):
        return None
    sid = str(s.get("_id") or s.get("id") or "").strip()
    if not sid:
        return None
    site = s.get("site")
    studio_name = site.get("name", "") if isinstance(site, dict) else ""
    thumb = _tpdb_scene_thumb(s)
    if not thumb:
        bg = s.get("background") or {}
        if isinstance(bg, dict):
            thumb = (
                bg.get("small") or bg.get("medium") or bg.get("large")
                or bg.get("url") or ""
            )
        else:
            thumb = ""
    if not thumb:
        thumb = s.get("poster_image") or s.get("image") or s.get("poster") or ""
    if not thumb:
        posters = s.get("posters") or []
        if posters:
            p0 = posters[0]
            if isinstance(p0, str):
                thumb = p0
            elif isinstance(p0, dict):
                thumb = p0.get("url") or ""
    return {
        "id": sid,
        "title": (s.get("title") or "") or "",
        "date": (s.get("date") or "") or "",
        "studio": studio_name or "",
        "thumb": thumb or None,
    }


def _tpdb_path_segment(seg: str) -> str:
    """Safe for TPDB URL path segments; keeps hyphens unencoded (UUIDs)."""
    return quote((seg or "").strip(), safe="-_.~")


def _tpdb_scenes_lookup_segments(kind: str, stored_id: str) -> list[str]:
    """Path segments to try for /performers/{seg}/scenes or /sites/{seg}/scenes (slug vs id)."""
    stored_id = (stored_id or "").strip()
    if not stored_id:
        return []
    seen: set[str] = set()
    ordered: list[str] = []

    def add(seg: str) -> None:
        seg = (seg or "").strip()
        if not seg or seg in seen:
            return
        seen.add(seg)
        ordered.append(seg)

    try:
        detail_url = (
            TPDB_PERFORMER_DETAIL.format(id=_tpdb_path_segment(stored_id))
            if kind == "performer"
            else TPDB_STUDIO_DETAIL.format(id=_tpdb_path_segment(stored_id))
        )
        r = requests.get(detail_url, headers=_tpdb_headers(), timeout=12)
        if r.status_code == 200:
            d = r.json().get("data")
            if isinstance(d, dict):
                if d.get("slug"):
                    add(str(d["slug"]))
                pid = d.get("id") or d.get("_id")
                if pid is not None:
                    add(str(pid))
    except Exception:
        pass
    add(stored_id)
    return ordered


def _tpdb_entity_scenes(kind: str, entity_id: str, limit: int) -> list[dict]:
    """Recent scenes for a performer or studio; tries slug/id variants and loose JSON shapes."""
    eid = str(entity_id or "").strip()
    if not eid or limit < 1:
        return []
    path = "performers" if kind == "performer" else "sites"
    headers = _tpdb_headers()
    out: list[dict] = []
    seen_ids: set[str] = set()
    # Oversample so the tag blacklist can drop some rows without
    # under-filling the popup grid; capped to keep the payload light.
    fetch_count = min(max(limit * 2, limit + 4), 40)
    for seg in _tpdb_scenes_lookup_segments(kind, eid):
        safe_seg = _tpdb_path_segment(seg)
        for params in ({"page": 1, "per_page": fetch_count}, {"page": 1, "limit": fetch_count}):
            try:
                resp = requests.get(
                    f"https://api.theporndb.net/{path}/{safe_seg}/scenes",
                    params=params,
                    headers=headers,
                    timeout=15,
                )
                if resp.status_code != 200:
                    continue
                parsed = _tpdb_scenes_list_from_response(resp.json())
                if not parsed:
                    continue
                dropped_by_tags = 0
                missing_tags_field = 0
                for raw in parsed:
                    # Apply the tag blacklist to the raw TPDB payload —
                    # `_tpdb_scene_row_from_api_item` strips tags when
                    # building the card, so we need to filter before the
                    # conversion.
                    rd = raw if isinstance(raw, dict) else {}
                    if not rd.get("tags"):
                        missing_tags_field += 1
                    if not _passes_tag_filter(rd):
                        dropped_by_tags += 1
                        continue
                    row = _tpdb_scene_row_from_api_item(raw)
                    if not row or not row["id"]:
                        continue
                    if row["id"] in seen_ids:
                        continue
                    seen_ids.add(row["id"])
                    out.append(row)
                    if len(out) >= limit:
                        emit(
                            f"TAG-FILTER tpdb {kind} {eid}: dropped {dropped_by_tags} of {len(parsed)} by blacklist"
                            + (f" ({missing_tags_field} rows had no 'tags' field and so could not be checked — TPDB list endpoint omits tags; use scene detail for strict filtering)" if missing_tags_field else "")
                        )
                        return out
                if dropped_by_tags or missing_tags_field:
                    emit(
                        f"TAG-FILTER tpdb {kind} {eid}: dropped {dropped_by_tags} of {len(parsed)} by blacklist"
                        + (f" ({missing_tags_field} rows had no 'tags' field — TPDB list endpoint omits tags; use scene detail for strict filtering)" if missing_tags_field else "")
                    )
                if out:
                    break
            except Exception:
                continue
        if out:
            break
        if len(out) >= limit:
            return out
    return out


def tpdb_performer_scenes(performer_id: str, limit: int = 8) -> list[dict]:
    """Fetch recent scenes for a performer from TPDB."""
    return _tpdb_entity_scenes("performer", performer_id, limit)


def tpdb_studio_scenes(studio_id: str, limit: int = 8) -> list[dict]:
    """Fetch recent scenes for a studio from TPDB."""
    return _tpdb_entity_scenes("studio", studio_id, limit)


_STASHBOX_SCENES_BY_ENTITY_GQL = """
query FavScenesByEntity($input: SceneQueryInput!) {
  queryScenes(input: $input) {
    scenes {
      id title release_date
      studio { name }
      images { url width height }
      tags { name }
    }
  }
}
"""


def _stashbox_scenes_for_library_match(
    endpoint: str,
    api_key: str,
    *,
    kind: str,
    entity_id: str,
    limit: int,
) -> list[dict]:
    """Recent scenes for a performer or studio when we already have the stash-box id."""
    eid = str(entity_id or "").strip()
    key = (api_key or "").strip()
    if not eid or not key or limit < 1:
        return []
    if kind == "performer":
        filt: dict[str, dict] = {"performers": {"value": [eid], "modifier": "INCLUDES"}}
    elif kind == "studio":
        filt = {"studios": {"value": [eid], "modifier": "INCLUDES"}}
    else:
        return []
    # Oversample so the tag blacklist can trim some scenes without
    # under-filling the popup — stash-box allows up to 50 per_page.
    fetch_count = min(max(limit * 2, limit + 4), 50)
    variables = {
        "input": {
            **filt,
            "per_page": fetch_count,
            "page": 1,
            "sort": "DATE",
            "direction": "DESC",
        }
    }
    try:
        resp = requests.post(
            endpoint,
            json={"query": _STASHBOX_SCENES_BY_ENTITY_GQL, "variables": variables},
            headers={"ApiKey": key, "Content-Type": "application/json"},
            timeout=22,
        )
        if resp.status_code != 200:
            return []
        body = resp.json()
        if body.get("errors"):
            return []
        scenes_data = (body.get("data") or {}).get("queryScenes", {}).get("scenes") or []
        out: list[dict] = []
        dropped_by_tags = 0
        for s in scenes_data:
            if not isinstance(s, dict):
                continue
            # Stash-box returns tags as `[{name: ...}]`, which
            # `_tag_names_from_tpdb_entity` already handles — so the
            # same blacklist helper used for TPDB feeds works here.
            if not _passes_tag_filter(s):
                dropped_by_tags += 1
                continue
            imgs = s.get("images") or []
            thumb = imgs[0].get("url") if imgs and isinstance(imgs[0], dict) else None
            out.append({
                "id": str(s.get("id") or ""),
                "title": s.get("title") or "",
                "date": (s.get("release_date") or "") or "",
                "studio": (s.get("studio") or {}).get("name", "")
                if isinstance(s.get("studio"), dict)
                else "",
                "thumb": thumb,
            })
        if dropped_by_tags:
            emit(f"TAG-FILTER stash-box {kind} {eid}: dropped {dropped_by_tags} of {len(scenes_data)} by blacklist")
        return [x for x in out if x.get("id")][:limit]
    except Exception:
        return []


def favourites_recent_scenes(row: dict, limit: int) -> tuple[list[dict], str | None]:
    """Library recent scenes: try TPDB (non-empty), then StashDB, then FansDB. Tags each row with scene_source."""
    kind = row.get("kind")
    if kind not in ("performer", "studio") or limit < 1:
        return [], None

    tpdb_id = str(row.get("match_tpdb_id") or "").strip()
    sid = str(row.get("match_stashdb_id") or "").strip()
    fid = str(row.get("match_fansdb_id") or "").strip()
    settings = db.get_settings()

    if tpdb_id:
        if kind == "studio":
            sc = tpdb_studio_scenes(tpdb_id, limit)
        else:
            sc = tpdb_performer_scenes(tpdb_id, limit)
        if sc:
            for x in sc:
                x["scene_source"] = "tpdb"
            return sc, "tpdb"

    ak_stash = (settings.get("api_key_stashdb") or "").strip()
    if sid and ak_stash:
        sc = _stashbox_scenes_for_library_match(
            STASHDB_ENDPOINT, ak_stash, kind=str(kind), entity_id=sid, limit=limit
        )
        if sc:
            for x in sc:
                x["scene_source"] = "stashdb"
            return sc, "stashdb"

    ak_fan = (settings.get("api_key_fansdb") or "").strip()
    if fid and ak_fan:
        sc = _stashbox_scenes_for_library_match(
            FANSDB_ENDPOINT, ak_fan, kind=str(kind), entity_id=fid, limit=limit
        )
        if sc:
            for x in sc:
                x["scene_source"] = "fansdb"
            return sc, "fansdb"

    return [], None


