@app.get("/api/queue")
async def get_queue():
    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    if not source_dir.exists():
        return JSONResponse({"files": [], "error": f"Source dir not found: {source_dir}"})

    # Mark any tracked files that no longer exist on disk as removed
    retryable = db.get_retry_files()
    for fname in retryable:
        if db.resolve_source_video_path(source_dir, fname) is None:
            db.update_file(fname, status="removed")

    history = {}
    for r in db.get_history(limit=10000):
        history[r["filename"]] = r

    # Lazy: library indexes are only built if at least one file lacks a
    # history-filed studio/performers pair. Keeps clean queues free of
    # the extra DB scan.
    lib_idx: tuple | None = None

    def _ensure_lib_idx():
        nonlocal lib_idx
        if lib_idx is None:
            try:
                lib_idx = db._build_library_match_indexes()
            except Exception:
                lib_idx = ([], [])
        return lib_idx

    files = []
    for f in sorted(source_dir.iterdir()):
        if f.is_file() and f.suffix.lower() in VIDEO_EXTENSIONS:
            hrow = history.get(f.name) or history.get(f.stem) or {}
            prev_status = hrow.get("status")
            match_studio = hrow.get("match_studio") or ""
            performers = hrow.get("performers") or ""
            guessed = False
            # Library fallback: files that haven't been filed (or history
            # didn't capture the studio/performers) still get matched via
            # the same name-tokeniser the download bars use, so the queue
            # row can show a studio logo + headshots before filing.
            if not match_studio and not performers:
                studio_idx, perf_idx = _ensure_lib_idx()
                try:
                    guess = db._library_guess_from_release_name(
                        f.stem, studio_idx, perf_idx
                    )
                except Exception:
                    guess = {"studio": None, "performers": []}
                g_studio = (guess.get("studio") or "").strip()
                g_perfs = [p for p in (guess.get("performers") or []) if p]
                if g_studio or g_perfs:
                    match_studio = g_studio
                    performers = ", ".join(g_perfs)
                    guessed = True
            files.append({
                "filename":         f.name,
                "display_name":     f.stem,
                "size_mb":          round(f.stat().st_size / 1024 / 1024, 1),
                "has_phash":        db.get_phash(f.name) is not None,
                "previously_filed": prev_status == "filed",
                "prev_status":      prev_status,
                "match_title":      hrow.get("match_title") or "",
                "match_source":     hrow.get("match_source") or "",
                "match_external_id": hrow.get("match_external_id") or "",
                "match_studio":     match_studio,
                "match_date":       hrow.get("match_date") or "",
                "performers":       performers,
                "match_guess":      guessed,
                #: Last filer error stored on the processed_files row —
                #: the queue UI surfaces this inline on error'd rows so
                #: the user doesn't have to dig through the log to see
                #: what failed.
                "error":            (hrow.get("error") or "").strip() if prev_status == "error" else "",
            })
    return {"files": files, "source_dir": str(source_dir)}


