_banner_downloads_cache: dict = {"fetched_at": 0.0, "data": {}}
_banner_downloads_lock = threading.Lock()


#: Max individual download circles rendered in the header banner before
#: the rest collapse into a "+N" overflow chip. Each circle is ~60 px;
#: progress pipelines + favourites + library index + phash can already
#: fill the row on busy servers, so we cap this low on purpose.
_BANNER_DOWNLOADS_MAX_ITEMS = 4


def _banner_downloads_snapshot() -> dict:
    """Per-item snapshot of *active* downloads for the header banner.
    Refreshes at most every 5 s — the full
    ``download_clients_combined_status`` call fans out HTTP requests to
    every configured download client, so we don't want every banner
    poll (~every 2 s) hitting that.

    Returns ``{count, extra, items: [{pct, headshot_url, label,
    download_name}, …]}``. ``count == 0`` tells the frontend to render
    nothing. ``items`` is capped at ``_BANNER_DOWNLOADS_MAX_ITEMS``;
    ``extra`` is the number of active downloads beyond the cap so the
    banner can render a "+N" chip.
    """
    now = time.time()
    with _banner_downloads_lock:
        if now - (_banner_downloads_cache.get("fetched_at") or 0.0) < 5.0:
            return dict(_banner_downloads_cache.get("data") or {"count": 0, "items": [], "extra": 0})
    empty = {"count": 0, "items": [], "extra": 0}
    try:
        status = download_clients_combined_status(None)
    except Exception:
        status = {"items": []}
    # Clients label anything in the queue as "active" — including items
    # that are paused, stalled, queued behind a concurrency limit, or
    # waiting on post-processing. The banner only cares about what's
    # genuinely downloading *right now*, so drop rows whose status word
    # is a non-progressing state.
    _non_active_tokens = ("queue", "paus", "stall", "wait", "stop")
    active = []
    for it in (status.get("items") or []):
        if it.get("queue") != "active":
            continue
        st = str(it.get("status") or "").strip().lower()
        if st and any(tok in st for tok in _non_active_tokens):
            continue
        active.append(it)
    if not active:
        out = empty
    else:
        visible = active[: _BANNER_DOWNLOADS_MAX_ITEMS]
        extra = max(0, len(active) - len(visible))
        entries: list[dict] = []
        for it in visible:
            raw = it.get("progress_pct")
            pct = 0.0
            if raw is not None and raw != "":
                try:
                    n = float(raw)
                    if 0 <= n <= 100:
                        pct = n
                except (TypeError, ValueError):
                    pct = 0.0
            headshot_url: str | None = None
            headshot_name = ""
            f = it.get("filing") or {}
            perf_names = [nm for nm in (f.get("performers") or []) if isinstance(nm, str) and nm.strip()]
            if perf_names:
                try:
                    resolved = _resolve_library_performers_for_movie(perf_names)
                except Exception:
                    resolved = []
                if resolved:
                    headshot_url = resolved[0].get("headshot_url") or None
                    headshot_name = resolved[0].get("name") or ""
            entries.append({
                "pct": pct,
                "headshot_url": headshot_url,
                "label": headshot_name,
                "download_name": (it.get("name") or "").strip(),
            })
        out = {"count": len(active), "items": entries, "extra": extra}
    with _banner_downloads_lock:
        _banner_downloads_cache["fetched_at"] = now
        _banner_downloads_cache["data"] = out
    return dict(out)


@app.get("/api/activity/banner")
async def api_activity_banner():
    db.notifications_delete_expired()
    with _library_index_lock:
        library_index = dict(_library_index_progress)
