@app.post("/api/favourites/set-weight")
async def api_favourites_set_weight(payload: dict = Body(...)):
    """Set (or clear) the router-weight override for a favourite row.

    Body: `{id: int, weight: int|null}`. `weight` in 1..10 sets the
    override; `null` / `0` / missing clears it so the default kicks
    back in (2 if starred, 1 otherwise). Returns `{ok, weight}` with
    the effective stored value (None when cleared).
    """
    row_id = int(payload.get("id") or 0)
    if not row_id:
        return JSONResponse({"error": "id required"}, status_code=400)
    if not db.favourite_get(row_id):
        return JSONResponse({"error": "Not found"}, status_code=404)
    raw = payload.get("weight")
    weight: int | None
    if raw is None or raw == "" or raw == 0:
        weight = None
    else:
        try:
            weight = int(raw)
        except (TypeError, ValueError):
            return JSONResponse({"error": "weight must be integer 1..10 or null"}, status_code=400)
        if weight < 1 or weight > 10:
            return JSONResponse({"error": "weight must be 1..10"}, status_code=400)
    try:
        db.favourite_set_weight(row_id, weight)
    except ValueError as e:
        return JSONResponse({"error": str(e)}, status_code=400)
    return {"ok": True, "weight": weight}


