@app.get("/api/performers/poster-roles")
async def api_performers_poster_roles(row_id: int):
    """Return URLs for the currently-saved primary + secondary posters of a
    performer row, plus the scraped candidate list from linked DB profiles.
    Used by the /library performer "manage posters" modal.

    The candidates list is prepended with a "Local library" entry pointing
    at the performer folder's local `poster.jpg` (if one exists on disk),
    so users can re-assign their existing on-disk poster to either role
    without having to re-download anything from a remote DB."""
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not a performer row"}, status_code=404)
    md = _metadata_dir_for("performer", row_id)
    def _role_url(role: str) -> str | None:
        for name in (f"{row_id}_poster_{role}.jpg",
                     f"{row_id}_poster_{1 if role == 'primary' else 2}.jpg"):
            p = md / name
            if p.is_file() and p.stat().st_size > 500:
                return (f"/api/performers/poster-role-image?row_id={row_id}"
                        f"&role={role}&v={int(p.stat().st_mtime)}")
        return None
    candidates = _favourites_matched_link_image_items(row) or []
    # Prepend the local library poster.jpg if present. The image URL is a
    # local API path that serves the file straight off disk — the frontend
    # opens it as <img> and it round-trips back through set-poster-role
    # which calls _favourites_download_image_bytes() with the absolute URL.
    local = _favourite_find_local_poster_file(row.get("path") or "")
    if local and local.is_file():
        local_url = f"/api/favourites/folder-poster?row_id={row_id}&v={int(local.stat().st_mtime)}"
        candidates.insert(0, {
            "name":   "Local library poster",
            "source": "Local",
            "image":  local_url,
        })
    # Current headshot URL — prefer the cached IAFD image (same path the
    # bio popup uses) so the preview matches what's actually on disk.
    # Fall back to any custom upload, then to whatever image_url is
    # stored on the favourite row. The stored image_url can go stale
    # (external scrape URL that 404s, wrong row from an earlier match),
    # so the IAFD-cached path is the most reliable signal.
    headshot_url = _performers_iafd_image_api_url(
        row_id, 0, _performers_iafd_read_meta(row_id)
    )
    if not headshot_url:
        cust = _performers_custom_ref_resolve(row_id)
        if cust:
            headshot_url = f"/api/performers/custom-image?row_id={row_id}"
    if not headshot_url:
        headshot_url = (row.get("image_url") or "").strip() or None
    return {
        "primary_url":   _role_url("primary"),
        "secondary_url": _role_url("secondary"),
        "headshot_url":  headshot_url,
        "candidates":    candidates,
        "name":          row.get("folder_name") or "",
    }


@app.get("/api/performers/poster-role-image")
async def api_performers_poster_role_image(row_id: int, role: str, v: int = 0):
    """Serve the current primary or secondary poster as a plain image for the
    modal preview. `role` is 'primary' or 'secondary'; `v` is a cache-bust
    mtime token from the poster-roles endpoint."""
    role = (role or "").strip().lower()
    if role not in ("primary", "secondary"):
        return JSONResponse({"error": "role must be primary or secondary"}, status_code=400)
    md = _metadata_dir_for("performer", row_id)
    for name in (
        f"{row_id}_poster_{role}.jpg",
        f"{row_id}_poster_{1 if role == 'primary' else 2}.jpg",
    ):
        p = md / name
        if p.is_file() and p.stat().st_size > 500:
            return FileResponse(
                p,
                media_type="image/jpeg",
                headers={"Cache-Control": "private, max-age=60"},
            )
    return JSONResponse({"error": "Not found"}, status_code=404)


@app.post("/api/performers/set-poster-role")
async def api_performers_set_poster_role(payload: dict = Body(...)):
    """Download a remote image (or copy the local library poster) and write
    it as the performer's primary or secondary poster in
    `metadata/performers/{row_id}/`. Body:
        { row_id: int, image_url: str, role: 'primary'|'secondary' }

    `image_url` is either an http(s) URL (scraped DB image) or the local
    `/api/favourites/folder-poster?row_id=…` path — in the second case we
    skip the HTTP fetch and read the file straight from the library folder.

    Returns {ok: True, role, poster_url} where poster_url is a cache-busted
    URL the frontend can load to refresh its preview.
    """
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    image_url = (payload.get("image_url") or "").strip()
    role = (payload.get("role") or "").strip().lower()
    if not row_id or not image_url or role not in ("primary", "secondary"):
        return JSONResponse(
            {"error": "row_id, image_url and role ('primary'|'secondary') required"},
            status_code=400,
        )
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not a performer row"}, status_code=404)
    # Local-poster shortcut: `/api/favourites/folder-poster?row_id=…` is our
    # own endpoint exposing the library folder's poster.jpg. Rather than
    # HTTP-fetch ourselves, read the file straight from disk.
    data: bytes
    if image_url.startswith("/api/favourites/folder-poster"):
        local = _favourite_find_local_poster_file(row.get("path") or "")
        if not local or not local.is_file():
            return JSONResponse(
                {"error": "Local poster file not found on disk"},
                status_code=404,
            )
        try:
            data = local.read_bytes()
        except OSError as e:
            return JSONResponse({"error": f"Could not read local poster: {e}"}, status_code=500)
    else:
        if not image_url.lower().startswith(("http://", "https://")):
            return JSONResponse({"error": "image_url must be http(s) or the local folder-poster path"}, status_code=400)
        try:
            data = _favourites_download_image_bytes(image_url)
        except requests.RequestException as e:
            return JSONResponse({"error": f"Download failed: {e}"}, status_code=502)
        except ValueError as e:
            return JSONResponse({"error": str(e)}, status_code=400)
    md = _metadata_dir_for("performer", row_id)
    dest = md / f"{row_id}_poster_{role}.jpg"
    try:
        ok = save_image_bytes_optimized(data, dest, max_edge=IMAGE_CACHE_POSTER_MAX)
    except OSError as e:
        return JSONResponse({"error": f"Write failed: {e}"}, status_code=500)
    if not ok:
        return JSONResponse({"error": "Could not encode image"}, status_code=500)
    # Remove any stale legacy filename (poster_1.jpg / poster_2.jpg) so the
    # serve chain sees only the canonical role file we just wrote.
    legacy = md / f"{row_id}_poster_{1 if role == 'primary' else 2}.jpg"
    if legacy.is_file() and legacy != dest:
        try:
            legacy.unlink()
        except OSError:
            pass
    emit(f"performer row {row_id}: {role} poster replaced via manual picker")
    return {
        "ok": True,
        "role": role,
        "poster_url": (f"/api/performers/poster-role-image?row_id={row_id}"
                       f"&role={role}&v={int(dest.stat().st_mtime)}"),
    }


@app.post("/api/favourites/apply-image")
async def api_favourites_apply_image(payload: dict = Body(...)):
    """Set favourites tile image from a remote URL; optionally save into the folder as poster.jpg or logo.png."""
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    image_url = (payload.get("image_url") or "").strip()
    save_local = bool(payload.get("save_local"))
    if not row_id or not image_url:
        return JSONResponse(
            {"error": "row_id and image_url required"},
            status_code=400,
        )
    if not image_url.lower().startswith(("http://", "https://")):
        return JSONResponse(
            {"error": "image_url must be http(s)"},
            status_code=400,
        )
    row = db.favourite_get(row_id)
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    kind = row.get("kind")
    folder = (row.get("path") or "").strip()
    new_stored_url: str

    if save_local:
        if not folder:
            return JSONResponse(
                {"error": "Folder path missing — cannot save file"},
                status_code=400,
            )
        try:
            root = Path(folder).expanduser().resolve()
        except (OSError, RuntimeError):
            return JSONResponse(
                {"error": "Invalid folder path"},
                status_code=400,
            )
        if not root.is_dir():
            return JSONResponse(
                {"error": "Folder not on disk — cannot save file"},
                status_code=400,
            )
        try:
            data = _favourites_download_image_bytes(image_url)
        except requests.RequestException as e:
            return JSONResponse(
                {"error": f"Download failed: {e}"},
                status_code=502,
            )
        except ValueError as e:
            return JSONResponse({"error": str(e)}, status_code=400)
        try:
            if kind in ("performer", "movie"):
                dest = root / "poster.jpg"
                ok = save_image_bytes_optimized(
                    data,
                    dest,
                    max_edge=FAVOURITES_SAVED_POSTER_MAX_EDGE,
                )
            elif kind == "studio":
                dest = root / "logo.png"
                ok = save_image_bytes_optimized(
                    data,
                    dest,
                    max_edge=FAVOURITES_SAVED_POSTER_MAX_EDGE,
                )
            else:
                return JSONResponse({"error": "Invalid row kind"}, status_code=400)
        except OSError:
            return JSONResponse({"error": "Could not write file"}, status_code=500)
        if not ok:
            return JSONResponse({"error": "Could not encode image"}, status_code=500)
        if kind in ("performer", "movie"):
            new_stored_url = f"/api/favourites/folder-poster?row_id={row_id}"
        else:
            new_stored_url = f"/api/favourites/folder-logo?row_id={row_id}"
    else:
        new_stored_url = image_url

    favourites_clear_image_disk_cache(row_id)
    db.favourite_update_matches(row_id, image_url=new_stored_url)
    return {"ok": True, "image_url": new_stored_url}


