def _resolve_library_performers_for_movie(names: list) -> list:
    """Cross-reference a list of performer names against the library, returning headshot URLs.

    Matching strategies, in order of preference:
      1. Exact folder-name match (``Silvia Dellai`` → ``Silvia Dellai``)
      2. Canonical primary-name match (``match_tpdb_name`` /
         ``match_stashdb_name`` / ``match_fansdb_name``) — picks up
         folders where the library folder name differs from the name
         the external DBs return as the performer's primary.

    ``aliases_json`` is deliberately NOT consulted here. That column
    holds the alternate-name lists scraped off TPDB / StashDB / FansDB,
    which are too noisy to use for credit matching (first-name-only
    entries, stage names shared across multiple performers). Only
    names the external DBs flag as a performer's *primary* name are
    trusted — those live in the ``match_*_name`` columns above.

    Multiple input names resolving to the same library row are
    deduplicated on the row id, so a scene crediting the same
    performer twice only surfaces one headshot tile.
    """
    try:
        rows = db.favourite_list()
        # Precompute every lookup surface for every performer folder so
        # the per-name loop below is O(1). Pulling this into a single
        # normalised dict keeps the resolver scan linear in the library
        # size rather than quadratic.
        folder_map: dict[str, dict] = {}
        canonical_map: dict[str, dict] = {}
        for r in rows:
            if r.get("kind") != "performer":
                continue
            fn = (r.get("folder_name") or "").lower().strip()
            if fn and fn not in folder_map:
                folder_map[fn] = r
            for canon_field in ("match_tpdb_name", "match_stashdb_name", "match_fansdb_name"):
                cn = (r.get(canon_field) or "").lower().strip()
                if cn and cn not in canonical_map:
                    canonical_map[cn] = r
        result = []
        seen_row_ids: set[int] = set()
        seen_input: set[str] = set()
        for name in (names or []):
            key = (name or "").lower().strip()
            if not key or key in seen_input:
                continue
            seen_input.add(key)
            row = folder_map.get(key) or canonical_map.get(key)
            if not row:
                continue
            rid = int(row["id"])
            if rid in seen_row_ids:
                continue
            seen_row_ids.add(rid)
            meta = _performers_iafd_read_meta(rid)
            headshot_url = _performers_iafd_image_api_url(rid, 0, meta) or row.get("image_url") or None
            result.append({
                "name": row["folder_name"],
                "row_id": rid,
                "headshot_url": headshot_url,
            })
        return result
    except Exception:
        return []


@app.get("/api/performers/headshots-by-name")
async def api_performers_headshots_by_name(names: str):
    """Return library headshot data for one or more comma-separated performer names."""
    name_list = [n.strip() for n in (names or "").split(",") if n.strip()]
    results = _resolve_library_performers_for_movie(name_list)
    return {"performers": results}


@app.get("/api/movies/tpdb/{movie_id}")
async def movies_tpdb_detail(movie_id: str):
    """Get full TPDB movie detail."""
    try:
        resp = requests.get(f"https://api.theporndb.net/movies/{movie_id}",
                            headers=_tpdb_headers(), timeout=15)
        if resp.status_code != 200:
            return JSONResponse({"error": f"TPDB returned {resp.status_code}"}, status_code=resp.status_code)
        m = resp.json().get("data") or {}
        # image = front cover (portrait), back_image = back cover
        poster = m.get("image") or m.get("poster") or m.get("poster_image")
        bg = m.get("back_image") or m.get("poster")
        if not poster:
            posters_obj = m.get("posters") or {}
            if isinstance(posters_obj, dict):
                poster = posters_obj.get("full") or posters_obj.get("large")
        # Dedup on a case-insensitive name key so TPDB records that list
        # the same performer twice (happens on older / merged entries)
        # don't surface a duplicate tag in the detail popup.
        performers = []
        performer_links = []
        seen_perf_keys: set[str] = set()
        def _register_perf(name_s: str, url: str = "") -> None:
            s = (name_s or "").strip()
            if not s:
                return
            k = s.lower()
            if k in seen_perf_keys:
                return
            seen_perf_keys.add(k)
            performers.append(s)
            performer_links.append({"name": s, "url": url})
        for p in (m.get("performers") or []):
            if isinstance(p, dict):
                perf = p.get("performer") or p
                name = perf.get("name") or perf.get("full_name") or ""
                slug = perf.get("slug") or perf.get("_id") or perf.get("id")
                url = ""
                if slug:
                    url = f"https://theporndb.net/performers/{slug}"
                elif perf.get("url"):
                    url = str(perf.get("url"))
                _register_perf(name, url)
            elif isinstance(p, str):
                _register_perf(p)
        scenes = []
        for s in (m.get("scenes") or []):
            thumb = s.get("poster_image") or s.get("image")
            scenes.append({
                "id": str(s.get("_id") or s.get("id") or ""),
                "title": s.get("title") or "",
                "date": s.get("date") or "",
                "thumb": thumb,
            })
        tmdb_id = (
            m.get("tmdb_id")
            or (m.get("tmdb") or {}).get("id")
            or (m.get("movie") or {}).get("tmdb_id")
        )
        tmdb_url = ""
        if tmdb_id:
            tmdb_url = f"https://www.themoviedb.org/movie/{tmdb_id}"
        else:
            tmdb_url = f"https://www.themoviedb.org/search/movie?query={quote_plus(m.get('title') or '')}"

        raw_dirs = m.get("directors") or []
        directors_norm = []
        for d in raw_dirs:
            if isinstance(d, dict):
                dn = d.get("name") or d.get("full_name") or ""
                if dn:
                    directors_norm.append(dn)
            elif isinstance(d, str) and d:
                directors_norm.append(d)
        library_perfs = _resolve_library_performers_for_movie(performers)
        return {
            "id":          str(m.get("_id") or m.get("id") or ""),
            "slug":        m.get("slug") or m.get("_id") or str(m.get("id", "")),
            "title":       m.get("title") or "",
            "date":        m.get("date") or "",
            "year":        (m.get("date") or "")[:4],
            "studio":      (m.get("site") or {}).get("name") or (m.get("studio") or {}).get("name") or "",
            "duration":    m.get("duration") or 0,
            "synopsis":    m.get("description") or m.get("synopsis") or "",
            "poster":      poster,
            "background":  bg,
            "performers":  performers,
            "performer_links": performer_links,
            "library_performers": library_perfs,
            "directors":   directors_norm,
            "scenes":      scenes,
            "tags":        _tpdb_scene_tag_names(m),
            "url":         f"https://theporndb.net/movies/{m.get('slug') or m.get('_id') or movie_id}",
            "tmdb_url":    tmdb_url,
        }
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


