@app.get("/api/movies/nfo")
async def api_movies_nfo(row_id: int):
    """Read and parse a movie's NFO file from disk for the popup display."""
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "movie":
        return JSONResponse({"error": "Not a movie"}, status_code=404)
    folder = (row.get("path") or "").strip()
    if not folder or not Path(folder).is_dir():
        return {"error": "Folder not found", "title": row.get("folder_name", "")}
    folder_p = Path(folder)
    nfo_path = None
    for candidate in [folder_p / "movie.nfo"] + list(folder_p.glob("*.nfo")):
        if candidate.is_file():
            nfo_path = candidate
            break
    if not nfo_path:
        return {"error": "No NFO found", "title": row.get("folder_name", "")}
    try:
        nfo_text = nfo_path.read_text(encoding="utf-8", errors="replace")
        root = ET.fromstring(nfo_text)
        title = (root.findtext("title") or "").strip()
        year = (root.findtext("year") or "").strip()
        plot = (root.findtext("plot") or "").strip()
        outline = (root.findtext("outline") or root.findtext("tagline") or "").strip()
        rating = (root.findtext("rating") or "").strip()
        runtime = (root.findtext("runtime") or "").strip()
        genres = [g.text.strip() for g in root.findall("genre") if g.text and g.text.strip()]
        directors = [d.text.strip() for d in root.findall("director") if d.text and d.text.strip()]
        cast = []
        for actor_el in root.findall("actor"):
            nm = actor_el.findtext("name")
            if nm and nm.strip():
                cast.append(nm.strip())
        poster_url = ""
        for ext in (".jpg", ".png", ".jpeg"):
            for pat in [f"{nfo_path.stem}-poster{ext}", f"poster{ext}", f"{nfo_path.stem}{ext}"]:
                pp = folder_p / pat
                if pp.is_file():
                    poster_url = f"/api/favourites/movie-poster?path={requests.utils.quote(str(pp))}"
                    break
            if poster_url:
                break
        fanart_url = ""
        for ext in (".jpg", ".png", ".jpeg"):
            for pat in [f"{nfo_path.stem}-fanart{ext}", f"fanart{ext}"]:
                fp = folder_p / pat
                if fp.is_file():
                    fanart_url = f"/api/favourites/movie-poster?path={requests.utils.quote(str(fp))}"
                    break
            if fanart_url:
                break
        return {
            "title": title or row.get("folder_name", ""),
            "year": year, "plot": plot, "outline": outline,
            "rating": rating, "runtime": runtime,
            "genres": genres, "directors": directors, "cast": cast,
            "poster_url": poster_url, "fanart_url": fanart_url,
            "folder": folder,
        }
    except Exception as e:
        return {"error": str(e), "title": row.get("folder_name", "")}


