@app.get("/api/health/library-stats")
async def health_library_stats():
    # Threadpool for the same reason as library-disk-usage: the payload
    # walks every library root end-to-end and would otherwise stall the
    # event loop until the scan finishes.
    return await run_in_threadpool(_health_library_stats_payload)


@app.get("/api/health/library-disk-usage")
async def health_library_disk_usage(include: str | None = None):
    """Disk usage by configured library root + top folders (may take a while on large libraries).

    Optional ``include``: comma-separated root ``key`` values (e.g. ``series,features,performer:1``)
    to restrict measurement. Omit for all roots.

    Runs in a worker thread — the scan walks potentially tens of
    thousands of files and calling it directly from the async handler
    blocks the event loop, which stalls every other request and makes
    the whole /health page feel unresponsive until the scan finishes.
    """
    keys: set[str] | None = None
    if include is not None and include.strip():
        keys = {x.strip() for x in include.split(",") if x.strip()}
    return await run_in_threadpool(_health_library_disk_usage_payload, keys)


