@app.get("/api/health/duplicate-frames")
async def health_duplicate_frames(path: str = Query("", description="Absolute video path")):
    raw = (path or "").strip()
    if not raw:
        return {"frames": [], "error": "path required"}
    p = Path(raw)
    if not p.is_file():
        return {"frames": [], "error": "File not found"}
    if p.suffix.lower() not in VIDEO_EXTENSIONS:
        return {"frames": [], "error": "Not a video file"}

    def grab() -> dict:
        out: list[str] = []
        for pct in (20.0, 50.0, 80.0):
            b64 = capture_frame_as_base64(p, pct)
            if b64:
                out.append(b64)
        if not out:
            return {"frames": [], "error": "Could not capture frames (ffmpeg or duration)"}
        return {"frames": out}

    loop = asyncio.get_event_loop()
    try:
        return await loop.run_in_executor(None, grab)
    except Exception as e:
        return {"frames": [], "error": str(e)}


@app.get("/api/health/duplicate-db-record")
async def health_duplicate_db_record(path: str = Query("")):
    raw = (path or "").strip()
    if not raw:
        return {"source": None}
    row = db.library_file_get_by_destination(raw)
    if not row:
        return {"source": None}
    sid = row.get("source_record_id")
    if sid is None:
        return {"source": None}
    pf = db.processed_file_get_by_id(int(sid))
    if not pf:
        return {"source": None}
    ms = (pf.get("match_source") or "").strip()
    tag = _api_source_tag(ms)
    if not tag:
        return {"source": None}
    perf_raw = (pf.get("performers") or "").strip()
    performers = [x.strip() for x in perf_raw.split(",") if x.strip()]
    match_id = None
    phash = (pf.get("phash") or "").strip()
    title = (pf.get("match_title") or "").strip()
    date = (pf.get("match_date") or "").strip()
    ep = _endpoint_query_var_for_match_source(ms)
    if ep:
        endpoint, api_key, _qvar = ep
        if (api_key or "").strip() and phash:
            q = STASHDB_QUERY if _qvar == "full" else TPDB_QUERY
            try:
                matches = query_stashbox(phash, endpoint, api_key, q, _qvar)
            except Exception:
                matches = []
            scene = _pick_scene_from_matches(matches, title, date)
            if scene and scene.get("id"):
                match_id = str(scene.get("id"))
    out = {
        "source": tag,
        "title": pf.get("match_title") or "",
        "studio": pf.get("match_studio") or "",
        "date": pf.get("match_date") or "",
        "performers": performers,
        "match_id": match_id or "",
    }
    return out


