@app.post("/api/health/orphaned/clear")
async def health_orphaned_clear(payload: dict = Body(...)):
    """Remove multiple filing-history rows that are currently orphaned (filed, destination missing on disk)."""
    raw = payload.get("ids")
    if not isinstance(raw, list) or not raw:
        return JSONResponse({"error": "ids required"}, status_code=400)
    try:
        want = {int(x) for x in raw}
    except (TypeError, ValueError):
        return JSONResponse({"error": "invalid ids"}, status_code=400)
    valid: set[int] = set()
    for r in db.processed_files_filed_rows():
        rd = dict(r)
        if db.processed_files_repair_destination_row_if_found(rd):
            continue
        dst = (rd.get("destination") or "").strip()
        if not dst:
            continue
        valid.add(int(rd["id"]))
    to_del = sorted(want & valid)
    if not to_del:
        return {"deleted": 0}
    n = db.processed_files_delete_by_ids(to_del)
    return {"deleted": n}


