@app.post("/api/health/create-tvshow-nfo")
async def health_create_tvshow_nfo(payload: dict = Body(...)):
    """
    Write full tvshow.nfo from Favourites index (TPDB/StashDB/FansDB match IDs).
    Overwrites existing tvshow.nfo. Downloads poster.jpg only if the file is not present.
    """
    roots = _health_library_roots()
    paths_bulk = payload.get("paths")
    if paths_bulk is not None:
        if not isinstance(paths_bulk, list):
            return JSONResponse({"error": "paths must be a list"}, status_code=400)
        written: list[str] = []
        errors: list[dict] = []
        for raw in paths_bulk:
            if not isinstance(raw, str):
                errors.append({"path": str(raw), "error": "invalid path"})
                continue
            out = _health_apply_tvshow_nfo_from_index(raw.strip(), roots)
            if out.get("ok"):
                written.append(out.get("path") or raw.strip())
            else:
                errors.append({"path": out.get("path") or raw.strip(), "error": out.get("error")})
        return {"ok": len(errors) == 0, "written": written, "errors": errors}

    folder_raw = (payload.get("path") or "").strip()
    if not folder_raw:
        return JSONResponse({"error": "path required"}, status_code=400)
    out = _health_apply_tvshow_nfo_from_index(folder_raw, roots)
    if not out.get("ok"):
        err = out.get("error", "failed")
        if "Not a directory" in err:
            return JSONResponse({"error": err}, status_code=400)
        if "not under" in err.lower() or "library directory" in err.lower():
            return JSONResponse({"error": err}, status_code=400)
        return JSONResponse({"error": err}, status_code=409)
    return {"ok": True, "path": out.get("nfo"), "folder": folder_raw}


