@app.post("/api/health/library-video/phash-match")
async def health_library_video_phash_match(payload: dict = Body(...)):
    """Match a library file by perceptual hash (same order as queue: StashDB → TPDB → FansDB)."""
    v = _health_resolve_library_video_path(payload.get("path") or "")
    if isinstance(v, JSONResponse):
        return v
    try:
        dest_key = str(v.resolve())
    except OSError:
        dest_key = str(v)
    row = db.library_file_get_by_destination(dest_key)
    phash = None
    if row:
        phash = (
            (row.get("phash_3") or "").strip()
            or (row.get("phash_2") or "").strip()
            or (row.get("phash_1") or "").strip()
            or None
        )
    if not phash:
        try:
            loop = asyncio.get_event_loop()
            phash = await loop.run_in_executor(None, compute_phash, v)
        except Exception as e:
            return JSONResponse({"error": str(e)}, status_code=500)
    try:
        matches, src = query_with_fallback(phash)
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)
    formatted = []
    for m in matches or []:
        raw = copy.deepcopy(m)
        raw["_source"] = src
        perf_names = [p["performer"]["name"] for p in raw.get("performers") or []]
        description = (
            raw.get("details")
            or raw.get("description")
            or raw.get("synopsis")
            or ""
        )
        formatted.append(
            {
                "id": raw.get("id"),
                "title": raw.get("title") or "Unknown",
                "studio": (raw.get("studio") or {}).get("name") or "Unknown",
                "date": raw.get("release_date") or "",
                "performers": ", ".join(perf_names),
                "source": src,
                "image": best_image_url(raw.get("images") or []),
                "description": (description or "").strip(),
                "_raw": raw,
            }
        )
    return {"phash": phash, "source": src, "results": formatted}


@app.post("/api/health/library-video/apply")
async def health_library_video_apply(payload: dict = Body(...)):
    """Write NFO + -thumb.jpg beside a library video from a scene dict or manual metadata fields."""
    v = _health_resolve_library_video_path(payload.get("path") or "")
    if isinstance(v, JSONResponse):
        return v
    scene = payload.get("scene")
    source = (payload.get("source") or "").strip() or "Manual"

    if not scene:
        title = (payload.get("title") or "").strip()
        studio_n = (payload.get("studio") or "").strip()
        date = (payload.get("date") or "").strip()
        performers = (payload.get("performers") or "").strip()
        image_url = (payload.get("image_url") or "").strip()
        thumb_data_url = (payload.get("thumb_data_url") or "").strip()
        if not all([title, studio_n, date]):
            return JSONResponse(
                {"error": "Provide scene, or title + studio + date for manual entry"},
                status_code=400,
            )
        perf_list = [p.strip() for p in performers.split(",") if p.strip()]
        scene = {
            "title": title,
            "release_date": date,
            "studio": {"name": studio_n},
            "performers": [{"performer": {"name": n, "gender": ""}} for n in perf_list],
            "images": ([{"url": image_url, "width": 0, "height": 0}] if image_url else []),
            "_thumb_data_url": thumb_data_url,
        }
        source = "Manual"

    result = write_library_scene_nfo_and_thumb(v, scene, source=source)
    if result.get("status") == "error":
        return JSONResponse({"error": result.get("error", "error")}, status_code=400)
    if result.get("status") == "no_dir":
        return JSONResponse({"error": result.get("error", "no_dir")}, status_code=409)
    return {"ok": True, **result}


