    """Submit a manually-created scene to FansDB."""
    s = db.get_settings()
    api_key = s.get("api_key_fansdb", "")
    if not api_key:
        return JSONResponse({"error": "No FansDB API key configured"}, status_code=400)

    filename = payload.get("filename", "")
    phash    = db.get_phash(filename) if filename else None

    duration = 0
    if filename:
        s2 = db.get_settings()
        source_dir = Path(s2.get("source_dir", ""))
        video_path = source_dir / filename
        if not video_path.exists():
            hist = [r for r in db.get_history(limit=1000) if r["filename"] == filename]
            if hist and hist[0].get("destination"):
                video_path = Path(hist[0]["destination"])
        try:
            dur = get_video_duration(video_path)
            if dur:
                duration = int(dur)
        except Exception:
            pass

    result = fansdb_submit_scene(
        title         = payload.get("title", ""),
        date          = payload.get("date", ""),
        studio_id     = payload.get("studio_id"),
        performer_ids = payload.get("performer_ids", []),
        phash         = phash,
        details       = payload.get("plot", ""),
        image_url     = payload.get("image_url", ""),
        api_key       = api_key,
        duration      = duration,
    )
    return result


