@app.post("/api/thumb/generate")
async def generate_thumb(payload: dict):
    """Generate a thumbnail from a video at a random percent between 10-90."""
    import random
    path_raw = (payload.get("path") or "").strip()
    filename = payload.get("filename", "").strip()
    percent = payload.get("percent")
    if percent is None:
        percent = random.uniform(10, 90)

    s = db.get_settings()
    source_dir = Path(s.get("source_dir", ""))
    video = None
    if path_raw:
        roots = _health_library_roots()
        try:
            video = _health_assert_path_under_roots(path_raw, roots)
        except ValueError as e:
            return JSONResponse({"error": str(e)}, status_code=400)
    elif filename:
        video = source_dir / filename
    else:
        return JSONResponse({"error": "filename or path required"}, status_code=400)

    if not video.exists():
        return JSONResponse({"error": "File not found"}, status_code=404)

    loop = asyncio.get_event_loop()
    data_url = await loop.run_in_executor(
        None, capture_frame_as_base64, video, float(percent)
    )
    if not data_url:
        return JSONResponse({"error": "Frame capture failed"}, status_code=500)
    return {"data_url": data_url, "percent": round(percent, 1)}


@app.post("/api/download/process-all")
async def process_all_downloads(background_tasks: BackgroundTasks):
    """Manually trigger processing of all existing entries in scene and movie download watch folders."""
    s = db.get_settings()
    dl_raw = (s.get("download_watch_dir") or "").strip()
    dl_dir = Path(dl_raw).expanduser() if dl_raw else None
    mdl_raw = (s.get("movie_download_watch_dir") or "").strip()
    mdl_dir = Path(mdl_raw).expanduser() if mdl_raw else None
    mq_raw = (s.get("movies_source_dir") or "").strip()
    dest_movie_queue = Path(mq_raw).expanduser() if mq_raw else None

    #: Extensions that end up in a download watch folder but aren't
    #: actionable — NFOs, partial/temp files, subtitles, thumbnails. We
    #: delete these directly so the "N entries" count reflects only
    #: folders + video files that the pipeline will actually touch.
    junk_exts = {
        ".nfo", ".txt", ".url", ".html", ".htm", ".sfv", ".md5",
        ".part", ".!ut", ".tmp", ".crdownload", ".aria2", ".incomplete",
        ".srt", ".sub", ".idx", ".vtt", ".ass",
        ".jpg", ".jpeg", ".png", ".gif", ".webp",
    }
    skipped_junk: list[str] = []

    def collect_entries(base: Path | None) -> list[Path]:
        if base is None or not base.is_dir():
            return []
        actionable: list[Path] = []
        for e in base.iterdir():
            name = e.name
            if name in (".", "..") or name.startswith("."):
                continue
            if e.is_file():
                ext = e.suffix.lower()
                if ext in VIDEO_EXTENSIONS:
                    actionable.append(e)
                    continue
                # Junk file dropped by a client (sample thumbnail,
                # partial download, .nfo). Delete so it doesn't hang
                # around forever; log it so the user can see why the
                # count shrank.
                if ext in junk_exts:
                    try:
                        e.unlink()
                        skipped_junk.append(name)
                    except Exception as exc:
                        emit(f"  Could not delete junk file {name}: {exc}")
                # Unknown-type file: leave it alone, don't count it.
                continue
            if e.is_dir():
                actionable.append(e)
        return actionable

    scene_entries = collect_entries(dl_dir)
    movie_entries = collect_entries(mdl_dir)
    if skipped_junk:
        emit(f"Download cleanup: removed {len(skipped_junk)} junk file(s): {', '.join(skipped_junk[:8])}" + (" …" if len(skipped_junk) > 8 else ""))
    if not scene_entries and not movie_entries:
        msg = "No entries found (scene or movie watch dirs missing or empty)"
        if skipped_junk:
            msg = f"Cleaned up {len(skipped_junk)} junk file(s); no video downloads to process"
        return {"started": False, "message": msg, "cleaned": len(skipped_junk)}

    def run():
        for entry in scene_entries:
            try:
                ep = entry.resolve()
                dest_dir, derr = _dl_resolve_import_dest_dir(
                    s, "", str(ep.parent), str(ep),
                )
                if derr or not dest_dir:
                    emit(f"  SKIP {entry.name}: {derr}")
                    continue
                folder_name = entry.name
                _process_download_entry(entry, dest_dir)
                _remove_client_jobs_matching_watch_folder(folder_name, s)
            except Exception as e:
                emit(f"  ERROR processing {entry.name}: {e}")
        if movie_entries:
            if not mq_raw or not dest_movie_queue or not dest_movie_queue.is_dir():
                for entry in movie_entries:
                    emit(
                        f"  SKIP {entry.name}: Movie queue directory not set or not found "
                        "(configure Movie queue / movies source path — download import uses it, then files into Title (Year))."
                    )
            else:
                for entry in movie_entries:
                    try:
                        folder_name = entry.name
                        moved = _process_download_entry(entry, dest_movie_queue)
                        _remove_client_jobs_matching_watch_folder(folder_name, s)
                        for vpath in moved:
                            if vpath.suffix.lower() in VIDEO_EXTENSIONS:
                                process_movie_file(vpath.name)
                    except Exception as e:
                        emit(f"  ERROR processing movie watch {entry.name}: {e}")

    background_tasks.add_task(run)
    total = len(scene_entries) + len(movie_entries)
    return {"started": True, "count": total, "cleaned": len(skipped_junk)}


@app.post("/api/downloads/remove")
async def api_downloads_remove(payload: dict = Body(...)):
    """Remove a single job from its download client by id (qbit-/tr-/dl-/sab-q-/sab-h-/nzbget-/nzbget-h-)."""
    dl_id = (payload or {}).get("id", "").strip()
    if not dl_id:
        return {"ok": False, "error": "Missing id"}
    emit(f"Client remove (manual): {dl_id}")
    try:
        res = _download_remove_by_id(dl_id)
    except Exception as e:
        emit(f"  Client remove (manual) exception: {e}")
        return {"ok": False, "error": str(e)}
    if res.get("ok"):
        try:
            db.mark_download_import_done(dl_id)
        except Exception:
            pass
        emit(f"  Client remove (manual) ok: {dl_id}")
        return {"ok": True}
    err = res.get("error", "unknown")
    emit(f"  Client remove (manual) failed: {err}")
    return {"ok": False, "error": err}


@app.get("/api/scan/status")
async def scan_status():
    """Return pending scan info for all media servers."""
    now = time.time()
    with _scan_lock:
        pending = {
            server: max(0, int(fire_at - now))
            for server, fire_at in _scan_pending.items()
            if fire_at > now
        }
    return {"pending": pending}


@app.get("/api/watcher/status")
async def watcher_status():
    s = db.get_settings()
    with _pending_lock:
        pending = [{"filename": f, "fires_in": max(0, int(t - time.time()))}
                   for f, t in _pending_files.items()]
    with _download_lock:
        dl_pending = [{"path": p, "fires_in": max(0, int(t - time.time()))}
                      for p, t in _pending_downloads.items()]
        md_pending = [{"path": p, "fires_in": max(0, int(t - time.time()))}
                      for p, t in _pending_movie_downloads.items()]
    dl_dir = Path(s.get("download_watch_dir", ""))
    mdl_dir = Path((s.get("movie_download_watch_dir") or "").strip())
    return {
        "enabled":             s.get("folder_watch_enabled", "true").lower() == "true",
        "watching":            observer is not None and observer.is_alive() if observer else False,
        "hold_secs":           int(s.get("folder_watch_hold_secs", "60")),
        "pending":             pending,
        "download_enabled":    s.get("download_watch_enabled", "false").lower() == "true",
        "download_watching":   download_observer is not None and download_observer.is_alive() if download_observer else False,
        "download_dir":        str(dl_dir),
        "download_dir_exists": dl_dir.exists(),
        "movie_download_dir":        str(mdl_dir),
        "movie_download_dir_exists": mdl_dir.exists() if str(mdl_dir) else False,
        "download_hold_secs":  int(s.get("download_watch_hold_secs", "300")),
        "download_pending":    dl_pending + md_pending,
    }


