def _fetch_tpdb_feed(limit: int = 24) -> list[dict]:
    """Build a personalised feed from library performer directories.

    Uses a thread pool for parallel API calls and caches results for 15 min.
    """
    import random
    from concurrent.futures import ThreadPoolExecutor, as_completed

    s = db.get_settings()
    api_key = s.get("api_key_tpdb", "")
    if not api_key:
        return []

    # Gather performer names from library directories
    performer_dirs = db.get_directories("performer")
    performer_names = []
    for entry in performer_dirs:
        base = Path(entry["path"])
        if not base.is_dir():
            continue
        for folder in base.iterdir():
            if folder.is_dir() and not folder.name.startswith("."):
                performer_names.append(folder.name)

    if not performer_names:
        emit("FEED no performer folders found in library")
        return []

    # Sample up to 8 performers
    sample = random.sample(performer_names, min(8, len(performer_names)))
    emit(f"FEED fetching scenes for {len(sample)} performers (parallel)...")

    headers = _tpdb_headers()
    all_scenes = []

    # Parallel fetch — up to 4 concurrent requests
    with ThreadPoolExecutor(max_workers=4) as pool:
        futures = {pool.submit(_fetch_performer_scenes, name, headers): name for name in sample}
        for future in as_completed(futures):
            result = future.result()
            all_scenes.extend(result)

    # Deduplicate by id, sort by date descending
    seen = set()
    deduped = []
    for sc in all_scenes:
        if sc["id"] and sc["id"] not in seen:
            seen.add(sc["id"])
            deduped.append(sc)

    deduped.sort(key=lambda x: x.get("date", ""), reverse=True)
    result = deduped[:limit]

    emit(f"FEED built {len(result)} scenes from {len(sample)} performers")
    return result


def _preferred_display_genders(allowed: set[str] | None = None) -> set[str]:
    """Which performer genders the user actually wants to see on a hover
    label, derived from their Content Filter category toggles.

    - Any of straight / lesbian / solo_female enabled → show females.
    - Gay enabled → show males.
    - Trans enabled → show trans performers.

    If every category is on (no filtering), all genders qualify so the
    hover shows every performer.
    """
    if allowed is None:
        _, _, allowed = _get_content_filter_config()
    all_five = allowed and len(allowed) == 5
    out: set[str] = set()
    if all_five:
        return {"female", "male", "trans", "transgender_female", "transgender_male", ""}
    if allowed and ("straight" in allowed or "lesbian" in allowed or "solo_female" in allowed):
        out.add("female")
    if allowed and "gay" in allowed:
        out.add("male")
    if allowed and "trans" in allowed:
        out.update({"trans", "transgender_female", "transgender_male"})
    return out


def _scene_hover_performer_names(s_item: dict, allowed: set[str] | None = None) -> list[str]:
    """Names of performers on the scene whose gender matches the user's
    Content Filter preferences — used for the bottom-pill hover label on
    /scenes. Falls back to every performer when gender metadata is
    missing so we don't strip perfectly good labels just because TPDB
    didn't tag the gender field."""
    if not isinstance(s_item, dict):
        return []
    prefs = _preferred_display_genders(allowed)

    raw = s_item.get("performers") or s_item.get("credits") or []
    if not isinstance(raw, list):
        return []
    names_kept: list[str] = []
    names_any: list[str] = []
    seen_kept: set[str] = set()
    seen_any: set[str] = set()
    for p in raw:
        if isinstance(p, dict):
            perf = p.get("performer") or p
            name = (
                perf.get("name")
                or perf.get("full_name")
                or (p.get("parent") or {}).get("name")
                or ""
            ).strip()
            gender_candidates = [
                perf.get("gender"),
                perf.get("sex"),
                ((perf.get("extras") or {}).get("gender") if isinstance(perf.get("extras"), dict) else None),
                ((p.get("parent") or {}).get("extras", {}) or {}).get("gender") if isinstance(p.get("parent"), dict) else None,
                p.get("gender"),
            ]
            gender = ""
            for g in gender_candidates:
                if g and str(g).strip():
                    gender = str(g).strip().lower()
                    break
        elif isinstance(p, str):
            name = p.strip()
            gender = ""
        else:
            continue
        if not name:
            continue
        key_any = name.lower()
        if key_any not in seen_any:
            seen_any.add(key_any)
            names_any.append(name)
        if gender in prefs or (not gender and not prefs):
            # Keep when gender matches, or when we can't filter at all
            # (prefs empty = filtering off). Unknown gender still surfaces
            # via the fallback below if nothing else matches.
            if key_any not in seen_kept:
                seen_kept.add(key_any)
                names_kept.append(name)
    if names_kept:
        return names_kept
    # Fallback: TPDB didn't tag any performer's gender — return all names
    # rather than an empty pill so the user still sees context.
    return names_any


def _tpdb_scene_tag_names(s_item: dict) -> list[str]:
    """Ordered list of display tag names from a TPDB scene payload.

    Preserves TPDB's original tag order and titlecases for display (the
    payload usually ships lowercase). Dedupes case-insensitively.
    """
    if not isinstance(s_item, dict):
        return []
    raw = s_item.get("tags")
    if not isinstance(raw, list):
        return []
    out: list[str] = []
    seen: set[str] = set()
    for t in raw:
        name = ""
        if isinstance(t, str):
            name = t.strip()
        elif isinstance(t, dict):
            name = (t.get("name") or t.get("label") or "").strip()
            if not name and isinstance(t.get("tag"), dict):
                name = (t["tag"].get("name") or "").strip()
        if not name:
            continue
        key = name.lower()
        if key in seen:
            continue
        seen.add(key)
        # TPDB sends lowercase; titlecase so "anal" → "Anal", but keep
        # multi-word phrases like "big tits" sensible → "Big Tits".
        out.append(" ".join(w[:1].upper() + w[1:] for w in name.split()))
    return out


def _tpdb_pick_thumb(s_item: dict) -> str:
    """Pick the best-loading thumbnail URL from a TPDB scene payload.

    TPDB responses include several image fields with different reliability:
    - ``posters`` / ``background`` — dicts with ``full/large/medium/small``
      keys, all TPDB-proxied CDN URLs (reliable, no hotlink protection).
    - ``poster`` — TPDB-proxied single URL (reliable).
    - ``image`` — direct studio CDN (mature.nl, manyvids.com etc.) that
      often 403s from a browser due to hotlink protection or expired tokens.
    - ``poster_image`` — almost always null on current TPDB responses.

    Prefer ``posters.medium`` as the happy path; fall back through the
    other TPDB-hosted fields before the brittle direct-CDN ``image``.
    """
    if not isinstance(s_item, dict):
        return ""

    posters = s_item.get("posters")
    if isinstance(posters, dict):
        for k in ("medium", "large", "small", "full"):
            v = posters.get(k)
            if isinstance(v, str) and v:
                return v
    elif isinstance(posters, list):
        for p in posters:
            if isinstance(p, str) and p:
                return p
            if isinstance(p, dict):
                for k in ("url", "medium", "large", "small", "full"):
                    v = p.get(k)
                    if isinstance(v, str) and v:
                        return v

    bg = s_item.get("background")
    if isinstance(bg, dict):
        for k in ("medium", "large", "small", "full", "url"):
            v = bg.get(k)
            if isinstance(v, str) and v:
                return v

    for key in ("poster", "poster_image", "image"):
        v = s_item.get(key)
        if isinstance(v, str) and v:
            return v
        if isinstance(v, dict):
            for k in ("medium", "large", "small", "full", "url"):
                u = v.get(k)
                if isinstance(u, str) and u:
                    return u

    return ""


def _tpdb_scene_payload_to_feed_card(s_item: dict, source: str = "api") -> dict | None:
    """Single scene resource → feed card, or None if filtered out."""
    genders = _extract_movie_genders(s_item)
    if not _passes_content_filter(genders):
        return None
    if not _passes_tag_filter(s_item):
        return None
    thumb = _tpdb_pick_thumb(s_item)
    perf_names = []
    for p in s_item.get("performers") or s_item.get("credits") or []:
        if isinstance(p, dict):
            n = (p.get("name") or p.get("parent", {}).get("name") or "").strip()
            if n:
                perf_names.append(n)
        elif isinstance(p, str) and p.strip():
            perf_names.append(p.strip())
    return {
        "id": str(s_item.get("_id") or s_item.get("id") or ""),
        "title": s_item.get("title", ""),
        "date": s_item.get("date", ""),
        "studio": (s_item.get("site") or {}).get("name", ""),
        "performer": ", ".join(perf_names),
        "hover_performers": _scene_hover_performer_names(s_item),
        "thumb": thumb,
        "link": "",
        "source": source,
        "tags": _tpdb_scene_tag_names(s_item),
        "description": (s_item.get("description") or s_item.get("synopsis") or "").strip(),
    }


def _tpdb_atom_feed_scene_ids(xml_text: str) -> list[str]:
    """Parse TPDB Atom feeds; return scene UUIDs in document order."""
    import re
    uuid_re = re.compile(
        r"([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})",
        re.I,
    )
    try:
        root = ET.fromstring(xml_text)
    except Exception:
        return []
    ns = {"atom": "http://www.w3.org/2005/Atom"}
    entries = root.findall("atom:entry", ns) or root.findall("entry")
    out: list[str] = []
    for entry in entries:
        sid = None
        for link in list(entry.findall("atom:link", ns)) + list(entry.findall("link")):
            href = (link.get("href") or "").strip()
            m = uuid_re.search(href)
            if m:
                sid = m.group(1).lower()
                break
        if not sid:
            id_el = entry.find("atom:id", ns) or entry.find("id")
            if id_el is not None and (id_el.text or "").strip():
                m = uuid_re.search(id_el.text)
                if m:
                    sid = m.group(1).lower()
        if sid:
            out.append(sid)
    return out


TPDB_RSS_FAVORITE_PERFORMERS = (
    "https://theporndb.net/feeds/scenes/recently-added-by-favorite-performers"
)
TPDB_RSS_FAVORITE_SITES = (
    "https://theporndb.net/feeds/scenes/recently-added-by-favorite-sites"
)


def _fetch_tpdb_favorite_rss_feed_scenes(feed_url: str, limit: int, source_tag: str) -> list[dict]:
    """Hydrate scene cards from a single TPDB Atom feed URL (API key auth)."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    if not (db.get_settings().get("api_key_tpdb") or "").strip():
        return []

    headers = _tpdb_headers()
    ordered_ids: list[str] = []
    try:
        resp = requests.get(feed_url, headers=headers, timeout=22)
        if resp.status_code != 200:
            emit(f"FEED RSS fetch HTTP {resp.status_code} ({feed_url})")
            return []
        ordered_ids = _tpdb_atom_feed_scene_ids(resp.text)
    except Exception as e:
        emit(f"FEED RSS fetch error ({feed_url}): {e}")
        return []

    if not ordered_ids:
        emit(f"FEED RSS: no entries ({feed_url})")
        return []

    take = ordered_ids[: max(limit * 2, limit)]

    def _one(sid: str) -> tuple[str, dict | None]:
        try:
            resp = requests.get(
                f"https://api.theporndb.net/scenes/{sid}",
                headers=_tpdb_headers(),
                timeout=14,
            )
            if resp.status_code != 200:
                return sid, None
            data = resp.json().get("data") or {}
            card = _tpdb_scene_payload_to_feed_card(data, source=source_tag)
            return sid, card
        except Exception:
            return sid, None

    by_id: dict[str, dict] = {}
    with ThreadPoolExecutor(max_workers=4) as pool:
        futures = [pool.submit(_one, sid) for sid in take]
        for fut in as_completed(futures):
            try:
                sid, card = fut.result()
                if card:
                    by_id[sid] = card
            except Exception:
                pass

    ordered = [by_id[sid] for sid in take if sid in by_id]
    ordered.sort(key=lambda x: x.get("date", ""), reverse=True)
    result = ordered[:limit]
    emit(f"FEED RSS ({source_tag}): {len(result)} scenes (from {len(ordered_ids)} feed ids)")
    return result


def _fetch_tpdb_feed_from_favorites_rss(limit: int = 24) -> list[dict]:
    """Scenes from both TPDB favourite-atom feeds (performers then sites), deduped."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    if not (db.get_settings().get("api_key_tpdb") or "").strip():
        return []

    headers = _tpdb_headers()
    feed_urls = (TPDB_RSS_FAVORITE_PERFORMERS, TPDB_RSS_FAVORITE_SITES)
    seen: set[str] = set()
    ordered_ids: list[str] = []
    for url in feed_urls:
        try:
            resp = requests.get(url, headers=headers, timeout=22)
            if resp.status_code != 200:
                continue
            for sid in _tpdb_atom_feed_scene_ids(resp.text):
                if sid not in seen:
                    seen.add(sid)
                    ordered_ids.append(sid)
        except Exception as e:
            emit(f"FEED RSS fetch error ({url}): {e}")

    if not ordered_ids:
        emit("FEED RSS: no entries (add favourite performers/sites on ThePornDB, or check API key)")
        return []

    take = ordered_ids[: max(limit * 2, limit)]

    def _one(sid: str) -> tuple[str, dict | None]:
        try:
            resp = requests.get(
                f"https://api.theporndb.net/scenes/{sid}",
                headers=_tpdb_headers(),
                timeout=14,
            )
            if resp.status_code != 200:
                return sid, None
            data = resp.json().get("data") or {}
            card = _tpdb_scene_payload_to_feed_card(data, source="rss_favorites")
            return sid, card
        except Exception:
            return sid, None

    by_id: dict[str, dict] = {}
    with ThreadPoolExecutor(max_workers=4) as pool:
        futures = [pool.submit(_one, sid) for sid in take]
        for fut in as_completed(futures):
            try:
                sid, card = fut.result()
                if card:
                    by_id[sid] = card
            except Exception:
                pass

    ordered = [by_id[sid] for sid in take if sid in by_id]
    ordered.sort(key=lambda x: x.get("date", ""), reverse=True)
    result = ordered[:limit]
    emit(f"FEED RSS favourites: {len(result)} scenes (from {len(ordered_ids)} feed ids)")
    return result


def _fetch_tpdb_feed_from_api(limit: int = 24) -> list[dict]:
    """Fallback: fetch latest scenes from TPDB API (not personalised)."""
    try:
        resp = requests.get(
            "https://api.theporndb.net/scenes",
            params={"page": 1, "per_page": limit},
            headers=_tpdb_headers(),
            timeout=15,
        )
        if resp.status_code != 200:
            return []
        data = resp.json().get("data") or []
        out = []
        for s_item in data:
            card = _tpdb_scene_payload_to_feed_card(s_item, source="api")
            if card:
                out.append(card)
        return out
    except Exception:
        return []


# Combined raw-scene cache for all monitored tags. TPDB's ``tags[]``
# filter only works when 2+ values are sent — a single value returns
# global latest (ignored filter), so per-tag pools don't actually
# filter. Workaround: one combined pool of scenes matching ANY monitored
# tag, then filter client-side per selection at feed time.
_tag_combined_pool: dict = {"scenes": [], "ts": 0.0, "key": ""}
_TAG_POOL_TTL = 1800  # 30 min
_TAG_POOL_DEEP = 300  # fetch up to 300 scenes across pages


def _fetch_tpdb_scenes_for_tags(tag_ids: list[str], max_scenes: int = _TAG_POOL_DEEP) -> list[dict]:
    """Fetch scenes that carry ANY of ``tag_ids`` from TPDB in a single
    ``tags[]`` array filter. Paginates up to ``max_scenes``. Requires 2+
    tag ids to trigger TPDB's actual array filter (single value is
    silently treated as no filter); if only one id is supplied the same
    id is padded in so the filter still engages.
    """
    ids = [str(t).strip() for t in tag_ids or [] if t and str(t).strip()]
    if not ids:
        return []
    # Pad a single id so the array length is always >= 2.
    effective = ids if len(ids) >= 2 else ids + ids
    headers = _tpdb_headers()
    out: list[dict] = []
    page = 1
    page_size = 50
    while len(out) < max_scenes and page <= 8:
        try:
            params: list[tuple[str, str]] = [
                ("per_page", str(page_size)),
                ("page", str(page)),
            ]
            params.extend(("tags[]", tid) for tid in effective)
            resp = requests.get(
                "https://api.theporndb.net/scenes",
                params=params,
                headers=headers,
                timeout=15,
            )
            if resp.status_code != 200:
                emit(f"FEED tags combined fetch page {page}: HTTP {resp.status_code} body={resp.text[:140]}")
                break
            data = resp.json().get("data") or []
            if not data:
                if page == 1:
                    emit(f"FEED tags combined fetch: 0 results url={resp.url[:180]}")
                break
            out.extend(data)
            if len(data) < page_size:
                break
            page += 1
        except Exception as e:
            emit(f"FEED tags combined fetch page {page} exception: {e}")
            break
    return out[:max_scenes]


def _combined_pool_key_from_monitored(stored: list) -> tuple[str, list[str]]:
    """Turn a monitored_tags payload into (cache_key, tag_ids)."""
    ids: list[str] = []
    seen: set[str] = set()
    for t in stored or []:
        if not isinstance(t, dict):
            continue
        tid = str(t.get("slug") or t.get("id") or "").strip()
        if tid and tid not in seen:
            seen.add(tid)
            ids.append(tid)
    return (",".join(sorted(ids)), ids)


def _tag_combined_scene_pool() -> list[dict]:
    """Return a fresh-enough combined pool of scenes carrying any
    monitored tag. Refetches if expired or if the monitored-tag set
    changed since the last cache write."""
    try:
        stored = json.loads(db.get_settings().get("monitored_tags") or "[]")
    except Exception:
        stored = []
    key, tag_ids = _combined_pool_key_from_monitored(stored if isinstance(stored, list) else [])
    if not tag_ids:
        return []
    with _content_cache_lock:
        ts = float(_tag_combined_pool.get("ts") or 0)
        scenes = _tag_combined_pool.get("scenes") or []
        cached_key = _tag_combined_pool.get("key") or ""
        if scenes and cached_key == key and (time.time() - ts) < _TAG_POOL_TTL:
            return scenes
    fresh = _fetch_tpdb_scenes_for_tags(tag_ids)
    with _content_cache_lock:
        _tag_combined_pool["scenes"] = fresh
        _tag_combined_pool["ts"] = time.time()
        _tag_combined_pool["key"] = key
    emit(f"FEED tags combined pool: cached {len(fresh)} raw scenes for {len(tag_ids)} monitored tags")
    return fresh


def _refresh_tag_scene_pools() -> None:
    """Warm the combined monitored-tag pool. Called on startup and by
    the APScheduler job so selections on /scenes are served instantly."""
    if not (db.get_settings().get("api_key_tpdb") or "").strip():
        return
    # Invalidate so the next call refetches. _tag_combined_scene_pool
    # handles the actual fetch + cache write.
    with _content_cache_lock:
        _tag_combined_pool["ts"] = 0.0
    _tag_combined_scene_pool()


def _fetch_tpdb_tags_feed_scenes(
    tag_tokens: list[str],
    limit: int = 30,
    selected_names: set[str] | None = None,
    name_by_token: dict[str, str] | None = None,
) -> list[dict]:
    """Filter the combined monitored-tag pool by the user's current
    selection, apply category/blacklist, sort by date desc, return top-N.

    The combined pool contains scenes carrying ANY monitored tag.
    At feed time we filter client-side: a scene is kept only if its
    ``tags[]`` payload actually includes at least one of the currently
    selected tag ids (or exact-lowercase name). ``matched_tags`` is the
    monitored display names genuinely present on the scene.
    """
    toks = [t.strip() for t in (tag_tokens or []) if t and t.strip()]
    if not toks:
        return []
    tok_to_name = name_by_token or {}
    selected_ids: set[str] = {str(t) for t in toks}

    # Build monitored lookups for the *selection* only — scene tags may
    # carry an id (preferred) or just a name; exact equality only.
    sel_by_id: dict[str, str] = {}
    sel_by_name_lower: dict[str, str] = {}
    for tid, raw_name in tok_to_name.items():
        display = (raw_name or "").strip()
        if not display:
            continue
        if tid and str(tid) in selected_ids:
            sel_by_id[str(tid)] = display
            sel_by_name_lower[display.lower()] = display

    merged = _tag_combined_scene_pool()
    if not merged:
        emit("FEED tags: combined pool empty (not warmed yet, or monitored list empty)")
        return []

    # Sort by date desc so newest-first.
    merged = sorted(merged, key=lambda s: str((s or {}).get("date") or ""), reverse=True)

    def _scene_monitored_matches(s_item: dict) -> list[str]:
        """Display names of the currently-selected monitored tags that
        actually appear on this scene's ``tags[]`` payload (by id or
        exact lowercase name)."""
        raw = (s_item or {}).get("tags")
        if not isinstance(raw, list):
            return []
        matched_names: list[str] = []
        seen: set[str] = set()
        for t in raw:
            hit: str | None = None
            if isinstance(t, dict):
                for k in ("id", "_id", "uuid"):
                    v = t.get(k)
                    if v is not None and str(v) in sel_by_id:
                        hit = sel_by_id[str(v)]
                        break
                if hit is None:
                    name = (t.get("name") or t.get("label") or "").strip()
                    if not name and isinstance(t.get("tag"), dict):
                        name = (t["tag"].get("name") or "").strip()
                    if name and name.lower() in sel_by_name_lower:
                        hit = sel_by_name_lower[name.lower()]
            elif isinstance(t, str):
                key = t.strip().lower()
                if key in sel_by_name_lower:
                    hit = sel_by_name_lower[key]
            if hit and hit not in seen:
                seen.add(hit)
                matched_names.append(hit)
        return matched_names

    out: list[dict] = []
    dropped_filter = 0
    dropped_no_match = 0
    for s_item in merged:
        if len(out) >= limit:
            break
        matches = _scene_monitored_matches(s_item)
        if not matches:
            dropped_no_match += 1
            continue
        try:
            card = _tpdb_scene_payload_to_feed_card(s_item, source="tags")
        except Exception as e:
            emit(f"FEED tags card exception: {e}")
            continue
        if not card:
            dropped_filter += 1
            continue
        card["matched_tags"] = matches
        out.append(card)
    emit(
        f"FEED tags merged: {len(out)} cards "
        f"({len(merged)} pool, {dropped_filter} category/blacklist, "
        f"{dropped_no_match} no-monitored-tag)"
    )
    return out


def _fetch_tpdb_studios_feed_scenes(limit: int = 24) -> tuple[list[dict], str]:
    """Studios tab: Favourites-index studios → TPDB favourite-site RSS → global API."""
    scenes = _fetch_tpdb_indexed_studios_feed(limit)
    if scenes:
        return scenes, "indexed_studios"
    scenes = _fetch_tpdb_favorite_rss_feed_scenes(
        TPDB_RSS_FAVORITE_SITES, limit, "rss_favorite_sites"
    )
    if scenes:
        return scenes, "rss_favorite_sites"
    scenes = _fetch_tpdb_feed_from_api(limit)
    return scenes, "api"


def _fetch_tpdb_feed_page_scenes(limit: int = 24) -> list[dict]:
    """Fetch the TPDB /feed page via Inertia.js JSON protocol.

    Returns the full favourite-performer feed (scenes grouped by date → performer)
    in a single request — no per-scene hydration needed.
    """
    api_key = (db.get_settings().get("api_key_tpdb") or "").strip()
    if not api_key:
        return []
    try:
        headers = {
            "Accept": "text/html, application/xhtml+xml",
            "Authorization": f"Bearer {api_key}",
            "Cookie": f"api_token={api_key}",
        }
        resp = requests.get("https://theporndb.net/feed", headers=headers, timeout=22)
        if resp.status_code != 200:
            emit(f"FEED page fetch HTTP {resp.status_code}")
            return []
        # Parse the Inertia page data from the embedded JSON
        import re as _re
        m = _re.search(r'<script[^>]*data-page="app"[^>]*type="application/json"[^>]*>(.*?)</script>', resp.text, _re.DOTALL)
        if not m:
            emit("FEED page: no Inertia data found")
            return []
        page_data = json.loads(m.group(1))
        feed_days = page_data.get("props", {}).get("feed", [])
        if not feed_days:
            emit("FEED page: feed array empty")
            return []
        # Over-collect before hydration so the post-hydrate tag-blacklist
        # drop still leaves enough cards to fill the grid. Cap the
        # oversample so a busy feed page doesn't explode the per-scene
        # hydrate cost (6 parallel requests per card).
        oversample_cap = min(limit * 2, 60)
        cards: list[dict] = []
        for day in feed_days:
            for perf_entry in day.get("performers", []):
                perf_info = perf_entry.get("performer", {})
                perf_name = perf_info.get("name", "")
                for scene in perf_entry.get("scenes", []):
                    bg = scene.get("background") or {}
                    thumb = ""
                    if isinstance(bg, dict):
                        thumb = bg.get("small") or bg.get("medium") or bg.get("url") or ""
                    site = scene.get("site") or {}
                    # Build performer string from scene performers list
                    scene_perfs = scene.get("performers") or []
                    perf_names = [p.get("name", "") for p in scene_perfs if p.get("name")]
                    card = {
                        "id": str(scene.get("id", "")),
                        "title": scene.get("title", ""),
                        "date": scene.get("date", ""),
                        "studio": site.get("name", ""),
                        "performer": ", ".join(perf_names) if perf_names else perf_name,
                        "hover_performers": _scene_hover_performer_names(scene) or ([perf_name] if perf_name else []),
                        "thumb": thumb,
                        "link": scene.get("link", ""),
                        "source": "tpdb_feed",
                        "tags": _tpdb_scene_tag_names(scene),
                        "description": (scene.get("description") or scene.get("synopsis") or "").strip(),
                    }
                    # Content filtering
                    genders = [p.get("gender", "") for p in scene_perfs]
                    if not _passes_content_filter(genders):
                        continue
                    cards.append(card)
                    if len(cards) >= oversample_cap:
                        break
                if len(cards) >= oversample_cap:
                    break
            if len(cards) >= oversample_cap:
                break
        emit(f"FEED page: collected {len(cards)} scenes from {len(feed_days)} days (target {limit}, oversample cap {oversample_cap})")
        # Hydrate tags + description + hover_performers from /scenes/{id}
        # — the Inertia feed page ships a trimmed scene payload without
        # tag or description fields, so cards from here arrive with empty
        # tag arrays. Parallelise at 6 workers so the 30-scene hydrate
        # completes in about the same time as a single scene detail.
        # Hydrate also applies the tag blacklist (only possible once
        # tags are loaded), so it may return a shorter list.
        try:
            cards = _hydrate_performers_feed_cards(cards)
        except Exception as e:
            emit(f"FEED page hydrate error: {e}")
        return cards[:limit]
    except Exception as e:
        emit(f"FEED page fetch error: {e}")
        return []


def _hydrate_performers_feed_cards(cards: list[dict]) -> list[dict]:
    """Fill in ``tags``, ``description``, and ``hover_performers`` on each
    card by fetching ``/scenes/{id}`` in parallel. Returns the list with
    blacklisted-tag cards removed — the TPDB Inertia feed page ships a
    trimmed payload with no tags, so we can only honour the blacklist
    after this hydration step. Cards whose detail fetch fails keep the
    trimmed data and stay in the list (fail-open for transient errors)."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    if not cards:
        return cards
    headers = _tpdb_headers()

    def _hydrate(card: dict) -> dict | None:
        sid = (card.get("id") or "").strip()
        if not sid:
            return None
        try:
            r = requests.get(
                f"https://api.theporndb.net/scenes/{sid}",
                headers=headers,
                timeout=10,
            )
            if r.status_code != 200:
                return None
            return (r.json() or {}).get("data") or None
        except Exception:
            return None

    to_drop: set[int] = set()
    with ThreadPoolExecutor(max_workers=6) as pool:
        futs = {pool.submit(_hydrate, c): c for c in cards}
        for fut in as_completed(futs):
            card = futs[fut]
            try:
                payload = fut.result()
            except Exception:
                payload = None
            if not payload:
                continue
            # Now that we have the full payload, apply the tag blacklist.
            # The feed-page parser couldn't check this earlier because
            # the Inertia payload didn't include the tags array.
            if not _passes_tag_filter(payload):
                to_drop.add(id(card))
                continue
            tags = _tpdb_scene_tag_names(payload)
            if tags:
                card["tags"] = tags
            desc = (payload.get("description") or payload.get("synopsis") or "").strip()
            if desc and not card.get("description"):
                card["description"] = desc
            hp = _scene_hover_performer_names(payload)
            if hp:
                card["hover_performers"] = hp
    if to_drop:
        before = len(cards)
        cards = [c for c in cards if id(c) not in to_drop]
        emit(f"TAG-FILTER tpdb feed-page: dropped {before - len(cards)} of {before} by blacklist")
    return cards


def _fetch_tpdb_performers_feed_scenes(limit: int = 24) -> tuple[list[dict], str]:
    """Performers tab: TPDB feed page → RSS fallback → API fallback."""
    # Try the rich feed page first (single request, full data)
    scenes = _fetch_tpdb_feed_page_scenes(limit)
    if scenes:
        return scenes, "tpdb_feed_page"
    # Fall back to RSS Atom feed + per-scene hydration
    scenes = _fetch_tpdb_favorite_rss_feed_scenes(
        TPDB_RSS_FAVORITE_PERFORMERS, limit, "rss_favorite_performers"
    )
    if scenes:
        return scenes, "rss_favorite_performers"
    scenes = _fetch_tpdb_feed(limit)
    if scenes:
        return scenes, "feed"
    scenes = _fetch_tpdb_feed_from_api(limit)
    return scenes, "api"


def _refresh_hourly_content_cache():
    """Background refresh: all three TPDB scene feed modes + movies latest cache."""
    try:
        fk = _content_filters_fingerprint()
        now = time.time()

        _cl = 30
        studios_scenes, studios_src = _fetch_tpdb_studios_feed_scenes(_cl)
        perf_scenes, perf_src = _fetch_tpdb_performers_feed_scenes(_cl)
        scenes_rand = _fetch_tpdb_feed(_cl)
        source_rand = "feed"
        if not scenes_rand:
            scenes_rand = _fetch_tpdb_feed_from_api(_cl)
            source_rand = "api"
        scenes_fav = _fetch_tpdb_starred_favourites_feed(_cl)
        source_fav = "favourites" if scenes_fav else "favourites_empty"

        with _content_cache_lock:
            _feed_cache["studios"] = {
                "scenes": studios_scenes,
                "ts": now,
                "source": studios_src,
                "filter_key": fk,
            }
            _feed_cache["performers"] = {
                "scenes": perf_scenes,
                "ts": now,
                "source": perf_src,
                "filter_key": fk,
            }
            _feed_cache["random"] = {
                "scenes": scenes_rand,
                "ts": now,
                "source": source_rand,
                "filter_key": fk,
            }
            _feed_cache["favourites"] = {
                "scenes": scenes_fav,
                "ts": now,
                "source": source_fav,
                "filter_key": fk,
            }

        movies_payload = _collect_filtered_tpdb_movies({}, page=1, page_size=30)
        with _content_cache_lock:
            _movies_latest_cache["results"] = movies_payload.get("results", [])
            _movies_latest_cache["ts"] = time.time()
            _movies_latest_cache["filter_key"] = _movies_cache_filter_key()
        emit(
            f"CACHE hourly refresh: studios={len(studios_scenes)} performers={len(perf_scenes)} "
            f"random={len(scenes_rand)} favourites={len(scenes_fav)} "
            f"movies={len(_movies_latest_cache['results'])}"
        )
    except Exception as e:
        emit(f"CACHE hourly refresh error: {e}")


def _sync_library_to_tpdb_favourites() -> dict:
    """Sync library performer + studio directories → TPDB favourites.

    For each performer/studio folder in the library, search TPDB for a match
    and add them to the user's TPDB favourites.
    """
    from concurrent.futures import ThreadPoolExecutor, as_completed

    s = db.get_settings()
    api_key = s.get("api_key_tpdb", "")
    if not api_key:
        return {"error": "No TPDB API key configured"}

    headers = _tpdb_headers()

    # Gather performer names from all performer directories
    performer_dirs = db.get_directories("performer")
    performer_names = []
    for entry in performer_dirs:
        base = Path(entry["path"])
        if not base.is_dir():
            continue
        for folder in base.iterdir():
            if folder.is_dir() and not folder.name.startswith("."):
                performer_names.append(folder.name)

    # Gather studio names from series directory
    series_dir = s.get("series_dir", "").strip()
    studio_names = []
    if series_dir and Path(series_dir).is_dir():
        for folder in Path(series_dir).iterdir():
            if folder.is_dir() and not folder.name.startswith("."):
                studio_names.append(folder.name)

    if not performer_names and not studio_names:
        return {"performers": {"added": 0, "skipped": 0, "failed": 0},
                "studios": {"added": 0, "skipped": 0, "failed": 0},
                "message": "No library folders found"}

    emit(f"SYNC→FAVS syncing {len(performer_names)} performers + {len(studio_names)} studios")

    def _add_performer(name: str) -> str:
        try:
            resp = requests.get(TPDB_PERFORMER_SEARCH, params={"q": name},
                                headers=headers, timeout=10)
            if resp.status_code != 200:
                return "failed"
            perf_data = resp.json().get("data") or []
            if not perf_data:
                return "failed"
            perf_id = perf_data[0].get("id") or perf_data[0].get("_id")
            if not perf_id:
                return "failed"
            fav_resp = requests.post(
                f"https://api.theporndb.net/performers/{perf_id}/favorite",
                headers=headers, timeout=10)
            return "added" if fav_resp.status_code in (200, 201) else "skipped"
        except Exception:
            return "failed"

    def _add_studio(name: str) -> str:
        try:
            resp = requests.get(TPDB_STUDIO_SEARCH, params={"q": name},
                                headers=headers, timeout=10)
            if resp.status_code != 200:
                return "failed"
            site_data = resp.json().get("data") or []
            if not site_data:
                return "failed"
            site_id = site_data[0].get("id") or site_data[0].get("_id")
            if not site_id:
                return "failed"
            fav_resp = requests.post(
                f"https://api.theporndb.net/sites/{site_id}/favorite",
                headers=headers, timeout=10)
            return "added" if fav_resp.status_code in (200, 201) else "skipped"
        except Exception:
            return "failed"

    def _count_results(futures_dict):
        added = skipped = failed = 0
        for future in as_completed(futures_dict):
            r = future.result()
            if r == "added": added += 1
            elif r == "skipped": skipped += 1
            else: failed += 1
        return {"added": added, "skipped": skipped, "failed": failed}

    with ThreadPoolExecutor(max_workers=4) as pool:
        perf_futures = {pool.submit(_add_performer, n): n for n in performer_names}
        studio_futures = {pool.submit(_add_studio, n): n for n in studio_names}
        perf_result = _count_results(perf_futures)
        studio_result = _count_results(studio_futures)

    emit(f"SYNC→FAVS performers: {perf_result} | studios: {studio_result}")
    return {"performers": perf_result, "studios": studio_result}


def sync_tpdb_favourites() -> dict:
    """Sync TPDB favourites with library directories — create missing TVShow folders."""
    s = db.get_settings()
    if s.get("tpdb_sync_enabled", "false") != "true":
        return {"skipped": True}

    api_key = s.get("api_key_tpdb", "")
    if not api_key:
        return {"error": "No TPDB API key configured"}

    performer_dir = s.get("tpdb_sync_performer_dir", "").strip()
    studio_dir = s.get("tpdb_sync_studio_dir", "").strip()
    created = []

    # Fetch favourited performers via RSS
    try:
        resp = requests.get(
            "https://theporndb.net/feeds/scenes/recently-added-by-favorite-performers",
            headers={"Authorization": f"Bearer {api_key}"},
            timeout=20,
        )
        if resp.status_code == 200:
            import xml.etree.ElementTree as ET
            root = ET.fromstring(resp.text)
            ns = {"atom": "http://www.w3.org/2005/Atom"}
            # Extract unique performer names from feed entries
            performer_names = set()
            for entry in root.findall("atom:entry", ns) or root.findall("entry"):
                cat_els = entry.findall("atom:category", ns) or entry.findall("category")
                for cat in cat_els:
                    term = cat.get("term", "")
                    if term:
                        performer_names.add(term)

            if performer_dir and Path(performer_dir).is_dir():
                existing = {d.name.lower() for d in Path(performer_dir).iterdir() if d.is_dir()}
                for name in performer_names:
                    if name.lower() not in existing:
                        folder = Path(performer_dir) / name
                        try:
                            folder.mkdir(parents=True, exist_ok=True)
                            # Create basic tvshow.nfo
                            nfo = build_performer_tvshow_nfo({"name": name})
                            (folder / "tvshow.nfo").write_text(nfo, encoding="utf-8")
                            created.append(str(folder))
                            emit(f"SYNC created performer folder: {folder}")
                        except Exception as e:
                            emit(f"SYNC error creating {folder}: {e}")
    except Exception as e:
        emit(f"SYNC performer feed error: {e}")

    # Also sync library → TPDB favourites if enabled
    to_favs_result = {}
    if s.get("tpdb_sync_to_favs", "false") == "true":
        to_favs_result = _sync_library_to_tpdb_favourites()

    return {"created": created, "count": len(created), "to_favs": to_favs_result}


def _tpdb_resolve_entity(endpoint_path: str, name: str, limit: int = 8) -> list[dict]:
    """GET https://api.theporndb.net/{endpoint_path}?q=<name>. Returns
    the raw ``data`` list (list of {id, name, slug}). Used to resolve
    performer / site / studio / tag names to numeric ids for precise
    filter-based scene search."""
    name = (name or "").strip()
    if not name:
        return []
    try:
        r = requests.get(
            f"https://api.theporndb.net/{endpoint_path.strip('/')}",
            params={"q": name, "per_page": str(limit)},
            headers=_tpdb_headers(),
            timeout=10,
        )
        if r.status_code == 200:
            return (r.json() or {}).get("data") or []
    except Exception as e:
        emit(f"search TPDB resolve {endpoint_path} {name!r}: {e}")
    return []


def _best_name_match(items: list[dict], wanted: str) -> list[str]:
    """From a list of ``{id, name, ...}``, pick items whose ``name``
    matches ``wanted`` exactly (case-insensitive). Returns **only**
    exact matches — no fuzzy fallback — so scene searches produce
    zero results rather than mis-filtered ones when the queried name
    doesn't actually exist on the source."""
    if not items:
        return []
    low = (wanted or "").strip().lower()
    return [str(x.get("id")) for x in items
            if str(x.get("name", "")).strip().lower() == low and x.get("id") is not None]


def _stashbox_resolve_entity(endpoint: str, api_key: str, kind: str, name: str) -> list[str]:
    """Resolve a performer / studio / tag NAME to ID(s) via the
    Stash-box GraphQL API. ``kind`` ∈ {'performer', 'studio', 'tag'}."""
    name = (name or "").strip()
    if not name or not api_key:
        return []
    queries = {
        "performer": """
            query R($n: String!) {
              queryPerformers(input: {name: $n, page: 1, per_page: 10}) {
                performers { id name }
              }
            }
        """,
        "studio": """
            query R($n: String!) {
              queryStudios(input: {name: $n, page: 1, per_page: 10}) {
                studios { id name }
              }
            }
        """,
        "tag": """
            query R($n: String!) {
              queryTags(input: {name: $n, page: 1, per_page: 10}) {
                tags { id name }
              }
            }
        """,
    }
    gql = queries.get(kind)
    if not gql:
        return []
    try:
        r = requests.post(
            endpoint,
            headers={"ApiKey": api_key, "Content-Type": "application/json"},
            json={"query": gql, "variables": {"n": name}},
            timeout=10,
        )
        if r.status_code != 200:
            return []
        body = (r.json() or {}).get("data") or {}
        root = {
            "performer": body.get("queryPerformers"),
            "studio":    body.get("queryStudios"),
            "tag":       body.get("queryTags"),
        }.get(kind) or {}
        collection = {
            "performer": root.get("performers"),
            "studio":    root.get("studios"),
            "tag":       root.get("tags"),
        }.get(kind) or []
        return _best_name_match(
            [{"id": x.get("id"), "name": x.get("name")} for x in collection],
            name,
        )
    except Exception as e:
        emit(f"search stashbox resolve {kind} {name!r}: {e}")
        return []


@app.post("/api/scenes/search")
async def api_scenes_search(payload: dict = Body(...)):
    """Cross-database scene search for /scenes → Search mode.

    Accepts optional ``title``, ``performer``, ``studio``, ``tag``,
    ``date_from``, ``date_to`` and a ``sources`` array (any of
    ``tpdb``, ``stashdb``, ``fansdb`` — defaults to all three).
    Results are merged, deduped by title+date, sorted by release date
    descending, and returned as feed-card dicts ready for the same
    ``renderSceneGrid`` renderer used by the other /scenes modes."""
    title   = (payload.get("title") or "").strip()
    perf    = (payload.get("performer") or "").strip()
    studio  = (payload.get("studio") or "").strip()
    tagname = (payload.get("tag") or "").strip()
    dfrom   = (payload.get("date_from") or "").strip()
    dto     = (payload.get("date_to") or "").strip()
    requested_sources = set((s or "").lower() for s in (payload.get("sources") or ["tpdb", "stashdb", "fansdb"]))
    per_page = min(max(int(payload.get("per_page") or 30), 1), 60)

    # Build a single combined query string for text endpoints (TPDB ``q``
    # and StashDB/FansDB ``queryScenes(name:)``). Filter-specific inputs
    # (date range, tag) are applied per-source below.
    q_parts = [x for x in (title, perf, studio, tagname) if x]
    q = " ".join(q_parts).strip()
    if not q and not (dfrom or dto):
        return JSONResponse({"error": "At least one search field required"}, status_code=400)

    cards: list[dict] = []
    seen_keys: set[str] = set()

    def _add(card: dict) -> None:
        if not card:
            return
        key = f"{(card.get('title') or '').lower()}|{(card.get('date') or '')}"
        if key in seen_keys:
            return
        seen_keys.add(key)
        cards.append(card)

    # ── TPDB (REST) ────────────────────────────────────────────────
    # Precise matching: resolve performer / studio / tag NAMES to numeric
    # ids first, then filter ``/scenes`` by those ids. If any name
    # filter the user provided doesn't exist on TPDB we skip the
    # source entirely — otherwise ``/scenes`` returns the global latest
    # (a dropped filter means no filter), which is exactly the
    # incorrect fuzzy-feeling behaviour we're trying to avoid.
    if "tpdb" in requested_sources and (db.get_settings().get("api_key_tpdb") or "").strip():
        tpdb_unresolved = False
        wanted_perf_ids: list[str] = []
        wanted_site_ids: list[str] = []
        wanted_tag_ids: list[str] = []
        wanted_tag_names_lower: set[str] = set()
        wanted_perf_names_lower: set[str] = set()
        wanted_site_names_lower: set[str] = set()
        if perf:
            wanted_perf_ids = _best_name_match(_tpdb_resolve_entity("performers", perf), perf)
            emit(f"search TPDB perf {perf!r} → {wanted_perf_ids}")
            if not wanted_perf_ids:
                tpdb_unresolved = True
            wanted_perf_names_lower.add(perf.strip().lower())
        if studio and not tpdb_unresolved:
            wanted_site_ids = _best_name_match(_tpdb_resolve_entity("sites", studio), studio)
            emit(f"search TPDB studio {studio!r} → {wanted_site_ids}")
            if not wanted_site_ids:
                tpdb_unresolved = True
            wanted_site_names_lower.add(studio.strip().lower())
        if tagname and not tpdb_unresolved:
            wanted_tag_ids = _best_name_match(_tpdb_resolve_entity("tags", tagname), tagname)
            emit(f"search TPDB tag {tagname!r} → {wanted_tag_ids}")
            if not wanted_tag_ids:
                tpdb_unresolved = True
            wanted_tag_names_lower.add(tagname.strip().lower())

        if tpdb_unresolved:
            emit("search TPDB: a name filter didn't resolve — skipping")
        else:
            # TPDB's combined ``performers[]`` + ``tags[]`` + ``sites[]``
            # behaviour is unreliable (we've seen it return 0 results
            # when the scene definitely has both). Instead: send ONE
            # primary filter (most selective → performer, then studio,
            # then tag) and post-filter the remaining fields client-side
            # against each scene's own payload. ``per_page`` bumped so
            # the candidate pool is wide enough after local filtering.
            fetch_count = per_page * 4
            params: list[tuple[str, str]] = [("per_page", str(min(fetch_count, 100))), ("page", "1")]
            if dfrom:
                params.append(("date[from]", dfrom))
            if dto:
                params.append(("date[to]", dto))
            if title:
                params.append(("title", title))
            primary_label = "none"
            if wanted_perf_ids:
                for pid in wanted_perf_ids:
                    params.append(("performers[]", pid))
                    params.append(("performers[]", pid))
                primary_label = f"performers={wanted_perf_ids}"
            elif wanted_site_ids:
                for sid in wanted_site_ids:
                    params.append(("sites[]", sid))
                    params.append(("sites[]", sid))
                primary_label = f"sites={wanted_site_ids}"
            elif wanted_tag_ids:
                for tid in wanted_tag_ids:
                    params.append(("tags[]", tid))
                    params.append(("tags[]", tid))
                primary_label = f"tags={wanted_tag_ids}"
            try:
                resp = requests.get(
                    "https://api.theporndb.net/scenes",
                    params=params, headers=_tpdb_headers(), timeout=15,
                )
                if resp.status_code != 200:
                    emit(f"search TPDB HTTP {resp.status_code}: {resp.text[:140]}")
                else:
                    hits = resp.json().get("data") or []
                    emit(f"search TPDB primary={primary_label}: {len(hits)} raw scenes")
                    kept = 0
                    for s_item in hits:
                        # Post-filter: when a secondary field was provided,
                        # the scene must carry that id (or at worst, that
                        # exact lowercase name) in its own payload. This
                        # is what gives us the AND semantics between
                        # filter fields that TPDB's own combined filter
                        # seems to fail at.
                        scene_perf_ids = {str((p or {}).get("parent", {}).get("id") or (p or {}).get("id") or (p or {}).get("performer", {}).get("id") or "") for p in (s_item.get("performers") or []) if isinstance(p, dict)}
                        scene_perf_names = {((p or {}).get("name") or (p or {}).get("parent", {}).get("name") or "").strip().lower() for p in (s_item.get("performers") or []) if isinstance(p, dict)}
                        scene_tag_ids = {str((t or {}).get("id") or "") for t in (s_item.get("tags") or []) if isinstance(t, dict)}
                        scene_tag_names = {((t or {}).get("name") or "").strip().lower() for t in (s_item.get("tags") or []) if isinstance(t, dict)}
                        scene_site_id = str((s_item.get("site") or {}).get("id") or "")
                        scene_site_name = str((s_item.get("site") or {}).get("name") or "").strip().lower()
                        # Performer check (if user asked for one and the
                        # primary filter wasn't performer-based).
                        if wanted_perf_ids and primary_label != f"performers={wanted_perf_ids}":
                            if not (set(wanted_perf_ids) & scene_perf_ids) and not (wanted_perf_names_lower & scene_perf_names):
                                continue
                        if wanted_site_ids and primary_label != f"sites={wanted_site_ids}":
                            if scene_site_id not in wanted_site_ids and scene_site_name not in wanted_site_names_lower:
                                continue
                        if wanted_tag_ids and primary_label != f"tags={wanted_tag_ids}":
                            if not (set(wanted_tag_ids) & scene_tag_ids) and not (wanted_tag_names_lower & scene_tag_names):
                                continue
                        try:
                            card = _tpdb_scene_payload_to_feed_card(s_item, source="search_tpdb")
                        except Exception:
                            card = None
                        if card:
                            kept += 1
                            _add(card)
                    emit(f"search TPDB: {kept} cards after post-filter")
            except Exception as e:
                emit(f"search TPDB error: {e}")

    # ── StashDB + FansDB (GraphQL queryScenes by name) ────────────
    stashbox_searches = []
    if "stashdb" in requested_sources:
        stashbox_searches.append(("stashdb", STASHDB_ENDPOINT, (db.get_settings().get("api_key_stashdb") or "").strip(), "https://stashdb.org/scenes/"))
    if "fansdb" in requested_sources:
        stashbox_searches.append(("fansdb", FANSDB_ENDPOINT, (db.get_settings().get("api_key_fansdb") or "").strip(), "https://fansdb.cc/scenes/"))

    gql_query = """
      query SearchScenes($input: SceneQueryInput!) {
        queryScenes(input: $input) {
          scenes {
            id title details release_date duration
            images { url }
            studio { name }
            performers { performer { name gender } }
            tags { name }
          }
        }
      }
    """
    for src_key, endpoint, key, url_prefix in stashbox_searches:
        if not key:
            emit(f"search {src_key}: skipped — no API key set")
            continue
        try:
            input_obj: dict = {
                "page": 1,
                "per_page": min(per_page, 40),
                "sort": "DATE",
                "direction": "DESC",
            }
            # Resolve name filters to IDs on the Stash-box instance, then
            # attach them as INCLUDES_ALL criterion filters for precise
            # matching. If a name doesn't resolve, we drop the search
            # silently (returning zero results rather than mis-filtered).
            missing_filter = False
            if title:
                input_obj["title"] = title
            if perf:
                pids = _stashbox_resolve_entity(endpoint, key, "performer", perf)
                if not pids:
                    emit(f"search {src_key}: performer {perf!r} not found")
                    missing_filter = True
                else:
                    # ``INCLUDES`` = scene has at least one of these ids.
                    # Since the resolver returns a single id for an exact
                    # name match, INCLUDES and INCLUDES_ALL are equivalent
                    # here — but INCLUDES is accepted on every underlying
                    # column (including ``studio_id`` which is scalar and
                    # rejects INCLUDES_ALL).
                    input_obj["performers"] = {"value": pids, "modifier": "INCLUDES"}
                    emit(f"search {src_key} perf {perf!r} → {pids}")
            if studio:
                sids = _stashbox_resolve_entity(endpoint, key, "studio", studio)
                if not sids:
                    emit(f"search {src_key}: studio {studio!r} not found")
                    missing_filter = True
                else:
                    input_obj["studios"] = {"value": sids, "modifier": "INCLUDES"}
            if tagname:
                tids = _stashbox_resolve_entity(endpoint, key, "tag", tagname)
                if not tids:
                    emit(f"search {src_key}: tag {tagname!r} not found")
                    missing_filter = True
                else:
                    input_obj["tags"] = {"value": tids, "modifier": "INCLUDES"}
            if dfrom or dto:
                input_obj["date"] = {}
                if dfrom: input_obj["date"]["value"] = dfrom
                if dto: input_obj["date"]["value2"] = dto
                input_obj["date"]["modifier"] = "BETWEEN" if (dfrom and dto) else ("GREATER_THAN" if dfrom else "LESS_THAN")
            if missing_filter:
                continue
            # If no structured filter resolved, fall back to broad text
            # search — otherwise the endpoint would return the latest
            # global scenes.
            if len(input_obj) <= 4 and q:
                input_obj["text"] = q

            r = requests.post(
                endpoint,
                headers={"ApiKey": key, "Content-Type": "application/json"},
                json={"query": gql_query, "variables": {"input": input_obj}},
                timeout=15,
            )
            if r.status_code != 200:
                emit(f"search {src_key} HTTP {r.status_code}: {r.text[:140]}")
                continue
            body = r.json() or {}
            if body.get("errors"):
                emit(f"search {src_key} GraphQL errors: {str(body['errors'])[:200]}")
            scenes = ((body.get("data") or {}).get("queryScenes") or {}).get("scenes") or []
            emit(f"search {src_key}: {len(scenes)} scenes")
            for sc in scenes:
                perf_names: list[str] = []
                seen_p: set[str] = set()
                for p in (sc.get("performers") or []):
                    nm = ((p or {}).get("performer") or {}).get("name") or ""
                    if nm and nm.lower() not in seen_p:
                        seen_p.add(nm.lower())
                        perf_names.append(nm)
                img = ""
                imgs = sc.get("images") or []
                if imgs and isinstance(imgs[0], dict):
                    img = imgs[0].get("url") or ""
                sid = str(sc.get("id") or "")
                _add({
                    "id": sid,
                    "title": sc.get("title") or "",
                    "date": sc.get("release_date") or "",
                    "studio": (sc.get("studio") or {}).get("name") or "",
                    "performer": ", ".join(perf_names),
                    "hover_performers": perf_names,
                    "thumb": img,
                    "link": f"{url_prefix}{sid}" if sid else "",
                    "source": f"search_{src_key}",
                    "tags": [(t or {}).get("name") or "" for t in (sc.get("tags") or []) if (t or {}).get("name")],
                    "description": (sc.get("details") or "").strip(),
                    "duration": int(sc.get("duration") or 0),
                })
        except Exception as e:
            emit(f"search {src_key} error: {e}")

    # Sort by date desc (newest first). Scenes without a date sink.
    cards.sort(key=lambda c: c.get("date") or "", reverse=True)
    return {"scenes": cards[:per_page], "count": len(cards), "sources_queried": sorted(list(requested_sources))}


@app.get("/api/scenes/feed")
async def scenes_feed(mode: str = "studios", tag_ids: str = ""):
    """TPDB scenes feed: ``studios``, ``performers``, ``random``, ``favourites``, ``tags``.

    ``tags`` mode filters TPDB /scenes by one or more tag UUIDs. When
    ``tag_ids`` is empty, falls back to every UUID in the ``monitored_tags``
    setting (JSON array of ``{id,name}`` objects).
    """
    fk = _content_filters_fingerprint()
    m = (mode or "studios").strip().lower()
    if m == "library":
        m = "random"
    if m == "recent":
        m = "performers"
    if m not in ("studios", "performers", "random", "favourites", "tags"):
        m = "studios"

    tag_selection: list[str] = []
    tag_selection_names: set[str] = set()
    tag_name_by_token: dict[str, str] = {}
    if m == "tags":
        # Empty ``tag_ids`` param = user has deselected everything. Return
        # no results (the frontend shows an empty-state message). Only an
        # explicit non-empty selection triggers a feed.
        requested_ids = {x.strip() for x in (tag_ids or "").split(",") if x.strip()}
        if requested_ids:
            try:
                stored = db.get_settings().get("monitored_tags") or "[]"
                parsed = json.loads(stored) if stored else []
            except Exception:
                parsed = []
            stored_tags = [t for t in parsed if isinstance(t, dict)]

            def _tok(t: dict) -> str:
                # Prefer slug (TPDB /scenes tag filter expects slugs); fall
                # back to id when older saved chips lack a slug field.
                return str(t.get("slug") or t.get("id") or "").strip()

            seen: set[str] = set()
            for t in stored_tags:
                if str(t.get("id") or "").strip() in requested_ids or str(t.get("slug") or "").strip() in requested_ids:
                    tok = _tok(t)
                    if tok and tok not in seen:
                        seen.add(tok)
                        tag_selection.append(tok)
                        raw_name = str(t.get("name") or "").strip()
                        if raw_name:
                            tag_selection_names.add(raw_name.lower())
                            tag_name_by_token[tok] = raw_name

    cache_key = m if m != "tags" else ("tags:" + ",".join(sorted(tag_selection)))

    # Skip the outer cache for tags mode — the per-tag raw-scene pool
    # cache already makes the re-build cheap, and bypassing this cache
    # means the user sees the latest matching logic immediately rather
    # than 1-hour-stale cards when they re-select tags.
    if m != "tags":
        with _content_cache_lock:
            bucket = _feed_cache.get(cache_key) or {}
            age = time.time() - float(bucket.get("ts") or 0)
            scenes_cached = bucket.get("scenes") or []
            if (
                scenes_cached
                and age < _FEED_CACHE_TTL
                and bucket.get("filter_key") == fk
            ):
                return {
                    "scenes": scenes_cached,
                    "source": bucket.get("source", ""),
                    "feed_mode": m,
                    "cached": True,
                    "cache_age_s": int(age),
                    "tag_ids": tag_selection,
                }

    _feed_limit = 30
    if m == "tags":
        if not tag_selection:
            return {
                "scenes": [],
                "source": "tags_empty",
                "feed_mode": "tags",
                "error": "no_tags",
                "tag_ids": [],
            }
        scenes = _fetch_tpdb_tags_feed_scenes(
            tag_selection, _feed_limit, tag_selection_names, tag_name_by_token,
        )
        source = "tags"
    elif m == "favourites":
        scenes = _fetch_tpdb_starred_favourites_feed(_feed_limit)
        source = "favourites" if scenes else ""
        if not scenes:
            source = "favourites_empty"
    elif m == "studios":
        scenes, source = _fetch_tpdb_studios_feed_scenes(_feed_limit)
    elif m == "performers":
        scenes, source = _fetch_tpdb_performers_feed_scenes(_feed_limit)
    else:
        scenes = _fetch_tpdb_feed(_feed_limit)
        source = "feed"
    if not scenes and m != "tags":
        scenes = _fetch_tpdb_feed_from_api(_feed_limit)
        source = "api"

    # Tags mode isn't stored in the outer cache (see earlier comment).
    if m != "tags":
        with _content_cache_lock:
            _feed_cache[cache_key] = {
                "scenes": scenes,
                "ts": time.time(),
                "source": source,
                "filter_key": fk,
            }
    return {
        "scenes": scenes,
        "source": source,
        "feed_mode": m,
        "tag_ids": tag_selection,
    }


