def _tpdb_extract_phash(payload: dict) -> str | None:
    """Pull a phash hex string from a TPDB scene payload's ``hashes``
    array. Accepts several shapes: list of dicts with ``type: phash``,
    list of strings, or nested objects."""
    if not isinstance(payload, dict):
        return None
    hashes = payload.get("hashes")
    if not hashes:
        return None
    if isinstance(hashes, list):
        for h in hashes:
            if isinstance(h, dict):
                t = (h.get("type") or h.get("algorithm") or "").strip().lower()
                if t == "phash":
                    v = h.get("hash") or h.get("value") or h.get("digest")
                    if v:
                        return str(v).strip().lower()
            elif isinstance(h, str) and len(h.strip()) in (16, 17):
                # Raw 16-char hex (phash) — fallback when type is implicit.
                return h.strip().lower()
    if isinstance(hashes, dict):
        v = hashes.get("phash") or hashes.get("PHASH") or hashes.get("perceptual")
        if v:
            return str(v).strip().lower()
    return None


def _wanted_enrich_row(row_id: int) -> None:
    """Fetch TPDB detail for a wanted row, pull its phash, then query
    StashDB + FansDB by that phash to establish cross-references.
    Runs in a background thread — never raises."""
    try:
        rows = db.wanted_list(active_only=False)
        row = next((r for r in rows if r.get("id") == int(row_id)), None)
        if not row:
            return
        kind = (row.get("kind") or "scene").lower()
        source = (row.get("source") or "").lower()
        ext_id = (row.get("external_id") or "").strip()
        if not ext_id:
            return

        keys = get_api_keys()
        phash = (row.get("phash") or "").strip().lower()

        # Step 1: pull TPDB detail (scenes only — movies have no phash
        # in their hashes field and don't exist on StashDB / FansDB).
        if source in ("tpdb", "theporndb", "porndb") and kind == "scene" and keys.get("tpdb"):
            try:
                r = requests.get(
                    f"https://api.theporndb.net/scenes/{ext_id}",
                    headers=_tpdb_headers(),
                    timeout=12,
                )
                if r.status_code == 200:
                    data = (r.json() or {}).get("data") or {}
                    title = data.get("title") or row.get("title") or ""
                    studio = ((data.get("site") or {}).get("name")
                              or (data.get("studio") or {}).get("name")
                              or row.get("studio") or "")
                    release_date = data.get("date") or row.get("release_date") or ""
                    description = (data.get("description") or row.get("description") or "").strip()
                    duration = int(data.get("duration") or row.get("duration") or 0)
                    thumb_url = _tpdb_pick_thumb(data) or row.get("thumb_url") or ""
                    tags_list = _tpdb_scene_tag_names(data)
                    perf_names: list[str] = []
                    seen = set()
                    for p in (data.get("performers") or []):
                        if not isinstance(p, dict):
                            continue
                        perf = p.get("performer") or p
                        nm = (perf.get("name") or perf.get("full_name") or "").strip()
                        if nm and nm.lower() not in seen:
                            seen.add(nm.lower())
                            perf_names.append(nm)
                    performers_str = ", ".join(perf_names) if perf_names else (row.get("performers") or "")
                    if not phash:
                        tpdb_phash = _tpdb_extract_phash(data)
                        if tpdb_phash:
                            phash = tpdb_phash
                    # Upsert enriched fields (keeps row id stable via ON CONFLICT).
                    db.wanted_add(
                        kind=kind, source=source, external_id=ext_id,
                        title=title, studio=studio, release_date=release_date,
                        performers=performers_str, thumb_url=thumb_url,
                        description=description, phash=phash or None,
                        tags=tags_list or [], duration=duration,
                        source_url=row.get("source_url") or _wanted_build_source_url(kind, source, ext_id),
                    )
            except Exception as e:
                emit(f"wanted enrich TPDB fetch error: {e}")

        # Step 2: cross-ref StashDB + FansDB by phash. Only when we have
        # a phash — which we may not, if TPDB has no submitted hash for
        # this scene yet.
        if not phash:
            db.wanted_mark_enriched(int(row_id))
            return

        probes = [
            ("stashdb", STASHDB_ENDPOINT, keys.get("stashdb"), STASHDB_QUERY, "full",  "https://stashdb.org/scenes/"),
            ("fansdb",  FANSDB_ENDPOINT,  keys.get("fansdb"),  STASHDB_QUERY, "full",  "https://fansdb.cc/scenes/"),
        ]
        for src_key, endpoint, key, gql, qtype, url_prefix in probes:
            if not key:
                continue
            try:
                matches = query_stashbox(phash, endpoint, key, gql, qtype)
            except Exception:
                matches = []
            if matches:
                first = matches[0]
                sid = (first or {}).get("id") or ""
                if sid:
                    db.wanted_set_crossref(int(row_id), src_key, str(sid), f"{url_prefix}{sid}")
                    # Stash the phash on the cross-referenced source
                    # too, so later rescans (regardless of which side
                    # the new file resolves to) auto-clear this entry.
                    db.wanted_set_phash("scene", src_key, str(sid), phash)
        db.wanted_mark_enriched(int(row_id))
    except Exception as e:
        emit(f"wanted enrich row {row_id} error: {e}")


def _wanted_cross_reference_by_phash(phash_hex: str) -> None:
    """Query StashDB / TPDB / FansDB for matches on ``phash_hex`` and
    clear any wanted row whose (kind, source, external_id) tuple matches
    one of the returned scene ids. This covers the case where a scene
    was added to Wanted from source A but the phash only resolves on
    source B — without this cross-ref the Wanted row would linger even
    though the library now has the file."""
    ph = (phash_hex or "").strip()
    if not ph:
        return
    keys = get_api_keys()
    probes = [
        ("stashdb", STASHDB_ENDPOINT, keys["stashdb"], STASHDB_QUERY, "full"),
        ("tpdb",    TPDB_ENDPOINT,    keys["tpdb"],    TPDB_QUERY,    "scene"),
        ("fansdb",  FANSDB_ENDPOINT,  keys["fansdb"],  STASHDB_QUERY, "full"),
    ]
    for source_key, endpoint, key, gql, qtype in probes:
        if not key:
            continue
        try:
            matches = query_stashbox(ph, endpoint, key, gql, qtype)
        except Exception:
            continue
        for m in matches or []:
            sid = (m or {}).get("id") or ""
            if not sid:
                continue
            try:
                db.wanted_mark_acquired("scene", source_key, str(sid))
                db.wanted_set_phash("scene", source_key, str(sid), ph)
            except Exception:
                pass


def _wanted_build_source_url(kind: str, source: str, external_id: str) -> str:
    """Derive the best public URL for the wanted item based on its
    origin database. Falls back to an empty string if we don't know
    the URL pattern for the given source."""
    k = (kind or "").lower()
    s = (source or "").lower()
    if not external_id:
        return ""
    if s in ("tpdb", "theporndb", "porndb"):
        return f"https://theporndb.net/{'movies' if k == 'movie' else 'scenes'}/{external_id}"
    if s == "stashdb":
        return f"https://stashdb.org/scenes/{external_id}"
    if s == "fansdb":
        return f"https://fansdb.cc/scenes/{external_id}"
    if s == "tmdb":
        return f"https://www.themoviedb.org/movie/{external_id}"
    return ""


@app.post("/api/wanted")
async def api_wanted_add(payload: dict = Body(...)):
    kind = (payload.get("kind") or "scene").strip().lower()
    source = (payload.get("source") or "").strip().lower()
    external_id = (payload.get("external_id") or payload.get("id") or "").strip()
    if not external_id:
        return JSONResponse({"error": "external_id required"}, status_code=400)
    if kind not in ("scene", "movie"):
        return JSONResponse({"error": "kind must be scene or movie"}, status_code=400)
    try:
        row_id = db.wanted_add(
            kind=kind,
            source=source,
            external_id=external_id,
            title=payload.get("title") or "",
            studio=payload.get("studio") or "",
            release_date=payload.get("release_date") or payload.get("date") or "",
            performers=payload.get("performers") or "",
            thumb_url=payload.get("thumb_url") or payload.get("thumb") or payload.get("image") or "",
            description=payload.get("description") or payload.get("synopsis") or "",
            phash=payload.get("phash"),
            tags=payload.get("tags") or [],
            duration=payload.get("duration") or 0,
            source_url=payload.get("source_url") or _wanted_build_source_url(kind, source, external_id),
        )
        # Enrich in the background so the toggle response is instant.
        # Pulls TPDB detail (fills any sparse fields) and cross-refs
        # StashDB / FansDB by the TPDB phash if one exists.
        if row_id:
            threading.Thread(
                target=_wanted_enrich_row, args=(row_id,),
                daemon=True, name=f"wanted-enrich-{row_id}",
            ).start()
        return {"added": True, "id": row_id}
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


@app.delete("/api/wanted/{wanted_id}")
async def api_wanted_delete(wanted_id: int):
    ok = db.wanted_remove(int(wanted_id))
    return {"removed": bool(ok)}


@app.post("/api/wanted/{wanted_id}/refresh")
async def api_wanted_refresh(wanted_id: int):
    """Re-fetch scene/movie detail from the source DB and update the
    wanted row with any fresh metadata (studio, performers, tags,
    description, duration). Used by the per-row refresh button to
    populate items that were saved before richer fields were captured."""
    rows = db.wanted_list(active_only=False)
    row = next((r for r in rows if r.get("id") == int(wanted_id)), None)
    if not row:
        return JSONResponse({"error": "not found"}, status_code=404)
    kind = (row.get("kind") or "scene").lower()
    source = (row.get("source") or "").lower()
    ext_id = (row.get("external_id") or "").strip()
    if not ext_id:
        return JSONResponse({"error": "missing external_id"}, status_code=400)

    title = row.get("title") or ""
    studio = row.get("studio") or ""
    release_date = row.get("release_date") or ""
    performers = row.get("performers") or ""
    thumb_url = row.get("thumb_url") or ""
    description = row.get("description") or ""
    duration = row.get("duration") or 0
    tags: list[str] = []
    try:
        existing_tags = json.loads(row.get("tags_json") or "[]")
        if isinstance(existing_tags, list):
            tags = [str(t) for t in existing_tags if t]
    except Exception:
        pass

    try:
        # TPDB scenes + movies: single-endpoint REST fetch with rich body.
        if source in ("tpdb", "theporndb", "porndb"):
            path = "movies" if kind == "movie" else "scenes"
            r = requests.get(
                f"https://api.theporndb.net/{path}/{ext_id}",
                headers=_tpdb_headers(),
                timeout=12,
            )
            if r.status_code == 200:
                data = (r.json() or {}).get("data") or {}
                title = data.get("title") or title
                studio = ((data.get("site") or {}).get("name")
                          or (data.get("studio") or {}).get("name")
                          or studio)
                release_date = data.get("date") or data.get("release_date") or release_date
                description = (data.get("description") or data.get("synopsis") or description or "").strip()
                duration = int(data.get("duration") or duration or 0)
                thumb_url = _tpdb_pick_thumb(data) or thumb_url
                tags = _tpdb_scene_tag_names(data) or tags
                perf_names: list[str] = []
                seen = set()
                for p in (data.get("performers") or []):
                    if not isinstance(p, dict):
                        continue
                    perf = p.get("performer") or p
                    nm = (perf.get("name") or perf.get("full_name") or "").strip()
                    if nm and nm.lower() not in seen:
                        seen.add(nm.lower())
                        perf_names.append(nm)
                if perf_names:
                    performers = ", ".join(perf_names)
    except Exception as e:
        emit(f"wanted refresh error: {e}")

    db.wanted_add(
        kind=kind,
        source=source,
        external_id=ext_id,
        title=title,
        studio=studio,
        release_date=release_date,
        performers=performers,
        thumb_url=thumb_url,
        description=description,
        phash=row.get("phash"),
        tags=tags,
        duration=duration,
        source_url=row.get("source_url") or _wanted_build_source_url(kind, source, ext_id),
    )
    # Also run the cross-box enrichment (TPDB phash → StashDB + FansDB)
    # synchronously so the user sees matched logos the moment the
    # refresh completes. This blocks the request for up to ~3s.
    try:
        _wanted_enrich_row(int(wanted_id))
    except Exception:
        pass
    return {"refreshed": True}


@app.post("/api/wanted/toggle")
async def api_wanted_toggle(payload: dict = Body(...)):
    """Idempotent toggle — remove if already wanted (by kind+source+id),
    otherwise add. Returns ``{wanted: bool}`` for the eye-icon state."""
    kind = (payload.get("kind") or "scene").strip().lower()
    source = (payload.get("source") or "").strip().lower()
    external_id = (payload.get("external_id") or payload.get("id") or "").strip()
    if not external_id:
        return JSONResponse({"error": "external_id required"}, status_code=400)
    keys = db.wanted_active_external_ids()
    already = any(
        k["kind"] == kind and k["source"] == source and k["external_id"] == external_id
        for k in keys
    )
    if already:
        db.wanted_remove_by_external(kind, source, external_id)
        return {"wanted": False}
    try:
        new_id = db.wanted_add(
            kind=kind,
            source=source,
            external_id=external_id,
            title=payload.get("title") or "",
            studio=payload.get("studio") or "",
            release_date=payload.get("release_date") or payload.get("date") or "",
            performers=payload.get("performers") or "",
            thumb_url=payload.get("thumb_url") or payload.get("thumb") or payload.get("image") or "",
            description=payload.get("description") or payload.get("synopsis") or "",
            phash=payload.get("phash"),
            tags=payload.get("tags") or [],
            duration=payload.get("duration") or 0,
            source_url=payload.get("source_url") or _wanted_build_source_url(kind, source, external_id),
        )
        if new_id:
            threading.Thread(
                target=_wanted_enrich_row, args=(new_id,),
                daemon=True, name=f"wanted-enrich-{new_id}",
            ).start()
        return {"wanted": True}
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


@app.get("/api/prowlarr/search")
async def prowlarr_search_endpoint(q: str):
    if not q.strip():
        return JSONResponse({"error": "Query required"}, status_code=400)
    # Search Prowlarr indexers directly
    results = prowlarr_search(q.strip())
    try:
        studio_idx, perf_idx = db._build_library_match_indexes()
        for r in results or []:
            title = (r.get("title") or "").strip()
            if not title:
                continue
            m = db._library_guess_from_release_name(title, studio_idx, perf_idx)
            r["match"] = {
                "studio": m.get("studio"),
                "performers": (m.get("performers") or [])[:3],
            }
    except Exception:
        pass
    return {"results": results}


#: Top-Shelf uid tagging — we inject a short opaque tag into the
#: prowlarr release title before sending it to the download client,
#: so when the file later lands in the source folder we can identify
#: which /scenes grab produced it without relying on filename
#: heuristics that the client may have mangled. Display strips the
#: tag for the user-facing name.
#:
#: We send the tag bracketed (`[ts-XXXXXXXX]`) but most download
#: clients sanitise the job name on intake — NZBGet and SABnzbd both
#: strip brackets, leaving us with a bare ` ts-XXXXXXXX` token. The
#: regex therefore accepts the tag with or without surrounding
#: brackets / parens / dots / underscores, so we match what actually
#: shows up on disk regardless of which client mangled it.
TS_UID_RE = re.compile(
    r"\s*[\[\(\.\_\-]*ts[-_]([a-f0-9]{8})[\]\)\.\_\-]*\s*",
    re.IGNORECASE,
)


def _strip_ts_uid(name: str) -> tuple[str, str]:
    """Remove the `[ts-XXXXXXXX]` tag from a job/file name. Returns
    (cleaned_name, uid_or_empty). Idempotent — safe on names that
    don't contain a tag, returns (name, '')."""
    if not name:
        return "", ""
    m = TS_UID_RE.search(name)
    if not m:
        return name, ""
    cleaned = TS_UID_RE.sub(" ", name).strip()
    return cleaned, m.group(1).lower()


@app.post("/api/prowlarr/grab")
async def prowlarr_grab_endpoint(payload: dict):
    guid         = payload.get("guid", "")
    indexer_id   = payload.get("indexer_id")
    is_torrent   = payload.get("type", "torrent") == "torrent"
    download_url = payload.get("download_url", "")
    if not guid and not download_url:
        return JSONResponse({"error": "guid or download_url required"}, status_code=400)

    # Mint a uid for this grab and inject it into the release title we
    # hand to the download client. The job/filename the client uses
    # carries the tag verbatim so we can match the eventual file back
    # to this scene_grab_log row regardless of how the client renames
    # things or how the unpack mangles the basename. 8 hex chars =
    # 32 bits of entropy — collision risk negligible for our scale.
    ts_uid = secrets.token_hex(4)
    raw_title = (payload.get("title") or "").strip()
    if raw_title and "[ts-" not in raw_title.lower():
        payload["title"] = f"{raw_title} [ts-{ts_uid}]"

    # If the caller (e.g. /scenes) tagged this grab with a source scene,
    # persist the link before we hand off to the download client. The
    # release title is what eventually shows up as the job name on the
    # client + as the filename in the queue, so it's our match key.
    def _record_source_scene_grab(success: bool) -> None:
        if not success:
            return
        src = payload.get("source_scene") or {}
        if not isinstance(src, dict):
            return
        sdb = (src.get("db") or "").strip()
        sid = (src.get("id") or "").strip()
        if not sdb or not sid:
            return
        rt = (payload.get("title") or "").strip()
        if not rt:
            return
        try:
            db.record_scene_grab(
                release_title=rt,
                guid=guid,
                download_url=download_url,
                source_db=sdb,
                source_id=sid,
                kind=str(payload.get("kind") or "scene").strip().lower(),
                ts_uid=ts_uid,
                source_title=src.get("title") or "",
                source_studio=src.get("studio") or "",
                source_performers=src.get("performers") or [],
                source_poster_url=src.get("poster_url") or "",
                source_date=src.get("date") or "",
            )
        except Exception as exc:
            emit(f"GRAB scene-tag persist error: {exc}")

    s = db.get_settings()
    kind = str(payload.get("kind") or payload.get("content") or "").strip().lower()
    base_cat = (s.get("prowlarr_category") or "Top-Shelf").strip() or "Top-Shelf"
    if kind in ("movie", "movies"):
        movie_cat = (s.get("prowlarr_category_movies") or "").strip()
        category = movie_cat or base_cat
    else:
        category = base_cat

    # Determine client settings — new dl_ fields, with legacy nzbget_ fallback
    nzb_client  = s.get("dl_nzb_client", "").lower().strip()
    nzb_host    = s.get("dl_nzb_host", "").strip()
    nzb_port    = s.get("dl_nzb_port", "").strip()
    nzb_user    = s.get("dl_nzb_user", "").strip()
    nzb_pass    = s.get("dl_nzb_pass", "")
    nzb_apikey  = s.get("dl_nzb_api_key", "").strip()

    # Legacy fallback for existing NZBGet settings
    if not nzb_client and s.get("nzbget_url", "").strip():
        nzb_client = "nzbget"
        legacy_url = s.get("nzbget_url", "").strip().rstrip("/")
        m = re.match(r'https?://([^:/]+)(?::(\d+))?', legacy_url)
        if m:
            nzb_host = m.group(1)
            nzb_port = m.group(2) or "6789"
        nzb_user = s.get("nzbget_user", "").strip()
        nzb_pass = s.get("nzbget_pass", "")

    torrent_client = s.get("dl_torrent_client", "").lower().strip()
    torrent_host   = s.get("dl_torrent_host", "").strip()
    torrent_port   = s.get("dl_torrent_port", "").strip()
    torrent_user   = s.get("dl_torrent_user", "").strip()
    torrent_pass   = s.get("dl_torrent_pass", "")

    # Helper: fetch torrent URL, handling magnet redirects
    def _fetch_torrent(url):
        """Returns (magnet_url, torrent_bytes) — one will be set."""
        r = requests.get(url, timeout=20, allow_redirects=False)
        if r.status_code in (301, 302, 303, 307, 308):
            loc = r.headers.get("Location", "")
            if loc.startswith("magnet:"):
                emit("GRAB download link redirected to magnet")
                return loc, None
            r = requests.get(loc, timeout=20, allow_redirects=True)
        if r.status_code == 200:
            return None, r.content
        raise Exception(f"Failed to fetch torrent (HTTP {r.status_code})")

    # ---- NZBs ----
    if download_url and not is_torrent:
        if not nzb_client or not nzb_host:
            return {"error": "No NZB download client configured — add one in Settings"}
        try:
            emit(f"GRAB nzb url → {download_url[:120]}")
            r = requests.get(download_url, timeout=20, allow_redirects=True)
            emit(f"GRAB nzb fetch → {r.status_code} size={len(r.content)}")
            if r.status_code != 200:
                return {"error": f"Failed to fetch NZB file (HTTP {r.status_code})"}

            import base64 as b64
            nzb_content  = r.content
            # Try to get a meaningful filename from URL query param, then title, then guid
            if "file=" in download_url:
                nzb_filename = download_url.split("file=")[-1].split("&")[0]
            elif "title=" in download_url:
                import urllib.parse
                nzb_filename = urllib.parse.unquote_plus(download_url.split("title=")[-1].split("&")[0])
            else:
                # Fall back to guid or a sanitised version of the item title from payload
                raw_name = payload.get("title") or guid.split("/")[-1] or "release"
                nzb_filename = re.sub(r'[^\w\s\-\.]', '', raw_name)[:120].strip() or "release"
            if not nzb_filename.lower().endswith(".nzb"):
                nzb_filename += ".nzb"

            if nzb_client == "nzbget":
                port = nzb_port or "6789"
                emit(f"GRAB NZBGet → {nzb_host}:{port} user={nzb_user!r}")
                auth = (nzb_user, nzb_pass) if nzb_user else None
                gr = requests.post(
                    f"http://{nzb_host}:{port}/jsonrpc",
                    json={"method": "append", "params": [
                        re.sub(r'[^\w\s\-]', '', payload.get("title") or nzb_filename.replace(".nzb",""))[:120].strip() or nzb_filename,
                        b64.b64encode(nzb_content).decode(),
                        category, 0, False, False, "", 0, "SCORE"
                    ]},
                    auth=auth, timeout=15,
                )
                emit(f"GRAB NZBGet → {gr.status_code} {gr.text[:120]}")
                if gr.status_code == 200:
                    result = gr.json().get("result")
                    if result and result > 0:
                        _record_source_scene_grab(True)
                        return {"ok": True}
                    return {"error": f"NZBGet rejected the file (result={result})"}
                return {"error": f"NZBGet HTTP {gr.status_code} — check credentials in Settings"}

            elif nzb_client == "sabnzbd":
                port = nzb_port or "8080"
                emit(f"GRAB SABnzbd → {nzb_host}:{port} nzbname={clean_job_name!r}")
                # nzbname overrides the internal job name (avoids all-'release' DUPE false-positives)
                clean_job_name = re.sub(r'[^\w\s\-]', '', payload.get("title") or nzb_filename.replace(".nzb", ""))[:120].strip() or nzb_filename.replace(".nzb", "")
                gr = requests.post(
                    f"http://{nzb_host}:{port}/sabnzbd/api",
                    data={"mode": "addfile", "apikey": nzb_apikey, "cat": category, "output": "json", "nzbname": clean_job_name},
                    files={"nzbfile": (nzb_filename, nzb_content)},
                    timeout=15,
                )
                emit(f"GRAB SABnzbd → {gr.status_code} {gr.text[:120]}")
                if gr.status_code == 200:
                    _record_source_scene_grab(True)
                    return {"ok": True}
                return {"error": f"SABnzbd HTTP {gr.status_code}"}

        except Exception as e:
            emit(f"GRAB nzb error: {e}")
            return {"error": f"NZB download failed: {e}"}

    # ---- Torrents ----
    if download_url and is_torrent:
        if not torrent_client or not torrent_host:
            return {"error": "No torrent download client configured — add one in Settings"}
        is_magnet = download_url.startswith("magnet:")
        try:
            if torrent_client == "qbittorrent":
                port = torrent_port or "8080"
                qb_base = f"http://{torrent_host}:{port}"
                emit(f"GRAB qBittorrent → {torrent_host}:{port} user={torrent_user!r}")
                sess = requests.Session()
                # qBittorrent 4.6.1+ requires Referer/Origin for CSRF protection
                sess.headers.update({
                    "Referer": f"{qb_base}/",
                    "Origin": qb_base,
                })
                login_r = sess.post(
                    f"{qb_base}/api/v2/auth/login",
                    data={"username": torrent_user, "password": torrent_pass}, timeout=10,
                )
                emit(f"GRAB qBittorrent login → {login_r.status_code} {login_r.text[:60]}")
                if login_r.status_code == 403:
                    return {"error": "qBittorrent returned 403 — check Web UI is enabled, and host IP is not banned. Try restarting qBittorrent."}
                if login_r.text.strip() == "Fails.":
                    return {"error": "qBittorrent login failed — wrong username or password in Settings"}
                if is_magnet:
                    gr = sess.post(
                        f"{qb_base}/api/v2/torrents/add",
                        data={"urls": download_url, "category": category}, timeout=15,
                    )
                else:
                    magnet, torrent_bytes = _fetch_torrent(download_url)
                    if magnet:
                        gr = sess.post(
                            f"{qb_base}/api/v2/torrents/add",
                            data={"urls": magnet, "category": category}, timeout=15,
                        )
                    else:
                        gr = sess.post(
                            f"{qb_base}/api/v2/torrents/add",
                            data={"category": category},
                            files={"torrents": ("release.torrent", torrent_bytes)}, timeout=15,
                        )
                emit(f"GRAB qBittorrent → {gr.status_code} {gr.text[:80]}")
                if gr.status_code == 200:
                    _record_source_scene_grab(True)
                    return {"ok": True}
                return {"error": f"qBittorrent HTTP {gr.status_code}"}

            elif torrent_client == "transmission":
                port = torrent_port or "9091"
                emit(f"GRAB Transmission → {torrent_host}:{port}")
                tsess = requests.Session()
                if torrent_user:
                    tsess.auth = (torrent_user, torrent_pass)
                try:
                    sr = tsess.get(f"http://{torrent_host}:{port}/transmission/rpc", timeout=10)
                except Exception:
                    sr = type('R', (), {'status_code': 0, 'headers': {}})()
                tsess.headers["X-Transmission-Session-Id"] = sr.headers.get("X-Transmission-Session-Id", "") if sr.status_code == 409 else ""
                if is_magnet:
                    args = {"filename": download_url}
                else:
                    magnet, torrent_bytes = _fetch_torrent(download_url)
                    if magnet:
                        args = {"filename": magnet}
                    else:
                        args = {"metainfo": base64.b64encode(torrent_bytes).decode()}
                gr = tsess.post(
                    f"http://{torrent_host}:{port}/transmission/rpc",
                    json={"method": "torrent-add", "arguments": args}, timeout=15,
                )
                emit(f"GRAB Transmission → {gr.status_code} {gr.text[:80]}")
                if gr.status_code == 200 and gr.json().get("result") == "success":
                    _record_source_scene_grab(True)
                    return {"ok": True}
                return {"error": f"Transmission: {gr.text[:120]}"}

            elif torrent_client == "deluge":
                port = torrent_port or "8112"
                emit(f"GRAB Deluge → {torrent_host}:{port}")
                dsess = requests.Session()
                dsess.post(
                    f"http://{torrent_host}:{port}/json",
                    json={"method": "auth.login", "params": [torrent_pass], "id": 1}, timeout=10,
                )
                if is_magnet:
                    gr = dsess.post(
                        f"http://{torrent_host}:{port}/json",
                        json={"method": "core.add_torrent_magnet", "params": [download_url, {}], "id": 2}, timeout=15,
                    )
                else:
                    magnet, torrent_bytes = _fetch_torrent(download_url)
                    if magnet:
                        gr = dsess.post(
                            f"http://{torrent_host}:{port}/json",
                            json={"method": "core.add_torrent_magnet", "params": [magnet, {}], "id": 2}, timeout=15,
                        )
                    else:
                        gr = dsess.post(
                            f"http://{torrent_host}:{port}/json",
                            json={"method": "core.add_torrent_file", "params": ["release.torrent", base64.b64encode(torrent_bytes).decode(), {}], "id": 2}, timeout=15,
                        )
                emit(f"GRAB Deluge → {gr.status_code} {gr.text[:80]}")
                if gr.status_code == 200 and gr.json().get("result"):
                    _record_source_scene_grab(True)
                    return {"ok": True}
                return {"error": f"Deluge: {gr.json().get('error', gr.text[:120])}"}

            else:
                return {"error": f"Unknown torrent client: {torrent_client}"}

        except Exception as e:
            emit(f"GRAB torrent error: {e}")
            return {"error": f"Torrent download failed: {e}"}

    client_type = "torrent client" if is_torrent else "NZB client"
    return {"error": f"No {client_type} configured — add one in Settings under Download Clients"}


