@app.get("/api/downloads/rss-feed")
async def api_downloads_rss_feed(refresh: bool = False):
    """Grouped RSS feed results, served from hourly cache. Pass ?refresh=true to force a reload."""
    if refresh or _rss_cache["fetched_at"] == 0.0:
        await asyncio.get_event_loop().run_in_executor(None, _refresh_rss_cache)

    with _rss_cache_lock:
        items = list(_rss_cache["items"])
        errors = list(_rss_cache["errors"])
        fetched_at = _rss_cache["fetched_at"]

    s = db.get_settings()
    raw = s.get("download_rss_feeds") or "[]"
    try:
        urls = json.loads(raw)
    except Exception:
        urls = []
    urls = [u.strip() for u in (urls if isinstance(urls, list) else []) if isinstance(u, str) and u.strip()]

    diagnostics = {
        "configured_urls": len(urls),
        "items_after_filter": len(items),
        "fetched_at": fetched_at,
        "cache_age_minutes": round((time.time() - fetched_at) / 60, 1) if fetched_at else None,
    }

    return {"results": items, "errors": errors, "diagnostics": diagnostics}


@app.get("/api/prowlarr/status")
async def prowlarr_status():
    s = db.get_settings()
    base = s.get("prowlarr_url", "").rstrip("/")
    if not base:
        return {"connected": False, "error": "Not configured"}
    try:
        resp = requests.get(f"{base}/api/v1/system/status",
                            headers=_prowlarr_headers(), timeout=8)
        resp.raise_for_status()
        d = resp.json()
        return {"connected": True, "version": d.get("version")}
    except Exception as e:
        return {"connected": False, "error": str(e)}


@app.get("/api/metadata/preview")
async def metadata_preview(type: str, source: str, id: str):
    """Fetch preview data (image, bio, meta, links) without creating any files."""
    if type == "performer":
        data = fetch_performer_detail(source, id)
        if not data:
            return {"image": None, "bio": "", "meta": "", "links": []}
        extras  = data.get("extras") or {}
        posters = data.get("posters") or []
        image   = posters[0].get("url") if posters and isinstance(posters[0], dict) else (posters[0] if posters else None)
        bio     = data.get("bio") or ""
        aliases = data.get("aliases") or []
        slug    = data.get("slug") or data.get("_id") or id
        meta_parts = [f"<span>{source}</span>"]
        if extras.get("birthday"):       meta_parts.append(f"Born: <span>{extras['birthday']}</span>")
        if extras.get("birthplace"):     meta_parts.append(f"From: <span>{extras['birthplace']}</span>")
        if extras.get("career_start_year"): meta_parts.append(f"Active: <span>{extras['career_start_year']}</span>")
        if extras.get("ethnicity"):      meta_parts.append(f"Ethnicity: <span>{extras['ethnicity']}</span>")
        if extras.get("measurements"):   meta_parts.append(f"Stats: <span>{extras['measurements']}</span>")
        if aliases: meta_parts.append(f"AKA: <span>{', '.join(aliases[:3])}</span>")

        # Build links — cross-reference all databases
        links = []
        performer_name = data.get("name") or ""
        settings = db.get_settings()

        # TPDB link
        if source == "TPDB":
            links.append({"label": "TPDB", "url": f"https://theporndb.net/performers/{slug}"})
        elif performer_name and settings.get("api_key_tpdb"):
            try:
                r = requests.get(TPDB_PERFORMER_SEARCH, params={"q": performer_name},
                                 headers=_tpdb_headers(), timeout=8)
                if r.status_code == 200:
                    pd = r.json().get("data") or []
                    if pd:
                        tslug = pd[0].get("slug") or pd[0].get("_id") or str(pd[0].get("id", ""))
                        links.append({"label": "TPDB", "url": f"https://theporndb.net/performers/{tslug}"})
            except Exception:
                pass

        # StashDB link + external URLs
        if settings.get("api_key_stashdb"):
            try:
                gql = 'query($t:String!){searchPerformer(term:$t,limit:1){id name urls{url type}}}'
                r = requests.post("https://stashdb.org/graphql",
                    json={"query": gql, "variables": {"t": performer_name}},
                    headers={"ApiKey": settings['api_key_stashdb'],
                             "Content-Type": "application/json"}, timeout=8)
                if r.status_code == 200:
                    sp = (r.json().get("data") or {}).get("searchPerformer") or []
                    if sp:
                        links.append({"label": "StashDB", "url": f"https://stashdb.org/performers/{sp[0]['id']}"})
                        # Add external URLs from StashDB performer profile
                        for u in (sp[0].get("urls") or []):
                            url = u.get("url", "")
                            if url:
                                label = _url_label(url)
                                # Don't duplicate links we already have
                                if not any(l["url"] == url for l in links):
                                    links.append({"label": label, "url": url})
            except Exception:
                pass

        # FansDB link
        if source == "FansDB":
            links.append({"label": "FansDB", "url": f"https://fansdb.cc/performers/{id}"})
        elif performer_name and settings.get("api_key_fansdb"):
            try:
                gql = "query($term:String!){searchPerformer(term:$term,limit:1){id name}}"
                data = _fansdb_gql(gql, {"term": performer_name})
                sp = (data or {}).get("searchPerformer") or []
                if sp:
                    links.append({"label": "FansDB", "url": f"https://fansdb.cc/performers/{sp[0]['id']}"})
            except Exception:
                pass

        # Pull external links from TPDB extras if available
        for link_item in (data.get("urls") or data.get("links") or []):
            if isinstance(link_item, str):
                links.append({"label": _url_label(link_item), "url": link_item})
            elif isinstance(link_item, dict):
                url = link_item.get("url") or link_item.get("link") or ""
                label = link_item.get("type") or link_item.get("label") or _url_label(url)
                if url:
                    links.append({"label": label, "url": url})

        return {"image": image, "bio": bio if bio else "", "meta": " &middot; ".join(meta_parts),
                "slug": slug, "links": links}
    else:
        data = fetch_studio_detail(source, id)
        if not data:
            return {"image": None, "bio": "", "meta": "", "links": []}
        image = data.get("logo") or data.get("poster")
        bio   = data.get("description") or data.get("bio") or ""
        slug  = data.get("slug") or data.get("_id") or id
        links = []
        if source == "TPDB":
            links.append({"label": "TPDB", "url": f"https://theporndb.net/sites/{slug}"})
        # Pull external links
        for link_item in (data.get("urls") or data.get("links") or data.get("url") and [data["url"]] or []):
            if isinstance(link_item, str):
                links.append({"label": _url_label(link_item), "url": link_item})
            elif isinstance(link_item, dict):
                url = link_item.get("url") or link_item.get("link") or ""
                label = link_item.get("type") or link_item.get("label") or _url_label(url)
                if url:
                    links.append({"label": label, "url": url})
        return {"image": image, "bio": bio if bio else "", "meta": f"<span>{source}</span>",
                "links": links}


def _url_label(url: str) -> str:
    """Extract a short label from a URL domain."""
    try:
        from urllib.parse import urlparse
        domain = urlparse(url).netloc.lower().replace("www.", "")
        labels = {
            "twitter.com": "Twitter", "x.com": "Twitter",
            "instagram.com": "Instagram",
            "reddit.com": "Reddit",
            "onlyfans.com": "OnlyFans",
            "fansly.com": "Fansly",
            "pornhub.com": "Pornhub",
            "xvideos.com": "XVideos",
            "theporndb.net": "TPDB",
            "stashdb.org": "StashDB",
            "fansdb.cc": "FansDB",
            "babepedia.com": "Babepedia",
            "freeones.com": "FreeOnes",
            "iafd.com": "IAFD",
        }
        return labels.get(domain, domain.split(".")[0].title())
    except Exception:
        return "Link"




def _fmt_measurements(p: dict | None) -> str:
    """Format performer measurement fields → '34D-24-36' from top-level StashDB fields."""
    if not p:
        return ""
    parts = []
    band = p.get("band_size")
    cup  = (p.get("cup_size") or "").strip().upper()
    if band and cup:
        parts.append(f"{band}{cup}")
    elif band:
        parts.append(str(band))
    if p.get("waist_size"):
        parts.append(str(p["waist_size"]))
    if p.get("hip_size"):
        parts.append(str(p["hip_size"]))
    return "-".join(parts)


# StashDB performer query for spotlight row
STASHDB_PERFORMER_QUERY = """
query QueryPerformers($input: PerformerQueryInput!) {
  queryPerformers(input: $input) {
    count
    performers {
      id
      name
      gender
      images { url }
      scene_count
      age
      created
      updated
      birth_date
      career_start_year
      height
      cup_size
      band_size
      waist_size
      hip_size
      breast_type
      country
      ethnicity
      eye_color
      hair_color
      tattoos { location }
      piercings { location }
    }
  }
}
"""

# Cup size ordinal for body-type classification
_CUP_RANK: dict[str, int] = {
    "A": 1, "B": 2, "C": 3, "D": 4, "DD": 5, "DDD": 6, "E": 6,
    "F": 7, "FF": 7, "G": 8, "GG": 8, "H": 9, "HH": 9,
}


def _spotlight_body_types(p: dict) -> set[str]:
    """Derive body-type tags from a performer's measurement/height fields.

    Tags: petite | tall | slim | athletic | curvy | busty | voluptuous
    Returns an empty set when there is not enough data to classify.
    """
    cup_raw  = (p.get("cup_size") or "").strip().upper()
    cup_rank = _CUP_RANK.get(cup_raw, 0)
    band     = p.get("band_size")     # int, inches
    waist    = p.get("waist_size")    # int, inches
    hip      = p.get("hip_size")      # int, inches
    height   = p.get("height")        # int, cm

    tags: set[str] = set()

    # Height-based
    if height:
        if height <= 163:
            tags.add("petite")
        if height >= 173:
            tags.add("tall")

    # Bust-based
    if cup_rank >= 5:                          # DD or larger
        tags.add("busty")
    if cup_rank >= 5 or (band and band >= 36):
        tags.add("voluptuous")

    # Waist-driven shape
    if waist:
        if waist <= 25 and (not cup_rank or cup_rank <= 3) and (not band or band <= 34):
            tags.add("slim")
        # Athletic: taller, lean waist, smaller bust
        if height and height >= 168 and waist <= 27 and cup_rank and cup_rank <= 3:
            tags.add("athletic")

    # Hip-to-waist ratio
    if hip and waist and (hip - waist) >= 12:
        tags.add("curvy")
    elif cup_rank >= 4 and not ("voluptuous" in tags):
        tags.add("curvy")

    return tags


def _spotlight_age(birthdate_str: str) -> int | None:
    if not birthdate_str:
        return None
    try:
        bd = _date.fromisoformat(birthdate_str[:10])
        today = _date.today()
        return today.year - bd.year - ((today.month, today.day) < (bd.month, bd.day))
    except Exception:
        return None


def _spotlight_in_library(name: str, s: dict) -> bool:
    norm = normalise(name)
    dirs = [s.get("series_dir", ""), s.get("features_dir", "")] + [
        d["path"] for d in db.get_directories()
    ]
    for dir_path in dirs:
        if not dir_path:
            continue
        base = Path(dir_path)
        if not base.exists():
            continue
        for folder in base.iterdir():
            if folder.is_dir() and normalise(folder.name) == norm:
                return True

    # Also check against saved aliases of library performers
    for entity in db.favourite_list():
        if entity.get("kind") != "performer":
            continue
        raw = entity.get("aliases_json")
        if not raw:
            continue
        try:
            aliases = json.loads(raw) if isinstance(raw, str) else raw
        except (json.JSONDecodeError, TypeError):
            continue
        for alias in _performer_aliases_as_strings(aliases):
            if normalise(alias) == norm:
                return True

    return False


